CREATE OR REPLACE FUNCTION "public"."abrir_ciclo"("p_cliente_id" "uuid", "p_numero" integer, "p_ano" integer DEFAULT NULL::integer, "p_meta_cobertura_pct" numeric DEFAULT 100.0, "p_observacao" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_ano          int := COALESCE(p_ano, EXTRACT(YEAR FROM now())::int);
  v_ciclo_id     uuid;
  v_user_id      uuid;
  v_data_inicio  date;
  v_data_fim     date;
  v_ja_ativo     boolean;
BEGIN
  -- Verificar permissão
  IF NOT public.usuario_pode_acessar_cliente(p_cliente_id) THEN
    RAISE EXCEPTION 'abrir_ciclo: sem permissão para este cliente';
  END IF;

  -- Verificar se já existe ciclo ativo para este cliente
  SELECT EXISTS (
    SELECT 1 FROM public.ciclos
    WHERE cliente_id = p_cliente_id AND status = 'ativo'
  ) INTO v_ja_ativo;

  IF v_ja_ativo THEN
    RAISE EXCEPTION 'abrir_ciclo: já existe um ciclo ativo. Feche-o antes de abrir um novo.';
  END IF;

  -- Calcular datas padrão do bimestre
  v_data_inicio := make_date(v_ano, (p_numero - 1) * 2 + 1, 1);
  v_data_fim    := (make_date(v_ano, LEAST(p_numero * 2, 12), 1)
                    + interval '1 month - 1 day')::date;

  -- Resolver usuário autenticado
  SELECT id INTO v_user_id
  FROM public.usuarios WHERE auth_id = auth.uid();

  -- Criar ou atualizar o ciclo para 'ativo'
  INSERT INTO public.ciclos (
    cliente_id, numero, ano, status,
    data_inicio, data_fim_prevista,
    meta_cobertura_pct, observacao_abertura,
    aberto_por
  ) VALUES (
    p_cliente_id, p_numero, v_ano, 'ativo',
    v_data_inicio, v_data_fim,
    p_meta_cobertura_pct, p_observacao,
    v_user_id
  )
  ON CONFLICT (cliente_id, numero, ano)
  DO UPDATE SET
    status               = 'ativo',
    meta_cobertura_pct   = EXCLUDED.meta_cobertura_pct,
    observacao_abertura  = EXCLUDED.observacao_abertura,
    aberto_por           = EXCLUDED.aberto_por,
    data_fechamento      = NULL,
    snapshot_fechamento  = NULL,
    fechado_por          = NULL
  RETURNING id INTO v_ciclo_id;

  RETURN jsonb_build_object(
    'ok',           true,
    'ciclo_id',     v_ciclo_id,
    'numero',       p_numero,
    'ano',          v_ano,
    'data_inicio',  v_data_inicio,
    'data_fim',     v_data_fim
  );
END;
$$;


ALTER FUNCTION "public"."abrir_ciclo"("p_cliente_id" "uuid", "p_numero" integer, "p_ano" integer, "p_meta_cobertura_pct" numeric, "p_observacao" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."abrir_ciclo"("p_cliente_id" "uuid", "p_numero" integer, "p_ano" integer, "p_meta_cobertura_pct" numeric, "p_observacao" "text") IS 'Abre formalmente um ciclo bimestral. Exige que não haja outro ciclo ativo. Registra aberto_por, datas e meta de cobertura.';



CREATE OR REPLACE FUNCTION "public"."analista_pode_acessar_cliente"("p_cliente_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM   public.agrupamento_cliente ac
    JOIN   public.usuarios u ON u.agrupamento_id = ac.agrupamento_id
    WHERE  u.auth_id   = auth.uid()
      AND  ac.cliente_id = p_cliente_id
  );
$$;


ALTER FUNCTION "public"."analista_pode_acessar_cliente"("p_cliente_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."avaliar_condicoes_voo"("p_cliente_id" "uuid", "p_data" "date" DEFAULT CURRENT_DATE) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row          record;
  v_apto         boolean := true;
  v_motivos      text[]  := '{}';
  v_nivel        text    := 'verde';
  v_vento        float   := null;
  v_chuva_24h    float   := null;
  v_prev_d1      float   := null;
  v_temp         float   := null;
  v_dt_ref       text    := null;

  -- Thresholds
  VENTO_LIMITE  constant float := 30.0;  -- km/h
  CHUVA_LIMITE  constant float := 10.0;  -- mm/24h
  PREV_LIMITE   constant float := 5.0;   -- mm forecast d+1
BEGIN
  -- Get worst-case pluvio_risco entry for the client on or near p_data
  -- (highest risk level wins, then most recent)
  SELECT
    pr.classificacao_final,
    pr.vento_kmh,
    pr.chuva_24h,
    pr.prev_d1_mm,
    pr.temp_c,
    pr.dt_ref::text
  INTO v_row
  FROM pluvio_risco pr
  JOIN regioes r ON r.id = pr.regiao_id
  WHERE r.cliente_id = p_cliente_id
    AND pr.dt_ref::date >= p_data - 1
  ORDER BY
    CASE pr.classificacao_final
      WHEN 'vermelho' THEN 4
      WHEN 'laranja'  THEN 3
      WHEN 'amarelo'  THEN 2
      ELSE 1
    END DESC,
    pr.updated_at DESC
  LIMIT 1;

  -- No pluvio data available — return unknown, apto=true (no grounds to block)
  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'apto',         true,
      'nivel_risco',  null,
      'motivos',      '[]'::jsonb,
      'vento_kmh',    null,
      'chuva_24h_mm', null,
      'prev_d1_mm',   null,
      'temp_c',       null,
      'dt_ref',       null
    );
  END IF;

  v_vento     := v_row.vento_kmh;
  v_chuva_24h := v_row.chuva_24h;
  v_prev_d1   := v_row.prev_d1_mm;
  v_temp      := v_row.temp_c;
  v_dt_ref    := v_row.dt_ref;
  v_nivel     := COALESCE(v_row.classificacao_final, 'verde');

  -- ── Evaluate each criterion ──────────────────────────────────────────────

  IF v_nivel IN ('vermelho', 'laranja') THEN
    v_apto    := false;
    v_motivos := array_append(v_motivos,
      'Risco pluviométrico ' || upper(substring(v_nivel, 1, 1)) || substring(v_nivel, 2)
      || ': condições desfavoráveis para operação de drone'
    );
  END IF;

  IF v_vento IS NOT NULL AND v_vento > VENTO_LIMITE THEN
    v_apto    := false;
    v_motivos := array_append(v_motivos,
      format('Vento elevado: %.0f km/h (limite seguro: %s km/h)', v_vento, VENTO_LIMITE)
    );
  END IF;

  IF v_chuva_24h IS NOT NULL AND v_chuva_24h > CHUVA_LIMITE THEN
    v_apto    := false;
    v_motivos := array_append(v_motivos,
      format('Chuva recente: %.1f mm nas últimas 24h', v_chuva_24h)
    );
  END IF;

  IF v_prev_d1 IS NOT NULL AND v_prev_d1 > PREV_LIMITE THEN
    v_apto    := false;
    v_motivos := array_append(v_motivos,
      format('Previsão de chuva: %.1f mm para hoje', v_prev_d1)
    );
  END IF;

  RETURN jsonb_build_object(
    'apto',         v_apto,
    'nivel_risco',  v_nivel,
    'motivos',      to_jsonb(v_motivos),
    'vento_kmh',    v_vento,
    'chuva_24h_mm', v_chuva_24h,
    'prev_d1_mm',   v_prev_d1,
    'temp_c',       v_temp,
    'dt_ref',       v_dt_ref
  );
END;
$$;


ALTER FUNCTION "public"."avaliar_condicoes_voo"("p_cliente_id" "uuid", "p_data" "date") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."avaliar_condicoes_voo"("p_cliente_id" "uuid", "p_data" "date") IS 'Avalia condições meteorológicas para voo de drone com base no pluvio_risco do cliente. Retorna { apto, nivel_risco, motivos[], vento_kmh, chuva_24h_mm, prev_d1_mm, temp_c, dt_ref }. Critérios: risco laranja/vermelho, vento > 30 km/h, chuva 24h > 10 mm, previsão > 5 mm.';



CREATE OR REPLACE FUNCTION "public"."calcular_score_prioridade_foco"("p_foco_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_score        integer := 0;
  v_foco         record;
  v_prazo_min    integer;
  v_tempo_min    integer;
  v_sla_status   text;
  v_casos_count  integer := 0;
BEGIN
  -- Dados básicos do foco
  SELECT cliente_id, status, foco_anterior_id, latitude, longitude
  INTO v_foco
  FROM public.focos_risco
  WHERE id = p_foco_id;

  IF NOT FOUND THEN RETURN 0; END IF;

  -- ── SLA Inteligente: busca prazo da fase atual ────────────────────────────
  SELECT prazo_minutos
  INTO v_prazo_min
  FROM public.sla_foco_config
  WHERE cliente_id = v_foco.cliente_id
    AND ativo = true
    AND fase = CASE v_foco.status
      WHEN 'suspeita'         THEN 'triagem'
      WHEN 'em_triagem'       THEN 'triagem'
      WHEN 'aguarda_inspecao' THEN 'triagem'
      WHEN 'em_inspecao'      THEN 'inspecao'
      WHEN 'confirmado'       THEN 'confirmacao'
      WHEN 'em_tratamento'    THEN 'tratamento'
      ELSE NULL
    END;

  -- Tempo no estado atual (minutos desde última transição registrada)
  SELECT EXTRACT(EPOCH FROM (now() - MAX(alterado_em)))::integer / 60
  INTO v_tempo_min
  FROM public.foco_risco_historico
  WHERE foco_risco_id = p_foco_id;

  -- Classificar status SLA
  IF v_prazo_min IS NOT NULL AND v_prazo_min > 0 AND v_tempo_min IS NOT NULL THEN
    v_sla_status := CASE
      WHEN v_tempo_min > v_prazo_min                   THEN 'vencido'
      WHEN v_tempo_min >= v_prazo_min * 0.9            THEN 'critico'
      WHEN v_tempo_min >= v_prazo_min * 0.7            THEN 'atencao'
      ELSE 'ok'
    END;
  ELSE
    v_sla_status := 'sem_prazo';
  END IF;

  v_score := v_score + CASE v_sla_status
    WHEN 'vencido' THEN 50
    WHEN 'critico' THEN 40
    WHEN 'atencao' THEN 20
    ELSE 10
  END;

  -- ── Reincidência ──────────────────────────────────────────────────────────
  IF v_foco.foco_anterior_id IS NOT NULL THEN
    v_score := v_score + 20;
  END IF;

  -- ── Casos notificados próximos (raio 300m, cap 30pts) ────────────────────
  IF v_foco.latitude IS NOT NULL AND v_foco.longitude IS NOT NULL THEN
    SELECT COUNT(*)::integer
    INTO v_casos_count
    FROM public.casos_notificados
    WHERE cliente_id = v_foco.cliente_id
      AND localizacao IS NOT NULL
      AND ST_DWithin(
        localizacao::geography,
        ST_MakePoint(v_foco.longitude, v_foco.latitude)::geography,
        300
      );

    v_score := v_score + LEAST(v_casos_count * 5, 30);
  END IF;

  RETURN v_score;

EXCEPTION WHEN OTHERS THEN
  RETURN COALESCE(v_score, 0);
END;
$$;


ALTER FUNCTION "public"."calcular_score_prioridade_foco"("p_foco_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."calcular_score_prioridade_foco"("p_foco_id" "uuid") IS 'Calcula score de prioridade inteiro para um foco_risco. SLA inteligente: ok=10, atencao=20, critico=40, vencido=50. Reincidência (foco_anterior_id IS NOT NULL): +20. Casos notificados em 300m: +5/caso, máximo +30. Retorna 0 em caso de erro (EXCEPTION handler).';



CREATE OR REPLACE FUNCTION "public"."calcular_uso_mensal"("p_cliente_id" "uuid", "p_inicio" "date", "p_fim" "date") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_vistorias         int;
  v_levantamentos     int;
  v_itens_focos       int;
  v_voos              int;
  v_denuncias         int;
  v_ia_calls          int;
  v_relatorios        int;
  v_syncs_cnes        int;
  v_notif_esus        int;
  v_usuarios_ativos   int;
  v_imoveis_total     int;
BEGIN
  IF NOT public.usuario_pode_acessar_cliente(p_cliente_id) THEN
    RAISE EXCEPTION 'Acesso negado ao cliente %', p_cliente_id
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  SELECT COUNT(*) INTO v_vistorias
  FROM vistorias
  WHERE cliente_id = p_cliente_id
    AND created_at >= p_inicio AND created_at < p_fim + 1;

  SELECT COUNT(*) INTO v_levantamentos
  FROM levantamentos
  WHERE cliente_id = p_cliente_id
    AND created_at >= p_inicio AND created_at < p_fim + 1;

  SELECT COUNT(*) INTO v_itens_focos
  FROM levantamento_itens
  WHERE cliente_id = p_cliente_id
    AND created_at >= p_inicio AND created_at < p_fim + 1
    AND deleted_at IS NULL;

  SELECT COUNT(*) INTO v_voos
  FROM voos
  WHERE cliente_id = p_cliente_id
    AND created_at >= p_inicio AND created_at < p_fim + 1;

  SELECT COUNT(*) INTO v_denuncias
  FROM levantamento_itens li
  JOIN levantamentos lev ON lev.id = li.levantamento_id
  WHERE lev.cliente_id = p_cliente_id
    AND li.payload->>'fonte' = 'cidadao'
    AND li.created_at >= p_inicio AND li.created_at < p_fim + 1;

  SELECT COUNT(*) INTO v_ia_calls
  FROM levantamento_analise_ia
  WHERE cliente_id = p_cliente_id
    AND processado_em >= p_inicio AND processado_em < p_fim + 1;

  SELECT COUNT(*) INTO v_relatorios
  FROM job_queue
  WHERE payload->>'cliente_id' = p_cliente_id::text
    AND tipo = 'relatorio_semanal'
    AND created_at >= p_inicio AND created_at < p_fim + 1;

  SELECT COUNT(*) INTO v_syncs_cnes
  FROM unidades_saude_sync_controle
  WHERE cliente_id = p_cliente_id
    AND ultima_execucao >= p_inicio AND ultima_execucao < p_fim + 1;

  SELECT COUNT(*) INTO v_notif_esus
  FROM item_notificacoes_esus
  WHERE cliente_id = p_cliente_id
    AND created_at >= p_inicio AND created_at < p_fim + 1;

  SELECT COUNT(DISTINCT agente_id) INTO v_usuarios_ativos
  FROM vistorias
  WHERE cliente_id = p_cliente_id
    AND created_at >= p_inicio AND created_at < p_fim + 1;

  SELECT COUNT(*) INTO v_imoveis_total
  FROM imoveis
  WHERE cliente_id = p_cliente_id;

  RETURN jsonb_build_object(
    'cliente_id',      p_cliente_id,
    'periodo_inicio',  p_inicio,
    'periodo_fim',     p_fim,
    'vistorias',       v_vistorias,
    'levantamentos',   v_levantamentos,
    'itens_focos',     v_itens_focos,
    'voos',            v_voos,
    'denuncias',       v_denuncias,
    'ia_calls',        v_ia_calls,
    'relatorios',      v_relatorios,
    'syncs_cnes',      v_syncs_cnes,
    'notif_esus',      v_notif_esus,
    'usuarios_ativos', v_usuarios_ativos,
    'imoveis_total',   v_imoveis_total
  );
END;
$$;


ALTER FUNCTION "public"."calcular_uso_mensal"("p_cliente_id" "uuid", "p_inicio" "date", "p_fim" "date") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."calcular_uso_mensal"("p_cliente_id" "uuid", "p_inicio" "date", "p_fim" "date") IS 'Calcula métricas de uso mensal por cliente para billing snapshot. Fix 20260903000000: SET search_path + tenant check adicionado.';



CREATE OR REPLACE FUNCTION "public"."check_quota_voos"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_limite    integer;
  v_utilizado integer;
  v_tz        text := 'America/Sao_Paulo';
BEGIN
  SELECT voos_mes INTO v_limite
  FROM cliente_quotas
  WHERE cliente_id = NEW.cliente_id;

  IF v_limite IS NULL THEN RETURN NEW; END IF;

  SELECT COUNT(*) INTO v_utilizado
  FROM voos
  WHERE cliente_id = NEW.cliente_id
    AND date_trunc('month', created_at AT TIME ZONE v_tz)
        = date_trunc('month', now()    AT TIME ZONE v_tz);

  IF v_utilizado >= v_limite THEN
    RAISE EXCEPTION
      'Quota de voos mensais atingida (% / %). Entre em contato para ampliar o plano.',
      v_utilizado, v_limite;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_quota_voos"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."check_quota_voos"() IS 'F-01: corte de mês em America/Sao_Paulo. P0-6: SET search_path adicionado.';



CREATE OR REPLACE FUNCTION "public"."cliente_verificar_quota"("p_cliente_id" "uuid", "p_metrica" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_status     text;
  v_trial_fim  timestamptz;
  v_limite     int;
  v_usado      int;
BEGIN
  -- ── 0. Status do tenant ──────────────────────────────────────────────────────
  SELECT cp.status, cp.data_trial_fim
  INTO   v_status, v_trial_fim
  FROM   public.cliente_plano cp
  WHERE  cp.cliente_id = p_cliente_id
  LIMIT  1;

  -- Tenant bloqueado → todas as quotas bloqueadas
  IF v_status IN ('suspenso', 'cancelado')
     OR (v_status = 'trial'
         AND v_trial_fim IS NOT NULL
         AND v_trial_fim < now()) THEN
    RETURN jsonb_build_object(
      'ok',     false,
      'usado',  0,
      'limite', 0,
      'motivo', 'tenant_bloqueado'
    );
  END IF;

  -- ── 1. Limite: COALESCE(override individual, plano) ─────────────────────────
  SELECT COALESCE(
    -- Override individual
    (SELECT CASE p_metrica
       WHEN 'voos_mes'          THEN cq.voos_mes
       WHEN 'levantamentos_mes' THEN cq.levantamentos_mes
       WHEN 'itens_mes'         THEN cq.itens_mes
       WHEN 'usuarios_ativos'   THEN cq.usuarios_ativos
       WHEN 'vistorias_mes'     THEN cq.vistorias_mes
       WHEN 'ia_calls_mes'      THEN cq.ia_calls_mes
       WHEN 'storage_gb'        THEN cq.storage_gb
       ELSE NULL
     END
     FROM public.cliente_quotas cq
     WHERE cq.cliente_id = p_cliente_id),
    -- Limite do plano
    (SELECT CASE p_metrica
       WHEN 'voos_mes'          THEN pl.limite_voos_mes
       WHEN 'levantamentos_mes' THEN pl.limite_levantamentos_mes
       WHEN 'itens_mes'         THEN NULL  -- não controlado a nível de plano (só quota)
       WHEN 'usuarios_ativos'   THEN pl.limite_usuarios
       WHEN 'vistorias_mes'     THEN pl.limite_vistorias_mes
       WHEN 'ia_calls_mes'      THEN pl.limite_ia_calls_mes
       WHEN 'storage_gb'        THEN pl.limite_storage_gb
       ELSE NULL
     END
     FROM   public.cliente_plano cp
     JOIN   public.planos pl ON pl.id = cp.plano_id
     WHERE  cp.cliente_id = p_cliente_id
     LIMIT  1)
  ) INTO v_limite;

  -- ── 2. Uso atual do mês ──────────────────────────────────────────────────────
  SELECT CASE p_metrica
    WHEN 'voos_mes' THEN (
      SELECT COUNT(*)::int FROM public.voos v
      WHERE  v.cliente_id = p_cliente_id
        AND  v.created_at >= date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo')
                             AT TIME ZONE 'America/Sao_Paulo'
    )
    WHEN 'levantamentos_mes' THEN (
      SELECT COUNT(*)::int FROM public.levantamentos l
      WHERE  l.cliente_id = p_cliente_id
        AND  l.created_at >= date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo')
                             AT TIME ZONE 'America/Sao_Paulo'
    )
    WHEN 'itens_mes' THEN (
      SELECT COUNT(*)::int FROM public.levantamento_itens li
      WHERE  li.cliente_id = p_cliente_id
        AND  li.created_at >= date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo')
                             AT TIME ZONE 'America/Sao_Paulo'
    )
    WHEN 'usuarios_ativos' THEN (
      SELECT COUNT(*)::int FROM public.usuarios u
      WHERE  u.cliente_id = p_cliente_id
        AND  u.ativo = true
    )
    WHEN 'vistorias_mes' THEN (
      SELECT COUNT(*)::int FROM public.vistorias v
      WHERE  v.cliente_id = p_cliente_id
        AND  v.created_at >= date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo')
                             AT TIME ZONE 'America/Sao_Paulo'
    )
    WHEN 'ia_calls_mes' THEN (
      SELECT COUNT(*)::int
      FROM   public.levantamento_analise_ia la
      JOIN   public.levantamentos lev ON lev.id = la.levantamento_id
      WHERE  lev.cliente_id = p_cliente_id
        AND  la.created_at >= date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo')
                             AT TIME ZONE 'America/Sao_Paulo'
    )
    -- storage_gb: estimativa via snapshots; sem contagem em tempo real
    WHEN 'storage_gb' THEN COALESCE((
      SELECT (bss.storage_gb)::int
      FROM   public.billing_usage_snapshot bss
      WHERE  bss.cliente_id = p_cliente_id
      ORDER  BY bss.criado_em DESC
      LIMIT  1
    ), 0)
    ELSE 0
  END INTO v_usado;

  RETURN jsonb_build_object(
    'ok',     v_limite IS NULL OR v_usado < v_limite,
    'usado',  COALESCE(v_usado, 0),
    'limite', v_limite
  );

EXCEPTION WHEN OTHERS THEN
  -- Fail-safe: erro interno não deve bloquear operações
  RETURN jsonb_build_object('ok', true, 'usado', 0, 'limite', null);
END;
$$;


ALTER FUNCTION "public"."cliente_verificar_quota"("p_cliente_id" "uuid", "p_metrica" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."cliente_verificar_quota"("p_cliente_id" "uuid", "p_metrica" "text") IS 'P1-2 v2: Verifica quota de uma métrica. Respeita status do tenant (suspenso/cancelado/trial expirado → ok=false). COALESCE(override individual, limite do plano). Fail-safe: retorna ok=true em caso de erro interno.';



CREATE OR REPLACE FUNCTION "public"."cobertura_quarteirao_ciclo"("p_cliente_id" "uuid", "p_ciclo" integer) RETURNS TABLE("quarteirao" "text", "bairro" "text", "agente_id" "uuid", "total_imoveis" bigint, "visitados" bigint, "pct_cobertura" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    d.quarteirao,
    MAX(i.bairro) AS bairro,
    d.agente_id,
    COUNT(DISTINCT i.id) AS total_imoveis,
    COUNT(DISTINCT v.imovel_id)
      FILTER (WHERE v.status IN ('visitado', 'fechado')) AS visitados,
    CASE
      WHEN COUNT(DISTINCT i.id) = 0 THEN 0
      ELSE ROUND(
        100.0 * COUNT(DISTINCT v.imovel_id) FILTER (WHERE v.status IN ('visitado', 'fechado'))
        / COUNT(DISTINCT i.id), 1
      )
    END AS pct_cobertura
  FROM distribuicao_quarteirao d
  LEFT JOIN imoveis i
         ON i.cliente_id = d.cliente_id
        AND i.quarteirao = d.quarteirao
        AND i.ativo = true
  LEFT JOIN vistorias v
         ON v.imovel_id = i.id
        AND v.ciclo = p_ciclo
  WHERE d.cliente_id = p_cliente_id
    AND d.ciclo = p_ciclo
  GROUP BY d.quarteirao, d.agente_id
  ORDER BY d.quarteirao;
$$;


ALTER FUNCTION "public"."cobertura_quarteirao_ciclo"("p_cliente_id" "uuid", "p_ciclo" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."consultar_denuncia_cidadao"("p_protocolo" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_proto text;
BEGIN
  v_proto := lower(trim(COALESCE(p_protocolo, '')));

  -- Mínimo de 8 caracteres — protocolo gerado pelo sistema tem exatamente 8.
  -- Aceitar entre 8 e 36 (UUID completo) para permitir buscas com UUID inteiro.
  IF length(v_proto) < 8 THEN
    RETURN jsonb_build_object(
      'ok',    false,
      'error', 'Protocolo inválido. Informe os 8 caracteres do protocolo de atendimento.'
    );
  END IF;

  -- Truncar para os 36 chars máximos de um UUID; qualquer entrada maior é inválida.
  IF length(v_proto) > 36 THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Protocolo inválido.');
  END IF;

  RETURN COALESCE(
    (
      SELECT jsonb_build_object(
        'ok',       true,
        'foco_id',  fr.id::text,
        'status',   fr.status,
        'data',     fr.created_at::date,
        'mensagem', CASE fr.status
          WHEN 'suspeita'         THEN 'Sua denúncia foi recebida e está sendo analisada.'
          WHEN 'em_triagem'       THEN 'Sua denúncia está em triagem pela equipe técnica.'
          WHEN 'aguarda_inspecao' THEN 'A equipe irá ao local em breve para inspeção.'
          WHEN 'em_inspecao'      THEN 'A equipe está inspecionando o local.'
          WHEN 'confirmado'       THEN 'O foco foi confirmado e está em fila de atendimento.'
          WHEN 'em_tratamento'    THEN 'A equipe municipal está realizando o tratamento no local.'
          WHEN 'resolvido'        THEN 'O foco foi resolvido. Obrigado pela sua denúncia!'
          WHEN 'descartado'       THEN 'Após análise, o local foi considerado sem risco no momento.'
          ELSE                         'Status em processamento.'
        END
      )
      FROM public.focos_risco fr
      WHERE starts_with(fr.id::text, v_proto)
        AND fr.origem_tipo = 'cidadao'
        AND fr.deleted_at  IS NULL
      LIMIT 1
    ),
    jsonb_build_object('ok', false, 'error', 'Protocolo não encontrado.')
  );
END;
$$;


