COMMENT ON FUNCTION "public"."consultar_denuncia_cidadao"("p_protocolo" "text") IS 'Consulta pública de protocolo. Exige mínimo 8 chars (impede enumeração em massa). Aceita 8–36 chars. Corrigido em 20261001000000 (H1).';



