CREATE OR REPLACE FUNCTION "public"."create_vistoria_completa"("p_payload" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_idempotency_key uuid;
  v_existing_id     uuid;
  v_vistoria_id     uuid;
  v_cliente_id      uuid;
  v_imovel_id       uuid;
  v_foco_risco_id   uuid;
  v_deposito        jsonb;
  v_calha           jsonb;
BEGIN
  -- Idempotência: se já existe vistoria com essa key, retorna sem duplicar
  v_idempotency_key := (p_payload->>'idempotency_key')::uuid;
  IF v_idempotency_key IS NOT NULL THEN
    SELECT id INTO v_existing_id
      FROM vistorias
     WHERE idempotency_key = v_idempotency_key
     LIMIT 1;
    IF v_existing_id IS NOT NULL THEN
      RETURN v_existing_id;
    END IF;
  END IF;

  v_cliente_id    := (p_payload->>'cliente_id')::uuid;
  v_imovel_id     := (p_payload->>'imovel_id')::uuid;
  v_foco_risco_id := (p_payload->>'foco_risco_id')::uuid;

  -- 1. Vistoria principal
  INSERT INTO vistorias (
    cliente_id, imovel_id, agente_id, ciclo, tipo_atividade, data_visita,
    status, acesso_realizado, motivo_sem_acesso, proximo_horario_sugerido,
    observacao_acesso, foto_externa_url, moradores_qtd, gravidas, idosos,
    criancas_7anos, lat_chegada, lng_chegada, checkin_em, observacao,
    origem_visita, habitat_selecionado, condicao_habitat,
    assinatura_responsavel_url, idempotency_key, foco_risco_id
  ) VALUES (
    v_cliente_id,
    v_imovel_id,
    (p_payload->>'agente_id')::uuid,
    (p_payload->>'ciclo')::int,
    p_payload->>'tipo_atividade',
    COALESCE((p_payload->>'data_visita')::timestamptz, now()),
    COALESCE(p_payload->>'status', 'visitado'),
    COALESCE((p_payload->>'acesso_realizado')::boolean, true),
    p_payload->>'motivo_sem_acesso',
    p_payload->>'proximo_horario_sugerido',
    p_payload->>'observacao_acesso',
    p_payload->>'foto_externa_url',
    COALESCE((p_payload->>'moradores_qtd')::int, 0),
    COALESCE((p_payload->>'gravidas')::boolean, false),
    COALESCE((p_payload->>'idosos')::boolean, false),
    COALESCE((p_payload->>'criancas_7anos')::boolean, false),
    (p_payload->>'lat_chegada')::float,
    (p_payload->>'lng_chegada')::float,
    (p_payload->>'checkin_em')::timestamptz,
    p_payload->>'observacao',
    p_payload->>'origem_visita',
    p_payload->>'habitat_selecionado',
    p_payload->>'condicao_habitat',
    p_payload->>'assinatura_responsavel_url',
    v_idempotency_key,
    v_foco_risco_id
  ) RETURNING id INTO v_vistoria_id;

  -- 2. Depósitos
  FOR v_deposito IN
    SELECT value FROM jsonb_array_elements(COALESCE(p_payload->'depositos', '[]'::jsonb))
  LOOP
    INSERT INTO vistoria_depositos (
      vistoria_id, cliente_id, tipo,
      qtd_inspecionados, qtd_com_agua, qtd_com_focos,
      eliminado, vedado, qtd_eliminados, usou_larvicida, qtd_larvicida_g,
      ia_identificacao
    ) VALUES (
      v_vistoria_id,
      v_cliente_id,
      v_deposito->>'tipo',
      COALESCE((v_deposito->>'qtd_inspecionados')::int, 0),
      COALESCE((v_deposito->>'qtd_com_agua')::int, 0),
      COALESCE((v_deposito->>'qtd_com_focos')::int, 0),
      COALESCE((v_deposito->>'eliminado')::boolean, false),
      COALESCE((v_deposito->>'vedado')::boolean, false),
      COALESCE((v_deposito->>'qtd_eliminados')::int, 0),
      COALESCE((v_deposito->>'usou_larvicida')::boolean, false),
      (v_deposito->>'qtd_larvicida_g')::float,
      v_deposito->'ia_identificacao'
    )
    ON CONFLICT (vistoria_id, tipo) DO UPDATE SET
      qtd_inspecionados = EXCLUDED.qtd_inspecionados,
      qtd_com_agua      = EXCLUDED.qtd_com_agua,
      qtd_com_focos     = EXCLUDED.qtd_com_focos,
      eliminado         = EXCLUDED.eliminado,
      vedado            = EXCLUDED.vedado,
      qtd_eliminados    = EXCLUDED.qtd_eliminados,
      usou_larvicida    = EXCLUDED.usou_larvicida,
      qtd_larvicida_g   = EXCLUDED.qtd_larvicida_g;
  END LOOP;

  -- 3. Sintomas
  IF p_payload->'sintomas' IS NOT NULL AND p_payload->>'sintomas' != 'null' THEN
    INSERT INTO vistoria_sintomas (
      vistoria_id, cliente_id, febre, manchas_vermelhas, dor_articulacoes,
      dor_cabeca, moradores_sintomas_qtd
    ) VALUES (
      v_vistoria_id, v_cliente_id,
      COALESCE((p_payload->'sintomas'->>'febre')::boolean, false),
      COALESCE((p_payload->'sintomas'->>'manchas_vermelhas')::boolean, false),
      COALESCE((p_payload->'sintomas'->>'dor_articulacoes')::boolean, false),
      COALESCE((p_payload->'sintomas'->>'dor_cabeca')::boolean, false),
      COALESCE((p_payload->'sintomas'->>'moradores_sintomas_qtd')::int, 0)
    ) ON CONFLICT DO NOTHING;
  END IF;

  -- 4. Riscos
  IF p_payload->'riscos' IS NOT NULL AND p_payload->>'riscos' != 'null' THEN
    INSERT INTO vistoria_riscos (
      vistoria_id, cliente_id,
      menor_incapaz, idoso_incapaz, dep_quimico, risco_alimentar, risco_moradia,
      criadouro_animais, lixo, residuos_organicos, residuos_quimicos, residuos_medicos,
      acumulo_material_organico, animais_sinais_lv, caixa_destampada, outro_risco_vetorial
    ) VALUES (
      v_vistoria_id, v_cliente_id,
      COALESCE((p_payload->'riscos'->>'menor_incapaz')::boolean, false),
      COALESCE((p_payload->'riscos'->>'idoso_incapaz')::boolean, false),
      COALESCE((p_payload->'riscos'->>'dep_quimico')::boolean, false),
      COALESCE((p_payload->'riscos'->>'risco_alimentar')::boolean, false),
      COALESCE((p_payload->'riscos'->>'risco_moradia')::boolean, false),
      COALESCE((p_payload->'riscos'->>'criadouro_animais')::boolean, false),
      COALESCE((p_payload->'riscos'->>'lixo')::boolean, false),
      COALESCE((p_payload->'riscos'->>'residuos_organicos')::boolean, false),
      COALESCE((p_payload->'riscos'->>'residuos_quimicos')::boolean, false),
      COALESCE((p_payload->'riscos'->>'residuos_medicos')::boolean, false),
      COALESCE((p_payload->'riscos'->>'acumulo_material_organico')::boolean, false),
      COALESCE((p_payload->'riscos'->>'animais_sinais_lv')::boolean, false),
      COALESCE((p_payload->'riscos'->>'caixa_destampada')::boolean, false),
      p_payload->'riscos'->>'outro_risco_vetorial'
    );
  END IF;

  -- 5. Calhas — FIX: cliente_id incluído (estava ausente na migration anterior)
  FOR v_calha IN
    SELECT value FROM jsonb_array_elements(COALESCE(p_payload->'calhas', '[]'::jsonb))
  LOOP
    INSERT INTO vistoria_calhas (
      vistoria_id, cliente_id, posicao, condicao, com_foco, observacao
    ) VALUES (
      v_vistoria_id,
      v_cliente_id,
      v_calha->>'posicao',
      v_calha->>'condicao',
      COALESCE((v_calha->>'com_foco')::boolean, false),
      v_calha->>'observacao'
    );
  END LOOP;

  -- 6. Atualizar perfil do imóvel quando há calha
  IF COALESCE((p_payload->>'tem_calha')::boolean, false)
     AND v_imovel_id IS NOT NULL THEN
    UPDATE imoveis
    SET
      tem_calha       = true,
      calha_acessivel = NOT COALESCE((p_payload->>'calha_inacessivel')::boolean, false),
      updated_at      = now()
    WHERE id = v_imovel_id;
  END IF;

  RETURN v_vistoria_id;
END;
$$;


ALTER FUNCTION "public"."create_vistoria_completa"("p_payload" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."create_vistoria_completa"("p_payload" "jsonb") IS 'RPC transacional para salvar vistoria completa. Corrigido em 20261001000000 (H3): agente_id do payload validado contra auth.uid(); apenas admin/gestor pode submeter vistoria com agente_id de terceiro.';



CREATE OR REPLACE FUNCTION "public"."criar_levantamento_com_itens"("p_lev_row" "jsonb", "p_itens" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
begin
  insert into public.levantamentos (cliente_id, usuario_id, planejamento_id, id_drone, titulo, data_voo, total_itens)
  values (
    (p_lev_row->>'cliente_id')::uuid,
    (p_lev_row->>'usuario_id')::uuid,
    case when nullif(trim(p_lev_row->>'planejamento_id'), '') is null then null
         else (p_lev_row->>'planejamento_id')::uuid end,
    case when nullif(trim(p_lev_row->>'id_drone'), '') is null then null
         else (p_lev_row->>'id_drone')::uuid end,
    nullif(trim(p_lev_row->>'titulo'), ''),
    case when nullif(trim(p_lev_row->>'data_voo'), '') is null then null
         else (p_lev_row->>'data_voo')::date end,
    coalesce((p_lev_row->>'total_itens')::int, 0)
  )
  returning id into v_id;

  insert into public.levantamento_itens (
    levantamento_id, arquivo, latitude, longitude, item, risco, peso, acao,
    score_final, prioridade, sla_horas, endereco_curto, endereco_completo,
    maps, waze, data_hora, image_url, uuid_img, payload, detection_bbox,
    id_drone, altitude_m, altura_relativa_m, focal_mm, iso, exposure_s,
    resolucao_largura_px, resolucao_altura_px, megapixels,
    inclinacao_camera_graus, direcao_yaw_graus, inclinacao_lateral_roll_graus, inclinacao_frontal_pitch_graus
  )
  select
    v_id,
    nullif(trim(elem->>'arquivo'), ''),
    (elem->>'latitude')::float8,
    (elem->>'longitude')::float8,
    nullif(trim(elem->>'item'), ''),
    nullif(trim(elem->>'risco'), ''),
    (elem->>'peso')::int,
    nullif(trim(elem->>'acao'), ''),
    (elem->>'score_final')::int,
    nullif(trim(elem->>'prioridade'), ''),
    (elem->>'sla_horas')::int,
    nullif(trim(elem->>'endereco_curto'), ''),
    nullif(trim(elem->>'endereco_completo'), ''),
    nullif(trim(elem->>'maps'), ''),
    nullif(trim(elem->>'waze'), ''),
    case when nullif(trim(elem->>'data_hora'), '') is null then null
         else (elem->>'data_hora')::timestamptz end,
    nullif(trim(elem->>'image_url'), ''),
    nullif(trim(elem->>'uuid_img'), ''),
    case when elem->'payload' is null or elem->'payload' = 'null'::jsonb then null
         else elem->'payload' end,
    case when elem->'detection_bbox' is null or elem->'detection_bbox' = 'null'::jsonb then null
         else elem->'detection_bbox' end,
    case when nullif(trim(elem->>'id_drone'), '') is null then null
         else (elem->>'id_drone')::uuid end,
    (elem->>'altitude_m')::float8,
    (elem->>'altura_relativa_m')::float8,
    (elem->>'focal_mm')::float8,
    (elem->>'iso')::float8,
    (elem->>'exposure_s')::float8,
    (elem->>'resolucao_largura_px')::int,
    (elem->>'resolucao_altura_px')::int,
    (elem->>'megapixels')::float8,
    (elem->>'inclinacao_camera_graus')::float8,
    (elem->>'direcao_yaw_graus')::float8,
    (elem->>'inclinacao_lateral_roll_graus')::float8,
    (elem->>'inclinacao_frontal_pitch_graus')::float8
  from jsonb_array_elements(p_itens) as elem;

  return v_id;
end;
$$;


ALTER FUNCTION "public"."criar_levantamento_com_itens"("p_lev_row" "jsonb", "p_itens" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."criar_levantamento_com_itens"("p_lev_row" "jsonb", "p_itens" "jsonb") IS 'Cria um levantamento e seus itens em uma única transação. Usado pelo app Sentinela.';



CREATE OR REPLACE FUNCTION "public"."criar_levantamento_item_manual"("p_planejamento_id" "uuid", "p_data_voo" "date", "p_latitude" double precision DEFAULT NULL::double precision, "p_longitude" double precision DEFAULT NULL::double precision, "p_item" "text" DEFAULT NULL::"text", "p_risco" "text" DEFAULT NULL::"text", "p_acao" "text" DEFAULT NULL::"text", "p_score_final" double precision DEFAULT NULL::double precision, "p_prioridade" "text" DEFAULT NULL::"text", "p_sla_horas" integer DEFAULT NULL::integer, "p_endereco_curto" "text" DEFAULT NULL::"text", "p_endereco_completo" "text" DEFAULT NULL::"text", "p_image_url" "text" DEFAULT NULL::"text", "p_maps" "text" DEFAULT NULL::"text", "p_waze" "text" DEFAULT NULL::"text", "p_data_hora" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_tags" "text"[] DEFAULT NULL::"text"[], "p_peso" double precision DEFAULT NULL::double precision, "p_payload" "jsonb" DEFAULT NULL::"jsonb", "p_image_public_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_auth_id             uuid;
  v_usuario_id          uuid;
  v_cliente_id          uuid;
  v_planejamento        RECORD;
  v_levantamento_id     uuid;
  v_levantamento_criado boolean := false;
  v_item_id             uuid;
  v_tag_slug            text;
  v_tag_id              uuid;
  v_papel               text;
BEGIN
  v_auth_id := auth.uid();
  IF v_auth_id IS NULL THEN
    RAISE EXCEPTION 'Não autenticado.';
  END IF;

  SELECT u.id, u.cliente_id INTO v_usuario_id, v_cliente_id
  FROM usuarios u WHERE u.auth_id = v_auth_id LIMIT 1;
  IF v_usuario_id IS NULL THEN
    RAISE EXCEPTION 'Usuário não encontrado em public.usuarios.';
  END IF;

  SELECT LOWER(pu.papel::text) INTO v_papel
  FROM papeis_usuarios pu WHERE pu.usuario_id = v_auth_id LIMIT 1;
  IF v_papel IS NULL OR v_papel NOT IN ('admin', 'supervisor', 'usuario', 'operador') THEN
    RAISE EXCEPTION 'Papel não permitido para criação manual de item.';
  END IF;

  IF p_planejamento_id IS NULL THEN
    RAISE EXCEPTION 'planejamento_id é obrigatório.';
  END IF;
  SELECT id, cliente_id, ativo INTO v_planejamento
  FROM planejamento WHERE id = p_planejamento_id LIMIT 1;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Planejamento % não encontrado.', p_planejamento_id;
  END IF;
  IF NOT (v_planejamento.ativo) THEN
    RAISE EXCEPTION 'Planejamento não está ativo.';
  END IF;
  v_cliente_id := v_planejamento.cliente_id;
  IF v_cliente_id IS NULL THEN
    RAISE EXCEPTION 'Planejamento sem cliente_id.';
  END IF;

  IF v_papel = 'operador' THEN
    IF (SELECT u.cliente_id FROM usuarios u WHERE u.auth_id = v_auth_id LIMIT 1) IS DISTINCT FROM v_cliente_id THEN
      RAISE EXCEPTION 'Operador só pode criar itens para o próprio cliente.';
    END IF;
  ELSE
    IF NOT public.usuario_pode_acessar_cliente(v_cliente_id) THEN
      RAISE EXCEPTION 'Sem permissão para acessar o cliente deste planejamento.';
    END IF;
  END IF;

  IF p_data_voo IS NULL THEN
    RAISE EXCEPTION 'data_voo é obrigatória.';
  END IF;

  SELECT l.id INTO v_levantamento_id
  FROM levantamentos l
  WHERE l.cliente_id = v_cliente_id
    AND l.planejamento_id = p_planejamento_id
    AND (l.data_voo::date) = p_data_voo
    AND l.tipo_entrada IS NOT NULL
    AND UPPER(l.tipo_entrada) = 'MANUAL'
  LIMIT 1;

  IF v_levantamento_id IS NULL THEN
    INSERT INTO levantamentos (
      cliente_id, usuario_id, planejamento_id, titulo, data_voo, total_itens, tipo_entrada
    ) VALUES (
      v_cliente_id, v_usuario_id, p_planejamento_id,
      'Levantamento manual ' || to_char(p_data_voo, 'DD/MM/YYYY'),
      p_data_voo, 0, 'MANUAL'
    )
    RETURNING id INTO v_levantamento_id;
    v_levantamento_criado := true;
  END IF;

  INSERT INTO levantamento_itens (
    levantamento_id,
    latitude, longitude, item, risco, peso, acao, score_final, prioridade, sla_horas,
    endereco_curto, endereco_completo, image_url, image_public_id,
    maps, waze, data_hora, payload
  ) VALUES (
    v_levantamento_id,
    p_latitude, p_longitude, p_item, p_risco, p_peso, p_acao, p_score_final, p_prioridade, p_sla_horas,
    p_endereco_curto, p_endereco_completo, p_image_url, p_image_public_id,
    p_maps, p_waze,
    COALESCE(p_data_hora, now()),
    p_payload
  )
  RETURNING id INTO v_item_id;

  UPDATE levantamentos
  SET total_itens = (SELECT count(*) FROM levantamento_itens WHERE levantamento_id = v_levantamento_id)
  WHERE id = v_levantamento_id;

  IF p_tags IS NOT NULL AND array_length(p_tags, 1) > 0 THEN
    FOREACH v_tag_slug IN ARRAY p_tags
    LOOP
      SELECT id INTO v_tag_id FROM tags WHERE slug = v_tag_slug LIMIT 1;
      IF v_tag_id IS NOT NULL THEN
        INSERT INTO levantamento_item_tags (levantamento_item_id, tag_id)
        VALUES (v_item_id, v_tag_id)
        ON CONFLICT (levantamento_item_id, tag_id) DO NOTHING;
      END IF;
    END LOOP;
  END IF;

  RETURN jsonb_build_object(
    'levantamento_item', (SELECT to_jsonb(li.*) FROM levantamento_itens li WHERE li.id = v_item_id),
    'levantamento_criado', v_levantamento_criado,
    'levantamento_id', v_levantamento_id
  );
END;
$$;


ALTER FUNCTION "public"."criar_levantamento_item_manual"("p_planejamento_id" "uuid", "p_data_voo" "date", "p_latitude" double precision, "p_longitude" double precision, "p_item" "text", "p_risco" "text", "p_acao" "text", "p_score_final" double precision, "p_prioridade" "text", "p_sla_horas" integer, "p_endereco_curto" "text", "p_endereco_completo" "text", "p_image_url" "text", "p_maps" "text", "p_waze" "text", "p_data_hora" timestamp with time zone, "p_tags" "text"[], "p_peso" double precision, "p_payload" "jsonb", "p_image_public_id" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."criar_levantamento_item_manual"("p_planejamento_id" "uuid", "p_data_voo" "date", "p_latitude" double precision, "p_longitude" double precision, "p_item" "text", "p_risco" "text", "p_acao" "text", "p_score_final" double precision, "p_prioridade" "text", "p_sla_horas" integer, "p_endereco_curto" "text", "p_endereco_completo" "text", "p_image_url" "text", "p_maps" "text", "p_waze" "text", "p_data_hora" timestamp with time zone, "p_tags" "text"[], "p_peso" double precision, "p_payload" "jsonb", "p_image_public_id" "text") IS 'Cria levantamento_item manual com suporte a image_public_id para rastreabilidade Cloudinary. (QW-10B)';



CREATE OR REPLACE FUNCTION "public"."criar_levantamento_item_manual"("p_planejamento_id" "uuid", "p_data_voo" "date", "p_latitude" double precision, "p_longitude" double precision, "p_tipo_problema" "text", "p_descricao" "text", "p_prioridade" "text", "p_score_final" double precision DEFAULT NULL::double precision, "p_classificacao_risco" "text" DEFAULT NULL::"text", "p_confianca_pct" integer DEFAULT NULL::integer, "p_origem_tipo" "text" DEFAULT 'MANUAL'::"text", "p_image_url" "text" DEFAULT NULL::"text", "p_image_public_id" "text" DEFAULT NULL::"text", "p_bairro" "text" DEFAULT NULL::"text", "p_regiao_id" "uuid" DEFAULT NULL::"uuid", "p_capturado_em" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_tags" "text"[] DEFAULT NULL::"text"[], "p_altitude_m" double precision DEFAULT NULL::double precision, "p_metadata" "jsonb" DEFAULT NULL::"jsonb", "p_observacao" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_auth_id             uuid;
  v_usuario_id          uuid;
  v_cliente_id          uuid;
  v_planejamento        RECORD;
  v_levantamento_id     uuid;
  v_levantamento_criado boolean := false;
  v_item_id             uuid;
  v_tag_slug            text;
  v_tag_id              uuid;
  v_papel               text;
BEGIN
  v_auth_id := auth.uid();
  IF v_auth_id IS NULL THEN
    RAISE EXCEPTION 'Não autenticado.';
  END IF;

  SELECT u.id, u.cliente_id INTO v_usuario_id, v_cliente_id
  FROM usuarios u WHERE u.auth_id = v_auth_id LIMIT 1;
  IF v_usuario_id IS NULL THEN
    RAISE EXCEPTION 'Usuário não encontrado em public.usuarios.';
  END IF;

  -- FIX 1B: busca papel via usuarios.auth_id → papeis_usuarios.usuario_id
  --         (papeis_usuarios.usuario_id ainda armazena auth_id por design legado;
  --          a query é idêntica ao que as policies usam — consistente)
  -- FIX 1A: apenas papéis canônicos ATIVOS são aceitos (removido 'usuario','operador')
  SELECT LOWER(pu.papel::text) INTO v_papel
  FROM papeis_usuarios pu WHERE pu.usuario_id = v_auth_id LIMIT 1;

  IF v_papel IS NULL OR v_papel NOT IN ('admin', 'supervisor', 'agente', 'notificador') THEN
    RAISE EXCEPTION 'Papel não permitido para criação manual de item. Papel encontrado: %', COALESCE(v_papel, 'NULL');
  END IF;

  IF p_planejamento_id IS NULL THEN
    RAISE EXCEPTION 'planejamento_id é obrigatório.';
  END IF;
  SELECT id, cliente_id, ativo INTO v_planejamento
  FROM planejamento WHERE id = p_planejamento_id LIMIT 1;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Planejamento % não encontrado.', p_planejamento_id;
  END IF;
  IF NOT (v_planejamento.ativo) THEN
    RAISE EXCEPTION 'Planejamento não está ativo.';
  END IF;
  v_cliente_id := v_planejamento.cliente_id;
  IF v_cliente_id IS NULL THEN
    RAISE EXCEPTION 'Planejamento sem cliente_id.';
  END IF;

  -- FIX 1A: removido branch especial para 'operador' (papel morto).
  --         Todo papel não-admin passa pelo check universal de tenant.
  IF NOT public.usuario_pode_acessar_cliente(v_cliente_id) THEN
    RAISE EXCEPTION 'Sem permissão para acessar o cliente deste planejamento.';
  END IF;

  IF p_data_voo IS NULL THEN
    RAISE EXCEPTION 'data_voo é obrigatória.';
  END IF;

  SELECT l.id INTO v_levantamento_id
  FROM levantamentos l
  WHERE l.cliente_id = v_cliente_id
    AND l.planejamento_id = p_planejamento_id
    AND (l.data_voo::date) = p_data_voo
    AND l.tipo_entrada IS NOT NULL
    AND UPPER(l.tipo_entrada) = 'MANUAL'
  LIMIT 1;

  IF v_levantamento_id IS NULL THEN
    INSERT INTO levantamentos (
      cliente_id, usuario_id, planejamento_id, titulo, data_voo, total_itens, tipo_entrada
    ) VALUES (
      v_cliente_id, v_usuario_id, p_planejamento_id,
      'Levantamento manual ' || to_char(p_data_voo, 'DD/MM/YYYY'),
      p_data_voo, 0, 'MANUAL'
    )
    RETURNING id INTO v_levantamento_id;
    v_levantamento_criado := true;
  END IF;

  INSERT INTO levantamento_itens (
    cliente_id,
    levantamento_id,
    tipo_problema,
    descricao,
    prioridade,
    latitude,
    longitude,
    score_final,
    classificacao_risco,
    confianca_pct,
    tipo_entrada,
    image_url,
    image_public_id,
    bairro,
    regiao_id,
    capturado_em,
    altitude_m,
    metadata,
    observacao
  ) VALUES (
    v_cliente_id,
    v_levantamento_id,
    p_tipo_problema,
    p_descricao,
    p_prioridade,
    p_latitude,
    p_longitude,
    p_score_final,
    p_classificacao_risco,
    p_confianca_pct,
    COALESCE(UPPER(p_origem_tipo), 'MANUAL'),
    p_image_url,
    p_image_public_id,
    p_bairro,
    p_regiao_id,
    COALESCE(p_capturado_em, now()),
    p_altitude_m,
    p_metadata,
    p_observacao
  )
  RETURNING id INTO v_item_id;

  -- Tags
  IF p_tags IS NOT NULL THEN
    FOREACH v_tag_slug IN ARRAY p_tags LOOP
      SELECT id INTO v_tag_id FROM levantamento_tags WHERE slug = v_tag_slug LIMIT 1;
      IF v_tag_id IS NOT NULL THEN
        INSERT INTO levantamento_item_tags (item_id, tag_id)
        VALUES (v_item_id, v_tag_id)
        ON CONFLICT DO NOTHING;
      END IF;
    END LOOP;
  END IF;

  RETURN jsonb_build_object(
    'item_id',             v_item_id,
    'levantamento_id',     v_levantamento_id,
    'levantamento_criado', v_levantamento_criado
  );

EXCEPTION WHEN OTHERS THEN
  RAISE;
END;
$$;


ALTER FUNCTION "public"."criar_levantamento_item_manual"("p_planejamento_id" "uuid", "p_data_voo" "date", "p_latitude" double precision, "p_longitude" double precision, "p_tipo_problema" "text", "p_descricao" "text", "p_prioridade" "text", "p_score_final" double precision, "p_classificacao_risco" "text", "p_confianca_pct" integer, "p_origem_tipo" "text", "p_image_url" "text", "p_image_public_id" "text", "p_bairro" "text", "p_regiao_id" "uuid", "p_capturado_em" timestamp with time zone, "p_tags" "text"[], "p_altitude_m" double precision, "p_metadata" "jsonb", "p_observacao" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."criar_levantamento_item_manual"("p_planejamento_id" "uuid", "p_data_voo" "date", "p_latitude" double precision, "p_longitude" double precision, "p_tipo_problema" "text", "p_descricao" "text", "p_prioridade" "text", "p_score_final" double precision, "p_classificacao_risco" "text", "p_confianca_pct" integer, "p_origem_tipo" "text", "p_image_url" "text", "p_image_public_id" "text", "p_bairro" "text", "p_regiao_id" "uuid", "p_capturado_em" timestamp with time zone, "p_tags" "text"[], "p_altitude_m" double precision, "p_metadata" "jsonb", "p_observacao" "text") IS 'Cria item manual de levantamento. FIX P0-2026-04-11: lista de papéis aceitos atualizada para canônicos ativos (admin, supervisor, agente, notificador); removidos operador e usuario (dead values). Branch especial "operador" removido — tenant check via usuario_pode_acessar_cliente() para todos os papéis não-admin.';



CREATE OR REPLACE FUNCTION "public"."criar_pluvio_run_com_itens"("p_run_row" "jsonb", "p_itens" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_run_id uuid;
begin
  -- Insere o run (cabeçalho)
  insert into public.pluvio_operacional_run (cliente_id, dt_ref, dt_gerado, total_bairros)
  values (
    (p_run_row->>'cliente_id')::uuid,
    (p_run_row->>'dt_ref')::date,
    coalesce(
      case when nullif(trim(p_run_row->>'dt_gerado'), '') is null then null
           else (p_run_row->>'dt_gerado')::timestamptz end,
      now()
    ),
    coalesce((p_run_row->>'total_bairros')::int, jsonb_array_length(p_itens))
  )
  returning id into v_run_id;

  -- Insere os itens (um por bairro)
  insert into public.pluvio_operacional_item (
    run_id,
    regiao_id,
    bairro_nome,
    classificacao_risco,
    situacao_ambiental,
    chuva_24h_mm,
    chuva_72h_mm,
    chuva_7d_mm,
    dias_com_chuva_7d,
    janela_sem_chuva,
    persistencia_7d,
    tendencia,
    temp_media_c,
    vento_medio_kmh,
    prob_label,
    prob_base_min,
    prob_base_max,
    prob_final_min,
    prob_final_max,
    criadouro_ativo,
    velocidade_ciclo,
    janela_emergencia_dias,
    prioridade_operacional,
    prazo_acao
  )
  select
    v_run_id,
    case when nullif(trim(elem->>'regiao_id'), '') is null then null
         else (elem->>'regiao_id')::uuid end,
    elem->>'bairro_nome',
    elem->>'classificacao_risco',
    nullif(trim(elem->>'situacao_ambiental'), ''),
    (elem->>'chuva_24h_mm')::numeric,
    (elem->>'chuva_72h_mm')::numeric,
    (elem->>'chuva_7d_mm')::numeric,
    (elem->>'dias_com_chuva_7d')::int,
    nullif(trim(elem->>'janela_sem_chuva'), ''),
    nullif(trim(elem->>'persistencia_7d'), ''),
    nullif(trim(elem->>'tendencia'), ''),
    (elem->>'temp_media_c')::numeric,
    (elem->>'vento_medio_kmh')::numeric,
    nullif(trim(elem->>'prob_label'), ''),
    (elem->>'prob_base_min')::numeric,
    (elem->>'prob_base_max')::numeric,
    (elem->>'prob_final_min')::numeric,
    (elem->>'prob_final_max')::numeric,
    nullif(trim(elem->>'criadouro_ativo'), ''),
    nullif(trim(elem->>'velocidade_ciclo'), ''),
    nullif(trim(elem->>'janela_emergencia_dias'), ''),
    elem->>'prioridade_operacional',
    nullif(trim(elem->>'prazo_acao'), '')
  from jsonb_array_elements(p_itens) as elem;

  return v_run_id;
end;
$$;


ALTER FUNCTION "public"."criar_pluvio_run_com_itens"("p_run_row" "jsonb", "p_itens" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."criar_pluvio_run_com_itens"("p_run_row" "jsonb", "p_itens" "jsonb") IS 'Cria um pluvio_operacional_run e seus itens em uma única transação. Usado por pluvio_supabase.upload_pluvio_operacional() e pelo sentinellaweb.';



