    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT u.id FROM public.usuarios u WHERE u.auth_id = auth.uid() LIMIT 1;
$$;


ALTER FUNCTION "public"."current_usuario_public_id"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."current_usuario_public_id"() IS 'Retorna o id (PK) do registro em usuarios do usuário autenticado (auth.uid()). Usado em RLS para operador = responsável.';



CREATE OR REPLACE FUNCTION "public"."custom_access_token_hook"("event" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id    uuid  := (event ->> 'user_id')::uuid;
  v_cliente_id uuid;
  v_ativo      boolean;
  v_papel      text;
  v_plano      text;
  v_claims     jsonb;
BEGIN
  SELECT u.cliente_id, u.ativo
  INTO   v_cliente_id, v_ativo
  FROM   public.usuarios u
  WHERE  u.auth_id = v_user_id
  LIMIT  1;

  SELECT LOWER(pu.papel::text)
  INTO   v_papel
  FROM   public.papeis_usuarios pu
  WHERE  pu.usuario_id = v_user_id
  ORDER BY CASE LOWER(pu.papel::text)
    WHEN 'admin'             THEN 5
    WHEN 'supervisor'        THEN 4
    WHEN 'moderador'         THEN 4
    WHEN 'agente'            THEN 3
    WHEN 'operador'          THEN 3
    WHEN 'notificador'       THEN 2
    WHEN 'analista_regional' THEN 1
    ELSE 0
  END DESC
  LIMIT 1;

  IF v_cliente_id IS NOT NULL THEN
    SELECT pl.nome
    INTO   v_plano
    FROM   public.cliente_plano cp
    JOIN   public.planos pl ON pl.id = cp.plano_id
    WHERE  cp.cliente_id = v_cliente_id
      AND  cp.status     = 'ativo'
    LIMIT 1;
  END IF;

  v_claims := COALESCE(event -> 'claims', '{}'::jsonb);
  v_claims := jsonb_set(
    v_claims,
    '{app_metadata}',
    COALESCE(v_claims -> 'app_metadata', '{}'::jsonb)
    || jsonb_build_object(
         'cliente_id',    v_cliente_id,
         'papel',         v_papel,
         'usuario_ativo', COALESCE(v_ativo, false),
         'plano',         v_plano
       )
  );

  RETURN jsonb_set(event, '{claims}', v_claims);

EXCEPTION WHEN OTHERS THEN
  RETURN event;
END;
$$;


ALTER FUNCTION "public"."custom_access_token_hook"("event" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."custom_access_token_hook"("event" "jsonb") IS 'Hook de JWT — injeta cliente_id, papel, usuario_ativo e plano em app_metadata. Escada completa: admin(5) > supervisor/moderador(4) > agente/operador(3) > notificador(2) > analista_regional(1).';



CREATE OR REPLACE FUNCTION "public"."denunciar_cidadao"("p_slug" "text", "p_bairro_id" "uuid", "p_descricao" "text", "p_latitude" double precision DEFAULT NULL::double precision, "p_longitude" double precision DEFAULT NULL::double precision) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cliente_id   uuid;
  v_lev_id       uuid;
  v_item_id      uuid;
  v_ip_raw       text;
  v_ip_hash      text;
  v_contagem     int;
  v_janela       timestamptz;
  c_limite_ip    CONSTANT int := 10;   -- por IP por hora
  c_limite_slug  CONSTANT int := 50;   -- por município por hora (anti-spoofing)
BEGIN
  -- ── Rate limit por IP ──────────────────────────────────────────────────────
  BEGIN
    v_ip_raw := split_part(
      (current_setting('request.headers', true)::jsonb ->> 'x-forwarded-for'),
      ',', 1
    );
  EXCEPTION WHEN OTHERS THEN
    v_ip_raw := 'unknown';
  END;

  v_ip_hash := md5(COALESCE(nullif(trim(v_ip_raw), ''), 'unknown'));
  v_janela  := date_trunc('hour', now());

  SELECT id INTO v_cliente_id FROM clientes WHERE slug = p_slug AND ativo = true;
  IF v_cliente_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Cliente não encontrado');
  END IF;

  -- Rate limit por IP
  INSERT INTO canal_cidadao_rate_limit (ip_hash, cliente_id, janela_hora, contagem)
  VALUES (v_ip_hash, v_cliente_id, v_janela, 1)
  ON CONFLICT (ip_hash, cliente_id, janela_hora)
  DO UPDATE SET contagem = canal_cidadao_rate_limit.contagem + 1
  RETURNING contagem INTO v_contagem;

  IF v_contagem > c_limite_ip THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'Muitas denúncias em pouco tempo. Tente novamente mais tarde.'
    );
  END IF;

  -- ── C-04: Rate limit global por município (anti X-Forwarded-For spoofing) ──
  INSERT INTO canal_cidadao_rate_limit (ip_hash, cliente_id, janela_hora, contagem)
  VALUES ('__global__', v_cliente_id, v_janela, 1)
  ON CONFLICT (ip_hash, cliente_id, janela_hora)
  DO UPDATE SET contagem = canal_cidadao_rate_limit.contagem + 1
  RETURNING contagem INTO v_contagem;

  IF v_contagem > c_limite_slug THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'Limite de denúncias por hora atingido para este município.'
    );
  END IF;

  -- ── Busca ou cria levantamento do canal cidadão ────────────────────────────
  SELECT id INTO v_lev_id
  FROM levantamentos
  WHERE cliente_id = v_cliente_id AND tipo_entrada = 'MANUAL'
    AND titulo = 'Canal Cidadão'
  LIMIT 1;

  IF v_lev_id IS NULL THEN
    INSERT INTO levantamentos (cliente_id, usuario_id, titulo, data_voo, total_itens, tipo_entrada)
    SELECT v_cliente_id, u.id, 'Canal Cidadão', CURRENT_DATE, 0, 'MANUAL'
    FROM usuarios u WHERE u.cliente_id = v_cliente_id LIMIT 1
    RETURNING id INTO v_lev_id;
  END IF;

  IF v_lev_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Não foi possível criar levantamento');
  END IF;

  INSERT INTO levantamento_itens (
    levantamento_id, item, risco, prioridade,
    latitude, longitude,
    endereco_curto,
    payload
  ) VALUES (
    v_lev_id, 'Denúncia Cidadão', 'Médio', 'Média',
    p_latitude, p_longitude,
    p_descricao,
    jsonb_build_object(
      'fonte',              'cidadao',
      'bairro_id',          p_bairro_id::text,
      'descricao_original', p_descricao
    )
  )
  RETURNING id INTO v_item_id;

  UPDATE levantamentos SET total_itens = total_itens + 1 WHERE id = v_lev_id;

  RETURN jsonb_build_object('ok', true, 'item_id', v_item_id::text);
END;
$$;


ALTER FUNCTION "public"."denunciar_cidadao"("p_slug" "text", "p_bairro_id" "uuid", "p_descricao" "text", "p_latitude" double precision, "p_longitude" double precision) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."denunciar_cidadao"("p_slug" "text", "p_bairro_id" "uuid", "p_descricao" "text", "p_latitude" double precision, "p_longitude" double precision) IS 'Canal do cidadão: cria denúncia de foco suspeito. Acessível sem autenticação. Rate limit: 10/hora por IP + 50/hora por município (anti X-Forwarded-For spoofing). Corrige vetor C-04: atacante não consegue mais criar >50 focos/h via IP rotation.';



CREATE OR REPLACE FUNCTION "public"."denunciar_cidadao"("p_slug" "text", "p_bairro_id" "uuid" DEFAULT NULL::"uuid", "p_descricao" "text" DEFAULT NULL::"text", "p_latitude" double precision DEFAULT NULL::double precision, "p_longitude" double precision DEFAULT NULL::double precision, "p_foto_url" "text" DEFAULT NULL::"text", "p_foto_public_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cliente_id  uuid;
  v_regiao_id   uuid;
  v_foco_id     uuid;
  v_foco_existe uuid;
  v_ciclo       int;
  -- rate limit
  v_ip_raw      text;
  v_ip_hash     text;
  v_janela      timestamptz;
  v_contagem    int;
  v_limite      int  := 5;
  v_janela_min  int  := 30;
  -- dedup
  v_raio_m      int  := 30;
  -- headers
  v_headers     jsonb;
BEGIN
  -- 1. Validar p_descricao antes de qualquer acesso ao banco
  IF p_descricao IS NULL OR trim(p_descricao) = '' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Descrição é obrigatória.');
  END IF;

  -- S-03: Validar foto_url — aceita apenas URLs Cloudinary ou NULL
  IF p_foto_url IS NOT NULL AND p_foto_url !~ '^https://res\.cloudinary\.com/' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'URL de foto inválida.');
  END IF;

  -- 2. Resolver cliente pelo slug
  SELECT id INTO v_cliente_id FROM public.clientes WHERE slug = p_slug AND ativo = true;
  IF v_cliente_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Canal não encontrado.');
  END IF;

  -- 3. Rate limit por IP (janela de 30 minutos)
  --    S-02: tenta x-real-ip primeiro; fallback para primeiro token de x-forwarded-for.
  BEGIN
    v_headers := current_setting('request.headers', true)::jsonb;
    v_ip_raw  := nullif(trim(COALESCE(v_headers->>'x-real-ip', '')), '');
    IF v_ip_raw IS NULL THEN
      v_ip_raw := nullif(
        trim(split_part(COALESCE(v_headers->>'x-forwarded-for', ''), ',', 1)),
        ''
      );
    END IF;
  EXCEPTION WHEN OTHERS THEN
    v_ip_raw := NULL;
  END;

  -- S-02: SHA-256 substitui MD5 — resistente a ataques de pré-imagem com wordlists de IP
  v_ip_hash := encode(
    extensions.digest(
      COALESCE(v_ip_raw, 'unknown_' || gen_random_uuid()::text)
      || v_cliente_id::text,
      'sha256'
    ),
    'hex'
  );

  -- Pular rate-limit quando IP genuinamente desconhecido (hash aleatório por request)
  IF v_ip_raw IS NOT NULL THEN
    v_janela := date_trunc('hour', now())
                 + INTERVAL '30 minutes'
                 * FLOOR(EXTRACT(minute FROM now()) / 30);

    INSERT INTO public.canal_cidadao_rate_limit (ip_hash, cliente_id, janela_hora, contagem)
    VALUES (v_ip_hash, v_cliente_id, v_janela, 1)
    ON CONFLICT (ip_hash, cliente_id, janela_hora)
    DO UPDATE SET contagem = canal_cidadao_rate_limit.contagem + 1
    RETURNING contagem INTO v_contagem;

    IF v_contagem > v_limite THEN
      UPDATE public.canal_cidadao_rate_limit
      SET contagem = v_limite
      WHERE ip_hash = v_ip_hash AND cliente_id = v_cliente_id AND janela_hora = v_janela;

      -- Log do bloqueio (fire-and-forget)
      BEGIN
        INSERT INTO public.canal_cidadao_rate_log (cliente_id, ip_hash, motivo, detalhes)
        VALUES (
          v_cliente_id,
          v_ip_hash,
          'RATE_LIMIT',
          jsonb_build_object('janela_min', v_janela_min, 'limite', v_limite, 'contagem', v_contagem)
        );
      EXCEPTION WHEN OTHERS THEN NULL; END;

      RETURN jsonb_build_object(
        'ok',    false,
        'error', 'Muitas denúncias registradas neste local. Aguarde ' || v_janela_min || ' minutos.'
      );
    END IF;
  END IF;

  -- 4. Deduplicação geoespacial: foco cidadão próximo (30m) nas últimas 24h
  IF p_latitude IS NOT NULL AND p_longitude IS NOT NULL THEN
    SELECT id INTO v_foco_existe
    FROM public.focos_risco
    WHERE cliente_id    = v_cliente_id
      AND origem_tipo   = 'cidadao'
      AND status        NOT IN ('descartado')
      AND deleted_at    IS NULL
      AND created_at    > now() - INTERVAL '24 hours'
      AND ST_DWithin(
            ST_MakePoint(longitude, latitude)::geography,
            ST_MakePoint(p_longitude, p_latitude)::geography,
            v_raio_m
          )
    ORDER BY created_at DESC
    LIMIT 1;

    IF v_foco_existe IS NOT NULL THEN
      UPDATE public.focos_risco
      SET payload = jsonb_set(
            COALESCE(payload, '{}'::jsonb),
            '{confirmacoes}',
            to_jsonb(COALESCE((payload->>'confirmacoes')::int, 1) + 1)
          )
      WHERE id = v_foco_existe;

      -- Log da deduplicação (fire-and-forget)
      BEGIN
        INSERT INTO public.canal_cidadao_rate_log (cliente_id, ip_hash, motivo, foco_id, detalhes)
        VALUES (
          v_cliente_id,
          v_ip_hash,
          'DEDUPLICADO',
          v_foco_existe,
          jsonb_build_object('raio_m', v_raio_m)
        );
      EXCEPTION WHEN OTHERS THEN NULL; END;

      RETURN jsonb_build_object(
        'ok',         true,
        'foco_id',    v_foco_existe::text,
        'deduplicado', true
      );
    END IF;
  END IF;

  -- 5. Resolver região pelo bairro_id (opcional)
  IF p_bairro_id IS NOT NULL THEN
    SELECT id INTO v_regiao_id
    FROM public.regioes
    WHERE id = p_bairro_id AND cliente_id = v_cliente_id;
  END IF;

  -- 6. Ciclo atual (1–6 por ano, 2 meses cada)
  v_ciclo := CEIL(EXTRACT(MONTH FROM now())::int / 2.0)::int;

  -- 7. Criar foco_risco
  INSERT INTO public.focos_risco (
    cliente_id,
    regiao_id,
    descricao,
    latitude,
    longitude,
    prioridade,
    status,
    origem_tipo,
    ciclo,
    foto_url,
    foto_public_id,
    payload
  ) VALUES (
    v_cliente_id,
    v_regiao_id,
    p_descricao,
    p_latitude,
    p_longitude,
    'P3',
    'suspeita',
    'cidadao',
    v_ciclo,
    p_foto_url,
    p_foto_public_id,
    jsonb_build_object('bairro_id', p_bairro_id, 'confirmacoes', 1)
  )
  RETURNING id INTO v_foco_id;

  -- Log da denúncia aceita (fire-and-forget)
  BEGIN
    INSERT INTO public.canal_cidadao_rate_log (cliente_id, ip_hash, motivo, foco_id)
    VALUES (v_cliente_id, v_ip_hash, 'ACEITO', v_foco_id);
  EXCEPTION WHEN OTHERS THEN NULL; END;

  RETURN jsonb_build_object(
    'ok',         true,
    'foco_id',    v_foco_id::text,
    'deduplicado', false
  );
END;
$$;


ALTER FUNCTION "public"."denunciar_cidadao"("p_slug" "text", "p_bairro_id" "uuid", "p_descricao" "text", "p_latitude" double precision, "p_longitude" double precision, "p_foto_url" "text", "p_foto_public_id" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."denunciar_cidadao"("p_slug" "text", "p_bairro_id" "uuid", "p_descricao" "text", "p_latitude" double precision, "p_longitude" double precision, "p_foto_url" "text", "p_foto_public_id" "text") IS 'Canal cidadão. Rate limit: 5/30min por IP. S-02: hash SHA-256 (extensions.digest) + fallback x-real-ip → x-forwarded-for. S-03: foto_url validada contra ^https://res\.cloudinary\.com/ — rejeita URLs externas. Log é fire-and-forget — nunca bloqueia o fluxo principal.';



CREATE OR REPLACE FUNCTION "public"."escalar_prioridade"("p_prioridade" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT CASE lower(trim(p_prioridade))
    WHEN 'monitoramento' THEN 'Baixa'
    WHEN 'baixa'         THEN 'Média'
    WHEN 'média'         THEN 'Alta'
    WHEN 'media'         THEN 'Alta'
    WHEN 'moderada'      THEN 'Alta'
    WHEN 'alta'          THEN 'Urgente'
    WHEN 'urgente'       THEN 'Urgente'
    WHEN 'crítica'       THEN 'Crítica'
    WHEN 'critica'       THEN 'Crítica'
    ELSE p_prioridade
  END;
$$;


ALTER FUNCTION "public"."escalar_prioridade"("p_prioridade" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."escalar_prioridade"("p_prioridade" "text") IS 'Retorna a próxima prioridade mais alta na escala: Monitoramento→Baixa→Média→Alta→Urgente. Urgente e Crítica são o topo e permanecem inalterados.';



CREATE OR REPLACE FUNCTION "public"."escalar_sla_operacional"("p_sla_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sla         public.sla_operacional%ROWTYPE;
  v_nova_prio   text;
  v_config      jsonb;
  v_horas_base  int;
  v_horas_final int;
  v_item_pluvio public.pluvio_operacional_item%ROWTYPE;
  v_regiao_id   uuid;
  v_agora       timestamptz := now();
  v_user_id     uuid;
BEGIN
  SELECT * INTO v_sla FROM public.sla_operacional WHERE id = p_sla_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'SLA não encontrado: %', p_sla_id;
  END IF;

  -- ── Verificação de tenant (Fix S-02) ──────────────────────────────────────
  IF NOT public.usuario_pode_acessar_cliente(v_sla.cliente_id) THEN
    RAISE EXCEPTION
      'escalar_sla_operacional: acesso negado — SLA pertence a outro cliente';
  END IF;

  IF v_sla.status = 'concluido' THEN
    RAISE EXCEPTION 'SLA já concluído; não é possível escalar.';
  END IF;

  v_nova_prio := public.escalar_prioridade(v_sla.prioridade);

  IF lower(trim(v_nova_prio)) = lower(trim(v_sla.prioridade)) THEN
    RETURN jsonb_build_object(
      'escalado', false,
      'mensagem', 'Prioridade já está no nível máximo (' || v_sla.prioridade || ').'
    );
  END IF;

  IF v_sla.levantamento_item_id IS NOT NULL THEN
    v_regiao_id := public.sla_regiao_do_item(v_sla.levantamento_item_id);
  END IF;

  v_config     := public.sla_resolve_config(v_sla.cliente_id, v_regiao_id);
  v_horas_base := public.sla_horas_from_config(v_config, v_nova_prio);

  IF v_sla.item_id IS NOT NULL THEN
    SELECT * INTO v_item_pluvio
    FROM public.pluvio_operacional_item
    WHERE id = v_sla.item_id;

    v_horas_final := public.sla_aplicar_fatores(
      v_horas_base, v_config,
      v_item_pluvio.classificacao_risco,
      v_item_pluvio.persistencia_7d,
      v_item_pluvio.temp_media_c
    );
  ELSE
    v_horas_final := v_horas_base;
  END IF;

  SELECT id INTO v_user_id
  FROM public.usuarios
  WHERE auth_id = auth.uid();

  UPDATE public.sla_operacional
  SET
    prioridade_original = COALESCE(prioridade_original, prioridade),
    prioridade          = v_nova_prio,
    sla_horas           = v_horas_final,
    inicio              = v_agora,
    prazo_final         = v_agora + (v_horas_final || ' hours')::interval,
    escalonado          = true,
    escalonado_em       = v_agora,
    escalado_por        = v_user_id,
    status              = CASE WHEN status = 'vencido' THEN 'pendente' ELSE status END,
    violado             = CASE WHEN status = 'vencido' THEN violado    ELSE violado END
  WHERE id = p_sla_id;

  RETURN jsonb_build_object(
    'escalado',            true,
    'prioridade_anterior', v_sla.prioridade,
    'prioridade_nova',     v_nova_prio,
    'sla_horas',           v_horas_final,
    'regiao_override',     v_regiao_id IS NOT NULL
  );
END;
$$;


ALTER FUNCTION "public"."escalar_sla_operacional"("p_sla_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."escalar_sla_operacional"("p_sla_id" "uuid") IS 'Escala SLA para próxima prioridade, recalcula prazo, registra escalado_por. Verifica tenant antes de agir. (QW-07 + Fix S-02)';



CREATE OR REPLACE FUNCTION "public"."escalar_slas_iminentes"("p_cliente_id" "uuid" DEFAULT NULL::"uuid", "p_limiar_pct" integer DEFAULT 20) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sla    RECORD;
  v_count  int := 0;
  v_result jsonb;
BEGIN
  FOR v_sla IN
    SELECT id, sla_horas, prazo_final, prioridade
    FROM public.sla_operacional
    WHERE status IN ('pendente', 'em_atendimento')
      AND prioridade NOT IN ('Crítica', 'Urgente')   -- já no topo operacional
      AND escalonado_automatico = false               -- não escalar mais de uma vez por ciclo
      AND prazo_final IS NOT NULL
      AND sla_horas > 0
      AND now() >= prazo_final - ((sla_horas::numeric * p_limiar_pct / 100.0) || ' hours')::interval
      AND now() < prazo_final                         -- ainda não vencido
      AND (p_cliente_id IS NULL OR cliente_id = p_cliente_id)
    ORDER BY prazo_final ASC                          -- mais urgentes primeiro
  LOOP
    v_result := public.escalar_sla_operacional(v_sla.id);

    IF (v_result ->> 'escalado')::boolean THEN
      -- Marca que este SLA foi escalado automaticamente
      UPDATE public.sla_operacional
      SET escalonado_automatico = true
      WHERE id = v_sla.id;

      v_count := v_count + 1;
    END IF;
  END LOOP;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."escalar_slas_iminentes"("p_cliente_id" "uuid", "p_limiar_pct" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."escalar_slas_iminentes"("p_cliente_id" "uuid", "p_limiar_pct" integer) IS 'Escala automaticamente SLAs que estão nos últimos limiar_pct% do prazo. Eleva prioridade, recalcula prazo_final via sla_calcular_prazo_final. Chamada pela Edge Function sla-marcar-vencidos a cada 15min.';



CREATE OR REPLACE FUNCTION "public"."fechar_ciclo"("p_cliente_id" "uuid", "p_numero" integer, "p_ano" integer DEFAULT NULL::integer, "p_observacao" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_ano        int := COALESCE(p_ano, EXTRACT(YEAR FROM now())::int);
  v_ciclo      public.ciclos%ROWTYPE;
  v_user_id    uuid;
  v_liraa      jsonb;
  v_snapshot   jsonb;
  v_vistorias  int;
  v_focos_res  int;
  v_focos_tot  int;
  v_cobertura  numeric;
  v_imoveis    int;
BEGIN
  IF NOT public.usuario_pode_acessar_cliente(p_cliente_id) THEN
    RAISE EXCEPTION 'fechar_ciclo: sem permissão para este cliente';
  END IF;

  SELECT * INTO v_ciclo
  FROM public.ciclos
  WHERE cliente_id = p_cliente_id AND numero = p_numero AND ano = v_ano;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'fechar_ciclo: ciclo %/% não encontrado', p_numero, v_ano;
  END IF;

  IF v_ciclo.status = 'fechado' THEN
    RAISE EXCEPTION 'fechar_ciclo: ciclo já está fechado';
  END IF;

  SELECT id INTO v_user_id FROM public.usuarios WHERE auth_id = auth.uid();

  -- Gerar snapshot de indicadores
  v_liraa := public.rpc_calcular_liraa(p_cliente_id, p_numero);

  SELECT COUNT(*) INTO v_focos_tot
  FROM public.focos_risco
  WHERE cliente_id = p_cliente_id AND ciclo = p_numero AND deleted_at IS NULL;

  SELECT COUNT(*) INTO v_focos_res
  FROM public.focos_risco
  WHERE cliente_id = p_cliente_id AND ciclo = p_numero
    AND status = 'resolvido' AND deleted_at IS NULL;

  SELECT COUNT(*) INTO v_imoveis
  FROM public.imoveis
  WHERE cliente_id = p_cliente_id AND ativo = true AND deleted_at IS NULL;

  SELECT COUNT(DISTINCT imovel_id) INTO v_vistorias
  FROM public.vistorias
  WHERE cliente_id = p_cliente_id AND ciclo = p_numero
    AND acesso_realizado = true AND deleted_at IS NULL;

  v_cobertura := CASE WHEN v_imoveis > 0
    THEN ROUND((v_vistorias::numeric / v_imoveis) * 100, 1)
    ELSE 0 END;

  v_snapshot := jsonb_build_object(
    'fechado_em',           now(),
    'total_vistorias',      v_vistorias,
    'total_imoveis',        v_imoveis,
    'cobertura_pct',        v_cobertura,
    'total_focos',          v_focos_tot,
    'focos_resolvidos',     v_focos_res,
    'taxa_resolucao_pct',   CASE WHEN v_focos_tot > 0
      THEN ROUND((v_focos_res::numeric / v_focos_tot) * 100, 1) ELSE 0 END,
    'liraa',                v_liraa
  );

  UPDATE public.ciclos SET
    status                = 'fechado',
    data_fechamento       = CURRENT_DATE,
    snapshot_fechamento   = v_snapshot,
    observacao_fechamento = p_observacao,
    fechado_por           = v_user_id
  WHERE cliente_id = p_cliente_id AND numero = p_numero AND ano = v_ano;

  RETURN jsonb_build_object(
    'ok',       true,
    'numero',   p_numero,
    'ano',      v_ano,
    'snapshot', v_snapshot
  );
END;
$$;


ALTER FUNCTION "public"."fechar_ciclo"("p_cliente_id" "uuid", "p_numero" integer, "p_ano" integer, "p_observacao" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fechar_ciclo"("p_cliente_id" "uuid", "p_numero" integer, "p_ano" integer, "p_observacao" "text") IS 'Fecha um ciclo bimestral: gera snapshot de LIRAa + indicadores e marca como fechado. O snapshot é imutável após fechamento.';



CREATE OR REPLACE FUNCTION "public"."fn_atualizar_perfil_imovel"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sem_acesso int;
  v_ja_drone   boolean;
  v_cliente_id uuid;
BEGIN
  -- Conta tentativas sem acesso nos últimos 90 dias (R1 — janela corrigida de 60→90 dias)
  SELECT COUNT(*)
    INTO v_sem_acesso
  FROM public.vistorias
  WHERE imovel_id        = NEW.imovel_id
    AND acesso_realizado = false
    AND deleted_at       IS NULL
    AND created_at       >= now() - interval '90 days';

  -- Lê estado atual do imóvel para detectar primeira ativação
  SELECT prioridade_drone, cliente_id
    INTO v_ja_drone, v_cliente_id
  FROM public.imoveis
  WHERE id = NEW.imovel_id;

  IF v_sem_acesso >= 3 THEN
    -- Marca imóvel como recusante e candidato a drone
    UPDATE public.imoveis
    SET historico_recusa = true,
        prioridade_drone  = true
    WHERE id = NEW.imovel_id;

    -- Notifica gestor apenas na PRIMEIRA ativação (evita job duplicado)
    IF NOT COALESCE(v_ja_drone, false) THEN
      INSERT INTO public.job_queue (tipo, payload)
      VALUES (
        'notif_imovel_prioridade_drone',
        jsonb_build_object(
          'imovel_id',   NEW.imovel_id,
          'cliente_id',  v_cliente_id,
          'vistoria_id', NEW.id,
          'agente_id',   NEW.agente_id,
          'tentativas',  v_sem_acesso
        )
      );
    END IF;

  ELSE
    -- Janela de 90 dias sem atingir 3 tentativas consecutivas:
    -- reseta prioridade_drone se estava ativo.
    -- NOTA: historico_recusa permanece true — é registro histórico permanente
    --       e não deve ser apagado mesmo com a janela vazia.
    UPDATE public.imoveis
    SET prioridade_drone = false
    WHERE id             = NEW.imovel_id
      AND prioridade_drone = true; -- só escreve se estava true (evita write desnecessário)
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_atualizar_perfil_imovel"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_atualizar_perfil_imovel"() IS 'R1 (20260916): janela 90 dias para tentativas sem acesso. Ativa prioridade_drone=true ao atingir 3 tentativas na janela; reseta para false se janela passa sem atingir o limiar (historico_recusa permanece). F-11: notifica gestor via job_queue apenas na primeira ativação.';



CREATE OR REPLACE FUNCTION "public"."fn_audit_cliente_plano"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_acao      text;
  v_descricao text;
  v_payload   jsonb;
BEGIN
  -- Ignorar se nada relevante mudou
  IF OLD.status IS NOT DISTINCT FROM NEW.status
     AND OLD.plano_id IS NOT DISTINCT FROM NEW.plano_id THEN
    RETURN NEW;
  END IF;

  -- Determinar ação pelo novo status (status tem prioridade sobre plano)
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    v_acao := CASE NEW.status
      WHEN 'suspenso'     THEN 'tenant_suspenso'
      WHEN 'cancelado'    THEN 'tenant_cancelado'
      WHEN 'inadimplente' THEN 'tenant_inadimplente'
      WHEN 'trial'        THEN 'tenant_trial_iniciado'
      WHEN 'ativo'        THEN 'tenant_reativado'
      ELSE                     'plano_status_alterado'
    END;
  ELSE
    v_acao := 'plano_alterado';
  END IF;

  v_descricao := 'Status: ' || OLD.status || ' → ' || NEW.status;
  IF OLD.plano_id IS DISTINCT FROM NEW.plano_id THEN
    v_descricao := v_descricao || '; plano alterado';
  END IF;

  v_payload := jsonb_build_object(
    'status_anterior',   OLD.status,
    'status_novo',       NEW.status,
    'plano_id_anterior', OLD.plano_id,
    'plano_id_novo',     NEW.plano_id,
    'data_trial_fim',    NEW.data_trial_fim
  );

  PERFORM public.fn_insert_audit_log(
    NEW.cliente_id, v_acao, 'cliente_plano', NEW.id, v_descricao, v_payload
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_audit_cliente_plano"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_audit_cliente_plano"() IS 'P1-3: Audita mudanças de status e plano em cliente_plano. Acoes: tenant_suspenso, tenant_cancelado, tenant_inadimplente, tenant_reativado, tenant_trial_iniciado, plano_alterado.';



CREATE OR REPLACE FUNCTION "public"."fn_audit_integracoes"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_acao      text;
  v_descricao text;
  v_payload   jsonb;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_acao      := 'integracao_criada';
    v_descricao := 'Integração criada: ' || NEW.tipo;
    v_payload   := jsonb_build_object(
      'tipo',      NEW.tipo,
      'ambiente',  NEW.ambiente,
      'ativo',     NEW.ativo
      -- api_key NUNCA logada
    );
    PERFORM public.fn_insert_audit_log(
      NEW.cliente_id, v_acao, 'cliente_integracoes', NEW.id, v_descricao, v_payload
    );

  ELSIF TG_OP = 'UPDATE' THEN
    v_acao      := 'integracao_alterada';
    v_descricao := 'Integração alterada: ' || NEW.tipo;
    v_payload   := jsonb_build_object(
      'tipo',              NEW.tipo,
      'ambiente_anterior', OLD.ambiente,
      'ambiente_novo',     NEW.ambiente,
      'ativo_anterior',    OLD.ativo,
      'ativo_novo',        NEW.ativo,
      -- Indica SE a chave mudou, nunca O VALOR
      'api_key_alterada',  (OLD.api_key IS DISTINCT FROM NEW.api_key)
    );
    PERFORM public.fn_insert_audit_log(
      NEW.cliente_id, v_acao, 'cliente_integracoes', NEW.id, v_descricao, v_payload
    );

  ELSIF TG_OP = 'DELETE' THEN
    v_acao      := 'integracao_removida';
    v_descricao := 'Integração removida: ' || OLD.tipo;
    v_payload   := jsonb_build_object('tipo', OLD.tipo, 'ambiente', OLD.ambiente);
    PERFORM public.fn_insert_audit_log(
      OLD.cliente_id, v_acao, 'cliente_integracoes', OLD.id, v_descricao, v_payload
    );
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."fn_audit_integracoes"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_audit_integracoes"() IS 'P1-3: Audita INSERT/UPDATE/DELETE em cliente_integracoes. SEGURANÇA: payload nunca contém api_key ou segredos — apenas flag api_key_alterada (bool).';



CREATE OR REPLACE FUNCTION "public"."fn_audit_papeis_usuarios"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cliente_id uuid;
  v_uid        uuid;
  v_acao       text;
  v_descricao  text;
  v_payload    jsonb;
BEGIN
  -- papeis_usuarios.usuario_id é o auth.uid() do usuário alvo (não o invocador)
  v_uid := COALESCE(NEW.usuario_id, OLD.usuario_id);
  SELECT u.cliente_id INTO v_cliente_id
  FROM   public.usuarios u
  WHERE  u.auth_id = v_uid
  LIMIT  1;

  IF TG_OP = 'INSERT' THEN
    v_acao      := 'papel_atribuido';
    v_descricao := 'Papel atribuído: ' || NEW.papel::text;
    v_payload   := jsonb_build_object('papel', NEW.papel, 'usuario_auth_id', NEW.usuario_id);

  ELSIF TG_OP = 'UPDATE' THEN
    v_acao      := 'papel_alterado';
    v_descricao := 'Papel alterado: ' || OLD.papel::text || ' → ' || NEW.papel::text;
    v_payload   := jsonb_build_object(
      'papel_anterior', OLD.papel,
      'papel_novo',     NEW.papel,
      'usuario_auth_id', NEW.usuario_id
    );

  ELSIF TG_OP = 'DELETE' THEN
    v_acao      := 'papel_removido';
    v_descricao := 'Papel removido: ' || OLD.papel::text;
    v_payload   := jsonb_build_object('papel', OLD.papel, 'usuario_auth_id', OLD.usuario_id);
  END IF;

  PERFORM public.fn_insert_audit_log(
    v_cliente_id, v_acao, 'papeis_usuarios', v_uid, v_descricao, v_payload
  );

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."fn_audit_papeis_usuarios"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_audit_papeis_usuarios"() IS 'P1-3: Audita INSERT/UPDATE/DELETE em papeis_usuarios. Acoes: papel_atribuido, papel_alterado, papel_removido.';



CREATE OR REPLACE FUNCTION "public"."fn_audit_sla_config"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  -- Tentar identificar o usuário logado
  SELECT u.id INTO v_user_id
    FROM usuarios u
   WHERE u.auth_id = auth.uid()
   LIMIT 1;

  IF TG_OP = 'INSERT' THEN
    INSERT INTO sla_config_audit (cliente_id, changed_by, action, config_before, config_after)
    VALUES (NEW.cliente_id, v_user_id, 'INSERT', NULL, NEW.config);
    RETURN NEW;

  ELSIF TG_OP = 'UPDATE' THEN
    -- Só auditar se config realmente mudou
    IF OLD.config IS DISTINCT FROM NEW.config THEN
      INSERT INTO sla_config_audit (cliente_id, changed_by, action, config_before, config_after)
      VALUES (NEW.cliente_id, v_user_id, 'UPDATE', OLD.config, NEW.config);
    END IF;
    RETURN NEW;

  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO sla_config_audit (cliente_id, changed_by, action, config_before, config_after)
    VALUES (OLD.cliente_id, v_user_id, 'DELETE', OLD.config, NULL);
    RETURN OLD;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."fn_audit_sla_config"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_audit_usuarios_status"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_acao      text;
  v_descricao text;
  v_payload   jsonb;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_acao      := 'usuario_removido';
    v_descricao := 'Usuário removido: ' || COALESCE(OLD.email, OLD.id::text);
    v_payload   := jsonb_build_object('email', OLD.email);
    PERFORM public.fn_insert_audit_log(
      OLD.cliente_id, v_acao, 'usuarios', OLD.id, v_descricao, v_payload
    );
    RETURN OLD;
  END IF;

  -- UPDATE: auditar apenas mudanças de ativo
  IF OLD.ativo IS DISTINCT FROM NEW.ativo THEN
    v_acao := CASE WHEN NEW.ativo THEN 'usuario_reativado' ELSE 'usuario_desativado' END;
    v_descricao := 'Usuário ' || CASE WHEN NEW.ativo THEN 'reativado' ELSE 'desativado' END
                 || ': ' || COALESCE(NEW.email, NEW.id::text);
    v_payload   := jsonb_build_object(
      'email',          NEW.email,
      'ativo_anterior', OLD.ativo,
      'ativo_novo',     NEW.ativo
    );
    PERFORM public.fn_insert_audit_log(
      NEW.cliente_id, v_acao, 'usuarios', NEW.id, v_descricao, v_payload
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_audit_usuarios_status"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_audit_usuarios_status"() IS 'P1-3: Audita desativação, reativação e remoção de usuários. Acoes: usuario_desativado, usuario_reativado, usuario_removido.';



CREATE OR REPLACE FUNCTION "public"."fn_auto_classificar_foco"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Drone e pluvio sempre são promovidos à classificação técnica,
  -- independente do valor default ou valor explicitamente passado.
  NEW.classificacao_inicial := CASE NEW.origem_tipo
    WHEN 'drone'  THEN 'foco'
    WHEN 'pluvio' THEN 'risco'
    ELSE NEW.classificacao_inicial   -- preserva valor explícito ou DEFAULT 'suspeito'
  END;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_auto_classificar_foco"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_auto_em_inspecao_por_vistoria"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_status_atual text;
BEGIN
  IF NEW.foco_risco_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT status INTO v_status_atual
  FROM focos_risco
  WHERE id = NEW.foco_risco_id;

  -- Só avança se estiver aguardando inspeção
  IF v_status_atual = 'aguarda_inspecao' THEN
    UPDATE focos_risco
    SET
      status         = 'em_inspecao',
      responsavel_id = COALESCE(responsavel_id, NEW.agente_id),
      updated_at     = now()
    WHERE id = NEW.foco_risco_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_auto_em_inspecao_por_vistoria"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_auto_escalar_focos_suspeita"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count int := 0;
BEGIN
  -- Eleva para P1 todos os focos em 'suspeita' criados há > 48h
  -- que ainda não estão em P1.
  -- Não altera status — apenas prioridade (visibilidade imediata no painel).
  UPDATE public.focos_risco
  SET
    prioridade = 'P1',
    updated_at = now()
  WHERE
    status    = 'suspeita'
    AND prioridade <> 'P1'
    AND created_at  < now() - interval '48 hours';

  GET DIAGNOSTICS v_count = ROW_COUNT;

  IF v_count > 0 THEN
    RAISE NOTICE 'fn_auto_escalar_focos_suspeita: % foco(s) elevado(s) para P1', v_count;
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_auto_escalar_focos_suspeita"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_auto_escalar_focos_suspeita"() IS 'F-08: Eleva para P1 focos em "suspeita" sem triagem após 48h. Executada pelo pg_cron a cada hora. Não altera status — apenas prioridade.';



CREATE OR REPLACE FUNCTION "public"."fn_auto_triagem_foco"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Avança direto para em_triagem; o trigger fn_validar_transicao_foco_risco
  -- permite suspeita → em_triagem, portanto este UPDATE é sempre bem-sucedido.
  UPDATE public.focos_risco
  SET status     = 'em_triagem',
      updated_at = now()
  WHERE id = NEW.id
    AND status = 'suspeita';   -- guard: evita dupla execução em reinserts
  RETURN NULL;
END;
$$;


