CREATE OR REPLACE FUNCTION "public"."fn_bloquear_delete_imovel"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF EXISTS (SELECT 1 FROM vistorias WHERE imovel_id = OLD.id LIMIT 1) THEN
    RAISE EXCEPTION
      'Imóvel com vistorias não pode ser apagado. Use deleted_at = now() para inativação.'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN OLD;
END;
$$;


