COMMENT ON FUNCTION "public"."fn_calcular_score_imovel"("p_imovel_id" "uuid", "p_cliente_id" "uuid") IS 'Calcula e persiste o score territorial de um imóvel (0–100). focos_ativos inclui em_inspecao (fix 20261006).';



CREATE OR REPLACE FUNCTION "public"."fn_cancelar_reinspecoes_ao_fechar_foco"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Dispara quando foco vai para resolvido ou descartado
  IF NEW.status IN ('resolvido', 'descartado')
     AND OLD.status NOT IN ('resolvido', 'descartado')
  THEN
    UPDATE reinspecoes_programadas
    SET
      status              = 'cancelada',
      motivo_cancelamento = 'Foco encerrado automaticamente (' || NEW.status || ')',
      cancelado_por       = NEW.responsavel_id,
      updated_at          = now()
    WHERE foco_risco_id = NEW.id
      AND status        = 'pendente';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_cancelar_reinspecoes_ao_fechar_foco"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_casos_notificados_page"("p_cliente_id" "uuid", "p_limit" integer DEFAULT 100, "p_cursor_created" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_cursor_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "cliente_id" "uuid", "unidade_saude_id" "uuid", "notificador_id" "uuid", "doenca" "text", "status" "text", "data_inicio_sintomas" "date", "data_notificacao" "date", "logradouro_bairro" "text", "bairro" "text", "latitude" double precision, "longitude" double precision, "regiao_id" "uuid", "observacao" "text", "payload" "jsonb", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "unidade_nome" "text", "unidade_tipo" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    c.id, c.cliente_id, c.unidade_saude_id, c.notificador_id,
    c.doenca::text, c.status::text,
    c.data_inicio_sintomas, c.data_notificacao,
    c.logradouro_bairro, c.bairro, c.latitude, c.longitude, c.regiao_id,
    c.observacao, c.payload, c.created_at, c.updated_at,
    u.nome  AS unidade_nome,
    u.tipo::text AS unidade_tipo
  FROM casos_notificados c
  LEFT JOIN unidades_saude u ON u.id = c.unidade_saude_id
  WHERE c.cliente_id = p_cliente_id
    AND (
      p_cursor_created IS NULL
      OR c.created_at < p_cursor_created
      OR (c.created_at = p_cursor_created AND c.id < p_cursor_id)
    )
  ORDER BY c.created_at DESC, c.id DESC
  LIMIT p_limit + 1;
$$;


