CREATE OR REPLACE FUNCTION "public"."fn_check_quota_itens"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cliente_id  uuid;
  v_limite      integer;
  v_utilizado   integer;
BEGIN
  -- Resolver cliente_id via levantamento pai (levantamento_itens não tem cliente_id direto)
  SELECT l.cliente_id INTO v_cliente_id
  FROM levantamentos l
  WHERE l.id = NEW.levantamento_id;

  IF v_cliente_id IS NULL THEN
    RETURN NEW; -- levantamento não encontrado, FK vai rejeitar
  END IF;

  SELECT itens_mes INTO v_limite
  FROM cliente_quotas
  WHERE cliente_id = v_cliente_id;

  -- NULL = ilimitado
  IF v_limite IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT COUNT(*) INTO v_utilizado
  FROM levantamento_itens li
  JOIN levantamentos l ON l.id = li.levantamento_id
  WHERE l.cliente_id = v_cliente_id
    AND date_trunc('month', li.created_at) = date_trunc('month', now());

  IF v_utilizado >= v_limite THEN
    RAISE EXCEPTION 'quota_itens_excedida: cliente % atingiu o limite de % itens/mês (uso atual: %)',
      v_cliente_id, v_limite, v_utilizado
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_check_quota_itens"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_check_quota_levantamentos"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_surto  boolean;
  v_limite numeric;
  v_usado  integer;
  v_mes    timestamptz;
BEGIN
  SELECT surto_ativo INTO v_surto FROM clientes WHERE id = NEW.cliente_id;
  IF COALESCE(v_surto, false) THEN RETURN NEW; END IF;

  SELECT COALESCE(cq.levantamentos_mes, pl.limite_levantamentos_mes)
  INTO v_limite
  FROM cliente_quotas cq
  LEFT JOIN cliente_plano cp ON cp.cliente_id = cq.cliente_id AND cp.status = 'ativo'
  LEFT JOIN planos pl         ON pl.id = cp.plano_id
  WHERE cq.cliente_id = NEW.cliente_id;

  IF v_limite IS NULL THEN RETURN NEW; END IF;

  v_mes := date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo');
  SELECT COUNT(*) INTO v_usado FROM levantamentos
  WHERE cliente_id = NEW.cliente_id AND created_at >= v_mes;

  IF v_usado >= (v_limite * 1.5)::int THEN
    RAISE EXCEPTION 'quota_levantamentos_excedida: limite=% usado=% (carencia_150pct)', v_limite, v_usado
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_check_quota_levantamentos"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_check_quota_usuarios"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_limite numeric;
  v_usado  integer;
BEGIN
  SELECT COALESCE(cq.usuarios_ativos, pl.limite_usuarios)
  INTO v_limite
  FROM cliente_quotas cq
  LEFT JOIN cliente_plano cp ON cp.cliente_id = cq.cliente_id AND cp.status = 'ativo'
  LEFT JOIN planos pl         ON pl.id = cp.plano_id
  WHERE cq.cliente_id = NEW.cliente_id;

  IF v_limite IS NULL THEN RETURN NEW; END IF;

  SELECT COUNT(*) INTO v_usado FROM usuarios
  WHERE cliente_id = NEW.cliente_id AND ativo = true;

  IF v_usado >= v_limite THEN
    RAISE EXCEPTION 'quota_usuarios_excedida: limite=% usado=%', v_limite, v_usado
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_check_quota_usuarios"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_check_quota_vistorias"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_limite  int;
  v_usado   int;
  v_surto   boolean;
BEGIN
  -- Bypass surto epidemiológico
  SELECT COALESCE(c.surto_ativo, false)
  INTO   v_surto
  FROM   public.clientes c
  WHERE  c.id = NEW.cliente_id;

  IF v_surto THEN RETURN NEW; END IF;

  -- Limite: COALESCE(override individual, limite do plano)
  SELECT COALESCE(
    (SELECT cq.vistorias_mes
     FROM   public.cliente_quotas cq
     WHERE  cq.cliente_id = NEW.cliente_id),
    (SELECT pl.limite_vistorias_mes
     FROM   public.cliente_plano cp
     JOIN   public.planos pl ON pl.id = cp.plano_id
     WHERE  cp.cliente_id = NEW.cliente_id
       AND  cp.status IN ('ativo', 'trial')
     LIMIT  1)
  ) INTO v_limite;

  IF v_limite IS NULL THEN RETURN NEW; END IF;  -- ilimitado

  -- Contagem do mês corrente (fuso: America/Sao_Paulo)
  SELECT COUNT(*)::int
  INTO   v_usado
  FROM   public.vistorias v
  WHERE  v.cliente_id = NEW.cliente_id
    AND  v.created_at >= date_trunc('month', now() AT TIME ZONE 'America/Sao_Paulo')
                         AT TIME ZONE 'America/Sao_Paulo';

  -- Grace period: bloqueia apenas em 150% do limite
  IF v_usado >= (v_limite * 1.5)::int THEN
    RAISE EXCEPTION
      'quota_vistorias_excedida: limite % (grace 150%%) atingido no ciclo atual', v_limite
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_check_quota_vistorias"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_check_quota_vistorias"() IS 'P1-2: Quota de vistorias_mes; 150% grace; bypassa surto_ativo.';



