SET default_tablespace = '';

SET default_table_access_method = "heap";


CREATE TABLE IF NOT EXISTS "public"."job_queue" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tipo" "text" NOT NULL,
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "status" "text" DEFAULT 'pendente'::"text" NOT NULL,
    "tentativas" integer DEFAULT 0 NOT NULL,
    "max_tentativas" integer DEFAULT 3 NOT NULL,
    "executar_em" timestamp with time zone DEFAULT "now"() NOT NULL,
    "iniciado_em" timestamp with time zone,
    "concluido_em" timestamp with time zone,
    "resultado" "jsonb",
    "erro" "text",
    "criado_em" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "job_queue_status_check" CHECK (("status" = ANY (ARRAY['pendente'::"text", 'em_execucao'::"text", 'concluido'::"text", 'falhou'::"text", 'cancelado'::"text"])))
);


ALTER TABLE "public"."job_queue" OWNER TO "postgres";


COMMENT ON TABLE "public"."job_queue" IS 'Fila de jobs assíncronos. RLS: admin vê todos; outros veem apenas jobs do próprio cliente. Escrita exclusiva por service_role. (QW-13 + Fix S-06)';



COMMENT ON COLUMN "public"."job_queue"."tipo" IS 'Tipo de job: triagem_ia | relatorio_semanal | cnes_sync | limpeza_retencao | cloudinary_cleanup | health_check';



COMMENT ON COLUMN "public"."job_queue"."executar_em" IS 'Momento mais cedo em que o job pode ser executado. Usado para backoff com retry.';



COMMENT ON COLUMN "public"."job_queue"."resultado" IS 'JSON com resultado da execução bem-sucedida (opcional, definido pelo handler).';



CREATE OR REPLACE FUNCTION "public"."fn_claim_jobs_round_robin"("p_max" integer DEFAULT 5) RETURNS SETOF "public"."job_queue"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_ids uuid[];
BEGIN
  SELECT array_agg(id ORDER BY executar_em ASC) INTO v_ids
  FROM (
    SELECT DISTINCT ON (COALESCE(cliente_id::text, 'platform'))
      id, executar_em
    FROM job_queue
    WHERE status     = 'pendente'
      AND executar_em <= now()
    ORDER BY COALESCE(cliente_id::text, 'platform'), executar_em ASC
    LIMIT p_max
  ) candidatos;

  IF v_ids IS NULL OR array_length(v_ids, 1) = 0 THEN
    RETURN;
  END IF;

  RETURN QUERY
    UPDATE job_queue
       SET status      = 'processando',
           iniciado_em = now()
     WHERE id    = ANY(v_ids)
       AND status = 'pendente'
    RETURNING *;
END;
$$;


ALTER FUNCTION "public"."fn_claim_jobs_round_robin"("p_max" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_claim_jobs_round_robin"("p_max" integer) IS 'QW-17: aloca até p_max jobs, 1 por cliente, em round-robin. P0-6: SET search_path adicionado.';



CREATE OR REPLACE FUNCTION "public"."fn_claim_next_job"() RETURNS SETOF "public"."job_queue"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH claimed AS (
    SELECT id
    FROM public.job_queue
    WHERE status = 'pendente'
      AND executar_em <= now()
    ORDER BY executar_em ASC
    LIMIT 1
    FOR UPDATE SKIP LOCKED
  )
  UPDATE public.job_queue jq
  SET
    status      = 'em_execucao',
    iniciado_em = now()
  FROM claimed
  WHERE jq.id = claimed.id
  RETURNING jq.*;
$$;


ALTER FUNCTION "public"."fn_claim_next_job"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_claim_next_job"() IS 'Atomicamente marca o próximo job pendente como em_execucao. Usa FOR UPDATE SKIP LOCKED para evitar corrida entre workers concorrentes. (QW-13)';



CREATE OR REPLACE FUNCTION "public"."fn_consolidar_vistoria"("p_vistoria_id" "uuid", "p_motivo_reprocessamento" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  -- ── Vistoria base ──────────────────────────────────────────────────────────
  v_vistoria              vistorias%ROWTYPE;

  -- ── Sub-tabelas (NULL quando não preenchidas) ──────────────────────────────
  v_sintomas              vistoria_sintomas%ROWTYPE;
  v_riscos                vistoria_riscos%ROWTYPE;

  v_tem_sintomas_record   boolean := false;
  v_tem_riscos_record     boolean := false;
  v_tem_depositos_record  boolean := false;

  -- ── Aggregates de depósitos ────────────────────────────────────────────────
  v_dep_focos_total       int     := 0;
  v_dep_inspecionados     int     := 0;

  -- ── Calhas ────────────────────────────────────────────────────────────────
  v_calha_com_foco        boolean := false;
  v_calha_com_agua        boolean := false;

  -- ── Pesos e limiares (carregados de consolidacao_pesos_config) ─────────────
  v_limiar_baixo_medio    numeric(5,2) := 2.0;   -- fallback hardcoded se config ausente
  v_limiar_medio_alto     numeric(5,2) := 5.0;
  v_versao_pesos          text         := 'fallback';

  -- ── Scores socioambientais ─────────────────────────────────────────────────
  v_score_social          numeric(8,2) := 0;
  v_score_sanitario       numeric(8,2) := 0;
  v_score_socioambiental  numeric(8,2) := 0;

  -- ── Array de flags ativas (social + sanitário) para score ─────────────────
  v_flags_ativas          text[] := '{}';

  -- [V2-2] Array de flags ativas sem peso configurado ────────────────────────
  v_flags_sem_peso        text[] := '{}';

  -- ── Sem acesso recorrente (contagem histórica do imóvel) ──────────────────
  v_sem_acesso_count      int    := 0;

  -- ── Proporção de sintomáticos ──────────────────────────────────────────────
  v_proporcao_sintomas    numeric(5,3) := 0;

  -- ── Dimensões calculadas ──────────────────────────────────────────────────
  v_resultado_op            text;
  v_vuln_domiciliar         text;
  v_alerta_saude            text;
  v_risco_socioambiental    text;
  v_risco_vetorial          text;
  v_prioridade_final        text;
  v_prioridade_motivo       text;
  v_dimensao_dominante      text;
  v_consolidacao_resumo     text;
  v_consolidacao_incompleta boolean := false;

  -- [V2-3] Campos de auditoria adicionais ────────────────────────────────────
  -- override_ativado: alerta_saude=urgente foi o fator determinante da prioridade
  -- fallback_aplicado: nenhuma dimensão atingiu limiar → prioridade por fallback
  -- dado_inconsistente: flag ativa sem peso cadastrado em consolidacao_pesos_config
  v_override_ativado      boolean := false;
  v_fallback_aplicado     boolean := false;
  v_dado_inconsistente    boolean := false;

  -- ── Snapshot JSON ─────────────────────────────────────────────────────────
  v_consolidacao_json     jsonb;

  -- ── Versão imutável da regra ───────────────────────────────────────────────
  VERSAO_REGRA CONSTANT text := '2.0.0';

BEGIN

  -- ────────────────────────────────────────────────────────────────────────────
  -- 1. CARREGAR VISTORIA
  -- ────────────────────────────────────────────────────────────────────────────
  SELECT * INTO v_vistoria FROM vistorias WHERE id = p_vistoria_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'fn_consolidar_vistoria: vistoria_id % não encontrada', p_vistoria_id;
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 2. ARQUIVAR CONSOLIDAÇÃO ANTERIOR
  --
  -- [V2-1] MUDANÇA CRÍTICA: arquiva SEMPRE que consolidado_em IS NOT NULL,
  -- independente de p_motivo_reprocessamento.
  --
  -- Raciocínio da escolha (arquivar vs. bloquear):
  --   • Bloquear (RAISE EXCEPTION sem motivo) forçaria motivo explícito mas
  --     quebraria automação da Fase 3 (trigger pós-INSERT não passa motivo).
  --   • Arquivar sempre preserva o histórico em qualquer cenário, incluindo
  --     re-execução acidental.
  --   • p_motivo_reprocessamento continua sendo o rótulo auditável; quando
  --     ausente usamos um rótulo default para não perder rastreabilidade.
  -- ────────────────────────────────────────────────────────────────────────────
  IF v_vistoria.consolidado_em IS NOT NULL THEN
    INSERT INTO vistoria_consolidacao_historico (
      vistoria_id,
      prioridade_final,
      dimensao_dominante,
      consolidacao_json,
      versao_regra,
      versao_pesos,
      consolidado_em,
      motivo_reprocessamento,
      reprocessado_por
    ) VALUES (
      p_vistoria_id,
      v_vistoria.prioridade_final,
      v_vistoria.dimensao_dominante,
      v_vistoria.consolidacao_json,
      v_vistoria.versao_regra_consolidacao,
      v_vistoria.versao_pesos_consolidacao,
      v_vistoria.consolidado_em,
      -- [V2-1] Fallback de motivo: nunca nulo no histórico
      COALESCE(p_motivo_reprocessamento, 'reprocessamento automático sem motivo explícito'),
      auth.uid()
    );
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 3. CARREGAR SUB-TABELAS
  -- ────────────────────────────────────────────────────────────────────────────
  SELECT * INTO v_sintomas
  FROM vistoria_sintomas
  WHERE vistoria_id = p_vistoria_id
  LIMIT 1;
  v_tem_sintomas_record := FOUND;

  SELECT * INTO v_riscos
  FROM vistoria_riscos
  WHERE vistoria_id = p_vistoria_id
  LIMIT 1;
  v_tem_riscos_record := FOUND;

  SELECT
    COALESCE(SUM(qtd_com_focos), 0),
    COALESCE(SUM(qtd_inspecionados), 0)
  INTO v_dep_focos_total, v_dep_inspecionados
  FROM vistoria_depositos
  WHERE vistoria_id = p_vistoria_id;
  v_tem_depositos_record := (v_dep_inspecionados > 0);

  SELECT
    COALESCE(bool_or(com_foco), false),
    COALESCE(bool_or(condicao = 'com_agua_parada'), false)
  INTO v_calha_com_foco, v_calha_com_agua
  FROM vistoria_calhas
  WHERE vistoria_id = p_vistoria_id;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 4. SEM ACESSO RECORRENTE
  --    Conta TODAS as tentativas falhas do imóvel (incluindo esta vistoria).
  -- ────────────────────────────────────────────────────────────────────────────
  SELECT COUNT(*) INTO v_sem_acesso_count
  FROM vistorias
  WHERE imovel_id = v_vistoria.imovel_id
    AND acesso_realizado = false;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 5. CARREGAR PESOS E LIMIARES
  --    Prioridade: config do cliente > config global; mais recente primeiro.
  --
  --    [V2-4] ORDER BY agora usa created_at DESC em vez de versao DESC.
  --    Motivo: ordenação por string é lexicográfica — '1.9.0' > '1.10.0' seria
  --    uma comparação incorreta. created_at é monotônico e não tem esse risco.
  -- ────────────────────────────────────────────────────────────────────────────
  SELECT peso, versao
  INTO v_limiar_baixo_medio, v_versao_pesos
  FROM consolidacao_pesos_config
  WHERE flag_nome = 'limiar_baixo_medio'
    AND ativo = true
    AND (cliente_id = v_vistoria.cliente_id OR cliente_id IS NULL)
  ORDER BY (cliente_id = v_vistoria.cliente_id) DESC, created_at DESC  -- [V2-4]
  LIMIT 1;

  SELECT peso
  INTO v_limiar_medio_alto
  FROM consolidacao_pesos_config
  WHERE flag_nome = 'limiar_medio_alto'
    AND ativo = true
    AND (cliente_id = v_vistoria.cliente_id OR cliente_id IS NULL)
  ORDER BY (cliente_id = v_vistoria.cliente_id) DESC, created_at DESC  -- [V2-4]
  LIMIT 1;

  IF v_versao_pesos IS NULL THEN
    v_versao_pesos := 'fallback';
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 6. DIMENSÃO: resultado_operacional
  --    acesso_realizado=true (ou NULL legado) → 'visitado'
  --    acesso_realizado=false, 1ª tentativa   → 'sem_acesso'
  --    acesso_realizado=false, 2ª+ tentativa  → 'sem_acesso_retorno'
  -- ────────────────────────────────────────────────────────────────────────────
  IF v_vistoria.acesso_realizado = true OR v_vistoria.acesso_realizado IS NULL THEN
    v_resultado_op := 'visitado';
  ELSIF v_sem_acesso_count >= 2 THEN
    v_resultado_op := 'sem_acesso_retorno';
  ELSE
    v_resultado_op := 'sem_acesso';
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 6b. COMPLETUDE DE DADOS (vistorias realizadas com fichas ausentes)
  --
  -- [V2-5] NOVO: consolidacao_incompleta = true também quando vistoria foi
  -- realizada mas faltam registros subsidiários.
  --
  -- Impacto no fallback (seção 11): se todas as dimensões ficarem baixo/nenhum
  -- E consolidacao_incompleta = true → prioridade_final = P3 (conservador).
  -- Isso eleva vistorias com fichas parciais de P5 para P3 — comportamento
  -- intencional para sinalizar qualidade de dados ao gestor.
  -- ────────────────────────────────────────────────────────────────────────────
  IF v_resultado_op = 'visitado' THEN
    IF NOT v_tem_sintomas_record THEN
      -- [V2-5] Ausência de registro de sintomas em visita realizada
      v_consolidacao_incompleta := true;
    END IF;
    IF NOT v_tem_riscos_record THEN
      -- [V2-5] Ausência de registro de riscos em visita realizada
      v_consolidacao_incompleta := true;
    END IF;
    IF NOT v_tem_depositos_record THEN
      -- [V2-5] Ausência de depósitos inspecionados em visita realizada
      v_consolidacao_incompleta := true;
    END IF;
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 7. DIMENSÃO: vulnerabilidade_domiciliar
  --    Hierarquia: critica > alta > media > baixa | inconclusivo (sem acesso)
  -- ────────────────────────────────────────────────────────────────────────────
  IF v_resultado_op = 'visitado' THEN

    -- Crítica: pessoa incapacitada no domicílio (exige ação imediata de proteção)
    IF v_tem_riscos_record AND (v_riscos.menor_incapaz = true OR v_riscos.idoso_incapaz = true) THEN
      v_vuln_domiciliar := 'critica';

    -- Alta: população vulnerável + falta de suporte básico combinados
    ELSIF (v_vistoria.gravidas = true OR v_vistoria.idosos = true OR v_vistoria.criancas_7anos = true)
      AND v_tem_riscos_record
      AND (v_riscos.risco_moradia = true OR v_riscos.risco_alimentar = true OR v_riscos.dep_quimico = true)
    THEN
      v_vuln_domiciliar := 'alta';

    -- Média: qualquer vulnerável OU risco social isolado
    ELSIF v_vistoria.gravidas = true
       OR v_vistoria.idosos = true
       OR v_vistoria.criancas_7anos = true
       OR (v_tem_riscos_record AND (
             v_riscos.dep_quimico     = true
          OR v_riscos.risco_alimentar = true
          OR v_riscos.risco_moradia   = true
       ))
    THEN
      v_vuln_domiciliar := 'media';

    ELSE
      v_vuln_domiciliar := 'baixa';
    END IF;

  ELSE
    -- Sem acesso: nenhum dado coletado
    v_vuln_domiciliar := 'inconclusivo';
    v_consolidacao_incompleta := true;
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 8. DIMENSÃO: alerta_saude
  --    Limiar de urgência: proporção de sintomáticos >= 50%
  --    'urgente' aciona override de prioridade (≥ P2) na seção 11.
  -- ────────────────────────────────────────────────────────────────────────────
  IF v_resultado_op = 'visitado' THEN

    IF v_tem_sintomas_record THEN

      -- Calcular proporção de sintomáticos
      -- Proteção tripla: qtd > 0 AND moradores IS NOT NULL AND moradores > 0
      IF v_sintomas.moradores_sintomas_qtd > 0
        AND v_vistoria.moradores_qtd IS NOT NULL
        AND v_vistoria.moradores_qtd > 0
      THEN
        v_proporcao_sintomas :=
          v_sintomas.moradores_sintomas_qtd::numeric
          / v_vistoria.moradores_qtd::numeric;
      END IF;
      -- Nota: se moradores_qtd for NULL, v_proporcao_sintomas permanece 0,
      -- o que impede classificação 'urgente' por proporção — comportamento
      -- conservador intencional (sem denominador, sem urgência por proporção).

      IF v_sintomas.febre           = true
      OR v_sintomas.manchas_vermelhas = true
      OR v_sintomas.dor_articulacoes = true
      OR v_sintomas.dor_cabeca       = true
      THEN
        IF v_proporcao_sintomas >= 0.5 THEN
          v_alerta_saude := 'urgente';
        ELSE
          v_alerta_saude := 'atencao';
        END IF;
      ELSIF v_sintomas.moradores_sintomas_qtd > 0 THEN
        v_alerta_saude := 'atencao';
      ELSE
        v_alerta_saude := 'nenhum';
      END IF;

    ELSE
      -- Visitado sem registro de sintomas: ausência = nenhum
      -- (consolidacao_incompleta já foi marcada na seção 6b)
      v_alerta_saude := 'nenhum';
    END IF;

  ELSE
    v_alerta_saude := 'inconclusivo';
    v_consolidacao_incompleta := true;
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 9. DIMENSÃO: risco_socioambiental
  --    Score ponderado via consolidacao_pesos_config (social + sanitário).
  --    DISTINCT ON garante um peso efetivo por flag_nome.
  -- ────────────────────────────────────────────────────────────────────────────
  IF v_resultado_op = 'visitado' AND v_tem_riscos_record THEN

    -- Montar array de flags ativas (social)
    IF v_riscos.menor_incapaz   = true THEN v_flags_ativas := v_flags_ativas || 'menor_incapaz';   END IF;
    IF v_riscos.idoso_incapaz   = true THEN v_flags_ativas := v_flags_ativas || 'idoso_incapaz';   END IF;
    IF v_riscos.dep_quimico     = true THEN v_flags_ativas := v_flags_ativas || 'dep_quimico';     END IF;
    IF v_riscos.risco_alimentar = true THEN v_flags_ativas := v_flags_ativas || 'risco_alimentar'; END IF;
    IF v_riscos.risco_moradia   = true THEN v_flags_ativas := v_flags_ativas || 'risco_moradia';   END IF;

    -- Montar array de flags ativas (sanitário)
    IF v_riscos.criadouro_animais  = true THEN v_flags_ativas := v_flags_ativas || 'criadouro_animais';  END IF;
    IF v_riscos.lixo               = true THEN v_flags_ativas := v_flags_ativas || 'lixo';               END IF;
    IF v_riscos.residuos_organicos = true THEN v_flags_ativas := v_flags_ativas || 'residuos_organicos'; END IF;
    IF v_riscos.residuos_quimicos  = true THEN v_flags_ativas := v_flags_ativas || 'residuos_quimicos';  END IF;
    IF v_riscos.residuos_medicos   = true THEN v_flags_ativas := v_flags_ativas || 'residuos_medicos';   END IF;

    -- ── [V2-2] Detectar flags ativas sem peso configurado ─────────────────
    -- Uma flag ativa sem peso no banco gera score subavaliado silenciosamente.
    -- Aqui detectamos, marcamos consolidacao_incompleta e registramos no JSON.
    IF array_length(v_flags_ativas, 1) > 0 THEN
      SELECT COALESCE(array_agg(f ORDER BY f), '{}')
      INTO v_flags_sem_peso
      FROM unnest(v_flags_ativas) AS f
      WHERE NOT EXISTS (
        SELECT 1
        FROM consolidacao_pesos_config
        WHERE flag_nome = f
          AND ativo = true
          AND (cliente_id = v_vistoria.cliente_id OR cliente_id IS NULL)
      );

      IF array_length(v_flags_sem_peso, 1) > 0 THEN
        -- [V2-2] Flags sem peso: consolidação não é confiável
        v_consolidacao_incompleta := true;
        -- [V2-3] dado_inconsistente: sinaliza configuração defeituosa
        v_dado_inconsistente := true;
      END IF;
    END IF;

    -- ── Calcular score com pesos efetivos ─────────────────────────────────
    -- DISTINCT ON (flag_nome): garante um peso por flag.
    -- ORDER BY: cliente-específico > global; mais recente > mais antigo.
    -- [V2-4] created_at DESC substitui versao DESC (evita comparação lexicográfica).
    IF array_length(v_flags_ativas, 1) > 0 THEN
      WITH effective_weights AS (
        SELECT DISTINCT ON (flag_nome)
          flag_nome,
          grupo,
          peso
        FROM consolidacao_pesos_config
        WHERE ativo = true
          AND grupo IN ('social', 'sanitario')
          AND (cliente_id = v_vistoria.cliente_id OR cliente_id IS NULL)
          AND flag_nome = ANY(v_flags_ativas)
        ORDER BY flag_nome,
                 (cliente_id = v_vistoria.cliente_id) DESC,
                 created_at DESC                              -- [V2-4]
      )
      SELECT
        COALESCE(SUM(peso) FILTER (WHERE grupo = 'social'),    0),
        COALESCE(SUM(peso) FILTER (WHERE grupo = 'sanitario'), 0)
      INTO v_score_social, v_score_sanitario
      FROM effective_weights;
    END IF;

    v_score_socioambiental := v_score_social + v_score_sanitario;

    IF v_score_socioambiental >= v_limiar_medio_alto THEN
      v_risco_socioambiental := 'alto';
    ELSIF v_score_socioambiental >= v_limiar_baixo_medio THEN
      v_risco_socioambiental := 'medio';
    ELSE
      v_risco_socioambiental := 'baixo';
    END IF;

  ELSIF v_resultado_op = 'visitado' THEN
    -- Visitado sem registro de riscos: ausência = baixo
    -- (consolidacao_incompleta já foi marcada na seção 6b)
    v_risco_socioambiental := 'baixo';

  ELSE
    v_risco_socioambiental := 'inconclusivo';
    v_consolidacao_incompleta := true;
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 10. DIMENSÃO: risco_vetorial
  --     Hierarquia: critico > alto > medio > baixo | inconclusivo (sem acesso)
  --
  --     critico : foco confirmado em depósito OU calha com com_foco=true
  --     alto    : flags vetoriais presentes OU calha com água parada (sem foco)
  --     medio   : depósitos foram inspecionados e todos negativos
  --     baixo   : visitado sem dados de campo vetorial
  --
  --     [V2-6] COMPORTAMENTO CONSERVADOR DOCUMENTADO:
  --     'medio' representa "depósitos inspecionados com resultado negativo",
  --     não apenas "foi ao local". Um imóvel com muitos depósitos inspecionados
  --     e todos negativos receberá risco_vetorial='medio' e pode ser classificado
  --     P4 mesmo sem risco real identificado. Isso é intencional: a inspeção
  --     ativa é considerada dado de campo relevante para monitoramento contínuo.
  --     Para indicar imóvel limpo e completamente monitorado, o caminho é P5
  --     (via fallback quando todas as dimensões estão baixo/nenhum).
  -- ────────────────────────────────────────────────────────────────────────────
  IF v_resultado_op = 'visitado' THEN

    -- critico: foco confirmado (qtd_com_focos > 0 em qualquer depósito) OU calha positiva
    IF v_dep_focos_total > 0 OR v_calha_com_foco THEN
      v_risco_vetorial := 'critico';

    -- alto: risco vetorial presente mas sem foco confirmado
    ELSIF (
            v_tem_riscos_record AND (
              v_riscos.acumulo_material_organico = true
           OR v_riscos.animais_sinais_lv         = true
           OR v_riscos.caixa_destampada          = true
           OR (v_riscos.outro_risco_vetorial IS NOT NULL
               AND length(trim(v_riscos.outro_risco_vetorial)) > 0)
            )
          )
          OR v_calha_com_agua
    THEN
      v_risco_vetorial := 'alto';

    -- [V2-6] medio: comportamento conservador — inspecionado e negativo
    ELSIF v_tem_depositos_record THEN
      v_risco_vetorial := 'medio';

    ELSE
      v_risco_vetorial := 'baixo';
    END IF;

  ELSE
    v_risco_vetorial := 'inconclusivo';
    v_consolidacao_incompleta := true;
  END IF;

  -- ────────────────────────────────────────────────────────────────────────────
  -- 11. PRIORIDADE FINAL + EXPLICABILIDADE
  --
  --     Camada 1 — Sem acesso recorrente (sobrepõe matriz de dimensões)
  --       ≥ 5 tentativas → P2
  --       ≥ 3 tentativas → P3
  --       1–2 tentativas → P4
  --
  --     Camada 2 — Matriz de dimensões (visitado)
  --       P1: alerta_saude=urgente AND risco elevado em ≥1 outra dimensão
  --       P2: alerta_saude=urgente (isolado) OU (vetorial=critico AND vuln=critica)
  --       P3: vetorial critico/alto OU socioamb alto OU vuln critica/alta
  --       P4: vetorial medio OU socioamb medio OU vuln media OU alerta=atencao
  --       fallback: P3 (incompleto) | P5 (dados completos e negativos) | P4 (sem fichas)
  --
  --     [V2-3] v_override_ativado: true quando alerta_saude=urgente é o fator
  --     determinante da prioridade final (ramos P1 e P2-via-alerta).
  --     [V2-3] v_fallback_aplicado: true quando nenhuma dimensão atingiu limiar
  --     e a prioridade foi determinada pelo bloco de fallback.
  -- ────────────────────────────────────────────────────────────────────────────

  -- ── Camada 1: sem acesso ──────────────────────────────────────────────────
  IF v_resultado_op != 'visitado' THEN

    IF v_sem_acesso_count >= 5 THEN
      v_prioridade_final   := 'P2';
      v_prioridade_motivo  := format('Sem acesso recorrente: %s tentativas (≥5)', v_sem_acesso_count);
      v_dimensao_dominante := 'resultado_operacional';
    ELSIF v_sem_acesso_count >= 3 THEN
      v_prioridade_final   := 'P3';
      v_prioridade_motivo  := format('Sem acesso recorrente: %s tentativas (≥3)', v_sem_acesso_count);
      v_dimensao_dominante := 'resultado_operacional';
    ELSE
      v_prioridade_final   := 'P4';
      v_prioridade_motivo  := format('Sem acesso: %s tentativa(s) — dados insuficientes', v_sem_acesso_count);
      v_dimensao_dominante := 'resultado_operacional';
    END IF;

  ELSE
    -- ── Camada 2: matriz de dimensões ──────────────────────────────────────

    -- P1: alerta urgente + risco elevado em ao menos uma outra dimensão
    IF v_alerta_saude = 'urgente'
      AND (
           v_risco_vetorial IN ('critico','alto')
        OR v_vuln_domiciliar IN ('critica','alta')
        OR v_risco_socioambiental = 'alto'
      )
    THEN
      v_prioridade_final   := 'P1';
      v_prioridade_motivo  := 'Alerta de saúde urgente com risco elevado em outra dimensão';
      v_dimensao_dominante := 'alerta_saude';
      v_override_ativado   := true;  -- [V2-3]

    -- P2: alerta urgente isolado OU foco + vulnerabilidade crítica
    ELSIF v_alerta_saude = 'urgente'
       OR (v_risco_vetorial = 'critico' AND v_vuln_domiciliar = 'critica')
    THEN
      v_prioridade_final := 'P2';
      IF v_alerta_saude = 'urgente' THEN
        v_prioridade_motivo  := 'Alerta de saúde urgente (proporção ≥50% de sintomáticos)';
        v_dimensao_dominante := 'alerta_saude';
        v_override_ativado   := true;  -- [V2-3]
      ELSE
        v_prioridade_motivo  := 'Foco vetorial confirmado com vulnerabilidade crítica';
        v_dimensao_dominante := 'risco_vetorial';
      END IF;

    -- P3: dimensão grave em qualquer eixo
    ELSIF v_risco_vetorial      IN ('critico','alto')
       OR v_risco_socioambiental = 'alto'
       OR v_vuln_domiciliar      IN ('critica','alta')
    THEN
      v_prioridade_final := 'P3';
      -- Dimensão dominante: vetorial > vuln > socioambiental (ordem de criticidade)
      IF v_risco_vetorial = 'critico' THEN
        v_prioridade_motivo  := 'Foco vetorial confirmado em depósito ou calha';
        v_dimensao_dominante := 'risco_vetorial';
      ELSIF v_vuln_domiciliar = 'critica' THEN
        v_prioridade_motivo  := 'Vulnerabilidade crítica: pessoa incapacitada no domicílio';
        v_dimensao_dominante := 'vulnerabilidade_domiciliar';
      ELSIF v_risco_socioambiental = 'alto' THEN
        v_prioridade_motivo  := 'Risco socioambiental alto (score ≥ limiar_medio_alto)';
        v_dimensao_dominante := 'risco_socioambiental';
      ELSIF v_risco_vetorial = 'alto' THEN
        v_prioridade_motivo  := 'Risco vetorial alto: flags ativas sem foco confirmado';
        v_dimensao_dominante := 'risco_vetorial';
      ELSE
        v_prioridade_motivo  := 'Vulnerabilidade domiciliar alta (população vulnerável + risco)';
        v_dimensao_dominante := 'vulnerabilidade_domiciliar';
      END IF;

    -- P4: dimensão moderada em qualquer eixo
    ELSIF v_risco_vetorial       = 'medio'
       OR v_risco_socioambiental  = 'medio'
       OR v_vuln_domiciliar       = 'media'
       OR v_alerta_saude          = 'atencao'
    THEN
      v_prioridade_final := 'P4';
      IF v_alerta_saude = 'atencao' THEN
        v_prioridade_motivo  := 'Sintomas presentes abaixo do limiar de urgência';
        v_dimensao_dominante := 'alerta_saude';
      ELSIF v_risco_vetorial = 'medio' THEN
        -- [V2-6] comportamento conservador documentado (ver seção 10)
        v_prioridade_motivo  := 'Depósitos inspecionados e negativos (inspeção ativa = P4 conservador)';
        v_dimensao_dominante := 'risco_vetorial';
      ELSIF v_risco_socioambiental = 'medio' THEN
        v_prioridade_motivo  := 'Risco socioambiental médio (score entre limiares)';
        v_dimensao_dominante := 'risco_socioambiental';
      ELSE
        v_prioridade_motivo  := 'Vulnerabilidade domiciliar média';
        v_dimensao_dominante := 'vulnerabilidade_domiciliar';
      END IF;

    ELSE
      -- ── [V2-3] Bloco de fallback ──────────────────────────────────────────
      -- Todas as dimensões estão baixo/nenhum.
      -- P3: dados incompletos (fichas faltantes ou flag sem peso)
      -- P5: dados completos e todos negativos (imóvel monitorado e limpo)
      -- P4: vistoria realizada mas sem fichas subsidiárias preenchidas
      v_fallback_aplicado := true;  -- [V2-3]

      IF v_consolidacao_incompleta THEN
        v_prioridade_final   := 'P3';
        v_prioridade_motivo  := 'Consolidação incompleta: dados faltantes ou flag sem peso cadastrado';
        v_dimensao_dominante := NULL;
      ELSIF v_tem_depositos_record OR v_tem_riscos_record OR v_tem_sintomas_record THEN
        v_prioridade_final   := 'P5';
        v_prioridade_motivo  := 'Vistoria completa sem riscos identificados';
        v_dimensao_dominante := NULL;
      ELSE
        v_prioridade_final   := 'P4';
        v_prioridade_motivo  := 'Vistoria realizada sem preenchimento de depósitos ou riscos';
        v_dimensao_dominante := NULL;
      END IF;
    END IF;

  END IF; -- fim camada 1 vs 2

  -- ────────────────────────────────────────────────────────────────────────────
  -- 12. RESUMO TEXTUAL (uma linha para exibição rápida)
  -- ────────────────────────────────────────────────────────────────────────────
  v_consolidacao_resumo := format(
    '%s | VD:%s AS:%s SA:%s RV:%s → %s%s',
    v_resultado_op,
    left(COALESCE(v_vuln_domiciliar,      '?'), 5),
    left(COALESCE(v_alerta_saude,         '?'), 5),
    left(COALESCE(v_risco_socioambiental, '?'), 5),
    left(COALESCE(v_risco_vetorial,       '?'), 6),
    v_prioridade_final,
    CASE WHEN v_consolidacao_incompleta THEN ' [INCOMPLETO]' ELSE '' END
  );

  -- ────────────────────────────────────────────────────────────────────────────
  -- 13. SNAPSHOT JSON (auditabilidade completa — spec V2 seção 7.2)
  --
  --     [V2-3] Novos campos de topo:
  --       override_ativado  : alerta_saude=urgente foi o fator determinante
  --       fallback_aplicado : prioridade definida pelo bloco de fallback
  --       dado_inconsistente: flag ativa sem peso no banco
  -- ────────────────────────────────────────────────────────────────────────────
  v_consolidacao_json := jsonb_build_object(
    'versao_regra',        VERSAO_REGRA,
    'versao_pesos',        v_versao_pesos,
    'consolidado_em',      now(),

    -- [V2-3] Campos de auditoria de alto nível
    'override_ativado',    v_override_ativado,
    'fallback_aplicado',   v_fallback_aplicado,
    'dado_inconsistente',  v_dado_inconsistente,

    'resultado_operacional', jsonb_build_object(
      'resultado',        v_resultado_op,
      'acesso_realizado', v_vistoria.acesso_realizado,
      'sem_acesso_count', v_sem_acesso_count
    ),

    'vulnerabilidade_domiciliar', jsonb_build_object(
      'resultado',      v_vuln_domiciliar,
      'gravidas',       v_vistoria.gravidas,
      'idosos',         v_vistoria.idosos,
      'criancas_7anos', v_vistoria.criancas_7anos,
      'menor_incapaz',  CASE WHEN v_tem_riscos_record THEN v_riscos.menor_incapaz   ELSE NULL END,
      'idoso_incapaz',  CASE WHEN v_tem_riscos_record THEN v_riscos.idoso_incapaz   ELSE NULL END,
      'dep_quimico',    CASE WHEN v_tem_riscos_record THEN v_riscos.dep_quimico     ELSE NULL END,
      'risco_alimentar',CASE WHEN v_tem_riscos_record THEN v_riscos.risco_alimentar ELSE NULL END,
      'risco_moradia',  CASE WHEN v_tem_riscos_record THEN v_riscos.risco_moradia   ELSE NULL END
    ),

    'alerta_saude', jsonb_build_object(
      'resultado',              v_alerta_saude,
      'moradores_qtd',          v_vistoria.moradores_qtd,
      'moradores_sintomas_qtd', CASE WHEN v_tem_sintomas_record THEN v_sintomas.moradores_sintomas_qtd ELSE NULL END,
      'proporcao_sintomas',     v_proporcao_sintomas,
      'febre',                  CASE WHEN v_tem_sintomas_record THEN v_sintomas.febre                ELSE NULL END,
      'manchas_vermelhas',      CASE WHEN v_tem_sintomas_record THEN v_sintomas.manchas_vermelhas    ELSE NULL END,
      'dor_articulacoes',       CASE WHEN v_tem_sintomas_record THEN v_sintomas.dor_articulacoes     ELSE NULL END,
      'dor_cabeca',             CASE WHEN v_tem_sintomas_record THEN v_sintomas.dor_cabeca           ELSE NULL END
    ),

    'risco_socioambiental', jsonb_build_object(
      'resultado',          v_risco_socioambiental,
      'score_total',        v_score_socioambiental,
      'score_social',       v_score_social,
      'score_sanitario',    v_score_sanitario,
      'limiar_baixo_medio', v_limiar_baixo_medio,
      'limiar_medio_alto',  v_limiar_medio_alto,
      'flags_ativas',       to_jsonb(v_flags_ativas),
      -- [V2-2] flags sem peso cadastrado (array vazio = configuração completa)
      'flags_sem_peso',     to_jsonb(v_flags_sem_peso)
    ),

    'risco_vetorial', jsonb_build_object(
      'resultado',                 v_risco_vetorial,
      'dep_inspecionados',         v_dep_inspecionados,
      'dep_focos_total',           v_dep_focos_total,
      'calha_com_foco',            v_calha_com_foco,
      'calha_com_agua_parada',     v_calha_com_agua,
      'acumulo_material_organico', CASE WHEN v_tem_riscos_record THEN v_riscos.acumulo_material_organico ELSE NULL END,
      'animais_sinais_lv',         CASE WHEN v_tem_riscos_record THEN v_riscos.animais_sinais_lv         ELSE NULL END,
      'caixa_destampada',          CASE WHEN v_tem_riscos_record THEN v_riscos.caixa_destampada          ELSE NULL END,
      'outro_risco_vetorial',      CASE WHEN v_tem_riscos_record THEN v_riscos.outro_risco_vetorial      ELSE NULL END
    ),

    'prioridade', jsonb_build_object(
      'final',              v_prioridade_final,
      'motivo',             v_prioridade_motivo,
      'dimensao_dominante', v_dimensao_dominante,
      'incompleta',         v_consolidacao_incompleta
    ),

    -- Completude de sub-tabelas (rastreabilidade de qualidade de dados)
    'cobertura_dados', jsonb_build_object(
      'tem_sintomas',  v_tem_sintomas_record,
      'tem_riscos',    v_tem_riscos_record,
      'tem_depositos', v_tem_depositos_record
    )
  );

  -- ────────────────────────────────────────────────────────────────────────────
  -- 14. GRAVAR NA VISTORIA
  -- ────────────────────────────────────────────────────────────────────────────
  UPDATE vistorias SET
    resultado_operacional      = v_resultado_op,
    vulnerabilidade_domiciliar = v_vuln_domiciliar,
    alerta_saude               = v_alerta_saude,
    risco_socioambiental       = v_risco_socioambiental,
    risco_vetorial             = v_risco_vetorial,
    prioridade_final           = v_prioridade_final,
    prioridade_motivo          = v_prioridade_motivo,
    dimensao_dominante         = v_dimensao_dominante,
    consolidacao_resumo        = v_consolidacao_resumo,
    consolidacao_json          = v_consolidacao_json,
    consolidacao_incompleta    = v_consolidacao_incompleta,
    versao_regra_consolidacao  = VERSAO_REGRA,
    versao_pesos_consolidacao  = v_versao_pesos,
    consolidado_em             = now(),
    -- Reprocessamento: preenche apenas quando havia consolidação anterior
    reprocessado_em  = CASE WHEN v_vistoria.consolidado_em IS NOT NULL THEN now()      ELSE reprocessado_em  END,
    reprocessado_por = CASE WHEN v_vistoria.consolidado_em IS NOT NULL THEN auth.uid() ELSE reprocessado_por END
  WHERE id = p_vistoria_id;

END;
$$;


ALTER FUNCTION "public"."fn_consolidar_vistoria"("p_vistoria_id" "uuid", "p_motivo_reprocessamento" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_consolidar_vistoria"("p_vistoria_id" "uuid", "p_motivo_reprocessamento" "text") IS 'Consolida 6 dimensões de uma vistoria e calcula prioridade_final (P1-P5). Spec V2, função V2. SECURITY DEFINER para escrita em vistoria_consolidacao_historico. Fase 3 adicionará trigger pós-INSERT. V2: arquiva histórico sempre; detecta flags sem peso; override/fallback/dado_inconsistente no JSON; created_at no ORDER BY de pesos; consolidacao_incompleta expandida para dados faltantes.';



CREATE OR REPLACE FUNCTION "public"."fn_correlacionar_vistoria_com_drone"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'visitado' AND (OLD.status IS NULL OR OLD.status != 'visitado') THEN
    INSERT INTO vistoria_drone_correlacao (
      vistoria_id, levantamento_item_id, cliente_id, distancia_metros, drone_detectou_foco
    )
    SELECT
      NEW.id,
      li.id,
      NEW.cliente_id,
      ST_Distance(
        ST_MakePoint(im.longitude, im.latitude)::geography,
        ST_MakePoint(li.longitude, li.latitude)::geography
      ),
      (li.risco NOT IN ('sem risco', 'baixo') OR li.risco IS NULL)
    FROM imoveis im
    JOIN levantamento_itens li ON li.cliente_id = NEW.cliente_id
    JOIN levantamentos l       ON l.id = li.levantamento_id
    WHERE im.id = NEW.imovel_id
      AND im.latitude  IS NOT NULL AND im.longitude  IS NOT NULL
      AND li.latitude  IS NOT NULL AND li.longitude  IS NOT NULL
      AND ST_DWithin(
        ST_MakePoint(im.longitude, im.latitude)::geography,
        ST_MakePoint(li.longitude, li.latitude)::geography,
        50
      )
      AND l.created_at >= now() - interval '90 days'
    ON CONFLICT (vistoria_id, levantamento_item_id) DO NOTHING;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_correlacionar_vistoria_com_drone"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_create_sla_on_item"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_run        pluvio_operacional_run%ROWTYPE;
  v_prioridade TEXT;
  v_config     JSONB;
  v_horas      INT;
  v_inicio     TIMESTAMPTZ;
  v_prazo      TIMESTAMPTZ;
  v_default_rules JSONB := '{
    "Crítica":{"horas":4,"criticidade":"Muito Alta"},
    "Urgente":{"horas":4,"criticidade":"Muito Alta"},
    "Alta":{"horas":12,"criticidade":"Alta"},
    "Moderada":{"horas":24,"criticidade":"Média"},
    "Média":{"horas":24,"criticidade":"Média"},
    "Baixa":{"horas":72,"criticidade":"Baixa"},
    "Monitoramento":{"horas":72,"criticidade":"Baixa"}
  }';
  -- fatores
  v_risco_pct       INT;
  v_persist_dias    INT;
  v_persist_pct     INT;
  v_temp_min        INT;
  v_temp_pct        INT;
  -- horário comercial
  v_hc_ativo        BOOLEAN;
  v_hc_inicio       TIME;
  v_hc_fim          TIME;
  v_hc_dias         INT[];
  v_remaining_mins  INT;
  v_cursor          TIMESTAMPTZ;
  v_day_start       TIMESTAMPTZ;
  v_day_end         TIMESTAMPTZ;
  v_avail_mins      INT;
BEGIN
  -- Buscar run para obter cliente_id
  SELECT * INTO v_run FROM pluvio_operacional_run WHERE id = NEW.run_id;
  IF v_run IS NULL THEN RETURN NEW; END IF;

  v_prioridade := COALESCE(NEW.prioridade_operacional, 'Baixa');
  v_inicio := NOW();

  -- Buscar config do cliente
  SELECT (config)::JSONB INTO v_config
    FROM sla_config
   WHERE cliente_id = v_run.cliente_id
   LIMIT 1;

  -- ═══ Horas base ═══
  IF v_config IS NOT NULL
     AND v_config->'prioridades' ? v_prioridade THEN
    v_horas := (v_config->'prioridades'->v_prioridade->>'horas')::INT;
  ELSIF v_default_rules ? v_prioridade THEN
    v_horas := (v_default_rules->v_prioridade->>'horas')::INT;
  ELSE
    v_horas := 72;
  END IF;

  -- ═══ Fatores de redução ═══
  IF v_config IS NOT NULL AND v_config ? 'fatores' THEN
    v_risco_pct    := COALESCE((v_config->'fatores'->>'risco_muito_alto_pct')::INT, 30);
    v_persist_dias := COALESCE((v_config->'fatores'->>'persistencia_dias_min')::INT, 3);
    v_persist_pct  := COALESCE((v_config->'fatores'->>'persistencia_pct')::INT, 20);
    v_temp_min     := COALESCE((v_config->'fatores'->>'temperatura_min')::INT, 30);
    v_temp_pct     := COALESCE((v_config->'fatores'->>'temperatura_pct')::INT, 10);
  ELSE
    v_risco_pct := 30; v_persist_dias := 3; v_persist_pct := 20;
    v_temp_min := 30;  v_temp_pct := 10;
  END IF;

  -- Risco muito alto
  IF LOWER(COALESCE(NEW.classificacao_risco, '')) = 'muito alto' THEN
    v_horas := GREATEST(2, v_horas * (100 - v_risco_pct) / 100);
  END IF;

  -- Persistência
  IF COALESCE(NEW.persistencia_7d::INT, 0) > v_persist_dias THEN
    v_horas := GREATEST(2, v_horas * (100 - v_persist_pct) / 100);
  END IF;

  -- Temperatura
  IF COALESCE(NEW.temp_media_c, 0) > v_temp_min THEN
    v_horas := GREATEST(2, v_horas * (100 - v_temp_pct) / 100);
  END IF;

  v_horas := GREATEST(2, v_horas);

  -- ═══ Calcular prazo_final com horário comercial ═══
  v_hc_ativo := FALSE;
  IF v_config IS NOT NULL AND v_config ? 'horario_comercial' THEN
    v_hc_ativo := COALESCE((v_config->'horario_comercial'->>'ativo')::BOOLEAN, FALSE);
  END IF;

  IF v_hc_ativo THEN
    -- Ler config de horário comercial
    v_hc_inicio := (v_config->'horario_comercial'->>'inicio')::TIME;
    v_hc_fim    := (v_config->'horario_comercial'->>'fim')::TIME;

    -- Converter array JSONB → INT[]
    SELECT ARRAY(
      SELECT (jsonb_array_elements_text(v_config->'horario_comercial'->'dias_semana'))::INT
    ) INTO v_hc_dias;

    v_remaining_mins := v_horas * 60;
    v_cursor := v_inicio;

    -- Avançar dia a dia contando apenas minutos úteis
    WHILE v_remaining_mins > 0 LOOP
      -- Verificar se o dia da semana é útil (0=Dom ... 6=Sáb)
      -- EXTRACT(DOW) retorna 0=Dom, coincide com a convenção do front-end
      IF EXTRACT(DOW FROM v_cursor)::INT = ANY(v_hc_dias) THEN
        v_day_start := DATE_TRUNC('day', v_cursor) + v_hc_inicio;
        v_day_end   := DATE_TRUNC('day', v_cursor) + v_hc_fim;

        -- Se cursor está antes do início do expediente, avançar
        IF v_cursor < v_day_start THEN
          v_cursor := v_day_start;
        END IF;

        -- Se cursor está dentro do expediente
        IF v_cursor < v_day_end THEN
          v_avail_mins := EXTRACT(EPOCH FROM (v_day_end - v_cursor))::INT / 60;

          IF v_avail_mins >= v_remaining_mins THEN
            v_cursor := v_cursor + (v_remaining_mins || ' minutes')::INTERVAL;
            v_remaining_mins := 0;
          ELSE
            v_remaining_mins := v_remaining_mins - v_avail_mins;
            v_cursor := v_day_end;
          END IF;
        END IF;
      END IF;

      -- Se ainda resta tempo, avançar para o próximo dia
      IF v_remaining_mins > 0 THEN
        v_cursor := DATE_TRUNC('day', v_cursor) + INTERVAL '1 day' + v_hc_inicio;
      END IF;
    END LOOP;

    v_prazo := v_cursor;
  ELSE
    -- Sem horário comercial: prazo contínuo
    v_prazo := v_inicio + (v_horas || ' hours')::INTERVAL;
  END IF;

  -- ═══ Inserir SLA ═══
  INSERT INTO sla_operacional (item_id, prioridade, sla_horas, inicio, prazo_final, status, violado)
  VALUES (NEW.id, v_prioridade, v_horas, v_inicio, v_prazo, 'pendente', FALSE);

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_create_sla_on_item"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_criar_alerta_retorno"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_retorno_em timestamptz;
BEGIN
  -- recusa_entrada: proprietário se recusou ativamente — sem alerta de retorno
  -- O caso é tratado via notificação formal, não retorno programado
  IF NEW.motivo_sem_acesso = 'recusa_entrada' THEN
    RETURN NEW;
  END IF;

  -- Prazo de retorno: fechado_viagem usa 48h fixos; demais usam horário sugerido
  v_retorno_em := CASE
    WHEN NEW.motivo_sem_acesso = 'fechado_viagem'       THEN now() + interval '48 hours'
    WHEN NEW.proximo_horario_sugerido = 'manha'         THEN date_trunc('day', now()) + interval '1 day' + interval '8 hours'
    WHEN NEW.proximo_horario_sugerido = 'tarde'         THEN date_trunc('day', now()) + interval '1 day' + interval '14 hours'
    WHEN NEW.proximo_horario_sugerido = 'fim_de_semana' THEN date_trunc('week', now()) + interval '5 days' + interval '9 hours'
    ELSE                                                     now() + interval '24 hours'
  END;

  INSERT INTO alerta_retorno_imovel (
    cliente_id, imovel_id, agente_id, vistoria_id, ciclo, motivo, retorno_em, resolvido
  ) VALUES (
    NEW.cliente_id,
    NEW.imovel_id,
    NEW.agente_id,
    NEW.id,
    NEW.ciclo,
    NEW.motivo_sem_acesso,
    v_retorno_em,
    false
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_criar_alerta_retorno"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_criar_foco_de_levantamento_item"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cliente_id    uuid;
  v_imovel_id     uuid;
  v_origem_tipo   text;
  v_is_cidadao    bool;
  v_prioridade_p  text;
  v_lev           record;
BEGIN
  SELECT l.cliente_id, l.tipo_entrada
    INTO v_lev
    FROM levantamentos l
   WHERE l.id = NEW.levantamento_id;

  IF v_lev.cliente_id IS NULL THEN RETURN NEW; END IF;

  v_cliente_id := v_lev.cliente_id;
  v_is_cidadao := COALESCE(NEW.payload->>'fonte', '') = 'cidadao';

  -- Filtro de prioridade/risco: cidadão sempre passa
  IF NOT v_is_cidadao THEN
    IF NEW.prioridade NOT IN ('P1','P2','P3')
       AND lower(COALESCE(NEW.risco,'')) NOT IN ('alto','crítico','critico')
    THEN
      RETURN NEW;
    END IF;
  END IF;

  -- Vincular ao imóvel mais próximo (raio 30m)
  IF NEW.latitude IS NOT NULL AND NEW.longitude IS NOT NULL THEN
    SELECT i.id INTO v_imovel_id
      FROM imoveis i
     WHERE i.cliente_id = v_cliente_id
       AND ST_DWithin(
             ST_MakePoint(NEW.longitude, NEW.latitude)::geography,
             ST_MakePoint(i.longitude,  i.latitude)::geography,
             30
           )
     ORDER BY ST_Distance(
               ST_MakePoint(NEW.longitude, NEW.latitude)::geography,
               ST_MakePoint(i.longitude,  i.latitude)::geography
              )
     LIMIT 1;
  END IF;

  v_origem_tipo := CASE
    WHEN v_is_cidadao                                    THEN 'cidadao'
    WHEN upper(COALESCE(v_lev.tipo_entrada,'')) = 'DRONE' THEN 'drone'
    ELSE 'agente'
  END;

  -- 4A: normalizar prioridade para P1-P5 usando função canônica
  v_prioridade_p := public.fn_prioridade_para_p(NEW.prioridade);

  INSERT INTO focos_risco (
    cliente_id,
    imovel_id,
    origem_tipo,
    origem_levantamento_item_id,
    prioridade,
    latitude,
    longitude,
    endereco_normalizado,
    suspeita_em
  ) VALUES (
    v_cliente_id,
    v_imovel_id,
    v_origem_tipo,
    NEW.id,
    v_prioridade_p,
    NEW.latitude,
    NEW.longitude,
    NEW.endereco_curto,
    NEW.created_at
  )
  ON CONFLICT DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_criar_foco_de_levantamento_item"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_criar_foco_de_levantamento_item"() IS 'Trigger AFTER INSERT em levantamento_itens: cria foco_risco. Fix 3A: origem_tipo=cidadao para payload->fonte=cidadao. Fix 4A: prioridade normalizada para P1-P5 via fn_prioridade_para_p().';



CREATE OR REPLACE FUNCTION "public"."fn_criar_foco_de_vistoria_deposito"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_vis record;
  v_imo record;
BEGIN
  IF NEW.qtd_com_focos IS NULL OR NEW.qtd_com_focos = 0 THEN
    RETURN NEW;
  END IF;

  SELECT v.cliente_id, v.imovel_id, v.ciclo, v.agente_id, v.foco_risco_id
    INTO v_vis
    FROM vistorias v
   WHERE v.id = NEW.vistoria_id;

  -- Se a vistoria já pertence a um foco existente, não duplicar.
  -- O foco original será confirmado pelo fluxo de transição normal.
  IF v_vis.foco_risco_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  IF v_vis.imovel_id IS NOT NULL THEN
    SELECT i.regiao_id, i.latitude, i.longitude,
           i.logradouro || ', ' || coalesce(i.numero,'S/N') AS endereco
      INTO v_imo
      FROM imoveis i
     WHERE i.id = v_vis.imovel_id;
  END IF;

  -- Cria como 'suspeita' — o trigger trg_auto_triagem_foco avança para em_triagem
  INSERT INTO focos_risco (
    cliente_id,
    imovel_id,
    regiao_id,
    origem_tipo,
    origem_vistoria_id,
    status,
    ciclo,
    latitude,
    longitude,
    endereco_normalizado
  ) VALUES (
    v_vis.cliente_id,
    v_vis.imovel_id,
    v_imo.regiao_id,
    'agente',
    NEW.vistoria_id,
    'suspeita',
    v_vis.ciclo,
    v_imo.latitude,
    v_imo.longitude,
    v_imo.endereco
  )
  ON CONFLICT DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_criar_foco_de_vistoria_deposito"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_criar_reinspecao_pos_tratamento"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Só dispara na transição *para* em_tratamento (não re-entrada)
  IF NEW.status = 'em_tratamento'
     AND (OLD.status IS DISTINCT FROM 'em_tratamento')
  THEN
    INSERT INTO reinspecoes_programadas (
      cliente_id,
      foco_risco_id,
      status,
      tipo,
      origem,
      data_prevista,
      responsavel_id,
      criado_por
    )
    VALUES (
      NEW.cliente_id,
      NEW.id,
      'pendente',
      'eficacia_pos_tratamento',
      'automatico',
      now() + interval '7 days',  -- prazo padrão: 7 dias
      NEW.responsavel_id,
      NEW.responsavel_id
    )
    -- Idempotência: se já existir uma pendente, ignora
    ON CONFLICT (foco_risco_id, tipo)
    WHERE (status = 'pendente')
    DO NOTHING;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_criar_reinspecao_pos_tratamento"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_cruzar_caso_com_focos"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  raio_metros CONSTANT int := 300;
BEGIN
  -- Ignorar casos sem coordenadas
  IF NEW.latitude IS NULL OR NEW.longitude IS NULL THEN
    RETURN NEW;
  END IF;

  -- 1. Inserir cruzamentos com focos_risco ATIVOS no raio de 300m
  --    Apenas focos com origem em levantamento_item (para manter a FK NOT NULL)
  INSERT INTO public.caso_foco_cruzamento (caso_id, levantamento_item_id, distancia_metros)
  SELECT
    NEW.id,
    fr.origem_levantamento_item_id,
    ST_Distance(
      ST_MakePoint(NEW.longitude, NEW.latitude)::geography,
      ST_MakePoint(fr.longitude,  fr.latitude)::geography
    )
  FROM public.focos_risco fr
  WHERE
    fr.cliente_id = NEW.cliente_id
    AND fr.latitude  IS NOT NULL
    AND fr.longitude IS NOT NULL
    AND fr.origem_levantamento_item_id IS NOT NULL
    AND fr.status NOT IN ('resolvido', 'descartado')
    AND fr.deleted_at IS NULL
    AND ST_DWithin(
      ST_MakePoint(NEW.longitude, NEW.latitude)::geography,
      ST_MakePoint(fr.longitude,  fr.latitude)::geography,
      raio_metros
    )
  ON CONFLICT (caso_id, levantamento_item_id) DO NOTHING;

  -- 2. Elevar prioridade para P1 em TODOS os focos ativos no raio
  --    (inclui focos sem origem em levantamento_item)
  UPDATE public.focos_risco
  SET
    prioridade_original_antes_caso = COALESCE(prioridade_original_antes_caso, prioridade),
    prioridade = 'P1',
    casos_ids  = CASE
      WHEN NEW.id = ANY(COALESCE(casos_ids, ARRAY[]::uuid[]))
        THEN casos_ids
      ELSE array_append(COALESCE(casos_ids, ARRAY[]::uuid[]), NEW.id)
    END,
    updated_at = now()
  WHERE
    cliente_id = NEW.cliente_id
    AND latitude  IS NOT NULL
    AND longitude IS NOT NULL
    AND status NOT IN ('resolvido', 'descartado')
    AND deleted_at IS NULL
    AND prioridade <> 'P1'   -- não faz downgrade se já for P1
    AND ST_DWithin(
      ST_MakePoint(NEW.longitude, NEW.latitude)::geography,
      ST_MakePoint(longitude,     latitude)::geography,
      raio_metros
    );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_cruzar_caso_com_focos"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_cruzar_caso_com_focos"() IS 'S03: Cruza caso notificado com focos_risco ativos em raio de 300m. Eleva prioridade para P1, registra caso_id no array casos_ids. Melhoria 20260910010000: usa focos_risco diretamente (sem levantamento_itens).';



CREATE OR REPLACE FUNCTION "public"."fn_cruzar_foco_com_casos"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  raio_metros CONSTANT int := 300;
  v_cliente_id uuid;
BEGIN
  IF NEW.latitude IS NULL OR NEW.longitude IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT l.cliente_id INTO v_cliente_id
  FROM levantamentos l
  WHERE l.id = NEW.levantamento_id;

  IF v_cliente_id IS NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO caso_foco_cruzamento (caso_id, levantamento_item_id, distancia_metros)
  SELECT
    cn.id,
    NEW.id,
    ST_Distance(
      ST_MakePoint(cn.longitude,  cn.latitude)::geography,
      ST_MakePoint(NEW.longitude, NEW.latitude)::geography
    )
  FROM casos_notificados cn
  WHERE
    cn.cliente_id = v_cliente_id
    AND cn.status  != 'descartado'
    AND cn.latitude  IS NOT NULL
    AND cn.longitude IS NOT NULL
    AND ST_DWithin(
      ST_MakePoint(cn.longitude, cn.latitude)::geography,
      ST_MakePoint(NEW.longitude, NEW.latitude)::geography,
      raio_metros
    )
  ON CONFLICT (caso_id, levantamento_item_id) DO NOTHING;

  IF EXISTS (
    SELECT 1 FROM caso_foco_cruzamento
    WHERE levantamento_item_id = NEW.id
  ) THEN
    UPDATE levantamento_itens
    SET
      prioridade = 'Crítico',
      payload = jsonb_set(
        COALESCE(payload, '{}'::jsonb),
        '{casos_notificados_proximidade}',
        COALESCE(
          (COALESCE(payload, '{}'::jsonb) -> 'casos_notificados_proximidade'),
          '[]'::jsonb
        ) || (
          SELECT jsonb_agg(to_jsonb(cfc.caso_id::text))
          FROM caso_foco_cruzamento cfc
          WHERE cfc.levantamento_item_id = NEW.id
        )
      )
    WHERE id = NEW.id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_cruzar_foco_com_casos"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_cruzar_foco_com_casos"() IS 'D-03: trigger inverso — ao inserir levantamento_item, busca casos_notificados existentes no raio de 300m e cria cruzamentos retroativos. P0-6: SET search_path adicionado.';



CREATE OR REPLACE FUNCTION "public"."fn_cruzar_foco_novo_com_casos"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  raio_metros CONSTANT int := 300;
  v_casos_ids  uuid[];
BEGIN
  IF NEW.latitude IS NULL OR NEW.longitude IS NULL THEN
    RETURN NEW;
  END IF;

  -- Inserir cruzamentos com casos não descartados no raio
  INSERT INTO caso_foco_cruzamento (caso_id, levantamento_item_id, distancia_metros)
  SELECT
    cn.id,
    NEW.origem_levantamento_item_id,
    ST_Distance(
      geography(ST_SetSRID(ST_MakePoint(NEW.longitude, NEW.latitude), 4326)),
      geography(ST_SetSRID(ST_MakePoint(cn.longitude,  cn.latitude),  4326))
    )
  FROM casos_notificados cn
  WHERE cn.cliente_id = NEW.cliente_id
    AND cn.status    != 'descartado'
    AND cn.latitude  IS NOT NULL
    AND cn.longitude IS NOT NULL
    AND ST_DWithin(
          geography(ST_SetSRID(ST_MakePoint(NEW.longitude, NEW.latitude), 4326)),
          geography(ST_SetSRID(ST_MakePoint(cn.longitude,  cn.latitude),  4326)),
          raio_metros
        )
    AND NEW.origem_levantamento_item_id IS NOT NULL
  ON CONFLICT (caso_id, levantamento_item_id) DO NOTHING;

  -- Coletar IDs dos casos próximos (direto via geo, sem depender do INSERT acima)
  SELECT array_agg(cn.id) INTO v_casos_ids
    FROM casos_notificados cn
   WHERE cn.cliente_id = NEW.cliente_id
     AND cn.status    != 'descartado'
     AND cn.latitude  IS NOT NULL
     AND cn.longitude IS NOT NULL
     AND ST_DWithin(
           geography(ST_SetSRID(ST_MakePoint(NEW.longitude, NEW.latitude), 4326)),
           geography(ST_SetSRID(ST_MakePoint(cn.longitude,  cn.latitude),  4326)),
           raio_metros
         );

  IF v_casos_ids IS NOT NULL AND array_length(v_casos_ids, 1) > 0 THEN
    -- Atualizar casos_ids e elevar prioridade para P1 (preservando original)
    UPDATE focos_risco
       SET casos_ids                     = v_casos_ids,
           prioridade_original_antes_caso = CASE
             WHEN prioridade IS DISTINCT FROM 'P1' THEN prioridade
             ELSE prioridade_original_antes_caso
           END,
           prioridade                    = 'P1'
     WHERE id = NEW.id
       AND prioridade IS DISTINCT FROM 'P1';

    -- Se já era P1, apenas atualiza casos_ids
    UPDATE focos_risco
       SET casos_ids = v_casos_ids
     WHERE id = NEW.id
       AND prioridade = 'P1'
       AND casos_ids IS DISTINCT FROM v_casos_ids;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_cruzar_foco_novo_com_casos"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_dados_minimos_auto_registrar"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_usuario_id uuid;
BEGIN
  -- Guard: se dados_minimos_em já estava preenchido, não faz nada (evita recursão)
  IF NEW.dados_minimos_em IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Verifica se agora tem dados mínimos
  IF NOT fn_foco_tem_dados_minimos(NEW.id) THEN
    RETURN NEW;
  END IF;

  -- Resolve usuário logado
  SELECT id INTO v_usuario_id FROM usuarios WHERE auth_id = auth.uid();

  -- Marca o timestamp
  UPDATE focos_risco
     SET dados_minimos_em = now()
   WHERE id = NEW.id
     AND dados_minimos_em IS NULL;

  -- Registra no histórico (tipo_evento especial — sem mudança de status)
  INSERT INTO foco_risco_historico (
    foco_risco_id, cliente_id, status_anterior, status_novo,
    tipo_evento, motivo, alterado_por
  ) VALUES (
    NEW.id, NEW.cliente_id, NEW.status, NULL,
    'dados_minimos_completos',
    'Foco passou a ter dados mínimos completos',
    v_usuario_id
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_dados_minimos_auto_registrar"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_elevar_prioridade_recorrencia"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_prioridade_atual text;
  v_prioridade_nova  text;
BEGIN
  -- Só age quando foco_anterior_id é preenchido (NULL → valor)
  IF OLD.foco_anterior_id IS NOT NULL OR NEW.foco_anterior_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_prioridade_atual := COALESCE(NEW.prioridade, 'P3');

  -- Eleva um nível (P5→P4, P4→P3, P3→P2, P2→P1, P1→P1)
  v_prioridade_nova := CASE v_prioridade_atual
    WHEN 'P5' THEN 'P4'
    WHEN 'P4' THEN 'P3'
    WHEN 'P3' THEN 'P2'
    WHEN 'P2' THEN 'P1'
    ELSE 'P1'  -- P1 permanece P1
  END;

  -- Só faz UPDATE se realmente subiu (evita trigger loop em P1)
  IF v_prioridade_nova <> v_prioridade_atual THEN
    UPDATE public.focos_risco
    SET
      prioridade = v_prioridade_nova,
      updated_at = now()
    WHERE id = NEW.id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_elevar_prioridade_recorrencia"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_elevar_prioridade_recorrencia"() IS 'F-12: Eleva prioridade do foco 1 nível ao vincular foco_anterior_id (recorrência). P5→P4→P3→P2→P1. Sem downgrade de P1. Registra em foco_risco_historico.';



CREATE OR REPLACE FUNCTION "public"."fn_enfileirar_score_imovel"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_imovel_id  uuid;
  v_cliente_id uuid;
BEGIN
  CASE TG_TABLE_NAME
    WHEN 'focos_risco' THEN
      v_imovel_id  := NEW.imovel_id;
      v_cliente_id := NEW.cliente_id;
    WHEN 'vistorias' THEN
      SELECT im.id, im.cliente_id INTO v_imovel_id, v_cliente_id
      FROM public.imoveis im WHERE im.id = NEW.imovel_id;
    WHEN 'casos_notificados' THEN
      INSERT INTO public.job_queue (tipo, status, payload)
      VALUES (
        'recalcular_score_por_caso',
        'pendente',
        jsonb_build_object(
          'caso_id',    NEW.id,
          'latitude',   NEW.latitude,
          'longitude',  NEW.longitude,
          'cliente_id', NEW.cliente_id,
          'raio_m',     300
        )
      );
      RETURN NEW;
  END CASE;

  IF v_imovel_id IS NULL OR v_cliente_id IS NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.job_queue (tipo, status, payload)
  VALUES (
    'recalcular_score_imovel',
    'pendente',
    jsonb_build_object('imovel_id', v_imovel_id, 'cliente_id', v_cliente_id)
  )
  ON CONFLICT DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_enfileirar_score_imovel"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_enqueue_job"("p_tipo" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id          uuid;
  v_cliente_id  uuid;
  -- Jobs que operam em um cliente específico (verificam tenant)
  TIPOS_CLIENTE CONSTANT text[] := ARRAY['triagem_ia', 'relatorio_semanal', 'cnes_sync'];
  -- Jobs de plataforma que requerem papel admin
  TIPOS_ADMIN   CONSTANT text[] := ARRAY['limpeza_retencao', 'cloudinary_cleanup', 'health_check'];
BEGIN
  -- 1. Validação de tipo permitido
  IF p_tipo NOT IN (
    'triagem_ia', 'relatorio_semanal', 'cnes_sync',
    'limpeza_retencao', 'cloudinary_cleanup', 'health_check'
  ) THEN
    RAISE EXCEPTION 'Tipo de job inválido: %', p_tipo;
  END IF;

  -- 2. Jobs de plataforma: requerem papel admin
  IF p_tipo = ANY(TIPOS_ADMIN) THEN
    IF NOT public.is_admin() THEN
      RAISE EXCEPTION
        'fn_enqueue_job: job do tipo "%" requer papel admin', p_tipo;
    END IF;

  -- 3. Jobs de cliente: verificar que cliente_id pertence ao caller
  ELSIF p_tipo = ANY(TIPOS_CLIENTE) THEN
    v_cliente_id := (p_payload->>'cliente_id')::uuid;

    IF v_cliente_id IS NULL THEN
      RAISE EXCEPTION
        'fn_enqueue_job: cliente_id obrigatório no payload para jobs do tipo "%"', p_tipo;
    END IF;

    IF NOT public.usuario_pode_acessar_cliente(v_cliente_id) THEN
      RAISE EXCEPTION
        'fn_enqueue_job: acesso negado — cliente_id não pertence ao usuário autenticado';
    END IF;
  END IF;

  -- 4. Inserir job
  INSERT INTO public.job_queue (tipo, payload)
  VALUES (p_tipo, p_payload)
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_enqueue_job"("p_tipo" "text", "p_payload" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_enqueue_job"("p_tipo" "text", "p_payload" "jsonb") IS 'Enfileira um job de forma segura. Jobs de cliente: valida tenant. Jobs de plataforma: requer papel admin. (QW-13 + Fix S-08)';



CREATE OR REPLACE FUNCTION "public"."fn_escalar_sla_vencido"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  r RECORD;
  v_nova_prioridade TEXT;
  v_supervisor_id UUID;
  v_novo_sla_horas INT;
  v_prioridade_map JSONB := '{
    "Monitoramento": "Baixa",
    "Baixa": "Média",
    "Média": "Moderada",
    "Moderada": "Alta",
    "Alta": "Urgente",
    "Urgente": "Crítica",
    "Crítica": "Crítica"
  }';
  v_horas_map JSONB := '{
    "Crítica": 4, "Urgente": 4, "Alta": 12,
    "Moderada": 24, "Média": 24, "Baixa": 72, "Monitoramento": 72
  }';
BEGIN
  FOR r IN
    SELECT so.*, poi.run_id,
           por.cliente_id
      FROM sla_operacional so
      JOIN pluvio_operacional_item poi ON poi.id = so.item_id
      JOIN pluvio_operacional_run por ON por.id = poi.run_id
     WHERE so.status = 'vencido'
       AND so.escalonado = FALSE
  LOOP
    -- Determinar nova prioridade (subir 1 nível)
    v_nova_prioridade := COALESCE(
      v_prioridade_map ->> r.prioridade,
      'Crítica'
    );
    
    v_novo_sla_horas := COALESCE(
      (v_horas_map ->> v_nova_prioridade)::INT,
      4
    );

    -- Buscar supervisor do cliente
    v_supervisor_id := NULL;
    SELECT u.id INTO v_supervisor_id
      FROM usuarios u
      JOIN papeis_usuarios pu ON pu.user_id = u.auth_id
     WHERE u.cliente_id = r.cliente_id
       AND pu.papel = 'supervisor'
     LIMIT 1;

    -- Atualizar SLA: elevar prioridade, reatribuir, novo prazo
    UPDATE sla_operacional SET
      escalonado = TRUE,
      escalonado_em = NOW(),
      prioridade_original = COALESCE(prioridade_original, r.prioridade),
      prioridade = v_nova_prioridade,
      sla_horas = v_novo_sla_horas,
      status = 'pendente',
      violado = TRUE,
      operador_id = COALESCE(v_supervisor_id, r.operador_id),
      prazo_final = NOW() + (v_novo_sla_horas || ' hours')::INTERVAL
    WHERE id = r.id;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."fn_escalar_sla_vencido"() OWNER TO "postgres";


