CREATE OR REPLACE FUNCTION "public"."fn_guard_focos_responsavel_update"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.responsavel_id IS DISTINCT FROM OLD.responsavel_id THEN
    IF NOT (public.is_supervisor() OR public.is_admin()) THEN
      RAISE EXCEPTION
        'Apenas supervisores podem redistribuir focos. Use rpc_atribuir_agente_foco.'
        USING ERRCODE = 'P0001';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_guard_focos_responsavel_update"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_guard_focos_responsavel_update"() IS 'Guard de trigger: bloqueia alteração direta de responsavel_id por não-supervisores. Corrige vetor de ataque onde agente chamava api.focos.update({responsavel_id}) sem passar pelo rpc_atribuir_agente_foco.';



CREATE OR REPLACE FUNCTION "public"."fn_iniciar_inspecao_foco"("p_foco_id" "uuid", "p_observacao" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_foco       focos_risco%ROWTYPE;
  v_usuario_id uuid;
  v_papel      text;
  v_ativo      boolean;
BEGIN
  -- Obter papel e status ativo do chamador via papeis_usuarios (canônico)
  SELECT u.id, pu.papel, u.ativo
    INTO v_usuario_id, v_papel, v_ativo
    FROM usuarios u
    LEFT JOIN papeis_usuarios pu ON pu.usuario_id = u.auth_id
   WHERE u.auth_id = auth.uid();

  IF v_usuario_id IS NULL THEN
    RAISE EXCEPTION 'Usuário não autenticado' USING ERRCODE = 'P0001';
  END IF;

  -- NULL guard: usuário sem papel em papeis_usuarios
  IF v_papel IS NULL THEN
    RAISE EXCEPTION 'Usuário sem papel definido — acesso negado' USING ERRCODE = 'P0001';
  END IF;

  -- Usuário inativo (JWT pode ficar válido por até 1h após desativação)
  IF NOT COALESCE(v_ativo, false) THEN
    RAISE EXCEPTION 'Usuário inativo — acesso negado' USING ERRCODE = 'P0001';
  END IF;

  -- SOMENTE agente executa campo
  IF v_papel != 'agente' THEN
    RAISE EXCEPTION 'Apenas agentes podem iniciar inspeções. Papel atual: %', v_papel
      USING ERRCODE = 'P0001';
  END IF;

  -- Buscar o foco
  SELECT * INTO v_foco FROM focos_risco WHERE id = p_foco_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Foco não encontrado' USING ERRCODE = 'P0002';
  END IF;

  -- Verificar tenant
  IF NOT usuario_pode_acessar_cliente(v_foco.cliente_id) THEN
    RAISE EXCEPTION 'Sem permissão para acessar este foco' USING ERRCODE = 'P0003';
  END IF;

  -- Idempotente: já está em inspeção
  IF v_foco.status = 'em_inspecao' THEN
    RETURN jsonb_build_object('ok', true, 'ja_em_inspecao', true, 'foco_id', p_foco_id);
  END IF;

  -- Só aguarda_inspecao pode iniciar inspeção
  IF v_foco.status != 'aguarda_inspecao' THEN
    RAISE EXCEPTION 'Foco não pode iniciar inspeção no estado atual: %', v_foco.status
      USING ERRCODE = 'P0001';
  END IF;

  -- Transicionar
  UPDATE focos_risco
  SET
    status         = 'em_inspecao',
    responsavel_id = COALESCE(responsavel_id, v_usuario_id),
    inspecao_em    = COALESCE(inspecao_em, now()),
    observacao     = COALESCE(NULLIF(p_observacao, ''), observacao),
    updated_at     = now()
  WHERE id = p_foco_id;

  RETURN jsonb_build_object('ok', true, 'ja_em_inspecao', false, 'foco_id', p_foco_id);
END;
$$;


ALTER FUNCTION "public"."fn_iniciar_inspecao_foco"("p_foco_id" "uuid", "p_observacao" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_iniciar_inspecao_foco"("p_foco_id" "uuid", "p_observacao" "text") IS 'Inicia inspeção de um foco. EXCLUSIVO para agentes ativos. Guards: papel NULL, ativo=false, papel != agente, estado != aguarda_inspecao.';



CREATE OR REPLACE FUNCTION "public"."fn_iniciar_sla_ao_confirmar_foco"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sla_existente_id  uuid;
  v_config            jsonb;
  v_prioridade        text;
  v_sla_horas         float8;
  v_prazo_final       timestamptz;
BEGIN
  -- 1. Se já existe SLA vinculado ao foco, não faz nada
  SELECT id INTO v_sla_existente_id
    FROM sla_operacional
   WHERE foco_risco_id = NEW.id
   LIMIT 1;

  IF v_sla_existente_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- 2. Se existe SLA vinculado ao levantamento_item de origem, apenas vincula
  IF NEW.origem_levantamento_item_id IS NOT NULL THEN
    UPDATE sla_operacional
       SET foco_risco_id = NEW.id
     WHERE levantamento_item_id = NEW.origem_levantamento_item_id
       AND foco_risco_id IS NULL;

    IF FOUND THEN
      RETURN NEW;
    END IF;
  END IF;

  -- 3. Cria SLA usando a config do cliente/região via sla_resolve_config()
  v_prioridade := COALESCE(NEW.prioridade, 'P3');
  v_config     := sla_resolve_config(NEW.cliente_id, NEW.regiao_id);

  v_sla_horas := CASE v_prioridade
    WHEN 'P1' THEN COALESCE((v_config->>'p1_horas')::float8, 4)
    WHEN 'P2' THEN COALESCE((v_config->>'p2_horas')::float8, 12)
    WHEN 'P3' THEN COALESCE((v_config->>'p3_horas')::float8, 24)
    WHEN 'P4' THEN COALESCE((v_config->>'p4_horas')::float8, 72)
    WHEN 'P5' THEN COALESCE((v_config->>'p5_horas')::float8, 168)
    ELSE 24
  END;

  v_prazo_final := COALESCE(NEW.confirmado_em, now()) + (v_sla_horas || ' hours')::interval;

  INSERT INTO sla_operacional (
    cliente_id,
    levantamento_item_id,
    foco_risco_id,
    prioridade,
    status,
    inicio,
    prazo_final,
    sla_horas
  ) VALUES (
    NEW.cliente_id,
    NEW.origem_levantamento_item_id,
    NEW.id,
    v_prioridade,
    'pendente',                        -- corrigido: era 'aberto'
    COALESCE(NEW.confirmado_em, now()),
    v_prazo_final,
    v_sla_horas
  )
  ON CONFLICT DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_iniciar_sla_ao_confirmar_foco"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_insert_audit_log"("p_cliente_id" "uuid", "p_acao" "text", "p_tabela" "text", "p_registro_id" "uuid", "p_descricao" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_usuario_id uuid;
  v_auth_uid   uuid;
BEGIN
  v_auth_uid   := auth.uid();  -- null em contexto service_role; aceito
  SELECT id INTO v_usuario_id FROM public.usuarios WHERE auth_id = v_auth_uid LIMIT 1;

  INSERT INTO public.audit_log(
    cliente_id, usuario_id, auth_uid,
    acao, tabela, registro_id,
    descricao, payload
  ) VALUES (
    p_cliente_id, v_usuario_id, v_auth_uid,
    p_acao, p_tabela, p_registro_id,
    p_descricao, COALESCE(p_payload, '{}')
  );
EXCEPTION WHEN OTHERS THEN
  -- Auditoria nunca deve bloquear a operação principal
  NULL;
END;
$$;


ALTER FUNCTION "public"."fn_insert_audit_log"("p_cliente_id" "uuid", "p_acao" "text", "p_tabela" "text", "p_registro_id" "uuid", "p_descricao" "text", "p_payload" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_insert_audit_log"("p_cliente_id" "uuid", "p_acao" "text", "p_tabela" "text", "p_registro_id" "uuid", "p_descricao" "text", "p_payload" "jsonb") IS 'P1-3: Helper interno para triggers de auditoria. Não tem verificação de tenant (triggers são confiáveis). Fail-safe: EXCEPTION é silenciado para não bloquear operações.';



