COMMENT ON COLUMN "public"."levantamentos"."id_drone" IS 'Drone utilizado no voo (cadastro em drones).';



COMMENT ON COLUMN "public"."levantamentos"."tipo_entrada" IS 'Origem do levantamento: DRONE ou MANUAL (avulso). Pode ser usado como TEXT ou via cast do enum tipo_entrada_levantamento.';



COMMENT ON COLUMN "public"."levantamentos"."status_processamento" IS 'Estado do pipeline Python: aguardando | processando | concluido | erro';



COMMENT ON COLUMN "public"."levantamentos"."config_fonte" IS 'Fonte da configuração usada no processamento do pipeline drone. ''supabase'' = configuração veio do banco (ideal). ''local_json'' (ou variantes com sufixo) = fallback para JSON local, indicando que a config do cliente no Supabase estava ausente ou inacessível.';



COMMENT ON COLUMN "public"."levantamentos"."deleted_at" IS 'Soft delete (complemento QW-10D).';



COMMENT ON COLUMN "public"."levantamentos"."deleted_by" IS 'Usuário que realizou o soft delete.';



CREATE TABLE IF NOT EXISTS "public"."usuarios" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "auth_id" "uuid",
    "nome" "text" NOT NULL,
    "email" "text" NOT NULL,
    "cliente_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "ativo" boolean DEFAULT true NOT NULL,
    "onboarding_concluido" boolean DEFAULT false NOT NULL,
    "onboarding_versao" "text",
    "onboarding_concluido_em" timestamp with time zone,
    "agrupamento_id" "uuid",
    CONSTRAINT "chk_usuarios_cliente_agrupamento_exclusivo" CHECK ((NOT (("cliente_id" IS NOT NULL) AND ("agrupamento_id" IS NOT NULL))))
);


ALTER TABLE "public"."usuarios" OWNER TO "postgres";


COMMENT ON TABLE "public"."usuarios" IS 'Usuários do app; auth_id = auth.users.id';



COMMENT ON COLUMN "public"."usuarios"."ativo" IS 'A08: Flag de usuário ativo. Usuários desativados não devem fazer login. Usar em vez de DELETE para preservar histórico de auditorias.';



COMMENT ON COLUMN "public"."usuarios"."onboarding_concluido" IS 'true quando o usuário completou ou dispensou o tour de onboarding';



COMMENT ON COLUMN "public"."usuarios"."onboarding_versao" IS 'versão do tour concluído — se diferente da versão atual, exibe novamente';



COMMENT ON COLUMN "public"."usuarios"."onboarding_concluido_em" IS 'timestamp da conclusão do onboarding';



COMMENT ON COLUMN "public"."usuarios"."agrupamento_id" IS 'Preenchido apenas para papel=analista_regional. Mutuamente exclusivo com cliente_id (CHECK constraint).';



CREATE TABLE IF NOT EXISTS "public"."vistorias" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "cliente_id" "uuid" NOT NULL,
    "imovel_id" "uuid",
    "agente_id" "uuid" NOT NULL,
    "planejamento_id" "uuid",
    "ciclo" integer DEFAULT 1 NOT NULL,
    "tipo_atividade" "text" DEFAULT 'pesquisa'::"text" NOT NULL,
    "data_visita" timestamp with time zone DEFAULT "now"() NOT NULL,
    "status" "text" DEFAULT 'pendente'::"text" NOT NULL,
    "moradores_qtd" integer,
    "gravidas" boolean DEFAULT false NOT NULL,
    "idosos" boolean DEFAULT false NOT NULL,
    "criancas_7anos" boolean DEFAULT false NOT NULL,
    "lat_chegada" double precision,
    "lng_chegada" double precision,
    "checkin_em" timestamp with time zone,
    "observacao" "text",
    "payload" "jsonb",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "acesso_realizado" boolean DEFAULT true NOT NULL,
    "motivo_sem_acesso" "text",
    "proximo_horario_sugerido" "text",
    "observacao_acesso" "text",
    "foto_externa_url" "text",
    "origem_visita" "text",
    "habitat_selecionado" "text",
    "condicao_habitat" "text",
    "assinatura_responsavel_url" "text",
    "pendente_assinatura" boolean DEFAULT false NOT NULL,
    "pendente_foto" boolean DEFAULT false NOT NULL,
    "origem_offline" boolean DEFAULT false NOT NULL,
    "assinatura_public_id" "text",
    "foto_externa_public_id" "text",
    "idempotency_key" "uuid",
    "deleted_at" timestamp with time zone,
    "deleted_by" "uuid",
    "created_by" "uuid",
    "foco_risco_id" "uuid",
    "resultado_operacional" "text",
    "vulnerabilidade_domiciliar" "text",
    "alerta_saude" "text",
    "risco_socioambiental" "text",
    "risco_vetorial" "text",
    "prioridade_final" "text",
    "prioridade_motivo" "text",
    "dimensao_dominante" "text",
    "consolidacao_resumo" "text",
    "consolidacao_json" "jsonb",
    "consolidacao_incompleta" boolean DEFAULT false NOT NULL,
    "versao_regra_consolidacao" "text",
    "versao_pesos_consolidacao" "text",
    "consolidado_em" timestamp with time zone,
    "reprocessado_em" timestamp with time zone,
    "reprocessado_por" "uuid",
    CONSTRAINT "chk_ciclo_range" CHECK ((("ciclo" >= 1) AND ("ciclo" <= 6))),
    CONSTRAINT "vistorias_alerta_saude_check" CHECK (("alerta_saude" = ANY (ARRAY['nenhum'::"text", 'atencao'::"text", 'urgente'::"text", 'inconclusivo'::"text"]))),
    CONSTRAINT "vistorias_ciclo_check" CHECK ((("ciclo" >= 1) AND ("ciclo" <= 6))),
    CONSTRAINT "vistorias_condicao_habitat_check" CHECK (("condicao_habitat" = ANY (ARRAY['seco'::"text", 'agua_parada'::"text", 'inundado'::"text"]))),
    CONSTRAINT "vistorias_motivo_sem_acesso_check" CHECK (("motivo_sem_acesso" = ANY (ARRAY['fechado_ausente'::"text", 'fechado_viagem'::"text", 'recusa_entrada'::"text", 'cachorro_bravo'::"text", 'calha_inacessivel'::"text", 'outro'::"text"]))),
    CONSTRAINT "vistorias_origem_visita_check" CHECK (("origem_visita" = ANY (ARRAY['denuncia'::"text", 'liraa'::"text", 'drone'::"text"]))),
    CONSTRAINT "vistorias_prioridade_final_check" CHECK (("prioridade_final" = ANY (ARRAY['P1'::"text", 'P2'::"text", 'P3'::"text", 'P4'::"text", 'P5'::"text"]))),
    CONSTRAINT "vistorias_proximo_horario_sugerido_check" CHECK (("proximo_horario_sugerido" = ANY (ARRAY['manha'::"text", 'tarde'::"text", 'fim_de_semana'::"text", 'sem_previsao'::"text"]))),
    CONSTRAINT "vistorias_resultado_operacional_check" CHECK (("resultado_operacional" = ANY (ARRAY['visitado'::"text", 'sem_acesso'::"text", 'sem_acesso_retorno'::"text"]))),
    CONSTRAINT "vistorias_risco_socioambiental_check" CHECK (("risco_socioambiental" = ANY (ARRAY['baixo'::"text", 'medio'::"text", 'alto'::"text", 'inconclusivo'::"text"]))),
    CONSTRAINT "vistorias_risco_vetorial_check" CHECK (("risco_vetorial" = ANY (ARRAY['baixo'::"text", 'medio'::"text", 'alto'::"text", 'critico'::"text", 'inconclusivo'::"text"]))),
    CONSTRAINT "vistorias_status_check" CHECK (("status" = ANY (ARRAY['pendente'::"text", 'visitado'::"text", 'fechado'::"text", 'revisita'::"text"]))),
    CONSTRAINT "vistorias_tipo_atividade_check" CHECK (("tipo_atividade" = ANY (ARRAY['tratamento'::"text", 'pesquisa'::"text", 'liraa'::"text", 'ponto_estrategico'::"text"]))),
    CONSTRAINT "vistorias_vulnerabilidade_domiciliar_check" CHECK (("vulnerabilidade_domiciliar" = ANY (ARRAY['baixa'::"text", 'media'::"text", 'alta'::"text", 'critica'::"text", 'inconclusivo'::"text"])))
);


ALTER TABLE "public"."vistorias" OWNER TO "postgres";


COMMENT ON COLUMN "public"."vistorias"."origem_visita" IS 'Origem da visita registrada na etapa pré-vistoria: denuncia, liraa, drone';



COMMENT ON COLUMN "public"."vistorias"."assinatura_responsavel_url" IS 'URL da assinatura digital do responsável coletada no campo e armazenada no Cloudinary via Edge Function upload-evidencia.';



COMMENT ON COLUMN "public"."vistorias"."origem_offline" IS 'true quando a vistoria foi criada offline e sincronizada posteriormente. (QW-07)';



COMMENT ON COLUMN "public"."vistorias"."assinatura_public_id" IS 'Cloudinary public_id da assinatura digital do responsável. (QW-10B)';



COMMENT ON COLUMN "public"."vistorias"."foto_externa_public_id" IS 'Cloudinary public_id da foto externa (fluxo sem acesso). (QW-10B)';



COMMENT ON COLUMN "public"."vistorias"."prioridade_final" IS 'P1–P5. Nunca nula após consolidação. Fallback P3 quando há dado/histórico; P4 quando completamente vazio. Gerada por fn_consolidar_vistoria() (Fase 2).';



COMMENT ON COLUMN "public"."vistorias"."consolidacao_json" IS 'Snapshot completo da consolidação: dimensões, regras acionadas, versões. Estrutura documentada na especificação V2, seção 7.2.';



COMMENT ON COLUMN "public"."vistorias"."consolidacao_incompleta" IS 'true quando uma ou mais dimensões ficaram inconclusivas. Indica baixa confiança na prioridade_final gerada por fallback.';



