COMMENT ON COLUMN "public"."voos"."piloto_id" IS 'Usuário que executou o voo (piloto / operador responsável). Preenchido pelo pipeline Python via supabase_auth.get_current_usuario().';



CREATE OR REPLACE VIEW "public"."v_cliente_uso_mensal" WITH ("security_invoker"='on') AS
 SELECT "c"."id" AS "cliente_id",
    "c"."nome" AS "cliente_nome",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."voos"
          WHERE (("cq"."cliente_id" = "c"."id") AND ("voos"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) AS "voos_mes_usado",
    "cq"."voos_mes" AS "voos_mes_limite",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."levantamentos"
          WHERE (("levantamentos"."cliente_id" = "c"."id") AND ("levantamentos"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) AS "levantamentos_mes_usado",
    "cq"."levantamentos_mes" AS "levantamentos_mes_limite",
    ( SELECT ("count"(*))::integer AS "count"
           FROM ("public"."levantamento_itens" "li"
             JOIN "public"."levantamentos" "lev" ON (("lev"."id" = "li"."levantamento_id")))
          WHERE (("lev"."cliente_id" = "c"."id") AND ("li"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) AS "itens_mes_usado",
    "cq"."itens_mes" AS "itens_mes_limite",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."usuarios"
          WHERE (("usuarios"."cliente_id" = "c"."id") AND ("c"."ativo" = true))) AS "usuarios_ativos_usado",
    "cq"."usuarios_ativos" AS "usuarios_ativos_limite",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."vistorias"
          WHERE (("vistorias"."cliente_id" = "c"."id") AND ("vistorias"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) AS "vistorias_mes_usado",
    "cq"."vistorias_mes" AS "vistorias_mes_limite",
    ( SELECT ("count"(*))::integer AS "count"
           FROM ("public"."levantamento_analise_ia" "ia"
             JOIN "public"."levantamentos" "lev" ON (("lev"."id" = "ia"."levantamento_id")))
          WHERE (("lev"."cliente_id" = "c"."id") AND ("ia"."status" = 'sucesso'::"text") AND ("ia"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) AS "ia_calls_mes_usado",
    "cq"."ia_calls_mes" AS "ia_calls_mes_limite",
    COALESCE(( SELECT "billing_usage_snapshot"."storage_gb"
           FROM "public"."billing_usage_snapshot"
          WHERE ("billing_usage_snapshot"."cliente_id" = "c"."id")
          ORDER BY "billing_usage_snapshot"."periodo_inicio" DESC
         LIMIT 1), (0)::numeric) AS "storage_gb_usado",
    "cq"."storage_gb" AS "storage_gb_limite",
    (("cq"."voos_mes" IS NOT NULL) AND (( SELECT "count"(*) AS "count"
           FROM "public"."voos"
          WHERE (("cq"."cliente_id" = "c"."id") AND ("voos"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) > "cq"."voos_mes")) AS "voos_excedido",
    (("cq"."levantamentos_mes" IS NOT NULL) AND (( SELECT "count"(*) AS "count"
           FROM "public"."levantamentos"
          WHERE (("levantamentos"."cliente_id" = "c"."id") AND ("levantamentos"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) > "cq"."levantamentos_mes")) AS "levantamentos_excedido",
    (("cq"."itens_mes" IS NOT NULL) AND (( SELECT "count"(*) AS "count"
           FROM ("public"."levantamento_itens" "li"
             JOIN "public"."levantamentos" "lev" ON (("lev"."id" = "li"."levantamento_id")))
          WHERE (("lev"."cliente_id" = "c"."id") AND ("li"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) > "cq"."itens_mes")) AS "itens_excedido",
    (("cq"."usuarios_ativos" IS NOT NULL) AND (( SELECT "count"(*) AS "count"
           FROM "public"."usuarios"
          WHERE (("usuarios"."cliente_id" = "c"."id") AND ("c"."ativo" = true))) > "cq"."usuarios_ativos")) AS "usuarios_excedido",
    (("cq"."vistorias_mes" IS NOT NULL) AND (( SELECT "count"(*) AS "count"
           FROM "public"."vistorias"
          WHERE (("vistorias"."cliente_id" = "c"."id") AND ("vistorias"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) > "cq"."vistorias_mes")) AS "vistorias_excedido",
    (("cq"."ia_calls_mes" IS NOT NULL) AND (( SELECT "count"(*) AS "count"
           FROM ("public"."levantamento_analise_ia" "ia"
             JOIN "public"."levantamentos" "lev" ON (("lev"."id" = "ia"."levantamento_id")))
          WHERE (("lev"."cliente_id" = "c"."id") AND ("ia"."status" = 'sucesso'::"text") AND ("ia"."created_at" >= "date_trunc"('month'::"text", ("now"() AT TIME ZONE 'America/Sao_Paulo'::"text"))))) > "cq"."ia_calls_mes")) AS "ia_calls_excedido"
   FROM ("public"."clientes" "c"
     LEFT JOIN "public"."cliente_quotas" "cq" ON (("cq"."cliente_id" = "c"."id")))
  WHERE ("c"."deleted_at" IS NULL);


ALTER VIEW "public"."v_cliente_uso_mensal" OWNER TO "postgres";


CREATE MATERIALIZED VIEW "public"."mv_cliente_uso_mensal" AS
 SELECT "cliente_id",
    "cliente_nome",
    "voos_mes_usado",
    "voos_mes_limite",
    "levantamentos_mes_usado",
    "levantamentos_mes_limite",
    "itens_mes_usado",
    "itens_mes_limite",
    "usuarios_ativos_usado",
    "usuarios_ativos_limite",
    "vistorias_mes_usado",
    "vistorias_mes_limite",
    "ia_calls_mes_usado",
    "ia_calls_mes_limite",
    "storage_gb_usado",
    "storage_gb_limite",
    "voos_excedido",
    "levantamentos_excedido",
    "itens_excedido",
    "usuarios_excedido",
    "vistorias_excedido",
    "ia_calls_excedido"
   FROM "public"."v_cliente_uso_mensal"
  WITH NO DATA;


ALTER MATERIALIZED VIEW "public"."mv_cliente_uso_mensal" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_meu_uso_mensal"() RETURNS SETOF "public"."mv_cliente_uso_mensal"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cliente_id uuid;
BEGIN
  SELECT u.cliente_id INTO v_cliente_id
  FROM usuarios u
  WHERE u.auth_id = auth.uid()
  LIMIT 1;

  IF v_cliente_id IS NULL THEN
    RETURN; -- usuário sem cliente: não retorna nada
  END IF;

  RETURN QUERY
  SELECT * FROM mv_cliente_uso_mensal
  WHERE cliente_id = v_cliente_id;
END;
$$;


ALTER FUNCTION "public"."fn_meu_uso_mensal"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_meu_uso_mensal"() IS 'Retorna uso mensal apenas do cliente do usuário autenticado. Substitui acesso direto a mv_cliente_uso_mensal (sem filtro = vazamento). Usado por QuotaBanner e AdminQuotas (visão do próprio cliente). (Fix S-01)';



CREATE OR REPLACE FUNCTION "public"."fn_normalizar_ciclo_foco_risco"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_ciclo_ativo int;
BEGIN
  -- Só age quando ciclo não foi explicitamente informado
  IF NEW.ciclo IS NOT NULL AND NEW.ciclo BETWEEN 1 AND 6 THEN
    RETURN NEW;
  END IF;

  v_ciclo_ativo := public.fn_ciclo_ativo_numero(NEW.cliente_id);

  IF v_ciclo_ativo IS NOT NULL THEN
    NEW.ciclo := v_ciclo_ativo;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_normalizar_ciclo_foco_risco"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_normalizar_ciclo_foco_risco"() IS 'CI-05: Auto-preenche focos_risco.ciclo com o ciclo ativo do cliente quando NULL ou inválido. Não bloqueia — focos são criados por triggers do sistema.';



CREATE OR REPLACE FUNCTION "public"."fn_normalize_quarteirao"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.quarteirao IS NOT NULL THEN
    NEW.quarteirao = TRIM(NEW.quarteirao);
    IF NEW.quarteirao = '' THEN
      NEW.quarteirao = NULL;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_normalize_quarteirao"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_notificar_foco_cidadao"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.origem_tipo <> 'cidadao' THEN
    RETURN NEW;
  END IF;

  INSERT INTO job_queue (
    tipo, status, payload
  ) VALUES (
    'notif_canal_cidadao',
    'pendente',
    jsonb_build_object(
      'foco_id',        NEW.id,
      'cliente_id',     NEW.cliente_id,
      'latitude',       NEW.latitude,
      'longitude',      NEW.longitude,
      'endereco',       NEW.endereco_normalizado,
      'suspeita_em',    NEW.suspeita_em,
      'origem_item_id', NEW.origem_levantamento_item_id
    )
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_notificar_foco_cidadao"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_notificar_foco_cidadao"() IS 'Enfileira job de Web Push ao criar foco com origem_tipo=cidadao. Processado pela Edge Function notif-canal-cidadao.';



CREATE OR REPLACE FUNCTION "public"."fn_orfaos_levantamento_item"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_cliente_id uuid;
BEGIN
  -- Dispara apenas quando deleted_at muda de NULL para não-NULL
  IF OLD.deleted_at IS NULL AND NEW.deleted_at IS NOT NULL THEN

    -- Resolve cliente_id via levantamento
    SELECT l.cliente_id INTO v_cliente_id
    FROM public.levantamentos l
    WHERE l.id = NEW.levantamento_id
    LIMIT 1;

    -- Imagem principal
    IF NEW.image_public_id IS NOT NULL THEN
      INSERT INTO public.cloudinary_orfaos
        (public_id, url, origem_tabela, origem_id, cliente_id, motivo)
      VALUES
        (NEW.image_public_id, NEW.image_url, 'levantamento_itens', NEW.id, v_cliente_id, 'soft_delete');
    END IF;

    -- Evidências vinculadas ao item
    INSERT INTO public.cloudinary_orfaos
      (public_id, url, origem_tabela, origem_id, cliente_id, motivo)
    SELECT
      lie.public_id,
      lie.image_url,
      'levantamento_item_evidencias',
      lie.id,
      v_cliente_id,
      'soft_delete_cascade'
    FROM public.levantamento_item_evidencias lie
    WHERE lie.levantamento_item_id = NEW.id
      AND lie.public_id IS NOT NULL;

  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_orfaos_levantamento_item"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_orfaos_levantamento_item"() IS 'Popula cloudinary_orfaos quando levantamento_itens é soft-deleted. Inclui imagem principal (image_public_id) e evidências vinculadas. (QW-10B)';



CREATE OR REPLACE FUNCTION "public"."fn_orfaos_vistoria"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Assinatura
  IF OLD.assinatura_public_id IS NOT NULL THEN
    INSERT INTO public.cloudinary_orfaos
      (public_id, url, origem_tabela, origem_id, cliente_id, motivo)
    VALUES
      (OLD.assinatura_public_id, OLD.assinatura_responsavel_url,
       'vistorias', OLD.id, OLD.cliente_id, 'delete_fisico');
  END IF;

  -- Foto externa (sem acesso)
  IF OLD.foto_externa_public_id IS NOT NULL THEN
    INSERT INTO public.cloudinary_orfaos
      (public_id, url, origem_tabela, origem_id, cliente_id, motivo)
    VALUES
      (OLD.foto_externa_public_id, OLD.foto_externa_url,
       'vistorias', OLD.id, OLD.cliente_id, 'delete_fisico');
  END IF;

  -- Fotos de calhas vinculadas
  INSERT INTO public.cloudinary_orfaos
    (public_id, url, origem_tabela, origem_id, cliente_id, motivo)
  SELECT
    vc.foto_public_id,
    vc.foto_url,
    'vistoria_calhas',
    vc.id,
    OLD.cliente_id,
    'delete_fisico_cascade'
  FROM public.vistoria_calhas vc
  WHERE vc.vistoria_id = OLD.id
    AND vc.foto_public_id IS NOT NULL;

  RETURN OLD;
END;
$$;


