CREATE OR REPLACE FUNCTION "public"."fn_p_para_prioridade"("p_p" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE PARALLEL SAFE
    SET "search_path" TO 'public'
    AS $$
  SELECT CASE upper(trim(COALESCE(p_p, '')))
    WHEN 'P1' THEN 'Crítico'
    WHEN 'P2' THEN 'Alta'
    WHEN 'P3' THEN 'Média'
    WHEN 'P4' THEN 'Baixa'
    WHEN 'P5' THEN 'Monitoramento'
    ELSE 'Média'
  END;
$$;


