COMMENT ON FUNCTION "public"."fn_p_para_prioridade"("p_p" "text") IS 'Converte notação P1-P5 (focos_risco) para rótulo legado em português. Útil para exibição em relatórios e compatibilidade com levantamento_itens.';



CREATE OR REPLACE FUNCTION "public"."fn_pluvio_risco_daily"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_dt_ref       date := current_date - 1;
  v_cliente      record;
  v_regiao       record;
  v_policy_id    uuid;
  v_past_days    int;
  v_threshold    numeric;
  v_tend_dias    int;
  v_start_date   date;
  v_end_date     date;
  v_url          text;
  v_response     http_response;
  v_daily        jsonb;
  v_len          int;
  v_dt_ref_idx   int;
  v_i            int;
  -- metrics
  v_chuva_24h    numeric;
  v_chuva_72h    numeric;
  v_chuva_7d     numeric;
  v_dias_pos     int;
  v_persist      int;
  v_tendencia    text;
  v_temp_c       numeric;
  v_vento_kmh    numeric;
  -- forecast
  v_prev_d1      numeric;
  v_prev_d2      numeric;
  v_prev_d3      numeric;
  -- classification
  v_rule         record;
  v_matched      boolean;
  v_situacao     text;
  v_prob_label   text;
  v_prob_min     numeric;
  v_prob_max     numeric;
  v_delta_pp     numeric;
  v_tmp_delta    numeric;
  v_final_min    numeric;
  v_final_max    numeric;
  v_avg_final    numeric;
  v_classif      text;
  v_janela       text;
  -- tendencia calc
  v_slice_start  int;
  v_slice_len    int;
  v_mid          int;
  v_avg1         numeric;
  v_avg2         numeric;
  v_cnt1         int;
  v_cnt2         int;
  -- fallback
  v_fb_situacao  text;
  v_fb_prob_lbl  text;
  v_fb_pmin      numeric;
  v_fb_pmax      numeric;
  v_fb_classif   text;
BEGIN
  -- ═══════════════════════════════════════════
  -- Loop: clientes ativos
  -- ═══════════════════════════════════════════
  FOR v_cliente IN SELECT id FROM clientes WHERE ativo = true
  LOOP
    -- Buscar policy ativa
    SELECT id INTO v_policy_id
    FROM sentinela_risk_policy
    WHERE cliente_id = v_cliente.id AND is_active = true
    LIMIT 1;

    IF v_policy_id IS NULL THEN CONTINUE; END IF;

    -- Carregar defaults
    SELECT COALESCE(chuva_relevante_mm, 5),
           COALESCE(dias_lookup_max, 30),
           COALESCE(tendencia_dias, 7)
    INTO v_threshold, v_past_days, v_tend_dias
    FROM sentinela_risk_defaults
    WHERE policy_id = v_policy_id
    LIMIT 1;

    -- Fallback rule
    SELECT situacao_ambiental, probabilidade_label,
           probabilidade_pct_min, probabilidade_pct_max, classificacao
    INTO v_fb_situacao, v_fb_prob_lbl, v_fb_pmin, v_fb_pmax, v_fb_classif
    FROM sentinela_risk_fallback_rule
    WHERE policy_id = v_policy_id
    LIMIT 1;

    IF v_fb_situacao IS NULL THEN
      v_fb_situacao := 'Sem regra';
      v_fb_prob_lbl := 'Media';
      v_fb_pmin := 40; v_fb_pmax := 60;
      v_fb_classif := 'Moderado';
    END IF;

    -- ═══════════════════════════════════════
    -- Loop: regiões com coordenadas
    -- ═══════════════════════════════════════
    FOR v_regiao IN
      SELECT id, regiao, latitude, longitude
      FROM regioes
      WHERE cliente_id = v_cliente.id
        AND latitude IS NOT NULL
        AND longitude IS NOT NULL
    LOOP
      -- Pular se já existe
      IF EXISTS (
        SELECT 1 FROM pluvio_risco
        WHERE regiao_id = v_regiao.id AND dt_ref = v_dt_ref
      ) THEN CONTINUE; END IF;

      -- ── Open-Meteo fetch ──────────────────
      v_start_date := v_dt_ref - (v_past_days - 1);
      v_end_date   := v_dt_ref + 3;  -- +3 dias de forecast

      v_url := format(
        'https://api.open-meteo.com/v1/forecast?latitude=%s&longitude=%s'
        || '&daily=precipitation_sum,temperature_2m_mean,wind_speed_10m_max'
        || '&start_date=%s&end_date=%s&timezone=America%%2FCampo_Grande',
        v_regiao.latitude, v_regiao.longitude, v_start_date, v_end_date
      );

      BEGIN
        SELECT * INTO v_response FROM http_get(v_url);
      EXCEPTION WHEN OTHERS THEN
        CONTINUE;
      END;

      IF v_response.status != 200 THEN CONTINUE; END IF;

      v_daily := (v_response.content::jsonb)->'daily';
      v_len   := jsonb_array_length(v_daily->'time');

      -- Encontrar índice do dt_ref
      v_dt_ref_idx := NULL;
      FOR v_i IN 0..v_len - 1 LOOP
        IF (v_daily->'time'->>v_i) = v_dt_ref::text THEN
          v_dt_ref_idx := v_i;
          EXIT;
        END IF;
      END LOOP;

      IF v_dt_ref_idx IS NULL THEN CONTINUE; END IF;

      -- ── Métricas de precipitação ──────────
      v_chuva_24h := COALESCE((v_daily->'precipitation_sum'->>v_dt_ref_idx)::numeric, 0);

      v_chuva_72h := 0;
      FOR v_i IN GREATEST(0, v_dt_ref_idx - 2)..v_dt_ref_idx LOOP
        v_chuva_72h := v_chuva_72h + COALESCE((v_daily->'precipitation_sum'->>v_i)::numeric, 0);
      END LOOP;

      v_chuva_7d := 0;
      FOR v_i IN GREATEST(0, v_dt_ref_idx - 6)..v_dt_ref_idx LOOP
        v_chuva_7d := v_chuva_7d + COALESCE((v_daily->'precipitation_sum'->>v_i)::numeric, 0);
      END LOOP;

      -- Dias pós chuva
      v_dias_pos := NULL;
      FOR v_i IN REVERSE v_dt_ref_idx..0 LOOP
        IF COALESCE((v_daily->'precipitation_sum'->>v_i)::numeric, 0) > v_threshold THEN
          v_dias_pos := v_dt_ref_idx - v_i;
          EXIT;
        END IF;
      END LOOP;

      -- Persistência 7d
      v_persist := 0;
      FOR v_i IN GREATEST(0, v_dt_ref_idx - 6)..v_dt_ref_idx LOOP
        IF COALESCE((v_daily->'precipitation_sum'->>v_i)::numeric, 0) > v_threshold THEN
          v_persist := v_persist + 1;
        END IF;
      END LOOP;

      -- ── Tendência ─────────────────────────
      v_slice_start := GREATEST(0, v_dt_ref_idx - v_tend_dias + 1);
      v_slice_len   := v_dt_ref_idx - v_slice_start + 1;

      IF v_slice_len < 4 THEN
        v_tendencia := 'estavel';
      ELSE
        v_mid  := v_slice_start + (v_slice_len / 2);
        v_avg1 := 0; v_cnt1 := 0;
        v_avg2 := 0; v_cnt2 := 0;

        FOR v_i IN v_slice_start..v_mid - 1 LOOP
          v_avg1 := v_avg1 + COALESCE((v_daily->'precipitation_sum'->>v_i)::numeric, 0);
          v_cnt1 := v_cnt1 + 1;
        END LOOP;
        FOR v_i IN v_mid..v_dt_ref_idx LOOP
          v_avg2 := v_avg2 + COALESCE((v_daily->'precipitation_sum'->>v_i)::numeric, 0);
          v_cnt2 := v_cnt2 + 1;
        END LOOP;

        IF v_cnt1 > 0 THEN v_avg1 := v_avg1 / v_cnt1; END IF;
        IF v_cnt2 > 0 THEN v_avg2 := v_avg2 / v_cnt2; END IF;

        IF (v_avg2 - v_avg1) > 1 THEN v_tendencia := 'crescente';
        ELSIF (v_avg2 - v_avg1) < -1 THEN v_tendencia := 'decrescente';
        ELSE v_tendencia := 'estavel';
        END IF;
      END IF;

      -- ── Temperatura e vento ───────────────
      v_temp_c    := (v_daily->'temperature_2m_mean'->>v_dt_ref_idx)::numeric;
      v_vento_kmh := (v_daily->'wind_speed_10m_max'->>v_dt_ref_idx)::numeric;

      -- ── Forecast D+1, D+2, D+3 ───────────
      v_prev_d1 := CASE WHEN v_dt_ref_idx + 1 < v_len
        THEN (v_daily->'precipitation_sum'->>(v_dt_ref_idx + 1))::numeric END;
      v_prev_d2 := CASE WHEN v_dt_ref_idx + 2 < v_len
        THEN (v_daily->'precipitation_sum'->>(v_dt_ref_idx + 2))::numeric END;
      v_prev_d3 := CASE WHEN v_dt_ref_idx + 3 < v_len
        THEN (v_daily->'precipitation_sum'->>(v_dt_ref_idx + 3))::numeric END;

      -- ── Classificação de risco ────────────
      v_matched := false;
      FOR v_rule IN
        SELECT * FROM sentinela_risk_rule
        WHERE policy_id = v_policy_id ORDER BY idx
      LOOP
        IF v_chuva_24h >= v_rule.chuva_mm_min
           AND v_chuva_24h < v_rule.chuva_mm_max
           AND COALESCE(v_dias_pos, 0) >= v_rule.dias_min
           AND COALESCE(v_dias_pos, 0) <= v_rule.dias_max
        THEN
          v_situacao   := v_rule.situacao_ambiental;
          v_prob_label := v_rule.probabilidade_label;
          v_prob_min   := v_rule.probabilidade_pct_min;
          v_prob_max   := v_rule.probabilidade_pct_max;
          v_classif    := v_rule.classificacao;
          v_matched    := true;
          EXIT;
        END IF;
      END LOOP;

      IF NOT v_matched THEN
        v_situacao   := v_fb_situacao;
        v_prob_label := v_fb_prob_lbl;
        v_prob_min   := v_fb_pmin;
        v_prob_max   := v_fb_pmax;
        v_classif    := v_fb_classif;
      END IF;

      -- ── Ajustes de probabilidade (PP) ─────
      v_delta_pp := 0;

      -- Temp adjust
      IF v_temp_c IS NOT NULL THEN
        SELECT a.delta_pp INTO v_tmp_delta
        FROM sentinela_risk_temp_adjust_pp a
        WHERE a.policy_id = v_policy_id
          AND v_temp_c >= a.temp_min AND v_temp_c <= a.temp_max
        ORDER BY a.idx LIMIT 1;
        v_delta_pp := v_delta_pp + COALESCE(v_tmp_delta, 0);
      END IF;

      -- Vento adjust
      IF v_vento_kmh IS NOT NULL THEN
        SELECT a.delta_pp INTO v_tmp_delta
        FROM sentinela_risk_vento_adjust_pp a
        WHERE a.policy_id = v_policy_id
          AND v_vento_kmh >= a.vento_min AND v_vento_kmh <= a.vento_max
        ORDER BY a.idx LIMIT 1;
        v_delta_pp := v_delta_pp + COALESCE(v_tmp_delta, 0);
      END IF;

      -- Persistência adjust
      SELECT a.delta_pp INTO v_tmp_delta
      FROM sentinela_risk_persistencia_adjust_pp a
      WHERE a.policy_id = v_policy_id
        AND v_persist >= a.dias_min AND v_persist <= a.dias_max
      ORDER BY a.idx LIMIT 1;
      v_delta_pp := v_delta_pp + COALESCE(v_tmp_delta, 0);

      -- Tendência adjust
      SELECT a.delta_pp INTO v_tmp_delta
      FROM sentinela_risk_tendencia_adjust_pp a
      WHERE a.policy_id = v_policy_id
        AND a.tendencia = v_tendencia
      LIMIT 1;
      v_delta_pp := v_delta_pp + COALESCE(v_tmp_delta, 0);

      -- ── Probabilidade final ───────────────
      v_final_min := GREATEST(0, LEAST(100, v_prob_min + v_delta_pp));
      v_final_max := GREATEST(0, LEAST(100, v_prob_max + v_delta_pp));
      v_avg_final := (v_final_min + v_final_max) / 2.0;

      IF    v_avg_final >= 80 THEN v_classif := 'Crítico';
      ELSIF v_avg_final >= 65 THEN v_classif := 'Muito Alto';
      ELSIF v_avg_final >= 45 THEN v_classif := 'Alto';
      ELSIF v_avg_final >= 25 THEN v_classif := 'Moderado';
      ELSE  v_classif := 'Baixo';
      END IF;

      -- ── Janela sem chuva label ────────────
      v_janela := NULL;
      IF v_dias_pos IS NOT NULL THEN
        SELECT format('%s-%s dias', b.min_val, b.max_val) INTO v_janela
        FROM sentinela_risk_bin_sem_chuva b
        WHERE b.policy_id = v_policy_id
          AND v_dias_pos >= b.min_val AND v_dias_pos <= b.max_val
        ORDER BY b.idx LIMIT 1;

        IF v_janela IS NULL THEN
          v_janela := v_dias_pos || ' dias';
        END IF;
      END IF;

      -- ── INSERT ────────────────────────────
      INSERT INTO pluvio_risco (
        regiao_id, dt_ref,
        chuva_24h, chuva_72h, chuva_7d,
        dias_pos_chuva, janela_sem_chuva,
        persistencia_7d, tendencia,
        situacao_ambiental, prob_label,
        prob_base_min, prob_base_max,
        prob_final_min, prob_final_max,
        classificacao_final,
        temp_c, vento_kmh, temp_med_c, vento_med_kmh,
        prev_d1_mm, prev_d2_mm, prev_d3_mm
      ) VALUES (
        v_regiao.id, v_dt_ref,
        v_chuva_24h, round(v_chuva_72h, 3), round(v_chuva_7d, 3),
        v_dias_pos, v_janela,
        v_persist, v_tendencia,
        v_situacao, v_prob_label,
        v_prob_min, v_prob_max,
        round(v_final_min, 2), round(v_final_max, 2),
        v_classif,
        v_temp_c, v_vento_kmh, v_temp_c, v_vento_kmh,
        v_prev_d1, v_prev_d2, v_prev_d3
      );

      -- Rate limit Open-Meteo (200ms)
      PERFORM pg_sleep(0.2);

    END LOOP; -- regiões
  END LOOP; -- clientes
END;
$$;


ALTER FUNCTION "public"."fn_pluvio_risco_daily"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_prioridade_para_p"("p_prioridade" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE PARALLEL SAFE
    SET "search_path" TO 'public'
    AS $$
  SELECT CASE upper(trim(COALESCE(p_prioridade, '')))
    WHEN 'P1' THEN 'P1'
    WHEN 'P2' THEN 'P2'
    WHEN 'P3' THEN 'P3'
    WHEN 'P4' THEN 'P4'
    WHEN 'P5' THEN 'P5'
    -- Legado em português — P1: Crítica/Urgente agrupados
    WHEN 'CRÍTICO'      THEN 'P1'
    WHEN 'CRITICO'      THEN 'P1'
    WHEN 'CRÍTICA'      THEN 'P1'
    WHEN 'CRITICA'      THEN 'P1'
    WHEN 'URGENTE'      THEN 'P1'  -- FIX: era P2
    -- P2: Alta
    WHEN 'ALTA'         THEN 'P2'  -- FIX: era P3
    -- P3: Média / Moderada
    WHEN 'MÉDIA'        THEN 'P3'  -- FIX: era P4
    WHEN 'MEDIA'        THEN 'P3'  -- FIX: era P4
    WHEN 'MODERADA'     THEN 'P3'
    WHEN 'MODERADO'     THEN 'P3'
    -- P4: Baixa
    WHEN 'BAIXA'        THEN 'P4'  -- FIX: era P5
    -- P5: Monitoramento
    WHEN 'MONITORAMENTO' THEN 'P5'
    ELSE 'P3'  -- fallback conservador: Média
  END;
$$;


ALTER FUNCTION "public"."fn_prioridade_para_p"("p_prioridade" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_prioridade_para_p"("p_prioridade" "text") IS 'Converte prioridade legada → P1–P5. P1=Crítico/Urgente(4h) | P2=Alta(12h) | P3=Média/Moderada(24h) | P4=Baixa(72h) | P5=Monitoramento(72h). Fix 20260900030000: corrigido offset que fazia Urgente→P2, Alta→P3, Média→P4, Baixa→P5.';



CREATE OR REPLACE FUNCTION "public"."fn_purge_expired_logs"("p_dry_run" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sla_erros            integer := 0;
  v_offline_sync         integer := 0;
  v_cnes_log             integer := 0;
  v_cnes_controle        integer := 0;
  v_analise_ia           integer := 0;
  v_notificacoes_esus    integer := 0;
  v_total                integer := 0;
BEGIN
  -- ── sla_erros_criacao (90 dias) ───────────────────────────────────────────
  IF p_dry_run THEN
    SELECT COUNT(*)::integer INTO v_sla_erros
    FROM public.sla_erros_criacao WHERE retention_until < now();
  ELSE
    DELETE FROM public.sla_erros_criacao WHERE retention_until < now();
    GET DIAGNOSTICS v_sla_erros = ROW_COUNT;
  END IF;

  -- ── offline_sync_log (90 dias) ────────────────────────────────────────────
  IF p_dry_run THEN
    SELECT COUNT(*)::integer INTO v_offline_sync
    FROM public.offline_sync_log WHERE retention_until < now();
  ELSE
    DELETE FROM public.offline_sync_log WHERE retention_until < now();
    GET DIAGNOSTICS v_offline_sync = ROW_COUNT;
  END IF;

  -- ── unidades_saude_sync_log (90 dias) — excluir após purgar controle ──────
  -- Nota: ON DELETE CASCADE no controle_id garante que os logs orfãos sejam
  --       removidos junto, mas purgas antecipadas são feitas aqui independentemente.
  IF p_dry_run THEN
    SELECT COUNT(*)::integer INTO v_cnes_log
    FROM public.unidades_saude_sync_log WHERE retention_until < now();
  ELSE
    DELETE FROM public.unidades_saude_sync_log WHERE retention_until < now();
    GET DIAGNOSTICS v_cnes_log = ROW_COUNT;
  END IF;

  -- ── unidades_saude_sync_controle (1 ano) ─────────────────────────────────
  IF p_dry_run THEN
    SELECT COUNT(*)::integer INTO v_cnes_controle
    FROM public.unidades_saude_sync_controle WHERE retention_until < now();
  ELSE
    DELETE FROM public.unidades_saude_sync_controle WHERE retention_until < now();
    GET DIAGNOSTICS v_cnes_controle = ROW_COUNT;
  END IF;

  -- ── levantamento_analise_ia (2 anos) ──────────────────────────────────────
  IF p_dry_run THEN
    SELECT COUNT(*)::integer INTO v_analise_ia
    FROM public.levantamento_analise_ia WHERE retention_until < now();
  ELSE
    DELETE FROM public.levantamento_analise_ia WHERE retention_until < now();
    GET DIAGNOSTICS v_analise_ia = ROW_COUNT;
  END IF;

  -- ── item_notificacoes_esus (5 anos) ───────────────────────────────────────
  IF p_dry_run THEN
    SELECT COUNT(*)::integer INTO v_notificacoes_esus
    FROM public.item_notificacoes_esus WHERE retention_until < now();
  ELSE
    DELETE FROM public.item_notificacoes_esus WHERE retention_until < now();
    GET DIAGNOSTICS v_notificacoes_esus = ROW_COUNT;
  END IF;

  v_total := v_sla_erros + v_offline_sync + v_cnes_log + v_cnes_controle
           + v_analise_ia + v_notificacoes_esus;

  RETURN jsonb_build_object(
    'dry_run',                    p_dry_run,
    'sla_erros_criacao',          v_sla_erros,
    'offline_sync_log',           v_offline_sync,
    'unidades_saude_sync_log',    v_cnes_log,
    'unidades_saude_sync_controle', v_cnes_controle,
    'levantamento_analise_ia',    v_analise_ia,
    'item_notificacoes_esus',     v_notificacoes_esus,
    'total',                      v_total,
    'executado_em',               now()
  );
END;
$$;


ALTER FUNCTION "public"."fn_purge_expired_logs"("p_dry_run" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_purge_expired_logs"("p_dry_run" boolean) IS 'QW-10C: Deleta linhas com retention_until < now(). Agendado diariamente às 02h30 UTC via pg_cron (retencao-logs-purge).';



CREATE OR REPLACE FUNCTION "public"."fn_recalcular_score_prioridade"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.status IN ('resolvido', 'descartado') THEN
    UPDATE public.focos_risco SET score_prioridade = 0 WHERE id = NEW.id;
  ELSE
    UPDATE public.focos_risco
    SET score_prioridade = public.calcular_score_prioridade_foco(NEW.id)
    WHERE id = NEW.id;
  END IF;
  RETURN NULL;
EXCEPTION WHEN OTHERS THEN
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."fn_recalcular_score_prioridade"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_redact_sensitive_log_fields"("p_dry_run" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_esus_redacted    integer := 0;
  v_clusters_redacted integer := 0;
BEGIN
  -- a) item_notificacoes_esus.resposta_api → nullificar após 90 dias
  IF p_dry_run THEN
    SELECT COUNT(*)::integer INTO v_esus_redacted
    FROM public.item_notificacoes_esus
    WHERE resposta_api IS NOT NULL
      AND resposta_redacted_at IS NULL
      AND created_at < now() - interval '90 days';
  ELSE
    UPDATE public.item_notificacoes_esus
    SET
      resposta_api         = NULL,
      resposta_redacted_at = now()
    WHERE resposta_api IS NOT NULL
      AND resposta_redacted_at IS NULL
      AND created_at < now() - interval '90 days';
    GET DIAGNOSTICS v_esus_redacted = ROW_COUNT;
  END IF;

  -- b) levantamento_analise_ia.clusters → nullificar após 1 ano
  IF p_dry_run THEN
    SELECT COUNT(*)::integer INTO v_clusters_redacted
    FROM public.levantamento_analise_ia
    WHERE clusters IS NOT NULL
      AND clusters_redacted_at IS NULL
      AND created_at < now() - interval '1 year';
  ELSE
    UPDATE public.levantamento_analise_ia
    SET
      clusters            = NULL,
      clusters_redacted_at = now()
    WHERE clusters IS NOT NULL
      AND clusters_redacted_at IS NULL
      AND created_at < now() - interval '1 year';
    GET DIAGNOSTICS v_clusters_redacted = ROW_COUNT;
  END IF;

  RETURN jsonb_build_object(
    'dry_run',             p_dry_run,
    'esus_resposta_api',   v_esus_redacted,
    'analise_ia_clusters', v_clusters_redacted,
    'executado_em',        now()
  );
END;
$$;


