COMMENT ON FUNCTION "public"."fn_risco_reincidencia_imovel"("p_imovel_id" "uuid", "p_cliente_id" "uuid") IS 'Score 0–100 de risco de nova reincidência em um imóvel. Diferente do score territorial: foca em padrão histórico de REINCIDÊNCIA. Classificação: alto (>=70) | medio (>=40) | baixo.';



