CREATE OR REPLACE FUNCTION "public"."fn_validar_ciclo_vistoria"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_ciclo_ativo int;
BEGIN
  v_ciclo_ativo := public.fn_ciclo_ativo_numero(NEW.cliente_id);

  -- Sem ciclo ativo formal → sem restrição (cliente ainda não usa tabela ciclos)
  IF v_ciclo_ativo IS NULL THEN
    RETURN NEW;
  END IF;

  -- Ciclo informado deve coincidir com o ativo
  IF NEW.ciclo <> v_ciclo_ativo THEN
    RAISE EXCEPTION
      'Vistoria com ciclo % rejeitada: ciclo ativo do cliente é %. '
      'Encerre o ciclo ativo antes de registrar vistorias em outro ciclo.',
      NEW.ciclo, v_ciclo_ativo
      USING ERRCODE = 'check_violation';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."fn_validar_ciclo_vistoria"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_validar_ciclo_vistoria"() IS 'V-11/CI-04: Bloqueia INSERT em vistorias com ciclo diferente do ciclo ativo do cliente. Só age se houver ciclo formal ativo — clientes sem tabela de ciclos não são afetados.';



CREATE OR REPLACE FUNCTION "public"."fn_validar_transicao_foco_risco"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF OLD.status = NEW.status THEN
    RETURN NEW;
  END IF;

  IF NOT (
    (OLD.status = 'suspeita'         AND NEW.status = 'em_triagem') OR
    (OLD.status = 'em_triagem'       AND NEW.status IN ('aguarda_inspecao', 'descartado')) OR
    (OLD.status = 'aguarda_inspecao' AND NEW.status IN ('em_inspecao', 'descartado')) OR
    (OLD.status = 'em_inspecao'      AND NEW.status IN ('confirmado', 'descartado')) OR
    (OLD.status = 'confirmado'       AND NEW.status = 'em_tratamento') OR
    (OLD.status = 'em_tratamento'    AND NEW.status IN ('resolvido', 'descartado'))
  ) THEN
    RAISE EXCEPTION 'Transição inválida de foco_risco: % → %. Consulte o fluxo canônico.',
      OLD.status, NEW.status
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$$;


