CREATE OR REPLACE FUNCTION "public"."get_integracao_api_key"("p_integracao_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_api_key    text;
  v_cliente_id uuid;
BEGIN
  SELECT ci.api_key, ci.cliente_id
  INTO v_api_key, v_cliente_id
  FROM public.cliente_integracoes ci
  WHERE ci.id = p_integracao_id;

  IF v_cliente_id IS NULL THEN
    RAISE EXCEPTION 'Integração não encontrada';
  END IF;

  -- Verificar: admin global OU supervisor do mesmo cliente
  IF NOT (
    public.is_admin()
    OR (public.is_supervisor() AND public.usuario_cliente_id() = v_cliente_id)
  ) THEN
    RAISE EXCEPTION 'Acesso negado — apenas admin ou supervisor do cliente podem visualizar a chave';
  END IF;

  -- Registrar auditoria antes de retornar a chave
  PERFORM public.registrar_audit(
    v_cliente_id,
    'integracao_api_key_vista',
    'cliente_integracoes',
    p_integracao_id,
    'Chave de API visualizada pelo usuário'
  );

  RETURN v_api_key;
END;
$$;


ALTER FUNCTION "public"."get_integracao_api_key"("p_integracao_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_integracao_api_key"("p_integracao_id" "uuid") IS 'Retorna a api_key completa de uma integração. Requer papel admin (global) ou supervisor do mesmo cliente. Registra auditoria em audit_log com ação integracao_api_key_vista.';



