CREATE OR REPLACE FUNCTION "public"."get_meu_papel"() RETURNS "text"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT LOWER(pu.papel::text)
  FROM papeis_usuarios pu
  WHERE pu.usuario_id = auth.uid()
  ORDER BY CASE LOWER(pu.papel::text)
    WHEN 'admin'             THEN 5
    WHEN 'supervisor'        THEN 4
    WHEN 'moderador'         THEN 4  -- alias histórico de supervisor
    WHEN 'agente'            THEN 3
    WHEN 'operador'          THEN 3  -- alias legado de agente
    WHEN 'notificador'       THEN 2
    WHEN 'analista_regional' THEN 1
    ELSE 0                           -- platform_admin (morto), desconhecido
  END DESC
  LIMIT 1;
$$;


ALTER FUNCTION "public"."get_meu_papel"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_meu_papel"() IS 'Retorna o papel de maior prioridade do usuário logado. Escada: admin(5) > supervisor/moderador(4) > agente/operador(3) > notificador(2) > analista_regional(1) > legado/morto(0). moderador é alias histórico de supervisor. operador é alias legado de agente.';



