CREATE OR REPLACE FUNCTION "public"."incrementar_upload_rate"("p_ip_hash" "text", "p_cliente_id" "uuid", "p_janela" timestamp with time zone, "p_limite" integer DEFAULT 5) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contagem int;
BEGIN
  INSERT INTO public.canal_cidadao_rate_limit (ip_hash, cliente_id, janela_hora, contagem)
  VALUES (p_ip_hash, p_cliente_id, p_janela, 1)
  ON CONFLICT (ip_hash, cliente_id, janela_hora)
  DO UPDATE SET contagem = canal_cidadao_rate_limit.contagem + 1
  RETURNING contagem INTO v_contagem;

  IF v_contagem > p_limite THEN
    -- Reverter ao limite para não crescer indefinidamente
    UPDATE public.canal_cidadao_rate_limit
    SET contagem = p_limite
    WHERE ip_hash = p_ip_hash AND cliente_id = p_cliente_id AND janela_hora = p_janela;

    RETURN jsonb_build_object('bloqueado', true);
  END IF;

  RETURN jsonb_build_object('bloqueado', false);
END;
$$;


ALTER FUNCTION "public"."incrementar_upload_rate"("p_ip_hash" "text", "p_cliente_id" "uuid", "p_janela" timestamp with time zone, "p_limite" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."incrementar_upload_rate"("p_ip_hash" "text", "p_cliente_id" "uuid", "p_janela" timestamp with time zone, "p_limite" integer) IS 'Rate limit de uploads anônimos para cloudinary-upload-image. Reutiliza canal_cidadao_rate_limit. Executada apenas pelo service_role da Edge Function.';



CREATE OR REPLACE FUNCTION "public"."is_admin"() RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    -- Fast-path: claim presente e válida
    CASE
      WHEN auth.jwt() -> 'app_metadata' ->> 'papel' IS NOT NULL
      THEN (auth.jwt() -> 'app_metadata' ->> 'papel') = 'admin'
      -- Fallback: DB (tokens pré-hook ou claim ausente)
      ELSE EXISTS (
        SELECT 1 FROM public.papeis_usuarios pu
        WHERE pu.usuario_id = auth.uid()
          AND pu.papel::text = 'admin'
      )
    END;
$$;


