CREATE OR REPLACE FUNCTION "public"."marcar_slas_vencidos"("p_cliente_id" "uuid" DEFAULT NULL::"uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count int;
BEGIN
  UPDATE public.sla_operacional
  SET
    status  = 'vencido',
    violado = true
  WHERE status     IN ('pendente', 'em_atendimento')
    AND prazo_final < now()
    AND (p_cliente_id IS NULL OR cliente_id = p_cliente_id);

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


