CREATE OR REPLACE FUNCTION "public"."mascarar_api_key"("p_key" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT CASE
    WHEN p_key IS NULL OR length(p_key) < 8
      THEN '****'
    ELSE
      left(p_key, 4) || repeat('*', greatest(length(p_key) - 8, 4)) || right(p_key, 4)
  END;
$$;


