CREATE OR REPLACE FUNCTION "public"."operacoes_on_status_concluido"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_now timestamptz := now();
BEGIN
  IF NEW.status <> 'concluido' THEN
    RETURN NEW;
  END IF;

  IF NEW.concluido_em IS NULL THEN
    NEW.concluido_em := v_now;
  END IF;

  -- Fecha SLA de item pluviométrico
  IF NEW.item_operacional_id IS NOT NULL THEN
    UPDATE public.sla_operacional
    SET concluido_em = v_now, status = 'concluido'
    WHERE item_id = NEW.item_operacional_id
      AND status IN ('pendente', 'em_atendimento');
  END IF;

  -- Fecha SLA de levantamento_item
  IF NEW.item_levantamento_id IS NOT NULL THEN
    UPDATE public.sla_operacional
    SET concluido_em = v_now, status = 'concluido'
    WHERE levantamento_item_id = NEW.item_levantamento_id
      AND status IN ('pendente', 'em_atendimento');
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."operacoes_on_status_concluido"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."operacoes_on_status_concluido"() IS 'Ao marcar operação como concluído: preenche concluido_em e fecha sla_operacional do item pluviométrico ou do levantamento_item vinculado.';



