CREATE OR REPLACE FUNCTION "public"."reabrir_sla"("p_sla_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  s             RECORD;
  v_prazo_final timestamptz;
  v_user_id     uuid;
BEGIN
  SELECT id, sla_horas, cliente_id
  INTO s
  FROM public.sla_operacional
  WHERE id = p_sla_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'reabrir_sla: SLA % não encontrado', p_sla_id;
  END IF;

  -- ── Verificação de tenant (Fix S-02) ──────────────────────────────────────
  IF NOT public.usuario_pode_acessar_cliente(s.cliente_id) THEN
    RAISE EXCEPTION
      'reabrir_sla: acesso negado — SLA pertence a outro cliente';
  END IF;

  BEGIN
    v_prazo_final := public.sla_calcular_prazo_final(
      now(),
      s.sla_horas,
      public.sla_resolve_config(s.cliente_id, NULL),
      s.cliente_id
    );
  EXCEPTION WHEN others THEN
    v_prazo_final := now() + (s.sla_horas || ' hours')::interval;
  END;

  SELECT id INTO v_user_id
  FROM public.usuarios
  WHERE auth_id = auth.uid();

  UPDATE public.sla_operacional
  SET
    status       = 'pendente',
    concluido_em = null,
    inicio       = now(),
    prazo_final  = v_prazo_final,
    violado      = false,
    reaberto_por = v_user_id
  WHERE id = p_sla_id;
END;
$$;


ALTER FUNCTION "public"."reabrir_sla"("p_sla_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."reabrir_sla"("p_sla_id" "uuid") IS 'Reabre um SLA: volta para pendente, recalcula prazo, registra reaberto_por. Verifica tenant antes de agir. (QW-06 + QW-07 + Fix S-02)';



CREATE OR REPLACE FUNCTION "public"."registrar_audit"("p_cliente_id" "uuid", "p_acao" "text", "p_tabela" "text" DEFAULT NULL::"text", "p_registro_id" "uuid" DEFAULT NULL::"uuid", "p_descricao" "text" DEFAULT NULL::"text", "p_payload" "jsonb" DEFAULT NULL::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_usuario_id uuid;
  v_ip_raw     text;
  v_ip_hash    text;
BEGIN
  -- Usuário só pode registrar auditoria do próprio cliente.
  -- Admin pode registrar para qualquer cliente (suporte de plataforma).
  IF p_cliente_id IS NOT NULL
     AND NOT public.usuario_pode_acessar_cliente(p_cliente_id) THEN
    RAISE EXCEPTION
      'registrar_audit: acesso negado — cliente_id não pertence ao usuário';
  END IF;

  SELECT id INTO v_usuario_id
  FROM usuarios WHERE auth_id = auth.uid() LIMIT 1;

  BEGIN
    v_ip_raw := split_part(
      (current_setting('request.headers', true)::jsonb ->> 'x-forwarded-for'),
      ',', 1
    );
  EXCEPTION WHEN OTHERS THEN
    v_ip_raw := 'unknown';
  END;

  v_ip_hash := md5(coalesce(nullif(trim(v_ip_raw), ''), 'unknown'));

  INSERT INTO audit_log (
    cliente_id, usuario_id, auth_uid, acao,
    tabela, registro_id, ip_hash, descricao, payload
  ) VALUES (
    p_cliente_id, v_usuario_id, auth.uid(), p_acao,
    p_tabela, p_registro_id, v_ip_hash, p_descricao, p_payload
  );
END;
$$;


ALTER FUNCTION "public"."registrar_audit"("p_cliente_id" "uuid", "p_acao" "text", "p_tabela" "text", "p_registro_id" "uuid", "p_descricao" "text", "p_payload" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."registrar_audit"("p_cliente_id" "uuid", "p_acao" "text", "p_tabela" "text", "p_registro_id" "uuid", "p_descricao" "text", "p_payload" "jsonb") IS 'Registra ação no audit_log. Valida tenant antes de inserir. P0-6: SET search_path adicionado para prevenir search_path hijacking.';



CREATE OR REPLACE FUNCTION "public"."resolver_cliente_por_coordenada"("p_lat" double precision, "p_lng" double precision) RETURNS TABLE("cliente_id" "uuid", "cliente_nome" "text", "cidade" "text", "uf" "text", "slug" "text", "encontrado" boolean, "metodo" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT * FROM (
    -- 1ª tentativa: ponto dentro do polígono GeoJSON (match exato)
    (
      SELECT
        id             AS cliente_id,
        nome           AS cliente_nome,
        cidade,
        uf,
        slug,
        true           AS encontrado,
        'poligono'     AS metodo
      FROM clientes
      WHERE ativo = true
        AND deleted_at IS NULL
        AND area IS NOT NULL
        AND ST_Contains(
          ST_SetSRID(ST_GeomFromGeoJSON(area::text), 4326),
          ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)
        )
      LIMIT 1
    )

    UNION ALL

    -- 2ª tentativa: centroide mais próximo (≤ 30 km)
    (
      SELECT
        id             AS cliente_id,
        nome           AS cliente_nome,
        cidade,
        uf,
        slug,
        true           AS encontrado,
        'centroide'    AS metodo
      FROM clientes
      WHERE ativo = true
        AND deleted_at IS NULL
        AND latitude_centro IS NOT NULL
        AND longitude_centro IS NOT NULL
        AND ST_Distance(
          ST_MakePoint(longitude_centro, latitude_centro)::geography,
          ST_MakePoint(p_lng, p_lat)::geography
        ) <= 30000
      ORDER BY
        ST_MakePoint(longitude_centro, latitude_centro)::geography
        <-> ST_MakePoint(p_lng, p_lat)::geography
      LIMIT 1
    )
  ) sub
  LIMIT 1;
$$;


ALTER FUNCTION "public"."resolver_cliente_por_coordenada"("p_lat" double precision, "p_lng" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resumo_agente_ciclo"("p_cliente_id" "uuid", "p_agente_id" "uuid", "p_ciclo" integer) RETURNS json
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_total     int;
  v_visitados int;
  v_pendentes int;
BEGIN
  -- FIX 1F-B: tenant check — agente só pode consultar seu próprio resumo dentro do cliente.
  IF NOT usuario_pode_acessar_cliente(p_cliente_id) THEN
    RAISE EXCEPTION 'Acesso negado ao cliente %', p_cliente_id
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- FIX 2B: v_total via quarteirões atribuídos ao agente neste ciclo.
  -- Se não há distribuição registrada, cai no total de imóveis do cliente (comportamento anterior).
  SELECT COUNT(DISTINCT im.id) INTO v_total
  FROM public.imoveis im
  JOIN public.distribuicao_quarteirao dq
    ON dq.quarteirao  = im.quarteirao
   AND dq.agente_id   = p_agente_id
   AND dq.ciclo       = p_ciclo
   AND dq.cliente_id  = p_cliente_id
  WHERE im.cliente_id = p_cliente_id AND im.ativo = true;

  -- Fallback: agente sem distribuição registrada → total do cliente
  IF v_total = 0 THEN
    SELECT COUNT(*) INTO v_total
    FROM public.imoveis
    WHERE cliente_id = p_cliente_id AND ativo = true;
  END IF;

  SELECT COUNT(*) INTO v_visitados
  FROM public.vistorias
  WHERE cliente_id = p_cliente_id
    AND agente_id  = p_agente_id
    AND ciclo      = p_ciclo
    AND status     IN ('visitado','fechado');

  v_pendentes := GREATEST(v_total - v_visitados, 0);

  RETURN json_build_object(
    'pendentes',     v_pendentes,
    'visitados',     v_visitados,
    'meta',          v_total,
    'cobertura_pct', CASE WHEN v_total > 0
                       THEN ROUND((v_visitados::numeric / v_total) * 100, 1)
                       ELSE 0
                     END
  );
END;
$$;


ALTER FUNCTION "public"."resumo_agente_ciclo"("p_cliente_id" "uuid", "p_agente_id" "uuid", "p_ciclo" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."resumo_agente_ciclo"("p_cliente_id" "uuid", "p_agente_id" "uuid", "p_ciclo" integer) IS 'Resumo de produtividade do agente num ciclo: pendentes, visitados, meta, cobertura%. Fix 1F: tenant check obrigatório. Fix 2B: v_total usa distribuicao_quarteirao (fallback para todos se sem atribuição).';



CREATE OR REPLACE FUNCTION "public"."rls_auto_enable"() RETURNS "event_trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog'
    AS $$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."rls_auto_enable"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_atribuir_agente_foco"("p_foco_id" "uuid", "p_agente_id" "uuid", "p_motivo" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_usuario    usuarios%ROWTYPE;
  v_papel      text;
  v_foco       focos_risco%ROWTYPE;
  v_novo_status text;
  v_regiao_id  uuid;
BEGIN
  -- Obter dados do chamador
  SELECT u.* INTO v_usuario FROM usuarios u WHERE u.auth_id = auth.uid();
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Usuário não encontrado' USING ERRCODE = 'P0001';
  END IF;

  -- Obter papel canônico do chamador (papeis_usuarios, não usuarios.papel_app)
  SELECT pu.papel INTO v_papel
    FROM papeis_usuarios pu
   WHERE pu.usuario_id = auth.uid();

  IF v_papel IS NULL THEN
    RAISE EXCEPTION 'Usuário sem papel definido — acesso negado' USING ERRCODE = 'P0001';
  END IF;

  IF NOT COALESCE(v_usuario.ativo, false) THEN
    RAISE EXCEPTION 'Usuário inativo — acesso negado' USING ERRCODE = 'P0001';
  END IF;

  IF v_papel != 'supervisor' THEN
    RAISE EXCEPTION 'Apenas supervisores podem distribuir focos para agentes'
      USING ERRCODE = 'P0001';
  END IF;

  -- Obter foco
  SELECT * INTO v_foco FROM focos_risco WHERE id = p_foco_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Foco não encontrado: %', p_foco_id USING ERRCODE = 'P0002';
  END IF;

  -- Validar acesso de tenant
  IF NOT public.usuario_pode_acessar_cliente(v_foco.cliente_id) THEN
    RAISE EXCEPTION 'Acesso negado ao foco' USING ERRCODE = 'P0003';
  END IF;

  -- Só permite distribuição nos estados corretos
  IF v_foco.status NOT IN ('em_triagem', 'aguarda_inspecao') THEN
    RAISE EXCEPTION 'Distribuição só é permitida nos estados em_triagem ou aguarda_inspecao. Estado atual: %',
      v_foco.status USING ERRCODE = 'P0004';
  END IF;

  -- Validar que o agente alvo pertence ao mesmo cliente, está ativo e tem papel agente
  IF NOT EXISTS (
    SELECT 1
    FROM usuarios u
    JOIN papeis_usuarios pu ON pu.usuario_id = u.auth_id
    WHERE u.id = p_agente_id
      AND u.cliente_id = v_foco.cliente_id
      AND pu.papel = 'agente'
      AND u.ativo = true
  ) THEN
    RAISE EXCEPTION 'Agente inválido ou inativo para este cliente'
      USING ERRCODE = 'P0005';
  END IF;

  -- BLOCO 1: Inferir regiao_id via ST_Contains se foco sem região e com coordenadas
  v_regiao_id := v_foco.regiao_id;
  IF v_regiao_id IS NULL
     AND v_foco.latitude  IS NOT NULL
     AND v_foco.longitude IS NOT NULL
  THEN
    SELECT r.id INTO v_regiao_id
      FROM regioes r
     WHERE r.cliente_id = v_foco.cliente_id
       AND r.area IS NOT NULL
       AND ST_Contains(
             r.area,
             ST_SetSRID(ST_MakePoint(v_foco.longitude, v_foco.latitude), 4326)
           )
     LIMIT 1;
  END IF;

  IF v_foco.status = 'em_triagem' THEN
    v_novo_status := 'aguarda_inspecao';
    UPDATE focos_risco
       SET status         = v_novo_status,
           responsavel_id = p_agente_id,
           regiao_id      = COALESCE(v_regiao_id, v_foco.regiao_id),
           updated_at     = now()
     WHERE id = p_foco_id;

    INSERT INTO foco_risco_historico (
      foco_risco_id, cliente_id, status_anterior, status_novo, alterado_por, motivo
    ) VALUES (
      p_foco_id, v_foco.cliente_id,
      'em_triagem', 'aguarda_inspecao',
      v_usuario.id, COALESCE(p_motivo, 'Atribuição de agente pelo supervisor')
    );
  ELSE
    UPDATE focos_risco
       SET responsavel_id = p_agente_id,
           regiao_id      = COALESCE(v_regiao_id, v_foco.regiao_id),
           updated_at     = now()
     WHERE id = p_foco_id;

    INSERT INTO foco_risco_historico (
      foco_risco_id, cliente_id, status_anterior, status_novo, alterado_por, motivo
    ) VALUES (
      p_foco_id, v_foco.cliente_id,
      'aguarda_inspecao', 'aguarda_inspecao',
      v_usuario.id, COALESCE(p_motivo, 'Reatribuição de agente pelo supervisor')
    );
  END IF;
END;
$$;


ALTER FUNCTION "public"."rpc_atribuir_agente_foco"("p_foco_id" "uuid", "p_agente_id" "uuid", "p_motivo" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."rpc_atribuir_agente_foco"("p_foco_id" "uuid", "p_agente_id" "uuid", "p_motivo" "text") IS 'Distribui ou reatribui um foco_risco para um agente. Exclusivo para supervisores. Papel verificado via papeis_usuarios.papel. Estados permitidos: em_triagem → aguarda_inspecao (primeira atribuição) ou aguarda_inspecao (reatribuição). P7.8.1: auto-infere regiao_id via ST_Contains(regioes.area, ponto) quando lat/lng disponível e regiao_id ausente.';



CREATE OR REPLACE FUNCTION "public"."rpc_atribuir_agente_foco_lote"("p_foco_ids" "uuid"[], "p_agente_id" "uuid", "p_motivo" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_usuario    usuarios%ROWTYPE;
  v_papel      text;
  v_ativo      boolean;
  v_foco       focos_risco%ROWTYPE;
  v_atribuidos int := 0;
  v_ignorados  int := 0;
  v_foco_id    uuid;
  v_novo_status text;
  v_regiao_id  uuid;
BEGIN
  -- Obter dados do chamador
  SELECT * INTO v_usuario FROM usuarios u WHERE u.auth_id = auth.uid();
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Usuário não encontrado' USING ERRCODE = 'P0001';
  END IF;
  v_ativo := v_usuario.ativo;

  -- Obter papel canônico via papeis_usuarios (não usuarios.papel_app — removida)
  SELECT pu.papel INTO v_papel
    FROM papeis_usuarios pu
   WHERE pu.usuario_id = auth.uid();

  IF v_papel IS NULL THEN
    RAISE EXCEPTION 'Usuário sem papel definido — acesso negado' USING ERRCODE = 'P0001';
  END IF;

  IF NOT COALESCE(v_ativo, false) THEN
    RAISE EXCEPTION 'Usuário inativo — acesso negado' USING ERRCODE = 'P0001';
  END IF;

  -- SOMENTE supervisor pode distribuir focos
  IF v_papel != 'supervisor' THEN
    RAISE EXCEPTION 'Apenas supervisores podem distribuir focos em lote. Papel atual: %', v_papel
      USING ERRCODE = 'P0001';
  END IF;

  -- Validar agente destino: mesmo cliente, ativo, papel agente — via papeis_usuarios
  IF NOT EXISTS (
    SELECT 1
    FROM usuarios u
    JOIN papeis_usuarios pu ON pu.usuario_id = u.auth_id
    JOIN focos_risco f ON f.id = p_foco_ids[1] AND f.cliente_id = u.cliente_id
    WHERE u.id = p_agente_id
      AND pu.papel = 'agente'
      AND u.ativo = true
  ) THEN
    RAISE EXCEPTION 'Agente inválido ou inativo para este cliente' USING ERRCODE = 'P0005';
  END IF;

  FOREACH v_foco_id IN ARRAY p_foco_ids LOOP
    SELECT * INTO v_foco FROM focos_risco WHERE id = v_foco_id;

    IF NOT FOUND
       OR NOT public.usuario_pode_acessar_cliente(v_foco.cliente_id)
       OR v_foco.status NOT IN ('em_triagem', 'aguarda_inspecao')
    THEN
      v_ignorados := v_ignorados + 1;
      CONTINUE;
    END IF;

    -- BLOCO 1: Inferir regiao_id via ST_Contains se foco sem região e com coordenadas
    v_regiao_id := v_foco.regiao_id;
    IF v_regiao_id IS NULL
       AND v_foco.latitude  IS NOT NULL
       AND v_foco.longitude IS NOT NULL
    THEN
      SELECT r.id INTO v_regiao_id
        FROM regioes r
       WHERE r.cliente_id = v_foco.cliente_id
         AND r.area IS NOT NULL
         AND ST_Contains(
               r.area,
               ST_SetSRID(ST_MakePoint(v_foco.longitude, v_foco.latitude), 4326)
             )
       LIMIT 1;
    END IF;

    IF v_foco.status = 'em_triagem' THEN
      v_novo_status := 'aguarda_inspecao';
      UPDATE focos_risco
         SET status         = v_novo_status,
             responsavel_id = p_agente_id,
             regiao_id      = COALESCE(v_regiao_id, v_foco.regiao_id),
             updated_at     = now()
       WHERE id = v_foco_id;

      INSERT INTO foco_risco_historico (
        foco_risco_id, cliente_id, status_anterior, status_novo, alterado_por, motivo
      ) VALUES (
        v_foco_id, v_foco.cliente_id,
        'em_triagem', 'aguarda_inspecao',
        v_usuario.id, COALESCE(p_motivo, 'Atribuição em lote pelo supervisor')
      );
    ELSE
      UPDATE focos_risco
         SET responsavel_id = p_agente_id,
             regiao_id      = COALESCE(v_regiao_id, v_foco.regiao_id),
             updated_at     = now()
       WHERE id = v_foco_id;

      INSERT INTO foco_risco_historico (
        foco_risco_id, cliente_id, status_anterior, status_novo, alterado_por, motivo
      ) VALUES (
        v_foco_id, v_foco.cliente_id,
        'aguarda_inspecao', 'aguarda_inspecao',
        v_usuario.id, COALESCE(p_motivo, 'Reatribuição em lote pelo supervisor')
      );
    END IF;

    v_atribuidos := v_atribuidos + 1;
  END LOOP;

  RETURN jsonb_build_object('atribuidos', v_atribuidos, 'ignorados', v_ignorados);
END;
$$;


ALTER FUNCTION "public"."rpc_atribuir_agente_foco_lote"("p_foco_ids" "uuid"[], "p_agente_id" "uuid", "p_motivo" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."rpc_atribuir_agente_foco_lote"("p_foco_ids" "uuid"[], "p_agente_id" "uuid", "p_motivo" "text") IS 'Distribui múltiplos focos a um agente. Exclusivo para supervisores ativos. Papel verificado via papeis_usuarios.papel (papel_app removida). Guards: NULL papel, ativo=false, papel != supervisor, agente inválido. P7.8.1: auto-infere regiao_id via ST_Contains(regioes.area, ponto) quando lat/lng disponível e regiao_id ausente.';



CREATE OR REPLACE FUNCTION "public"."rpc_atualizar_classificacao_inicial"("p_foco_id" "uuid", "p_classificacao" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_foco    focos_risco%ROWTYPE;
  v_usuario uuid;
BEGIN
  -- Validação de valor aceito
  IF p_classificacao NOT IN ('suspeito', 'risco', 'foco', 'caso_notificado') THEN
    RETURN jsonb_build_object('ok', false, 'error',
      'Classificação inválida. Aceitos: suspeito, risco, foco, caso_notificado.');
  END IF;

  -- Busca o foco (com soft-delete)
  SELECT * INTO v_foco
    FROM focos_risco
   WHERE id = p_foco_id
     AND deleted_at IS NULL;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Foco não encontrado.');
  END IF;

  -- Isolamento de tenant
  IF NOT public.usuario_pode_acessar_cliente(v_foco.cliente_id) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Acesso não autorizado.');
  END IF;

  -- Sem mudança real
  IF v_foco.classificacao_inicial = p_classificacao THEN
    RETURN jsonb_build_object('ok', true, 'changed', false);
  END IF;

  -- Identifica o usuário corrente
  SELECT id INTO v_usuario
    FROM usuarios
   WHERE auth_id = auth.uid()
   LIMIT 1;

  -- Atualiza o foco
  UPDATE focos_risco
     SET classificacao_inicial = p_classificacao,
         updated_at            = now()
   WHERE id = p_foco_id;

  -- Registra no histórico (tipo_evento = 'classificacao_alterada')
  INSERT INTO foco_risco_historico (
    foco_risco_id, cliente_id,
    tipo_evento,
    classificacao_anterior, classificacao_nova,
    alterado_por, alterado_em
  ) VALUES (
    p_foco_id, v_foco.cliente_id,
    'classificacao_alterada',
    v_foco.classificacao_inicial, p_classificacao,
    v_usuario, now()
  );

  RETURN jsonb_build_object(
    'ok',      true,
    'changed', true,
    'de',      v_foco.classificacao_inicial,
    'para',    p_classificacao
  );
END;
$$;


ALTER FUNCTION "public"."rpc_atualizar_classificacao_inicial"("p_foco_id" "uuid", "p_classificacao" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_calcular_liraa"("p_cliente_id" "uuid", "p_ciclo" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.usuario_pode_acessar_cliente(p_cliente_id) THEN
    RAISE EXCEPTION 'Acesso negado ao cliente %', p_cliente_id
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  RETURN (
    WITH base AS (
      SELECT
        v.id                                                    AS vistoria_id,
        v.imovel_id,
        v.data_visita,
        v.acesso_realizado,
        COALESCE(SUM(d.qtd_inspecionados), 0)                  AS total_recipientes,
        COALESCE(SUM(d.qtd_com_focos), 0)                      AS recipientes_com_foco,
        COALESCE(SUM(CASE WHEN d.qtd_com_focos > 0 THEN 1 ELSE 0 END), 0) AS tipos_foco
      FROM vistorias v
      LEFT JOIN vistoria_depositos d ON d.vistoria_id = v.id
      WHERE v.cliente_id = p_cliente_id
        AND v.ciclo = p_ciclo
        AND v.tipo_atividade = 'liraa'
      GROUP BY v.id
    ),
    por_tipo AS (
      SELECT
        v.id AS vistoria_id,
        d.tipo,
        SUM(d.qtd_inspecionados) AS inspecionados,
        SUM(d.qtd_com_focos)     AS com_foco
      FROM vistorias v
      JOIN vistoria_depositos d ON d.vistoria_id = v.id
      WHERE v.cliente_id = p_cliente_id
        AND v.ciclo = p_ciclo
        AND v.tipo_atividade = 'liraa'
      GROUP BY v.id, d.tipo
    ),
    totais AS (
      SELECT
        COUNT(*)                                                    AS total_imoveis,
        COUNT(*) FILTER (WHERE acesso_realizado = true)             AS inspecionados,
        COUNT(*) FILTER (WHERE acesso_realizado = false)            AS fechados,
        COUNT(*) FILTER (WHERE recipientes_com_foco > 0)           AS imoveis_com_foco,
        SUM(recipientes_com_foco)                                   AS total_recipientes_foco,
        SUM(total_recipientes)                                      AS total_recipientes
      FROM base
    ),
    por_deposito AS (
      SELECT
        tipo,
        SUM(inspecionados) AS inspecionados,
        SUM(com_foco)      AS com_foco,
        ROUND(
          CASE WHEN SUM(inspecionados) > 0
            THEN SUM(com_foco)::numeric / SUM(inspecionados) * 100
            ELSE 0 END, 2
        ) AS indice
      FROM por_tipo
      GROUP BY tipo
    ),
    focos AS (
      SELECT
        fr.id,
        fr.status,
        fr.prioridade,
        fr.origem_tipo
      FROM focos_risco fr
      WHERE fr.cliente_id = p_cliente_id
        AND fr.ciclo      = p_ciclo
    ),
    focos_totais AS (
      SELECT
        COUNT(*) FILTER (WHERE origem_tipo = 'drone')                               AS detectados_drone,
        COUNT(*) FILTER (WHERE status IN ('confirmado', 'em_tratamento'))           AS confirmados,
        COUNT(*) FILTER (WHERE status = 'resolvido')                                AS resolvidos,
        COUNT(*) FILTER (WHERE status = 'descartado')                               AS descartados,
        COUNT(*) FILTER (WHERE prioridade = 'P1')                                   AS p1,
        COUNT(*) FILTER (WHERE prioridade = 'P2')                                   AS p2,
        COUNT(*) FILTER (WHERE prioridade = 'P3')                                   AS p3,
        COUNT(*) FILTER (WHERE prioridade = 'P4')                                   AS p4,
        COUNT(*) FILTER (WHERE prioridade = 'P5')                                   AS p5
      FROM focos
    )
    SELECT jsonb_build_object(
      'ciclo',               p_ciclo,
      'total_imoveis',       t.total_imoveis,
      'inspecionados',       t.inspecionados,
      'fechados',            t.fechados,
      'iip',                 ROUND(CASE WHEN t.inspecionados > 0
                               THEN t.imoveis_com_foco::numeric / t.inspecionados * 100
                               ELSE 0 END, 2),
      'ib',                  ROUND(CASE WHEN t.inspecionados > 0
                               THEN t.total_recipientes_foco::numeric / t.inspecionados * 100
                               ELSE 0 END, 2),
      'imoveis_com_foco',    t.imoveis_com_foco,
      'total_recipientes_foco', t.total_recipientes_foco,
      'classificacao_risco', CASE
        WHEN ROUND(CASE WHEN t.inspecionados > 0
             THEN t.imoveis_com_foco::numeric / t.inspecionados * 100
             ELSE 0 END, 2) < 1   THEN 'satisfatório'
        WHEN ROUND(CASE WHEN t.inspecionados > 0
             THEN t.imoveis_com_foco::numeric / t.inspecionados * 100
             ELSE 0 END, 2) < 3.9 THEN 'alerta'
        ELSE 'risco'
      END,
      'por_deposito',        (SELECT jsonb_agg(row_to_json(d)) FROM por_deposito d),
      'focos_detectados_drone',   ft.detectados_drone,
      'focos_confirmados',        ft.confirmados,
      'focos_resolvidos',         ft.resolvidos,
      'focos_descartados',        ft.descartados,
      'taxa_resolucao_focos_pct', ROUND(
        CASE WHEN (ft.confirmados + ft.resolvidos) > 0
          THEN ft.resolvidos::numeric / (ft.confirmados + ft.resolvidos) * 100
          ELSE 0 END, 1
      ),
      'focos_por_prioridade', jsonb_build_object(
        'P1', ft.p1, 'P2', ft.p2, 'P3', ft.p3, 'P4', ft.p4, 'P5', ft.p5
      )
    )
    FROM totais t
    CROSS JOIN focos_totais ft
  );
END;
$$;


