CREATE OR REPLACE FUNCTION "public"."rpc_cancelar_reinspecao"("p_reinspecao_id" "uuid", "p_motivo_cancelamento" "text" DEFAULT 'Cancelado manualmente'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_r           reinspecoes_programadas%ROWTYPE;
  v_usuario_id  uuid;
BEGIN
  SELECT * INTO v_r
  FROM   reinspecoes_programadas
  WHERE  id = p_reinspecao_id
  FOR    UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Reinspeção não encontrada');
  END IF;

  IF NOT public.usuario_pode_acessar_cliente(v_r.cliente_id) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Acesso negado');
  END IF;

  IF v_r.status NOT IN ('pendente', 'vencida') THEN
    RETURN jsonb_build_object('ok', false, 'error',
      'Só é possível cancelar reinspeções pendentes ou vencidas');
  END IF;

  -- C-02: Resolve auth.uid() → usuarios.id (FK correto para cancelado_por)
  SELECT id INTO v_usuario_id FROM usuarios WHERE auth_id = auth.uid();

  UPDATE reinspecoes_programadas
  SET
    status              = 'cancelada',
    motivo_cancelamento = p_motivo_cancelamento,
    cancelado_por       = v_usuario_id,
    updated_at          = now()
  WHERE id = p_reinspecao_id;

  RETURN jsonb_build_object('ok', true);
END;
$$;


ALTER FUNCTION "public"."rpc_cancelar_reinspecao"("p_reinspecao_id" "uuid", "p_motivo_cancelamento" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_comparativo_agentes"("p_cliente_id" "uuid", "p_ciclo" integer) RETURNS TABLE("agente_id" "uuid", "agente_nome" "text", "total_visitas" integer, "com_acesso" integer, "sem_acesso" integer, "imoveis_com_foco" integer, "larvicida_aplicado" integer, "taxa_acesso" numeric, "media_depositos_dia" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    v.agente_id,
    u.nome                                                            AS agente_nome,
    COUNT(v.id)::int                                                  AS total_visitas,
    COUNT(v.id) FILTER (WHERE v.acesso_realizado = true)::int         AS com_acesso,
    COUNT(v.id) FILTER (WHERE v.acesso_realizado = false)::int        AS sem_acesso,
    COUNT(DISTINCT v.id) FILTER (
      WHERE EXISTS (
        SELECT 1 FROM vistoria_depositos d
        WHERE d.vistoria_id = v.id AND d.qtd_com_focos > 0
      )
    )::int                                                            AS imoveis_com_foco,
    COUNT(DISTINCT v.id) FILTER (
      WHERE EXISTS (
        SELECT 1 FROM vistoria_depositos d
        WHERE d.vistoria_id = v.id AND d.usou_larvicida = true
      )
    )::int                                                            AS larvicida_aplicado,
    ROUND(
      COUNT(v.id) FILTER (WHERE v.acesso_realizado = true)::numeric
      / NULLIF(COUNT(v.id), 0) * 100, 1
    )                                                                 AS taxa_acesso,
    ROUND(
      COUNT(v.id) FILTER (WHERE v.acesso_realizado = true)::numeric
      / NULLIF(COUNT(DISTINCT v.data_visita), 0), 1
    )                                                                 AS media_depositos_dia
  FROM vistorias v
  JOIN usuarios u ON u.id = v.agente_id
  WHERE v.cliente_id = p_cliente_id
    AND v.ciclo = p_ciclo
  GROUP BY v.agente_id, u.nome
  ORDER BY total_visitas DESC;
$$;


ALTER FUNCTION "public"."rpc_comparativo_agentes"("p_cliente_id" "uuid", "p_ciclo" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_consumo_larvicida"("p_cliente_id" "uuid", "p_ciclo" integer) RETURNS TABLE("agente_id" "uuid", "agente_nome" "text", "total_larvicida_g" numeric, "total_vistorias" integer, "depositos_tratados" integer, "por_tipo" "jsonb")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  -- Pré-agregar por (agente, tipo) para evitar agregações aninhadas
  WITH base AS (
    SELECT
      v.agente_id,
      u.nome           AS agente_nome,
      v.id             AS vistoria_id,
      d.id             AS deposito_id,
      d.tipo,
      d.qtd_larvicida_g,
      d.usou_larvicida
    FROM vistorias v
    JOIN usuarios u ON u.id = v.agente_id
    JOIN vistoria_depositos d ON d.vistoria_id = v.id
    WHERE v.cliente_id = p_cliente_id
      AND v.ciclo = p_ciclo
      AND v.acesso_realizado = true
  ),
  tipo_agg AS (
    SELECT
      agente_id,
      tipo,
      COALESCE(SUM(qtd_larvicida_g) FILTER (WHERE usou_larvicida), 0) AS g_tipo
    FROM base
    WHERE tipo IS NOT NULL
    GROUP BY agente_id, tipo
  ),
  tipo_json AS (
    SELECT
      agente_id,
      jsonb_object_agg(tipo, g_tipo) AS por_tipo
    FROM tipo_agg
    GROUP BY agente_id
  )
  SELECT
    b.agente_id,
    MAX(b.agente_nome)::text                                      AS agente_nome,
    COALESCE(SUM(b.qtd_larvicida_g), 0)                          AS total_larvicida_g,
    COUNT(DISTINCT b.vistoria_id)::int                            AS total_vistorias,
    COUNT(b.deposito_id) FILTER (WHERE b.usou_larvicida)::int     AS depositos_tratados,
    COALESCE(tj.por_tipo, '{}'::jsonb)                            AS por_tipo
  FROM base b
  LEFT JOIN tipo_json tj ON tj.agente_id = b.agente_id
  GROUP BY b.agente_id, tj.por_tipo
  ORDER BY total_larvicida_g DESC;
$$;


ALTER FUNCTION "public"."rpc_consumo_larvicida"("p_cliente_id" "uuid", "p_ciclo" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_criar_reinspecao_manual"("p_foco_risco_id" "uuid", "p_tipo" "public"."reinspecao_tipo" DEFAULT 'eficacia_pos_tratamento'::"public"."reinspecao_tipo", "p_data_prevista" timestamp with time zone DEFAULT ("now"() + '7 days'::interval), "p_responsavel_id" "uuid" DEFAULT NULL::"uuid", "p_observacao" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_f           focos_risco%ROWTYPE;
  v_id          uuid;
  v_usuario_id  uuid;
BEGIN
  SELECT * INTO v_f FROM focos_risco WHERE id = p_foco_risco_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Foco não encontrado');
  END IF;

  IF NOT public.usuario_pode_acessar_cliente(v_f.cliente_id) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Acesso negado');
  END IF;

  IF v_f.status NOT IN ('confirmado', 'em_tratamento') THEN
    RETURN jsonb_build_object('ok', false, 'error',
      'Reinspeção só pode ser criada para focos confirmados ou em tratamento');
  END IF;

  IF p_data_prevista < now() THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Data prevista não pode ser no passado');
  END IF;

  -- C-02: Resolve auth.uid() → usuarios.id (FK correto para criado_por)
  SELECT id INTO v_usuario_id FROM usuarios WHERE auth_id = auth.uid();

  INSERT INTO reinspecoes_programadas (
    cliente_id, foco_risco_id, status, tipo, origem,
    data_prevista, responsavel_id, observacao, criado_por
  )
  VALUES (
    v_f.cliente_id, p_foco_risco_id, 'pendente', p_tipo, 'manual',
    p_data_prevista, p_responsavel_id, p_observacao, v_usuario_id
  )
  ON CONFLICT (foco_risco_id, tipo) WHERE (status = 'pendente')
  DO UPDATE SET
    data_prevista  = EXCLUDED.data_prevista,
    responsavel_id = EXCLUDED.responsavel_id,
    observacao     = COALESCE(EXCLUDED.observacao, reinspecoes_programadas.observacao),
    origem         = 'manual',
    updated_at     = now()
  RETURNING id INTO v_id;

  RETURN jsonb_build_object('ok', true, 'id', v_id);
END;
$$;


ALTER FUNCTION "public"."rpc_criar_reinspecao_manual"("p_foco_risco_id" "uuid", "p_tipo" "public"."reinspecao_tipo", "p_data_prevista" timestamp with time zone, "p_responsavel_id" "uuid", "p_observacao" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_reagendar_reinspecao"("p_reinspecao_id" "uuid", "p_nova_data" timestamp with time zone, "p_responsavel_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_r reinspecoes_programadas%ROWTYPE;
BEGIN
  SELECT * INTO v_r
  FROM   reinspecoes_programadas
  WHERE  id = p_reinspecao_id
  FOR    UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Reinspeção não encontrada');
  END IF;

  IF NOT public.usuario_pode_acessar_cliente(v_r.cliente_id) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Acesso negado');
  END IF;

  IF v_r.status NOT IN ('pendente', 'vencida') THEN
    RETURN jsonb_build_object('ok', false, 'error',
      'Só é possível reagendar reinspeções pendentes ou vencidas');
  END IF;

  IF p_nova_data < now() THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Nova data não pode ser no passado');
  END IF;

  UPDATE reinspecoes_programadas
  SET
    status         = 'pendente',      -- vencida volta para pendente ao reagendar
    data_prevista  = p_nova_data,
    responsavel_id = COALESCE(p_responsavel_id, responsavel_id),
    updated_at     = now()
  WHERE id = p_reinspecao_id;

  RETURN jsonb_build_object('ok', true);
END;
$$;


ALTER FUNCTION "public"."rpc_reagendar_reinspecao"("p_reinspecao_id" "uuid", "p_nova_data" timestamp with time zone, "p_responsavel_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_registrar_reinspecao_resultado"("p_reinspecao_id" "uuid", "p_resultado" "public"."reinspecao_resultado", "p_observacao" "text" DEFAULT NULL::"text", "p_data_realizada" timestamp with time zone DEFAULT "now"()) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_r reinspecoes_programadas%ROWTYPE;
  v_f focos_risco%ROWTYPE;
BEGIN
  -- Bloqueia e carrega a reinspeção
  SELECT * INTO v_r
  FROM   reinspecoes_programadas
  WHERE  id = p_reinspecao_id
  FOR    UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Reinspeção não encontrada');
  END IF;

  -- Verifica acesso multi-tenant
  IF NOT public.usuario_pode_acessar_cliente(v_r.cliente_id) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Acesso negado');
  END IF;

  -- Só pode registrar resultado em pendente ou vencida
  IF v_r.status NOT IN ('pendente', 'vencida') THEN
    RETURN jsonb_build_object('ok', false, 'error',
      'Reinspeção não está em estado executável (status atual: ' || v_r.status || ')');
  END IF;

  SELECT * INTO v_f FROM focos_risco WHERE id = v_r.foco_risco_id;

  UPDATE reinspecoes_programadas
  SET
    status         = 'realizada',
    resultado      = p_resultado,
    observacao     = COALESCE(p_observacao, observacao),
    data_realizada = p_data_realizada,
    updated_at     = now()
  WHERE id = p_reinspecao_id;

  RETURN jsonb_build_object(
    'ok',               true,
    'reinspecao_id',    p_reinspecao_id,
    'resultado',        p_resultado,
    'foco_id',          v_r.foco_risco_id,
    'foco_status',      v_f.status,
    -- Sinaliza para o frontend que o foco pode ser resolvido agora
    'pode_resolver_foco', (
      p_resultado = 'resolvido'
      AND v_f.status = 'em_tratamento'
    )
  );
END;
$$;


ALTER FUNCTION "public"."rpc_registrar_reinspecao_resultado"("p_reinspecao_id" "uuid", "p_resultado" "public"."reinspecao_resultado", "p_observacao" "text", "p_data_realizada" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_resumo_regional"("p_cliente_id" "uuid", "p_ciclo" integer DEFAULT NULL::integer, "p_de" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_ate" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.usuario_pode_acessar_cliente(p_cliente_id) THEN
    RAISE EXCEPTION 'Acesso negado ao cliente %', p_cliente_id
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  RETURN (
    WITH focos AS (
      SELECT
        fr.regiao_id,
        r.regiao AS regiao_nome,
        fr.status,
        fr.origem_tipo,
        fr.resolvido_em,
        fr.suspeita_em,
        fr.confirmado_em,
        sla.prazo_final,
        sla.violado AS sla_violado
      FROM focos_risco fr
      LEFT JOIN regioes r ON r.id = fr.regiao_id
      LEFT JOIN sla_operacional sla ON sla.foco_risco_id = fr.id
      WHERE fr.cliente_id = p_cliente_id
        AND (p_ciclo IS NULL OR fr.ciclo = p_ciclo)
        AND (p_de    IS NULL OR fr.suspeita_em >= p_de)
        AND (p_ate   IS NULL OR fr.suspeita_em <= p_ate)
    ),
    por_regiao AS (
      SELECT
        regiao_id,
        regiao_nome,
        COUNT(*) AS total_focos,
        COUNT(*) FILTER (WHERE status = 'resolvido') AS focos_resolvidos,
        COUNT(*) FILTER (WHERE status NOT IN ('resolvido','descartado')) AS focos_ativos,
        COUNT(*) FILTER (WHERE status = 'descartado') AS focos_descartados,
        ROUND(
          CASE WHEN COUNT(*) FILTER (WHERE origem_tipo = 'drone') > 0
            THEN COUNT(*) FILTER (WHERE origem_tipo = 'drone' AND status = 'descartado')::numeric
                 / COUNT(*) FILTER (WHERE origem_tipo = 'drone') * 100
            ELSE 0 END, 1
        ) AS taxa_falso_positivo_drone,
        ROUND(AVG(
          CASE WHEN resolvido_em IS NOT NULL
            THEN EXTRACT(EPOCH FROM (resolvido_em - COALESCE(confirmado_em, suspeita_em))) / 3600.0
          END
        )::numeric, 2) AS media_tempo_tratamento_horas,
        COUNT(*) FILTER (WHERE sla_violado = true) AS sla_violado_count
      FROM focos
      GROUP BY regiao_id, regiao_nome
    )
    SELECT jsonb_agg(
      jsonb_build_object(
        'regiao_id',                    regiao_id,
        'regiao_nome',                  regiao_nome,
        'total_focos',                  total_focos,
        'focos_resolvidos',             focos_resolvidos,
        'focos_ativos',                 focos_ativos,
        'focos_descartados',            focos_descartados,
        'taxa_falso_positivo_drone',    taxa_falso_positivo_drone,
        'media_tempo_tratamento_horas', media_tempo_tratamento_horas,
        'sla_violado_count',            sla_violado_count
      )
      ORDER BY total_focos DESC
    )
    FROM por_regiao
  );
END;
$$;


ALTER FUNCTION "public"."rpc_resumo_regional"("p_cliente_id" "uuid", "p_ciclo" integer, "p_de" timestamp with time zone, "p_ate" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."rpc_resumo_regional"("p_cliente_id" "uuid", "p_ciclo" integer, "p_de" timestamp with time zone, "p_ate" timestamp with time zone) IS 'Resumo agregado por regiao: total/resolvidos/ativos/descartados, taxa de falso positivo drone, media de tempo de tratamento, SLA violados. Filtros: p_ciclo (opcional), p_de/p_ate (intervalo em suspeita_em). Fix 20260903000000: tenant check adicionado.';



CREATE OR REPLACE FUNCTION "public"."rpc_score_surto_regioes"("p_cliente_id" "uuid") RETURNS TABLE("regiao_id" "uuid", "regiao_nome" "text", "score_total" numeric, "classificacao" "text", "score_pluvio" numeric, "score_recorrencia" numeric, "score_casos" numeric, "score_sla_vencido" numeric, "total_casos_14d" integer, "total_focos_rec" integer, "prob_pluvio_max" numeric, "sla_vencidos" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.usuario_pode_acessar_cliente(p_cliente_id) THEN
    RAISE EXCEPTION 'rpc_score_surto_regioes: acesso negado ao cliente'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  RETURN QUERY
  WITH
  pluvio AS (
    SELECT
      poi.bairro_nome,
      r.id AS regiao_id,
      COALESCE(MAX(poi.prob_final_max), 0) AS prob_pluvio
    FROM pluvio_operacional_run por
    JOIN pluvio_operacional_item poi ON poi.run_id = por.id
    LEFT JOIN regioes r ON r.regiao ILIKE poi.bairro_nome
      AND r.cliente_id = p_cliente_id
    WHERE por.cliente_id = p_cliente_id
      AND por.dt_ref = (
        SELECT MAX(dt_ref) FROM pluvio_operacional_run
        WHERE cliente_id = p_cliente_id
      )
    GROUP BY poi.bairro_nome, r.id
  ),
  recorrencia AS (
    SELECT
      fr.regiao_id,
      COUNT(*)::bigint AS total_recorrentes
    FROM focos_risco fr
    WHERE fr.cliente_id = p_cliente_id
      AND fr.regiao_id IS NOT NULL
      AND fr.deleted_at IS NULL
      AND fr.foco_anterior_id IS NOT NULL
    GROUP BY fr.regiao_id
  ),
  casos AS (
    SELECT
      cn.regiao_id,
      COUNT(*) AS total_casos
    FROM casos_notificados cn
    WHERE cn.cliente_id = p_cliente_id
      AND cn.deleted_at IS NULL
      AND cn.data_notificacao >= (now() - interval '14 days')::date
      AND cn.regiao_id IS NOT NULL
    GROUP BY cn.regiao_id
  ),
  sla_venc AS (
    SELECT
      u.regiao_id,
      COUNT(DISTINCT u.sla_id) AS sla_vencidos
    FROM (
      SELECT p.regiao_id AS regiao_id, so.id AS sla_id
      FROM sla_operacional so
      JOIN levantamento_itens li ON li.id = so.levantamento_item_id
        AND li.deleted_at IS NULL
      JOIN levantamentos lev ON lev.id = li.levantamento_id
      JOIN planejamento p ON p.id = lev.planejamento_id
      WHERE so.cliente_id = p_cliente_id
        AND so.status = 'vencido'
        AND so.deleted_at IS NULL
        AND p.regiao_id IS NOT NULL
        AND so.prazo_final >= now() - interval '30 days'
        AND so.levantamento_item_id IS NOT NULL

      UNION

      SELECT fr.regiao_id, so.id
      FROM sla_operacional so
      JOIN focos_risco fr ON fr.id = so.foco_risco_id
        AND fr.deleted_at IS NULL
      WHERE so.cliente_id = p_cliente_id
        AND so.status = 'vencido'
        AND so.deleted_at IS NULL
        AND fr.regiao_id IS NOT NULL
        AND so.prazo_final >= now() - interval '30 days'
        AND so.foco_risco_id IS NOT NULL
    ) u
    GROUP BY u.regiao_id
  )
  SELECT
    reg.id                                            AS regiao_id,
    reg.regiao                                        AS regiao_nome,
    ROUND(
      LEAST(100,
        COALESCE(p.prob_pluvio, 0) * 0.3 +
        LEAST(100, COALESCE(rec.total_recorrentes, 0) * 5) * 0.3 +
        LEAST(100, COALESCE(c.total_casos, 0) * 10) * 0.25 +
        LEAST(100, COALESCE(sv.sla_vencidos, 0) * 8) * 0.15
      ), 1
    )                                                 AS score_total,
    CASE
      WHEN LEAST(100, COALESCE(p.prob_pluvio,0)*0.3 + LEAST(100,COALESCE(rec.total_recorrentes,0)*5)*0.3 + LEAST(100,COALESCE(c.total_casos,0)*10)*0.25 + LEAST(100,COALESCE(sv.sla_vencidos,0)*8)*0.15) >= 80 THEN 'crítico'
      WHEN LEAST(100, COALESCE(p.prob_pluvio,0)*0.3 + LEAST(100,COALESCE(rec.total_recorrentes,0)*5)*0.3 + LEAST(100,COALESCE(c.total_casos,0)*10)*0.25 + LEAST(100,COALESCE(sv.sla_vencidos,0)*8)*0.15) >= 60 THEN 'alto'
      WHEN LEAST(100, COALESCE(p.prob_pluvio,0)*0.3 + LEAST(100,COALESCE(rec.total_recorrentes,0)*5)*0.3 + LEAST(100,COALESCE(c.total_casos,0)*10)*0.25 + LEAST(100,COALESCE(sv.sla_vencidos,0)*8)*0.15) >= 30 THEN 'moderado'
      ELSE 'baixo'
    END                                               AS classificacao,
    ROUND(COALESCE(p.prob_pluvio, 0) * 0.3, 1)      AS score_pluvio,
    ROUND(LEAST(100, COALESCE(rec.total_recorrentes, 0) * 5) * 0.3, 1) AS score_recorrencia,
    ROUND(LEAST(100, COALESCE(c.total_casos, 0) * 10) * 0.25, 1)       AS score_casos,
    ROUND(LEAST(100, COALESCE(sv.sla_vencidos, 0) * 8) * 0.15, 1)      AS score_sla_vencido,
    COALESCE(c.total_casos, 0)::int                   AS total_casos_14d,
    COALESCE(rec.total_recorrentes, 0)::int           AS total_focos_rec,
    COALESCE(p.prob_pluvio, 0)                        AS prob_pluvio_max,
    COALESCE(sv.sla_vencidos, 0)::int                 AS sla_vencidos
  FROM regioes reg
  LEFT JOIN pluvio p ON p.regiao_id = reg.id
  LEFT JOIN recorrencia rec ON rec.regiao_id = reg.id
  LEFT JOIN casos c ON c.regiao_id = reg.id
  LEFT JOIN sla_venc sv ON sv.regiao_id = reg.id
  WHERE reg.cliente_id = p_cliente_id
  ORDER BY score_total DESC;
END;
$$;


ALTER FUNCTION "public"."rpc_score_surto_regioes"("p_cliente_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."rpc_score_surto_regioes"("p_cliente_id" "uuid") IS 'Score preditivo de surto por região: pluvio, reincidência focos_risco (foco_anterior_id), casos 14d, SLA vencido (item legado + foco). Tenant: usuario_pode_acessar_cliente.';



CREATE OR REPLACE FUNCTION "public"."rpc_transicionar_foco_risco"("p_foco_id" "uuid", "p_status_novo" "text", "p_motivo" "text" DEFAULT NULL::"text", "p_responsavel_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_foco   focos_risco;
  v_papel  text;
  v_ativo  boolean;
BEGIN
  -- Obter papel e status ativo do chamador
  -- usuarios.papel_app foi removida; papel canônico vem de papeis_usuarios.papel
  SELECT pu.papel, u.ativo
  INTO   v_papel, v_ativo
  FROM   usuarios u
  LEFT JOIN papeis_usuarios pu ON pu.usuario_id = u.auth_id
  WHERE  u.auth_id = auth.uid();

  -- C-02: NULL guard — usuário sem linha em usuarios
  IF v_papel IS NULL THEN
    RAISE EXCEPTION 'Usuário sem papel definido — acesso negado'
      USING ERRCODE = 'P0001';
  END IF;

  -- C-05: ativo check — JWT pode ficar válido por até 1h após desativação
  IF NOT COALESCE(v_ativo, false) THEN
    RAISE EXCEPTION 'Usuário inativo — acesso negado'
      USING ERRCODE = 'P0001';
  END IF;

  -- Obter foco
  SELECT * INTO v_foco FROM focos_risco WHERE id = p_foco_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Foco não encontrado: %', p_foco_id;
  END IF;

  -- Validar acesso de tenant
  IF NOT usuario_pode_acessar_cliente(v_foco.cliente_id) THEN
    RAISE EXCEPTION 'Acesso negado ao foco %', p_foco_id;
  END IF;

  -- Admin e supervisor NÃO executam transições de campo
  IF v_papel IN ('admin', 'supervisor') THEN
    RAISE EXCEPTION
      'Papel % não executa transições de campo. Supervisores usam rpc_atribuir_agente_foco.',
      v_papel
      USING ERRCODE = 'P0001';
  END IF;

  -- Apenas agentes executam transições operacionais
  IF v_papel != 'agente' THEN
    RAISE EXCEPTION 'Papel % não autorizado a transicionar focos',
      v_papel USING ERRCODE = 'P0001';
  END IF;

  IF v_foco.status NOT IN ('aguarda_inspecao', 'em_inspecao', 'confirmado', 'em_tratamento') THEN
    RAISE EXCEPTION
      'Agente só pode transicionar focos em estados operacionais. '
      'Estado atual: %. Aguarde distribuição do supervisor.',
      v_foco.status
      USING ERRCODE = 'P0001';
  END IF;

  UPDATE focos_risco
     SET status         = p_status_novo,
         desfecho       = COALESCE(p_motivo, desfecho),
         responsavel_id = COALESCE(p_responsavel_id, responsavel_id)
   WHERE id = p_foco_id
  RETURNING * INTO v_foco;

  RETURN jsonb_build_object(
    'id',            v_foco.id,
    'status',        v_foco.status,
    'confirmado_em', v_foco.confirmado_em,
    'resolvido_em',  v_foco.resolvido_em,
    'updated_at',    v_foco.updated_at
  );
END;
$$;


ALTER FUNCTION "public"."rpc_transicionar_foco_risco"("p_foco_id" "uuid", "p_status_novo" "text", "p_motivo" "text", "p_responsavel_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."rpc_transicionar_foco_risco"("p_foco_id" "uuid", "p_status_novo" "text", "p_motivo" "text", "p_responsavel_id" "uuid") IS 'Transiciona o estado de um foco_risco. Exclusivo para agentes ativos. Admin e supervisor NÃO têm acesso. Guards: NULL papel (C-02), ativo=false (C-05), papel != agente, estado operacional.';



