CREATE OR REPLACE FUNCTION "public"."sla_aplicar_fatores"("p_horas_base" integer, "p_config" "jsonb", "p_classificacao_risco" "text", "p_persistencia_7d" "text", "p_temp_media_c" numeric) RETURNS integer
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_horas numeric := p_horas_base;
  v_fatores jsonb;
  v_risco_pct int;
  v_pers_pct int;
  v_temp_pct int;
  v_pers_num int;
BEGIN
  v_fatores := coalesce(p_config->'fatores', '{}'::jsonb);
  v_risco_pct := coalesce((v_fatores->>'risco_muito_alto_pct')::int, 30);
  v_pers_pct := coalesce((v_fatores->>'persistencia_pct')::int, 20);
  v_temp_pct := coalesce((v_fatores->>'temperatura_pct')::int, 10);

  -- Risco "Muito Alto" → reduz (ex.: 30%)
  IF p_classificacao_risco IS NOT NULL AND lower(trim(p_classificacao_risco)) = 'muito alto' THEN
    v_horas := v_horas * (1 - v_risco_pct / 100.0);
  END IF;

  -- Persistência 7d > 3 → reduz (ex.: 20%)
  v_pers_num := (regexp_replace(coalesce(p_persistencia_7d, '0'), '[^0-9]', '', 'g'))::int;
  IF v_pers_num > 3 THEN
    v_horas := v_horas * (1 - v_pers_pct / 100.0);
  END IF;

  -- Temperatura > 30 → reduz (ex.: 10%)
  IF p_temp_media_c IS NOT NULL AND p_temp_media_c > 30 THEN
    v_horas := v_horas * (1 - v_temp_pct / 100.0);
  END IF;

  RETURN greatest(2, round(v_horas)::integer);
END;
$$;


ALTER FUNCTION "public"."sla_aplicar_fatores"("p_horas_base" integer, "p_config" "jsonb", "p_classificacao_risco" "text", "p_persistencia_7d" "text", "p_temp_media_c" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sla_calcular_prazo_final"("p_inicio" timestamp with time zone, "p_sla_horas" integer, "p_config" "jsonb", "p_cliente_id" "uuid" DEFAULT NULL::"uuid") RETURNS timestamp with time zone
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_hc           jsonb;
  v_ativo        boolean;
  v_hora_inicio  time;
  v_hora_fim     time;
  v_dias_semana  int[];
  v_feriados     date[];
  v_cursor       timestamptz;
  v_horas_rest   numeric;
  v_horas_hoje   numeric;
  v_horas_dia    numeric;
BEGIN
  v_hc    := p_config -> 'horario_comercial';
  v_ativo := COALESCE((v_hc ->> 'ativo')::boolean, false);

  -- Modo simples: sem horário comercial
  IF NOT v_ativo OR v_hc IS NULL OR p_sla_horas IS NULL OR p_sla_horas <= 0 THEN
    RETURN p_inicio + (COALESCE(p_sla_horas, 0) || ' hours')::interval;
  END IF;

  v_hora_inicio := COALESCE((v_hc ->> 'inicio')::time, '08:00'::time);
  v_hora_fim    := COALESCE((v_hc ->> 'fim')::time,    '18:00'::time);
  v_horas_dia   := extract(epoch from (v_hora_fim - v_hora_inicio)) / 3600.0;

  IF v_horas_dia <= 0 THEN
    RETURN p_inicio + (p_sla_horas || ' hours')::interval;
  END IF;

  -- Dias úteis da semana (padrão: seg–sex)
  SELECT array_agg(value::int)
  INTO v_dias_semana
  FROM jsonb_array_elements_text(COALESCE(v_hc -> 'dias_semana', '[1,2,3,4,5]'::jsonb));
  v_dias_semana := COALESCE(v_dias_semana, ARRAY[1,2,3,4,5]);

  -- Feriados no período estimado (3x o prazo como margem)
  IF p_cliente_id IS NOT NULL THEN
    SELECT array_agg(data) INTO v_feriados
    FROM public.sla_feriados
    WHERE cliente_id = p_cliente_id
      AND data BETWEEN p_inicio::date
                   AND (p_inicio + ((p_sla_horas * 3) || ' hours')::interval)::date;
  END IF;
  v_feriados := COALESCE(v_feriados, ARRAY[]::date[]);

  -- Posiciona cursor no primeiro slot útil
  v_cursor    := public.sla_proximo_slot_comercial(p_inicio, v_hora_inicio, v_hora_fim, v_dias_semana, v_feriados);
  v_horas_rest := p_sla_horas;

  WHILE v_horas_rest > 0 LOOP
    -- Horas disponíveis até o fim do expediente de hoje
    v_horas_hoje := extract(epoch from (v_hora_fim - v_cursor::time)) / 3600.0;

    IF v_horas_hoje <= 0 THEN
      -- Já passou do expediente: avança para o próximo dia útil
      v_cursor := public.sla_proximo_slot_comercial(
        date_trunc('day', v_cursor) + interval '1 day' + v_hora_inicio,
        v_hora_inicio, v_hora_fim, v_dias_semana, v_feriados
      );
      CONTINUE;
    END IF;

    IF v_horas_rest <= v_horas_hoje THEN
      v_cursor     := v_cursor + (v_horas_rest || ' hours')::interval;
      v_horas_rest := 0;
    ELSE
      v_horas_rest := v_horas_rest - v_horas_hoje;
      v_cursor := public.sla_proximo_slot_comercial(
        date_trunc('day', v_cursor) + interval '1 day' + v_hora_inicio,
        v_hora_inicio, v_hora_fim, v_dias_semana, v_feriados
      );
    END IF;
  END LOOP;

  RETURN v_cursor;
END;
$$;


ALTER FUNCTION "public"."sla_calcular_prazo_final"("p_inicio" timestamp with time zone, "p_sla_horas" integer, "p_config" "jsonb", "p_cliente_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."sla_calcular_prazo_final"("p_inicio" timestamp with time zone, "p_sla_horas" integer, "p_config" "jsonb", "p_cliente_id" "uuid") IS 'Calcula prazo_final do SLA. Se horario_comercial.ativo = true, avança apenas em horário útil, respeitando dias da semana e feriados do cliente. Compatível com código anterior: quando ativo = false, retorna inicio + sla_horas simples.';



CREATE OR REPLACE FUNCTION "public"."sla_horas_from_config"("p_config" "jsonb", "p_prioridade" "text") RETURNS integer
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_horas numeric;
  v_key text;
BEGIN
  -- Tentar da config: config.prioridades[prioridade].horas
  IF p_config IS NOT NULL AND p_config ? 'prioridades' THEN
    v_key := trim(both '"' from p_prioridade);
    IF p_config->'prioridades' ? v_key THEN
      v_horas := (p_config->'prioridades'->v_key->>'horas')::numeric;
      IF v_horas IS NOT NULL AND v_horas >= 1 THEN
        RETURN greatest(2, round(v_horas)::integer);
      END IF;
    END IF;
  END IF;

  -- Padrão (mesmo do app types/sla.ts)
  v_horas := CASE
    WHEN lower(trim(p_prioridade)) IN ('crítica', 'critica', 'urgente') THEN 4
    WHEN lower(trim(p_prioridade)) = 'alta' THEN 12
    WHEN lower(trim(p_prioridade)) IN ('moderada', 'média', 'media') THEN 24
    WHEN lower(trim(p_prioridade)) IN ('baixa', 'monitoramento') THEN 72
    ELSE 72
  END;
  RETURN greatest(2, v_horas::integer);
END;
$$;


ALTER FUNCTION "public"."sla_horas_from_config"("p_config" "jsonb", "p_prioridade" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sla_proximo_slot_comercial"("p_cursor" timestamp with time zone, "p_hora_inicio" time without time zone, "p_hora_fim" time without time zone, "p_dias_semana" integer[], "p_feriados" "date"[]) RETURNS timestamp with time zone
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
DECLARE
  v_cursor    timestamptz := p_cursor;
  v_tentativas int := 0;
BEGIN
  LOOP
    -- Proteção contra loop infinito (ex.: nenhum dia útil configurado)
    v_tentativas := v_tentativas + 1;
    IF v_tentativas > 365 THEN
      RETURN v_cursor; -- fallback: retorna sem ajuste
    END IF;

    -- Verifica se o dia é útil (não é feriado e está nos dias configurados)
    IF extract(dow from v_cursor)::int = ANY(p_dias_semana)
       AND NOT (v_cursor::date = ANY(p_feriados))
    THEN
      -- Dia útil: ajusta para dentro do horário comercial
      IF v_cursor::time < p_hora_inicio THEN
        -- Antes do expediente: avança para o início
        RETURN date_trunc('day', v_cursor) + p_hora_inicio;
      ELSIF v_cursor::time >= p_hora_fim THEN
        -- Depois do expediente: vai para o início do próximo dia útil
        v_cursor := date_trunc('day', v_cursor) + interval '1 day' + p_hora_inicio;
        CONTINUE;
      ELSE
        -- Dentro do expediente
        RETURN v_cursor;
      END IF;
    ELSE
      -- Dia não útil: pula para o início do próximo dia
      v_cursor := date_trunc('day', v_cursor) + interval '1 day' + p_hora_inicio;
    END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."sla_proximo_slot_comercial"("p_cursor" timestamp with time zone, "p_hora_inicio" time without time zone, "p_hora_fim" time without time zone, "p_dias_semana" integer[], "p_feriados" "date"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."sla_proximo_slot_comercial"("p_cursor" timestamp with time zone, "p_hora_inicio" time without time zone, "p_hora_fim" time without time zone, "p_dias_semana" integer[], "p_feriados" "date"[]) IS 'Avança o cursor para o próximo momento dentro do horário comercial, respeitando dias da semana e feriados.';



CREATE OR REPLACE FUNCTION "public"."sla_regiao_do_item"("p_item_id" "uuid") RETURNS "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT p.regiao_id
  FROM levantamento_itens li
  JOIN levantamentos l      ON l.id = li.levantamento_id
  JOIN planejamento  p      ON p.id = l.planejamento_id
  WHERE li.id = p_item_id
  LIMIT 1;
$$;


ALTER FUNCTION "public"."sla_regiao_do_item"("p_item_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sla_resolve_config"("p_cliente_id" "uuid", "p_regiao_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_config jsonb;
BEGIN
  -- 1. Config por região (se fornecida)
  IF p_regiao_id IS NOT NULL THEN
    SELECT config INTO v_config
    FROM public.sla_config_regiao
    WHERE cliente_id = p_cliente_id
      AND regiao_id  = p_regiao_id
    LIMIT 1;

    IF FOUND AND v_config IS NOT NULL THEN
      RETURN v_config;
    END IF;
  END IF;

  -- 2. Config cliente-wide
  SELECT config INTO v_config
  FROM public.sla_config
  WHERE cliente_id = p_cliente_id
  LIMIT 1;

  RETURN v_config;  -- pode ser NULL (funções downstream tratam isso)
END;
$$;


ALTER FUNCTION "public"."sla_resolve_config"("p_cliente_id" "uuid", "p_regiao_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."sla_resolve_config"("p_cliente_id" "uuid", "p_regiao_id" "uuid") IS 'Retorna a config de SLA efetiva para o cliente+região. Prioridade: sla_config_regiao > sla_config (cliente-wide). Retorna NULL se nenhuma config estiver cadastrada.';



