CREATE OR REPLACE FUNCTION "public"."trg_fn_consolidar_subtabela"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_vistoria_id uuid;
BEGIN
  IF pg_trigger_depth() > 1 THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  v_vistoria_id := COALESCE(NEW.vistoria_id, OLD.vistoria_id);

  IF v_vistoria_id IS NULL THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  -- Motivo identificável no histórico por tabela e operação
  PERFORM public.fn_consolidar_vistoria(
    v_vistoria_id,
    'automático — ' || TG_OP || ' em ' || TG_TABLE_NAME
  );

  RETURN COALESCE(NEW, OLD);
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING
    '[consolidação automática] fn_consolidar_vistoria falhou: vistoria_id=%, tabela=%, op=%, erro: %',
    v_vistoria_id, TG_TABLE_NAME, TG_OP, SQLERRM;
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."trg_fn_consolidar_subtabela"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."trg_fn_consolidar_subtabela"() IS 'Wrapper de trigger para sub-tabelas. Motivo gravado no histórico: "automático — <OP> em <tabela>". Nunca cancela a operação original — erros viram WARNING.';



CREATE OR REPLACE FUNCTION "public"."trg_fn_consolidar_vistoria_auto"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Guarda de profundidade (3ª camada anti-recursão)
  IF pg_trigger_depth() > 1 THEN
    RETURN NEW;
  END IF;

  -- Motivo identificável no histórico: distingue trigger de reprocessamento manual
  PERFORM public.fn_consolidar_vistoria(
    NEW.id,
    'automático — ' || TG_OP || ' em vistorias'
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING
    '[consolidação automática] fn_consolidar_vistoria falhou: vistoria_id=%, op=%, erro: %',
    NEW.id, TG_OP, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_fn_consolidar_vistoria_auto"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."trg_fn_consolidar_vistoria_auto"() IS 'Wrapper de trigger para vistorias. Motivo gravado no histórico: "automático — <OP> em vistorias". Nunca cancela a operação original — erros viram WARNING.';



CREATE OR REPLACE FUNCTION "public"."trg_levantamento_item_criar_sla_auto"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cliente_id uuid;
  v_regiao_id  uuid;
  v_config     jsonb;
  v_horas      int;
  v_inicio     timestamptz;
BEGIN
  -- Idempotência
  IF EXISTS (
    SELECT 1 FROM public.sla_operacional
    WHERE levantamento_item_id = NEW.id
      AND status IN ('pendente', 'em_atendimento')
  ) THEN
    RETURN NEW;
  END IF;

  -- Resolve cliente e região via levantamento → planejamento
  SELECT l.cliente_id, p.regiao_id
  INTO   v_cliente_id, v_regiao_id
  FROM   public.levantamentos l
  LEFT JOIN public.planejamento p ON p.id = l.planejamento_id
  WHERE  l.id = NEW.levantamento_id;

  IF v_cliente_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF NEW.sla_horas IS NOT NULL AND NEW.sla_horas >= 1 THEN
    v_horas := NEW.sla_horas;
  ELSE
    v_config := public.sla_resolve_config(v_cliente_id, v_regiao_id);
    v_horas  := COALESCE(
      public.sla_horas_from_config(v_config, COALESCE(NEW.prioridade, 'Média')),
      24
    );
  END IF;

  v_inicio := now();

  INSERT INTO public.sla_operacional (
    levantamento_item_id, cliente_id, prioridade, sla_horas, inicio, prazo_final, status
  ) VALUES (
    NEW.id, v_cliente_id,
    COALESCE(NEW.prioridade, 'Média'),
    v_horas, v_inicio,
    public.sla_calcular_prazo_final(
      v_inicio, v_horas,
      public.sla_resolve_config(v_cliente_id, v_regiao_id),
      v_cliente_id
    ),
    'pendente'
  );

  RETURN NEW;

EXCEPTION WHEN others THEN
  INSERT INTO public.sla_erros_criacao (
    cliente_id, item_id, levantamento_item_id, erro, contexto, created_at
  ) VALUES (
    v_cliente_id, NULL, NEW.id,
    SQLERRM,
    jsonb_build_object(
      'trigger', 'trg_levantamento_item_criar_sla_auto',
      'sqlstate', SQLSTATE,
      'levantamento_id', NEW.levantamento_id
    ),
    now()
  );
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_levantamento_item_criar_sla_auto"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."trg_levantamento_item_criar_sla_auto"() IS 'S05: Cria SLA para levantamento_itens. Erros registrados em sla_erros_criacao.';



