CREATE OR REPLACE FUNCTION "public"."trg_seed_plano_acao_catalogo_on_cliente"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
