CREATE OR REPLACE FUNCTION "public"."trg_sync_total_itens"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_lev_id uuid;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_lev_id := NEW.levantamento_id;

  ELSIF TG_OP = 'DELETE' THEN
    v_lev_id := OLD.levantamento_id;

  ELSIF TG_OP = 'UPDATE' THEN
    IF OLD.levantamento_id IS DISTINCT FROM NEW.levantamento_id THEN
      -- Mudou de levantamento: atualizar o antigo
      UPDATE public.levantamentos
      SET total_itens = (
        SELECT COUNT(*) FROM public.levantamento_itens
        WHERE levantamento_id = OLD.levantamento_id
          AND deleted_at IS NULL
      )
      WHERE id = OLD.levantamento_id;
      v_lev_id := NEW.levantamento_id;
    ELSIF OLD.deleted_at IS DISTINCT FROM NEW.deleted_at THEN
      -- Soft delete/restore
      v_lev_id := NEW.levantamento_id;
    ELSE
      -- Nenhuma mudança relevante para total_itens
      RETURN COALESCE(NEW, OLD);
    END IF;
  END IF;

  UPDATE public.levantamentos
  SET total_itens = (
    SELECT COUNT(*) FROM public.levantamento_itens
    WHERE levantamento_id = v_lev_id
      AND deleted_at IS NULL
  )
  WHERE id = v_lev_id;

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."trg_sync_total_itens"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."trg_sync_total_itens"() IS 'A10: Mantém levantamentos.total_itens sincronizado em INSERT/UPDATE/DELETE/soft-delete.';



CREATE OR REPLACE FUNCTION "public"."upsert_drone_risk_config"("p_cliente_id" "uuid", "p_base_by_risco" "jsonb", "p_priority_thresholds" "jsonb", "p_sla_by_priority_hours" "jsonb", "p_item_overrides" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
begin
  insert into public.sentinela_drone_risk_config
    (cliente_id, base_by_risco, priority_thresholds, sla_by_priority_hours, item_overrides)
  values
    (p_cliente_id, p_base_by_risco, p_priority_thresholds, p_sla_by_priority_hours, p_item_overrides)
  on conflict (cliente_id) do update
    set base_by_risco         = excluded.base_by_risco,
        priority_thresholds   = excluded.priority_thresholds,
        sla_by_priority_hours = excluded.sla_by_priority_hours,
        item_overrides        = excluded.item_overrides,
        updated_at            = now()
  returning id into v_id;

  return v_id;
end;
$$;


ALTER FUNCTION "public"."upsert_drone_risk_config"("p_cliente_id" "uuid", "p_base_by_risco" "jsonb", "p_priority_thresholds" "jsonb", "p_sla_by_priority_hours" "jsonb", "p_item_overrides" "jsonb") OWNER TO "postgres";


