CREATE OR REPLACE FUNCTION "public"."usuario_cliente_id"() RETURNS "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    CASE
      WHEN auth.jwt() -> 'app_metadata' ->> 'cliente_id' IS NOT NULL
      THEN (auth.jwt() -> 'app_metadata' ->> 'cliente_id')::uuid
      ELSE (
        SELECT u.cliente_id FROM public.usuarios u
        WHERE u.auth_id = auth.uid()
        LIMIT 1
      )
    END;
$$;


ALTER FUNCTION "public"."usuario_cliente_id"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."usuario_cliente_id"() IS 'P1-1: JWT fast-path + DB fallback.';



CREATE OR REPLACE FUNCTION "public"."usuario_pode_acessar_cliente"("p_cliente_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    -- Admin: acesso global
    public.is_admin()
    -- Não-admin: cliente_id do JWT ou da tabela usuarios deve bater
    OR CASE
      WHEN auth.jwt() -> 'app_metadata' ->> 'cliente_id' IS NOT NULL
      THEN (auth.jwt() -> 'app_metadata' ->> 'cliente_id')::uuid = p_cliente_id
      ELSE EXISTS (
        SELECT 1 FROM public.usuarios u
        WHERE u.auth_id    = auth.uid()
          AND u.cliente_id = p_cliente_id
      )
    END;
$$;


ALTER FUNCTION "public"."usuario_pode_acessar_cliente"("p_cliente_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."usuario_pode_acessar_cliente"("p_cliente_id" "uuid") IS 'P1-1: JWT fast-path + DB fallback. Admin bypassa tenant check.';



CREATE OR REPLACE FUNCTION "public"."usuario_pode_acessar_risk_policy"("p_policy_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM sentinela_risk_policy p
    WHERE p.id = p_policy_id
    AND public.usuario_pode_acessar_cliente(p.cliente_id)
  );
$$;


