CREATE TABLE IF NOT EXISTS "public"."focos_risco" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "cliente_id" "uuid" NOT NULL,
    "imovel_id" "uuid",
    "regiao_id" "uuid",
    "origem_tipo" "text" NOT NULL,
    "origem_levantamento_item_id" "uuid",
    "origem_vistoria_id" "uuid",
    "status" "text" DEFAULT 'suspeita'::"text" NOT NULL,
    "prioridade" "text",
    "ciclo" integer,
    "latitude" double precision,
    "longitude" double precision,
    "endereco_normalizado" "text",
    "suspeita_em" timestamp with time zone DEFAULT "now"() NOT NULL,
    "confirmado_em" timestamp with time zone,
    "resolvido_em" timestamp with time zone,
    "responsavel_id" "uuid",
    "desfecho" "text",
    "foco_anterior_id" "uuid",
    "casos_ids" "uuid"[] DEFAULT '{}'::"uuid"[] NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "prioridade_original_antes_caso" "text",
    "deleted_at" timestamp with time zone,
    "deleted_by" "uuid",
    "created_by" "uuid",
    "observacao" "text",
    "classificacao_inicial" "text" DEFAULT 'suspeito'::"text" NOT NULL,
    "dados_minimos_em" timestamp with time zone,
    "inspecao_em" timestamp with time zone,
    "payload" "jsonb" DEFAULT '{}'::"jsonb",
    "score_prioridade" integer DEFAULT 0 NOT NULL,
    "codigo_foco" "text",
    CONSTRAINT "focos_risco_ciclo_check" CHECK ((("ciclo" >= 1) AND ("ciclo" <= 6))),
    CONSTRAINT "focos_risco_classificacao_inicial_check" CHECK (("classificacao_inicial" = ANY (ARRAY['suspeito'::"text", 'risco'::"text", 'foco'::"text", 'caso_notificado'::"text"]))),
    CONSTRAINT "focos_risco_origem_tipo_check" CHECK (("origem_tipo" = ANY (ARRAY['drone'::"text", 'agente'::"text", 'cidadao'::"text", 'pluvio'::"text", 'manual'::"text"]))),
    CONSTRAINT "focos_risco_prioridade_check" CHECK (("prioridade" = ANY (ARRAY['P1'::"text", 'P2'::"text", 'P3'::"text", 'P4'::"text", 'P5'::"text"]))),
    CONSTRAINT "focos_risco_prioridade_original_antes_caso_check" CHECK (("prioridade_original_antes_caso" = ANY (ARRAY['P1'::"text", 'P2'::"text", 'P3'::"text", 'P4'::"text", 'P5'::"text"]))),
    CONSTRAINT "focos_risco_status_check" CHECK (("status" = ANY (ARRAY['suspeita'::"text", 'em_triagem'::"text", 'aguarda_inspecao'::"text", 'em_inspecao'::"text", 'confirmado'::"text", 'em_tratamento'::"text", 'resolvido'::"text", 'descartado'::"text"])))
);

ALTER TABLE ONLY "public"."focos_risco" REPLICA IDENTITY FULL;


ALTER TABLE "public"."focos_risco" OWNER TO "postgres";


COMMENT ON TABLE "public"."focos_risco" IS 'Aggregate Root do evento de risco territorial. State machine com 7 estados. Nasce na suspeita, termina em resolvido/descartado. SLA inicia em confirmado_em. Recorrência = novo foco com foco_anterior_id preenchido.';



COMMENT ON COLUMN "public"."focos_risco"."endereco_normalizado" IS 'Único campo texto de endereço nesta tabela. Derivado de imoveis.logradouro quando imovel_id existir. Nunca duplicar endereço de outras tabelas aqui.';



COMMENT ON COLUMN "public"."focos_risco"."foco_anterior_id" IS 'Preenchido quando este foco representa recorrência no mesmo imóvel. Descartados/resolvidos são terminais — novo foco_risco é criado, não reabrimos.';



COMMENT ON COLUMN "public"."focos_risco"."casos_ids" IS 'Array de caso_notificado.id próximos a este foco (raio 300m). Mantido pelo trigger de cruzamento — não editar manualmente.';



COMMENT ON COLUMN "public"."focos_risco"."prioridade_original_antes_caso" IS 'Prioridade antes de ser elevada para P1 pela proximidade de caso notificado. Usada por fn_reverter_prioridade_caso_descartado para restaurar o valor original.';



COMMENT ON COLUMN "public"."focos_risco"."deleted_at" IS 'Soft delete — timestamp de exclusão lógica. Registros não nulos ficam ocultos nas views operacionais. (QW-10A)';



COMMENT ON COLUMN "public"."focos_risco"."deleted_by" IS 'UUID do usuário que executou o soft delete. (QW-10A)';



COMMENT ON COLUMN "public"."focos_risco"."observacao" IS 'Observação livre do operador sobre o atendimento do foco. Persistida via api.itens.updateObservacaoAtendimento (busca foco por origem_levantamento_item_id) ou diretamente via api.focosRisco.update.';



COMMENT ON COLUMN "public"."focos_risco"."dados_minimos_em" IS 'Timestamp da 1ª vez que o foco passou a ter dados mínimos completos. Preenchido automaticamente pelo trigger trg_dados_minimos_auto_registrar. Nunca editar manualmente.';



COMMENT ON COLUMN "public"."focos_risco"."payload" IS 'Metadados extras por origem_tipo. Ex: {foto_url, foto_public_id, confirmacoes, fonte} para origem=cidadao.';



COMMENT ON COLUMN "public"."focos_risco"."score_prioridade" IS 'Score inteiro de prioridade calculado automaticamente. Componentes: SLA inteligente (10–50), reincidência (+20), casos próximos (+5/caso, max 30). Atualizado por trg_recalcular_score_prioridade. Zerado ao encerrar.';



COMMENT ON COLUMN "public"."focos_risco"."codigo_foco" IS 'Identificador legível no formato YYYY-NNNNNNNN. Único por (cliente_id, codigo_foco). Gerado automaticamente pelo trigger trg_set_codigo_foco via fn_gerar_codigo_foco.';



