CREATE TABLE IF NOT EXISTS "public"."pipeline_runs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "cliente_id" "uuid" NOT NULL,
    "voo_id" "uuid",
    "levantamento_id" "uuid",
    "status" "text" DEFAULT 'em_andamento'::"text" NOT NULL,
    "total_imagens" integer,
    "imagens_processadas" integer,
    "itens_gerados" integer,
    "focos_criados" integer,
    "erro_mensagem" "text",
    "erro_detalhe" "jsonb",
    "versao_pipeline" "text",
    "iniciado_em" timestamp with time zone DEFAULT "now"() NOT NULL,
    "concluido_em" timestamp with time zone,
    "duracao_s" integer GENERATED ALWAYS AS (
CASE
    WHEN ("concluido_em" IS NOT NULL) THEN (EXTRACT(epoch FROM ("concluido_em" - "iniciado_em")))::integer
    ELSE NULL::integer
END) STORED,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "pipeline_runs_status_check" CHECK (("status" = ANY (ARRAY['em_andamento'::"text", 'concluido'::"text", 'erro'::"text", 'parcial'::"text"])))
);


