CREATE OR REPLACE VIEW "public"."pluvio_operacional_latest" WITH ("security_invoker"='on') AS
 SELECT "r"."id" AS "run_id",
    "r"."cliente_id",
    "r"."dt_ref",
    "r"."dt_gerado",
    "r"."total_bairros",
    "i"."id" AS "item_id",
    "i"."regiao_id",
    "i"."bairro_nome",
    "i"."classificacao_risco",
    "i"."situacao_ambiental",
    "i"."chuva_24h_mm",
    "i"."chuva_72h_mm",
    "i"."chuva_7d_mm",
    "i"."dias_com_chuva_7d",
    "i"."janela_sem_chuva",
    "i"."persistencia_7d",
    "i"."tendencia",
    "i"."temp_media_c",
    "i"."vento_medio_kmh",
    "i"."prob_label",
    "i"."prob_final_min",
    "i"."prob_final_max",
    "i"."criadouro_ativo",
    "i"."prioridade_operacional",
    "i"."prazo_acao"
   FROM ("public"."pluvio_operacional_run" "r"
     JOIN "public"."pluvio_operacional_item" "i" ON (("i"."run_id" = "r"."id")))
  WHERE ("r"."dt_ref" = ( SELECT "max"("r2"."dt_ref") AS "max"
           FROM "public"."pluvio_operacional_run" "r2"
          WHERE ("r2"."cliente_id" = "r"."cliente_id")));


ALTER VIEW "public"."pluvio_operacional_latest" OWNER TO "postgres";


COMMENT ON VIEW "public"."pluvio_operacional_latest" IS 'Itens do último run pluvio por cliente (join run + item, filtrado pelo dt_ref mais recente).';



