ALTER TABLE "public"."sla_erros_criacao" OWNER TO "postgres";


COMMENT ON TABLE "public"."sla_erros_criacao" IS 'Registra falhas na criação automática de SLA. Populado pelos triggers trg_pluvio_item_criar_sla_auto (item_id) e trg_levantamento_item_criar_sla_auto (levantamento_item_id). Colunas: cliente_id, item_id, levantamento_item_id, erro, contexto, created_at, criado_em.';



COMMENT ON COLUMN "public"."sla_erros_criacao"."retention_until" IS 'Data limite de retenção. Purga automática após 90 dias — log técnico sem valor probatório de longo prazo. (QW-10C)';



COMMENT ON COLUMN "public"."sla_erros_criacao"."cliente_id" IS 'Prefeitura do item; preenchido pelo trigger e backfill para filtro RLS/API.';



COMMENT ON COLUMN "public"."sla_erros_criacao"."item_id" IS 'FIX-02: ID do pluvio_operacional_item quando o erro vem do trigger de SLA pluviométrico.';



COMMENT ON COLUMN "public"."sla_erros_criacao"."contexto" IS 'FIX-02: Payload JSONB com detalhes do erro (prioridade, sla_horas, inicio, prazo_final, status).';



COMMENT ON COLUMN "public"."sla_erros_criacao"."created_at" IS 'FIX-02: Alias padronizado de criado_em; usado pelos triggers S05 nos INSERTs.';



