    "sla_horas" integer NOT NULL,
    "inicio" timestamp with time zone DEFAULT "now"() NOT NULL,
    "prazo_final" timestamp with time zone NOT NULL,
    "concluido_em" timestamp with time zone,
    "status" "text" DEFAULT 'pendente'::"text" NOT NULL,
    "violado" boolean DEFAULT false,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "escalonado" boolean DEFAULT false,
    "escalonado_em" timestamp with time zone,
    "prioridade_original" "text",
    "cliente_id" "uuid",
    "levantamento_item_id" "uuid",
    "escalonado_automatico" boolean DEFAULT false NOT NULL,
    "foco_risco_id" "uuid",
    "escalado_por" "uuid",
    "reaberto_por" "uuid",
