    "deleted_by" "uuid",
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chk_sla_prioridade" CHECK (("prioridade" = ANY (ARRAY['Crítica'::"text", 'Critica'::"text", 'Crítico'::"text", 'Critico'::"text", 'Urgente'::"text", 'Alta'::"text", 'Moderada'::"text", 'Média'::"text", 'Media'::"text", 'Baixa'::"text", 'Monitoramento'::"text", 'P1'::"text", 'P2'::"text", 'P3'::"text", 'P4'::"text", 'P5'::"text"]))),
    CONSTRAINT "sla_operacional_item_exclusivo" CHECK ((("num_nonnulls"("item_id", "levantamento_item_id") = 1) OR (("item_id" IS NULL) AND ("levantamento_item_id" IS NULL) AND ("foco_risco_id" IS NOT NULL))))
);


