CREATE OR REPLACE VIEW "public"."v_billing_resumo" WITH ("security_invoker"='on') AS
 SELECT "c"."id" AS "cliente_id",
    "c"."nome" AS "cliente_nome",
    "cp"."plano_id",
    "pl"."nome" AS "plano_nome",
    "cp"."status" AS "plano_status",
    "cp"."contrato_ref",
    "cp"."data_inicio",
    "cp"."data_fim",
    "bus"."periodo_inicio" AS "ultimo_snapshot_inicio",
    "bus"."vistorias_mes",
    "bus"."levantamentos_mes",
    "bus"."itens_focos_mes",
    "bus"."ia_calls_mes",
    "bus"."storage_gb",
    "bus"."usuarios_ativos_mes",
    "bus"."calculado_em" AS "snapshot_calculado_em",
    COALESCE((("cp"."limites_personalizados" ->> 'limite_vistorias_mes'::"text"))::integer, "pl"."limite_vistorias_mes") AS "limite_vistorias_mes",
    COALESCE((("cp"."limites_personalizados" ->> 'limite_ia_calls_mes'::"text"))::integer, "pl"."limite_ia_calls_mes") AS "limite_ia_calls_mes",
    COALESCE((("cp"."limites_personalizados" ->> 'limite_storage_gb'::"text"))::numeric, "pl"."limite_storage_gb") AS "limite_storage_gb",
    COALESCE((("cp"."limites_personalizados" ->> 'limite_usuarios'::"text"))::integer, "pl"."limite_usuarios") AS "limite_usuarios"
   FROM ((("public"."clientes" "c"
     LEFT JOIN "public"."cliente_plano" "cp" ON (("cp"."cliente_id" = "c"."id")))
     LEFT JOIN "public"."planos" "pl" ON (("pl"."id" = "cp"."plano_id")))
     LEFT JOIN LATERAL ( SELECT "billing_usage_snapshot"."id",
            "billing_usage_snapshot"."cliente_id",
            "billing_usage_snapshot"."billing_ciclo_id",
            "billing_usage_snapshot"."periodo_inicio",
            "billing_usage_snapshot"."periodo_fim",
            "billing_usage_snapshot"."vistorias_mes",
            "billing_usage_snapshot"."levantamentos_mes",
            "billing_usage_snapshot"."itens_focos_mes",
            "billing_usage_snapshot"."voos_mes",
            "billing_usage_snapshot"."denuncias_mes",
            "billing_usage_snapshot"."ia_calls_mes",
            "billing_usage_snapshot"."relatorios_mes",
            "billing_usage_snapshot"."syncs_cnes_mes",
            "billing_usage_snapshot"."notificacoes_esus_mes",
            "billing_usage_snapshot"."usuarios_ativos_mes",
            "billing_usage_snapshot"."imoveis_total",
            "billing_usage_snapshot"."storage_gb",
            "billing_usage_snapshot"."calculado_em",
            "billing_usage_snapshot"."payload_detalhado"
           FROM "public"."billing_usage_snapshot"
          WHERE ("billing_usage_snapshot"."cliente_id" = "c"."id")
          ORDER BY "billing_usage_snapshot"."periodo_inicio" DESC
         LIMIT 1) "bus" ON (true))
  WHERE ("c"."deleted_at" IS NULL);


ALTER VIEW "public"."v_billing_resumo" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_billing_resumo" IS 'Resumo de billing por cliente: plano contratado + snapshot mais recente + limites efetivos.';



CREATE OR REPLACE VIEW "public"."v_central_operacional" WITH ("security_invoker"='true') AS
 SELECT "cliente_id",
    CURRENT_DATE AS "data_ref",
    ( SELECT "count"(*) AS "count"
           FROM "public"."focos_risco" "fr"
          WHERE (("fr"."cliente_id" = "u"."cliente_id") AND ("fr"."status" = ANY (ARRAY['suspeita'::"text", 'em_triagem'::"text", 'aguarda_inspecao'::"text", 'em_inspecao'::"text"])) AND ("fr"."deleted_at" IS NULL))) AS "focos_pendentes",
    ( SELECT "count"(*) AS "count"
           FROM "public"."focos_risco" "fr"
          WHERE (("fr"."cliente_id" = "u"."cliente_id") AND ("fr"."status" = ANY (ARRAY['confirmado'::"text", 'em_tratamento'::"text"])) AND ("fr"."deleted_at" IS NULL))) AS "focos_em_atendimento",
    ( SELECT "count"(*) AS "count"
           FROM "public"."focos_risco" "fr"
          WHERE (("fr"."cliente_id" = "u"."cliente_id") AND ("fr"."prioridade" = 'P1'::"text") AND ("fr"."responsavel_id" IS NULL) AND ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"])) AND ("fr"."deleted_at" IS NULL))) AS "focos_p1_sem_agente",
    ( SELECT "count"(*) AS "count"
           FROM "public"."sla_operacional" "sla"
          WHERE (("sla"."cliente_id" = "u"."cliente_id") AND ("sla"."status" = 'vencido'::"text") AND ("sla"."violado" = true) AND ("sla"."deleted_at" IS NULL))) AS "slas_vencidos",
    ( SELECT "count"(*) AS "count"
           FROM "public"."sla_operacional" "sla"
          WHERE (("sla"."cliente_id" = "u"."cliente_id") AND ("sla"."status" = ANY (ARRAY['pendente'::"text", 'em_atendimento'::"text"])) AND ("sla"."prazo_final" <= ("now"() + '02:00:00'::interval)) AND ("sla"."prazo_final" > "now"()) AND ("sla"."deleted_at" IS NULL))) AS "slas_vencendo_2h",
    ( SELECT "count"(*) AS "count"
           FROM "public"."territorio_score" "ts"
          WHERE (("ts"."cliente_id" = "u"."cliente_id") AND ("ts"."classificacao" = 'critico'::"text"))) AS "imoveis_criticos",
    ( SELECT "count"(*) AS "count"
           FROM "public"."territorio_score" "ts"
          WHERE (("ts"."cliente_id" = "u"."cliente_id") AND ("ts"."classificacao" = 'muito_alto'::"text"))) AS "imoveis_muito_alto",
    ( SELECT "round"("avg"("ts"."score"), 1) AS "round"
           FROM "public"."territorio_score" "ts"
          WHERE ("ts"."cliente_id" = "u"."cliente_id")) AS "score_medio_municipio",
    ( SELECT "count"(*) AS "count"
           FROM "public"."vistorias" "v"
          WHERE (("v"."cliente_id" = "u"."cliente_id") AND (("v"."created_at")::"date" = CURRENT_DATE) AND ("v"."deleted_at" IS NULL))) AS "vistorias_hoje",
    ( SELECT "count"(DISTINCT "v"."agente_id") AS "count"
           FROM "public"."vistorias" "v"
          WHERE (("v"."cliente_id" = "u"."cliente_id") AND (("v"."created_at")::"date" = CURRENT_DATE) AND ("v"."deleted_at" IS NULL))) AS "agentes_ativos_hoje",
    ( SELECT "count"(*) AS "count"
           FROM "public"."focos_risco" "fr2"
          WHERE (("fr2"."cliente_id" = "u"."cliente_id") AND ("fr2"."origem_tipo" = 'cidadao'::"text") AND ("fr2"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"])) AND ("fr2"."created_at" >= ("now"() - '24:00:00'::interval)) AND ("fr2"."deleted_at" IS NULL))) AS "denuncias_ultimas_24h",
    ( SELECT "count"(*) AS "count"
           FROM "public"."casos_notificados" "cn"
          WHERE (("cn"."cliente_id" = "u"."cliente_id") AND (("cn"."created_at")::"date" = CURRENT_DATE) AND ("cn"."deleted_at" IS NULL))) AS "casos_hoje"
   FROM "public"."usuarios" "u"
  WHERE ("auth_id" = "auth"."uid"());


ALTER VIEW "public"."v_central_operacional" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_central_operacional" IS 'KPIs do dia para a Central Operacional. Um row por usuário logado. security_invoker garante isolamento multitenante. focos_pendentes inclui em_inspecao (fix 20261006).';



CREATE OR REPLACE VIEW "public"."v_ciclo_ativo" WITH ("security_invoker"='true') AS
 SELECT "c"."id",
    "c"."cliente_id",
    "c"."numero",
    "c"."ano",
    "c"."status",
    "c"."data_inicio",
    "c"."data_fim_prevista",
    "c"."data_fechamento",
    "c"."meta_cobertura_pct",
    "c"."snapshot_fechamento",
    "c"."observacao_abertura",
    "c"."observacao_fechamento",
    "c"."aberto_por",
    "c"."fechado_por",
    "c"."created_at",
    "c"."updated_at",
        CASE
            WHEN ("c"."id" IS NOT NULL) THEN "c"."numero"
            ELSE ("ceil"(((EXTRACT(month FROM "now"()) + (1)::numeric) / (2)::numeric)))::integer
        END AS "ciclo_numero_efetivo",
        CASE
            WHEN (("c"."data_inicio" IS NOT NULL) AND ("c"."data_fim_prevista" IS NOT NULL)) THEN "round"(((100.0 * ((CURRENT_DATE - "c"."data_inicio"))::numeric) / (NULLIF(("c"."data_fim_prevista" - "c"."data_inicio"), 0))::numeric), 1)
            ELSE NULL::numeric
        END AS "pct_tempo_decorrido"
   FROM ("public"."usuarios" "u"
     LEFT JOIN "public"."ciclos" "c" ON ((("c"."cliente_id" = "u"."cliente_id") AND ("c"."status" = 'ativo'::"text"))))
  WHERE ("u"."auth_id" = "auth"."uid"());


ALTER VIEW "public"."v_ciclo_ativo" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_ciclo_ativo" IS 'Ciclo ativo do cliente do usuário logado. Retorna 1 row (NULL se sem ciclo formal ativo). ciclo_numero_efetivo: usa o ciclo formal se ativo, senão calcula pelo calendário.';



CREATE OR REPLACE VIEW "public"."v_ciclo_progresso" WITH ("security_invoker"='true') AS
 WITH "ciclo_ref" AS (
         SELECT "u"."cliente_id",
            COALESCE(( SELECT "ciclos"."numero"
                   FROM "public"."ciclos"
                  WHERE (("ciclos"."cliente_id" = "u"."cliente_id") AND ("ciclos"."status" = 'ativo'::"text"))
                 LIMIT 1), ("ceil"(((EXTRACT(month FROM "now"()) + (1)::numeric) / (2)::numeric)))::integer) AS "ciclo"
           FROM "public"."usuarios" "u"
          WHERE ("u"."auth_id" = "auth"."uid"())
        )
 SELECT "cr"."cliente_id",
    "cr"."ciclo",
    "count"(DISTINCT "im"."id") AS "imoveis_total",
    "count"(DISTINCT "v"."imovel_id") FILTER (WHERE ("v"."acesso_realizado" = true)) AS "imoveis_visitados",
    "count"(DISTINCT "v"."imovel_id") FILTER (WHERE ("v"."acesso_realizado" = false)) AS "imoveis_sem_acesso",
    "round"(((100.0 * ("count"(DISTINCT "v"."imovel_id") FILTER (WHERE ("v"."acesso_realizado" = true)))::numeric) / (NULLIF("count"(DISTINCT "im"."id"), 0))::numeric), 1) AS "cobertura_pct",
    "count"(DISTINCT "v"."id") AS "vistorias_total",
    "count"(DISTINCT "v"."id") FILTER (WHERE ("v"."tipo_atividade" = 'liraa'::"text")) AS "vistorias_liraa",
    "count"(DISTINCT "v"."agente_id") AS "agentes_ativos",
    "count"(DISTINCT "fr"."id") AS "focos_total",
    "count"(DISTINCT "fr"."id") FILTER (WHERE ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"]))) AS "focos_ativos",
    "count"(DISTINCT "fr"."id") FILTER (WHERE ("fr"."status" = 'resolvido'::"text")) AS "focos_resolvidos",
    "count"(DISTINCT "ar"."id") FILTER (WHERE ("ar"."resolvido" = false)) AS "alertas_retorno_pendentes"
   FROM ((((("ciclo_ref" "cr"
     JOIN "public"."clientes" "cl" ON (("cl"."id" = "cr"."cliente_id")))
     LEFT JOIN "public"."imoveis" "im" ON ((("im"."cliente_id" = "cr"."cliente_id") AND ("im"."ativo" = true) AND ("im"."deleted_at" IS NULL))))
     LEFT JOIN "public"."vistorias" "v" ON ((("v"."imovel_id" = "im"."id") AND ("v"."ciclo" = "cr"."ciclo") AND ("v"."deleted_at" IS NULL))))
     LEFT JOIN "public"."focos_risco" "fr" ON ((("fr"."cliente_id" = "cr"."cliente_id") AND ("fr"."ciclo" = "cr"."ciclo") AND ("fr"."deleted_at" IS NULL))))
     LEFT JOIN "public"."alerta_retorno_imovel" "ar" ON ((("ar"."cliente_id" = "cr"."cliente_id") AND ("ar"."ciclo" = "cr"."ciclo"))))
  GROUP BY "cr"."cliente_id", "cr"."ciclo";


ALTER VIEW "public"."v_ciclo_progresso" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_ciclo_progresso" IS 'Progresso do ciclo ativo: cobertura, vistorias, focos e alertas. Usa ciclo formal se existir, senão calcula pelo calendário. security_invoker = true.';



CREATE TABLE IF NOT EXISTS "public"."vistoria_depositos" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "vistoria_id" "uuid" NOT NULL,
    "tipo" "text" NOT NULL,
    "qtd_inspecionados" integer DEFAULT 0 NOT NULL,
    "qtd_com_focos" integer DEFAULT 0 NOT NULL,
    "qtd_eliminados" integer DEFAULT 0 NOT NULL,
    "usou_larvicida" boolean DEFAULT false NOT NULL,
    "qtd_larvicida_g" double precision,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "qtd_com_agua" integer DEFAULT 0 NOT NULL,
    "eliminado" boolean DEFAULT false NOT NULL,
    "vedado" boolean DEFAULT false NOT NULL,
    "ia_identificacao" "jsonb",
    "deleted_at" timestamp with time zone,
    "cliente_id" "uuid" NOT NULL,
    CONSTRAINT "chk_deposito_agua_inspecionados" CHECK (("qtd_com_agua" <= "qtd_inspecionados")),
    CONSTRAINT "chk_deposito_focos_agua" CHECK (("qtd_com_focos" <= "qtd_com_agua")),
    CONSTRAINT "chk_eliminados_lte_focos" CHECK (("qtd_eliminados" <= "qtd_com_focos")),
    CONSTRAINT "chk_focos_lte_inspecionados" CHECK (("qtd_com_focos" <= "qtd_inspecionados")),
    CONSTRAINT "vistoria_depositos_tipo_check" CHECK (("tipo" = ANY (ARRAY['A1'::"text", 'A2'::"text", 'B'::"text", 'C'::"text", 'D1'::"text", 'D2'::"text", 'E'::"text"])))
);


ALTER TABLE "public"."vistoria_depositos" OWNER TO "postgres";


COMMENT ON COLUMN "public"."vistoria_depositos"."qtd_com_agua" IS 'Quantidade de depósitos do tipo com água parada (≤ qtd_inspecionados)';



COMMENT ON COLUMN "public"."vistoria_depositos"."eliminado" IS 'O depósito foi eliminado/destruído durante a vistoria';



COMMENT ON COLUMN "public"."vistoria_depositos"."vedado" IS 'O depósito foi vedado/tampado durante a vistoria';



COMMENT ON COLUMN "public"."vistoria_depositos"."ia_identificacao" IS 'Resultado da identificação de larvas por IA. Formato: { identified: bool, confidence: float, classe: string, image_url: string }';



CREATE OR REPLACE VIEW "public"."v_eficacia_tratamento" WITH ("security_invoker"='true') AS
 WITH "focos_resolvidos" AS (
         SELECT "fr"."id" AS "foco_id",
            "fr"."cliente_id",
            "fr"."imovel_id",
            "fr"."regiao_id",
            "fr"."confirmado_em",
            "fr"."resolvido_em",
            (EXTRACT(epoch FROM ("fr"."resolvido_em" - "fr"."confirmado_em")) / (3600)::numeric) AS "horas_resolucao",
            (EXISTS ( SELECT 1
                   FROM "public"."focos_risco" "fr2"
                  WHERE (("fr2"."imovel_id" = "fr"."imovel_id") AND ("fr2"."cliente_id" = "fr"."cliente_id") AND ("fr2"."id" <> "fr"."id") AND ("fr2"."foco_anterior_id" = "fr"."id") AND ("fr2"."created_at" > "fr"."resolvido_em") AND ("fr2"."created_at" <= ("fr"."resolvido_em" + '90 days'::interval)) AND ("fr2"."deleted_at" IS NULL)))) AS "teve_recorrencia_90d"
           FROM "public"."focos_risco" "fr"
          WHERE (("fr"."status" = 'resolvido'::"text") AND ("fr"."confirmado_em" IS NOT NULL) AND ("fr"."resolvido_em" IS NOT NULL) AND ("fr"."deleted_at" IS NULL))
        ), "depositos_na_vistoria" AS (
         SELECT "fr"."foco_id",
            "fr"."cliente_id",
            "vd"."tipo" AS "tipo_deposito",
            "vd"."usou_larvicida",
            "vd"."qtd_larvicida_g",
            "vd"."qtd_com_focos",
            "vd"."qtd_eliminados",
            "fr"."teve_recorrencia_90d"
           FROM (("focos_resolvidos" "fr"
             JOIN "public"."vistorias" "v" ON ((("v"."imovel_id" = "fr"."imovel_id") AND ("v"."acesso_realizado" = true) AND (("v"."created_at" >= "fr"."confirmado_em") AND ("v"."created_at" <= ("fr"."resolvido_em" + '7 days'::interval))) AND ("v"."deleted_at" IS NULL))))
             JOIN "public"."vistoria_depositos" "vd" ON ((("vd"."vistoria_id" = "v"."id") AND ("vd"."qtd_com_focos" > 0))))
        )
 SELECT "cliente_id",
    "tipo_deposito",
    "usou_larvicida",
    "count"(*) AS "total_casos",
    "count"(*) FILTER (WHERE (NOT "teve_recorrencia_90d")) AS "sem_recorrencia",
    "round"(((("count"(*) FILTER (WHERE (NOT "teve_recorrencia_90d")))::numeric / (NULLIF("count"(*), 0))::numeric) * (100)::numeric), 1) AS "taxa_eficacia_pct",
    "avg"(
        CASE
            WHEN "usou_larvicida" THEN "qtd_larvicida_g"
            ELSE NULL::double precision
        END) AS "larvicida_medio_g",
    "round"(("avg"((("qtd_eliminados")::numeric / (NULLIF("qtd_com_focos", 0))::numeric)) * (100)::numeric), 1) AS "taxa_eliminacao_pct"
   FROM "depositos_na_vistoria" "d"
  GROUP BY "cliente_id", "tipo_deposito", "usou_larvicida"
 HAVING ("count"(*) >= 5);


ALTER VIEW "public"."v_eficacia_tratamento" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_eficacia_tratamento" IS 'Eficácia de tratamentos: taxa de não-recorrência em 90 dias por tipo de depósito e uso de larvicida. Mínimo 5 casos por combinação para relevância estatística. security_invoker=true herda RLS.';



CREATE OR REPLACE VIEW "public"."v_executivo_bairros_variacao" WITH ("security_invoker"='true') AS
 WITH "cliente" AS (
         SELECT "usuarios"."cliente_id"
           FROM "public"."usuarios"
          WHERE ("usuarios"."auth_id" = "auth"."uid"())
         LIMIT 1
        ), "base" AS (
         SELECT "im"."cliente_id",
            "im"."bairro",
            "im"."id" AS "imovel_id"
           FROM ("public"."imoveis" "im"
             JOIN "cliente" "c" ON (("im"."cliente_id" = "c"."cliente_id")))
          WHERE ("im"."deleted_at" IS NULL)
        )
 SELECT "b"."cliente_id",
    "b"."bairro",
    "round"("avg"("ts"."score"), 1) AS "score_atual",
    "count"(DISTINCT "fr7"."id") AS "focos_novos_7d",
    "count"(DISTINCT "fr30"."id") AS "focos_novos_30d",
    "count"(DISTINCT "cn"."id") AS "casos_30d",
    "count"(DISTINCT "v"."id") AS "vistorias_30d",
    "round"((("count"(DISTINCT "fr7"."id"))::numeric - (("count"(DISTINCT "fr30"."id"))::numeric / 4.0)), 1) AS "variacao_focos",
        CASE
            WHEN ("round"((("count"(DISTINCT "fr7"."id"))::numeric - (("count"(DISTINCT "fr30"."id"))::numeric / 4.0)), 1) > (2)::numeric) THEN 'piorando'::"text"
            WHEN ("round"((("count"(DISTINCT "fr7"."id"))::numeric - (("count"(DISTINCT "fr30"."id"))::numeric / 4.0)), 1) < ('-2'::integer)::numeric) THEN 'melhorando'::"text"
            ELSE 'estavel'::"text"
        END AS "classificacao_tendencia"
   FROM ((((("base" "b"
     LEFT JOIN "public"."territorio_score" "ts" ON ((("ts"."imovel_id" = "b"."imovel_id") AND ("ts"."cliente_id" = "b"."cliente_id"))))
     LEFT JOIN "public"."focos_risco" "fr7" ON ((("fr7"."imovel_id" = "b"."imovel_id") AND ("fr7"."deleted_at" IS NULL) AND ("fr7"."created_at" >= (CURRENT_DATE - '7 days'::interval)))))
     LEFT JOIN "public"."focos_risco" "fr30" ON ((("fr30"."imovel_id" = "b"."imovel_id") AND ("fr30"."deleted_at" IS NULL) AND ("fr30"."created_at" >= (CURRENT_DATE - '30 days'::interval)))))
     LEFT JOIN "public"."casos_notificados" "cn" ON ((("cn"."cliente_id" = "b"."cliente_id") AND ("cn"."bairro" = "b"."bairro") AND ("cn"."deleted_at" IS NULL) AND ("cn"."created_at" >= (CURRENT_DATE - '30 days'::interval)))))
     LEFT JOIN "public"."vistorias" "v" ON ((("v"."imovel_id" = "b"."imovel_id") AND ("v"."deleted_at" IS NULL) AND ("v"."acesso_realizado" = true) AND ("v"."created_at" >= (CURRENT_DATE - '30 days'::interval)))))
  GROUP BY "b"."cliente_id", "b"."bairro"
  ORDER BY ("round"("avg"("ts"."score"), 1)) DESC NULLS LAST;


ALTER VIEW "public"."v_executivo_bairros_variacao" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_executivo_cobertura" WITH ("security_invoker"='true') AS
 WITH "cliente" AS (
         SELECT "usuarios"."cliente_id"
           FROM "public"."usuarios"
          WHERE ("usuarios"."auth_id" = "auth"."uid"())
         LIMIT 1
        )
 SELECT "im"."cliente_id",
    "im"."bairro",
    "count"(DISTINCT "im"."id") AS "total_imoveis",
    "count"(DISTINCT "v"."imovel_id") FILTER (WHERE (("v"."acesso_realizado" = true) AND ("v"."created_at" >= (CURRENT_DATE - '30 days'::interval)))) AS "imoveis_visitados_30d",
    "round"(((("count"(DISTINCT "v"."imovel_id") FILTER (WHERE (("v"."acesso_realizado" = true) AND ("v"."created_at" >= (CURRENT_DATE - '30 days'::interval)))))::numeric * 100.0) / (NULLIF("count"(DISTINCT "im"."id"), 0))::numeric), 1) AS "cobertura_pct",
    "round"("avg"("ts"."score"), 1) AS "score_medio_bairro",
    "count"(DISTINCT "fr"."id") FILTER (WHERE ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"]))) AS "focos_ativos",
    "count"(DISTINCT "ts2"."imovel_id") FILTER (WHERE ("ts2"."classificacao" = ANY (ARRAY['critico'::"text", 'muito_alto'::"text"]))) AS "imoveis_criticos"
   FROM ((((("public"."imoveis" "im"
     JOIN "cliente" "c" ON (("im"."cliente_id" = "c"."cliente_id")))
     LEFT JOIN "public"."vistorias" "v" ON ((("v"."imovel_id" = "im"."id") AND ("v"."deleted_at" IS NULL))))
     LEFT JOIN "public"."territorio_score" "ts" ON ((("ts"."imovel_id" = "im"."id") AND ("ts"."cliente_id" = "im"."cliente_id"))))
     LEFT JOIN "public"."focos_risco" "fr" ON ((("fr"."imovel_id" = "im"."id") AND ("fr"."deleted_at" IS NULL))))
     LEFT JOIN "public"."territorio_score" "ts2" ON ((("ts2"."imovel_id" = "im"."id") AND ("ts2"."cliente_id" = "im"."cliente_id"))))
  WHERE ("im"."deleted_at" IS NULL)
  GROUP BY "im"."cliente_id", "im"."bairro"
  ORDER BY ("count"(DISTINCT "fr"."id") FILTER (WHERE ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"])))) DESC, ("round"("avg"("ts"."score"), 1)) DESC NULLS LAST;


ALTER VIEW "public"."v_executivo_cobertura" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_executivo_comparativo_ciclos" WITH ("security_invoker"='true') AS
 WITH "cliente" AS (
         SELECT "usuarios"."cliente_id"
           FROM "public"."usuarios"
          WHERE ("usuarios"."auth_id" = "auth"."uid"())
         LIMIT 1
        ), "ciclos" AS (
         SELECT (("date_trunc"('month'::"text", (CURRENT_DATE)::timestamp with time zone) - ((((EXTRACT(month FROM CURRENT_DATE))::integer % 2))::double precision * '1 mon'::interval)))::"date" AS "ciclo_atual_inicio",
            ((("date_trunc"('month'::"text", (CURRENT_DATE)::timestamp with time zone) - ((((EXTRACT(month FROM CURRENT_DATE))::integer % 2))::double precision * '1 mon'::interval)) - '2 mons'::interval))::"date" AS "ciclo_anterior_inicio"
        )
 SELECT "c"."cliente_id",
    "ci"."ciclo_atual_inicio",
    "ci"."ciclo_anterior_inicio",
    "count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."created_at" >= "ci"."ciclo_atual_inicio") AND ("fr"."created_at" < ("ci"."ciclo_atual_inicio" + '2 mons'::interval)))) AS "focos_atual",
    "count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."created_at" >= "ci"."ciclo_anterior_inicio") AND ("fr"."created_at" < ("ci"."ciclo_anterior_inicio" + '2 mons'::interval)))) AS "focos_anterior",
    "count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."resolvido_em" >= "ci"."ciclo_atual_inicio") AND ("fr"."resolvido_em" < ("ci"."ciclo_atual_inicio" + '2 mons'::interval)))) AS "resolucao_atual",
    "count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."resolvido_em" >= "ci"."ciclo_anterior_inicio") AND ("fr"."resolvido_em" < ("ci"."ciclo_anterior_inicio" + '2 mons'::interval)))) AS "resolucao_anterior",
    "count"(DISTINCT "v"."id") FILTER (WHERE (("v"."data_visita" >= "ci"."ciclo_atual_inicio") AND ("v"."data_visita" < ("ci"."ciclo_atual_inicio" + '2 mons'::interval)))) AS "vistorias_atual",
    "count"(DISTINCT "v"."id") FILTER (WHERE (("v"."data_visita" >= "ci"."ciclo_anterior_inicio") AND ("v"."data_visita" < ("ci"."ciclo_anterior_inicio" + '2 mons'::interval)))) AS "vistorias_anterior",
    "count"(DISTINCT "cn"."id") FILTER (WHERE (("cn"."created_at" >= "ci"."ciclo_atual_inicio") AND ("cn"."created_at" < ("ci"."ciclo_atual_inicio" + '2 mons'::interval)))) AS "casos_atual",
    "count"(DISTINCT "cn"."id") FILTER (WHERE (("cn"."created_at" >= "ci"."ciclo_anterior_inicio") AND ("cn"."created_at" < ("ci"."ciclo_anterior_inicio" + '2 mons'::interval)))) AS "casos_anterior",
    "round"((((("count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."created_at" >= "ci"."ciclo_atual_inicio") AND ("fr"."created_at" < ("ci"."ciclo_atual_inicio" + '2 mons'::interval)))) - "count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."created_at" >= "ci"."ciclo_anterior_inicio") AND ("fr"."created_at" < ("ci"."ciclo_anterior_inicio" + '2 mons'::interval))))))::numeric * 100.0) / (NULLIF("count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."created_at" >= "ci"."ciclo_anterior_inicio") AND ("fr"."created_at" < ("ci"."ciclo_anterior_inicio" + '2 mons'::interval)))), 0))::numeric), 1) AS "variacao_focos_pct",
    "round"((((("count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."resolvido_em" >= "ci"."ciclo_atual_inicio") AND ("fr"."resolvido_em" < ("ci"."ciclo_atual_inicio" + '2 mons'::interval)))) - "count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."resolvido_em" >= "ci"."ciclo_anterior_inicio") AND ("fr"."resolvido_em" < ("ci"."ciclo_anterior_inicio" + '2 mons'::interval))))))::numeric * 100.0) / (NULLIF("count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."resolvido_em" >= "ci"."ciclo_anterior_inicio") AND ("fr"."resolvido_em" < ("ci"."ciclo_anterior_inicio" + '2 mons'::interval)))), 0))::numeric), 1) AS "variacao_resolucao_pct"
   FROM (((("cliente" "c"
     CROSS JOIN "ciclos" "ci")
     LEFT JOIN "public"."focos_risco" "fr" ON ((("fr"."cliente_id" = "c"."cliente_id") AND ("fr"."deleted_at" IS NULL))))
     LEFT JOIN "public"."vistorias" "v" ON ((("v"."cliente_id" = "c"."cliente_id") AND ("v"."deleted_at" IS NULL))))
     LEFT JOIN "public"."casos_notificados" "cn" ON ((("cn"."cliente_id" = "c"."cliente_id") AND ("cn"."deleted_at" IS NULL))))
  GROUP BY "c"."cliente_id", "ci"."ciclo_atual_inicio", "ci"."ciclo_anterior_inicio";


ALTER VIEW "public"."v_executivo_comparativo_ciclos" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_executivo_kpis" WITH ("security_invoker"='true') AS
 WITH "cliente" AS (
         SELECT "usuarios"."cliente_id"
           FROM "public"."usuarios"
          WHERE ("usuarios"."auth_id" = "auth"."uid"())
         LIMIT 1
        ), "sla_stats" AS (
         SELECT "so"."cliente_id",
            "count"(*) FILTER (WHERE (("so"."status" = 'vencido'::"text") AND ("so"."violado" = true) AND ("so"."deleted_at" IS NULL))) AS "slas_vencidos",
            "count"(*) FILTER (WHERE ("so"."deleted_at" IS NULL)) AS "total_slas"
           FROM ("public"."sla_operacional" "so"
             JOIN "cliente" "c_1" ON (("so"."cliente_id" = "c_1"."cliente_id")))
          GROUP BY "so"."cliente_id"
        ), "focos_stats" AS (
         SELECT "fr"."cliente_id",
            "count"(*) FILTER (WHERE ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"]))) AS "total_focos_ativos",
            "count"(*) FILTER (WHERE ("fr"."created_at" >= (CURRENT_DATE - '7 days'::interval))) AS "focos_novos_semana",
            "count"(*) FILTER (WHERE (("fr"."status" = 'resolvido'::"text") AND ("fr"."resolvido_em" >= (CURRENT_DATE - '7 days'::interval)))) AS "focos_resolvidos_semana"
           FROM ("public"."focos_risco" "fr"
             JOIN "cliente" "c_1" ON (("fr"."cliente_id" = "c_1"."cliente_id")))
          WHERE ("fr"."deleted_at" IS NULL)
          GROUP BY "fr"."cliente_id"
        ), "vistorias_stats" AS (
         SELECT "v"."cliente_id",
            "count"(DISTINCT "v"."imovel_id") FILTER (WHERE (("v"."acesso_realizado" = true) AND ("v"."created_at" >= (CURRENT_DATE - '7 days'::interval)))) AS "imoveis_visitados_semana",
            "count"(DISTINCT "v"."agente_id") FILTER (WHERE ("v"."created_at" >= (CURRENT_DATE - '7 days'::interval))) AS "agentes_ativos_semana"
           FROM ("public"."vistorias" "v"
             JOIN "cliente" "c_1" ON (("v"."cliente_id" = "c_1"."cliente_id")))
          WHERE ("v"."deleted_at" IS NULL)
          GROUP BY "v"."cliente_id"
        ), "imoveis_stats" AS (
         SELECT "im"."cliente_id",
            "count"(*) FILTER (WHERE ("im"."deleted_at" IS NULL)) AS "total_imoveis"
           FROM ("public"."imoveis" "im"
             JOIN "cliente" "c_1" ON (("im"."cliente_id" = "c_1"."cliente_id")))
          GROUP BY "im"."cliente_id"
        ), "score_stats" AS (
         SELECT "ts"."cliente_id",
            "round"("avg"("ts"."score"), 1) AS "score_medio",
            "count"(*) FILTER (WHERE ("ts"."classificacao" = 'critico'::"text")) AS "imoveis_criticos"
           FROM ("public"."territorio_score" "ts"
             JOIN "cliente" "c_1" ON (("ts"."cliente_id" = "c_1"."cliente_id")))
          GROUP BY "ts"."cliente_id"
        ), "casos_stats" AS (
         SELECT "cn"."cliente_id",
            "count"(*) FILTER (WHERE ("cn"."created_at" >= (CURRENT_DATE - '7 days'::interval))) AS "casos_novos_semana"
           FROM ("public"."casos_notificados" "cn"
             JOIN "cliente" "c_1" ON (("cn"."cliente_id" = "c_1"."cliente_id")))
          WHERE ("cn"."deleted_at" IS NULL)
          GROUP BY "cn"."cliente_id"
        )
 SELECT "c"."cliente_id",
    ("date_trunc"('week'::"text", (CURRENT_DATE)::timestamp with time zone))::"date" AS "semana_ref",
    COALESCE("fs"."total_focos_ativos", (0)::bigint) AS "total_focos_ativos",
    COALESCE("fs"."focos_novos_semana", (0)::bigint) AS "focos_novos_semana",
    COALESCE("fs"."focos_resolvidos_semana", (0)::bigint) AS "focos_resolvidos_semana",
    "round"((((COALESCE("fs"."focos_resolvidos_semana", (0)::bigint))::numeric * 100.0) / (NULLIF((COALESCE("fs"."focos_novos_semana", (0)::bigint) + COALESCE("fs"."focos_resolvidos_semana", (0)::bigint)), 0))::numeric), 1) AS "taxa_resolucao_pct",
    COALESCE("ss"."slas_vencidos", (0)::bigint) AS "slas_vencidos",
    "round"(((((COALESCE("ss"."total_slas", (0)::bigint) - COALESCE("ss"."slas_vencidos", (0)::bigint)))::numeric * 100.0) / (NULLIF(COALESCE("ss"."total_slas", (0)::bigint), 0))::numeric), 1) AS "sla_conformidade_pct",
    COALESCE("vs"."imoveis_visitados_semana", (0)::bigint) AS "imoveis_visitados_semana",
    "round"((((COALESCE("vs"."imoveis_visitados_semana", (0)::bigint))::numeric * 100.0) / (NULLIF(COALESCE("ims"."total_imoveis", (0)::bigint), 0))::numeric), 1) AS "cobertura_pct",
    "scs"."score_medio",
    COALESCE("scs"."imoveis_criticos", (0)::bigint) AS "imoveis_criticos",
    COALESCE("cas"."casos_novos_semana", (0)::bigint) AS "casos_novos_semana",
    COALESCE("vs"."agentes_ativos_semana", (0)::bigint) AS "agentes_ativos_semana"
   FROM (((((("cliente" "c"
     LEFT JOIN "focos_stats" "fs" ON (("fs"."cliente_id" = "c"."cliente_id")))
     LEFT JOIN "sla_stats" "ss" ON (("ss"."cliente_id" = "c"."cliente_id")))
     LEFT JOIN "vistorias_stats" "vs" ON (("vs"."cliente_id" = "c"."cliente_id")))
     LEFT JOIN "imoveis_stats" "ims" ON (("ims"."cliente_id" = "c"."cliente_id")))
     LEFT JOIN "score_stats" "scs" ON (("scs"."cliente_id" = "c"."cliente_id")))
     LEFT JOIN "casos_stats" "cas" ON (("cas"."cliente_id" = "c"."cliente_id")));


ALTER VIEW "public"."v_executivo_kpis" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_executivo_tendencia" WITH ("security_invoker"='true') AS
 WITH "cliente" AS (
         SELECT "usuarios"."cliente_id"
           FROM "public"."usuarios"
          WHERE ("usuarios"."auth_id" = "auth"."uid"())
         LIMIT 1
        ), "weeks" AS (
         SELECT ("generate_series"(("date_trunc"('week'::"text", (CURRENT_DATE)::timestamp with time zone) - '49 days'::interval), "date_trunc"('week'::"text", (CURRENT_DATE)::timestamp with time zone), '7 days'::interval))::"date" AS "semana_inicio"
        ), "score_stats" AS (
         SELECT "ts"."cliente_id",
            "round"("avg"("ts"."score"), 1) AS "score_medio"
           FROM ("public"."territorio_score" "ts"
             JOIN "cliente" "c_1" ON (("ts"."cliente_id" = "c_1"."cliente_id")))
          GROUP BY "ts"."cliente_id"
        )
 SELECT "c"."cliente_id",
    "w"."semana_inicio",
    "count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."created_at" >= "w"."semana_inicio") AND ("fr"."created_at" < ("w"."semana_inicio" + '7 days'::interval)))) AS "focos_novos",
    "count"(DISTINCT "fr"."id") FILTER (WHERE (("fr"."resolvido_em" >= "w"."semana_inicio") AND ("fr"."resolvido_em" < ("w"."semana_inicio" + '7 days'::interval)))) AS "focos_resolvidos",
    "count"(DISTINCT "v"."id") FILTER (WHERE (("v"."data_visita" >= "w"."semana_inicio") AND ("v"."data_visita" < ("w"."semana_inicio" + '7 days'::interval)))) AS "vistorias",
    "count"(DISTINCT "cn"."id") FILTER (WHERE (("cn"."created_at" >= "w"."semana_inicio") AND ("cn"."created_at" < ("w"."semana_inicio" + '7 days'::interval)))) AS "casos",
    "ss"."score_medio"
   FROM ((((("cliente" "c"
     CROSS JOIN "weeks" "w")
     LEFT JOIN "public"."focos_risco" "fr" ON ((("fr"."cliente_id" = "c"."cliente_id") AND ("fr"."deleted_at" IS NULL))))
     LEFT JOIN "public"."vistorias" "v" ON ((("v"."cliente_id" = "c"."cliente_id") AND ("v"."deleted_at" IS NULL))))
     LEFT JOIN "public"."casos_notificados" "cn" ON ((("cn"."cliente_id" = "c"."cliente_id") AND ("cn"."deleted_at" IS NULL))))
     LEFT JOIN "score_stats" "ss" ON (("ss"."cliente_id" = "c"."cliente_id")))
  GROUP BY "c"."cliente_id", "w"."semana_inicio", "ss"."score_medio"
  ORDER BY "w"."semana_inicio";


ALTER VIEW "public"."v_executivo_tendencia" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_foco_risco_timeline" WITH ("security_invoker"='true') AS
 SELECT "frh"."foco_risco_id",
    'estado'::"text" AS "tipo",
    "frh"."alterado_em" AS "ts",
    ((('Status: '::"text" || COALESCE("frh"."status_anterior", 'novo'::"text")) || ' → '::"text") || COALESCE("frh"."status_novo", '?'::"text")) AS "titulo",
    "frh"."motivo" AS "descricao",
    "frh"."alterado_por" AS "ator_id",
    NULL::"uuid" AS "ref_id"
   FROM "public"."foco_risco_historico" "frh"
  WHERE (COALESCE("frh"."tipo_evento", 'transicao_status'::"text") = 'transicao_status'::"text")
UNION ALL
 SELECT "frh"."foco_risco_id",
    'classificacao_alterada'::"text" AS "tipo",
    "frh"."alterado_em" AS "ts",
    ((('Classificação: '::"text" || COALESCE("frh"."classificacao_anterior", '—'::"text")) || ' → '::"text") || COALESCE("frh"."classificacao_nova", '?'::"text")) AS "titulo",
    NULL::"text" AS "descricao",
    "frh"."alterado_por" AS "ator_id",
    NULL::"uuid" AS "ref_id"
   FROM "public"."foco_risco_historico" "frh"
  WHERE ("frh"."tipo_evento" = 'classificacao_alterada'::"text")
UNION ALL
 SELECT "fr"."id" AS "foco_risco_id",
    'vistoria'::"text" AS "tipo",
    "v"."checkin_em" AS "ts",
    ('Vistoria: '::"text" || "v"."tipo_atividade") AS "titulo",
        CASE
            WHEN ("v"."acesso_realizado" = false) THEN ('Sem acesso — '::"text" || COALESCE("v"."motivo_sem_acesso", ''::"text"))
            ELSE "v"."observacao"
        END AS "descricao",
    "v"."agente_id" AS "ator_id",
    "v"."id" AS "ref_id"
   FROM ("public"."focos_risco" "fr"
     JOIN "public"."vistorias" "v" ON (("v"."id" = "fr"."origem_vistoria_id")))
UNION ALL
 SELECT "fr"."id" AS "foco_risco_id",
    'vistoria_campo'::"text" AS "tipo",
    "v"."checkin_em" AS "ts",
    ('Vistoria de campo: '::"text" || "v"."tipo_atividade") AS "titulo",
    "v"."observacao" AS "descricao",
    "v"."agente_id" AS "ator_id",
    "v"."id" AS "ref_id"
   FROM ("public"."focos_risco" "fr"
     JOIN "public"."vistorias" "v" ON ((("v"."imovel_id" = "fr"."imovel_id") AND ("v"."ciclo" = "fr"."ciclo") AND ("v"."id" <> COALESCE("fr"."origem_vistoria_id", '00000000-0000-0000-0000-000000000000'::"uuid")))))
  WHERE (("fr"."imovel_id" IS NOT NULL) AND ("fr"."ciclo" IS NOT NULL))
UNION ALL
 SELECT "fr"."id" AS "foco_risco_id",
    'sla'::"text" AS "tipo",
    COALESCE("sla"."concluido_em", "sla"."prazo_final", "sla"."inicio") AS "ts",
        CASE "sla"."status"
            WHEN 'aberto'::"text" THEN ('SLA aberto — prazo: '::"text" || "to_char"("sla"."prazo_final", 'DD/MM/YYYY HH24:MI'::"text"))
            WHEN 'vencido'::"text" THEN 'SLA vencido'::"text"
            WHEN 'concluido'::"text" THEN 'SLA concluído'::"text"
            ELSE ('SLA: '::"text" || "sla"."status")
        END AS "titulo",
    (((('Prioridade '::"text" || "sla"."prioridade") || ' — '::"text") || ("sla"."sla_horas")::"text") || 'h'::"text") AS "descricao",
    NULL::"uuid" AS "ator_id",
    "sla"."id" AS "ref_id"
   FROM ("public"."focos_risco" "fr"
     JOIN "public"."sla_operacional" "sla" ON (("sla"."foco_risco_id" = "fr"."id")))
UNION ALL
 SELECT "fr"."id" AS "foco_risco_id",
    'caso_notificado'::"text" AS "tipo",
    ("cn"."data_notificacao")::timestamp with time zone AS "ts",
    ('Caso notificado: '::"text" || "cn"."doenca") AS "titulo",
    ((('Status: '::"text" || "cn"."status") || ' — '::"text") || COALESCE("cn"."bairro", ''::"text")) AS "descricao",
    "cn"."notificador_id" AS "ator_id",
    "cn"."id" AS "ref_id"
   FROM ("public"."focos_risco" "fr"
     JOIN "public"."casos_notificados" "cn" ON (("cn"."id" = ANY ("fr"."casos_ids"))))
  WHERE ("array_length"("fr"."casos_ids", 1) > 0)
UNION ALL
 SELECT "r"."foco_risco_id",
    'reinspecao'::"text" AS "tipo",
    COALESCE("r"."data_realizada", "r"."updated_at") AS "ts",
        CASE "r"."status"
            WHEN 'pendente'::"public"."reinspecao_status" THEN 'Reinspeção pendente'::"text"
            WHEN 'vencida'::"public"."reinspecao_status" THEN 'Reinspeção vencida'::"text"
            WHEN 'realizada'::"public"."reinspecao_status" THEN 'Reinspeção realizada'::"text"
            WHEN 'cancelada'::"public"."reinspecao_status" THEN 'Reinspeção cancelada'::"text"
            ELSE 'Reinspeção'::"text"
        END AS "titulo",
        CASE
            WHEN ("r"."resultado" IS NOT NULL) THEN (('Resultado: '::"text" ||
            CASE "r"."resultado"
                WHEN 'resolvido'::"public"."reinspecao_resultado" THEN 'Problema resolvido'::"text"
                WHEN 'persiste'::"public"."reinspecao_resultado" THEN 'Problema persiste'::"text"
                WHEN 'nao_realizado'::"public"."reinspecao_resultado" THEN 'Não foi possível realizar'::"text"
                ELSE ("r"."resultado")::"text"
            END) ||
            CASE
                WHEN ("r"."observacao" IS NOT NULL) THEN (' — '::"text" || "r"."observacao")
                ELSE ''::"text"
            END)
            WHEN ("r"."status" = ANY (ARRAY['pendente'::"public"."reinspecao_status", 'vencida'::"public"."reinspecao_status"])) THEN ('Prevista para '::"text" || "to_char"("r"."data_prevista", 'DD/MM/YYYY HH24:MI'::"text"))
            WHEN ("r"."status" = 'cancelada'::"public"."reinspecao_status") THEN COALESCE("r"."motivo_cancelamento", 'Cancelada'::"text")
            ELSE NULL::"text"
        END AS "descricao",
    "r"."responsavel_id" AS "ator_id",
    "r"."id" AS "ref_id"
   FROM "public"."reinspecoes_programadas" "r";


ALTER VIEW "public"."v_foco_risco_timeline" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_foco_risco_timeline" IS 'Linha do tempo unificada: estado, classificacao_alterada, vistorias, SLA, casos notificados e reinspeções. Ordenar por ts DESC no cliente. security_invoker = true.';



CREATE OR REPLACE VIEW "public"."v_focos_com_casos" WITH ("security_invoker"='true') AS
 SELECT "fr"."id" AS "foco_id",
    "fr"."cliente_id",
    "fr"."status" AS "foco_status",
    "fr"."prioridade" AS "foco_prioridade",
    "fr"."latitude" AS "foco_lat",
    "fr"."longitude" AS "foco_lng",
    "fr"."endereco_normalizado",
    "fr"."suspeita_em",
    "fr"."confirmado_em",
    "cn"."id" AS "caso_id",
    "cn"."status" AS "caso_status",
    "cn"."doenca" AS "caso_doenca",
    "cn"."data_notificacao",
    "cn"."bairro" AS "caso_bairro",
    "cfc"."distancia_metros"
   FROM ((("public"."focos_risco" "fr"
     JOIN LATERAL "unnest"("fr"."casos_ids") "cid"("caso_uuid") ON (true))
     JOIN "public"."casos_notificados" "cn" ON (("cn"."id" = "cid"."caso_uuid")))
     LEFT JOIN "public"."caso_foco_cruzamento" "cfc" ON ((("cfc"."caso_id" = "cn"."id") AND ("cfc"."levantamento_item_id" = "fr"."origem_levantamento_item_id"))))
  WHERE (("array_length"("fr"."casos_ids", 1) > 0) AND ("fr"."deleted_at" IS NULL) AND ("cn"."deleted_at" IS NULL));


ALTER VIEW "public"."v_focos_com_casos" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_focos_com_casos" IS 'Focos com pelo menos um caso notificado próximo (casos_ids não vazio). Exclui focos e casos com soft delete. security_invoker = true — RLS aplicada automaticamente.';



CREATE OR REPLACE VIEW "public"."v_focos_dados_minimos_status" WITH ("security_invoker"='true') AS
 SELECT "id" AS "foco_id",
    "cliente_id",
    (("endereco_normalizado" IS NOT NULL) OR (("latitude" IS NOT NULL) AND ("longitude" IS NOT NULL)) OR ("imovel_id" IS NOT NULL)) AS "tem_localizacao",
    (("imovel_id" IS NOT NULL) OR ("regiao_id" IS NOT NULL)) AS "tem_bairro",
    ("classificacao_inicial" IS NOT NULL) AS "tem_classificacao",
    (("observacao" IS NOT NULL) AND ("length"(TRIM(BOTH FROM "observacao")) > 0)) AS "tem_descricao",
    (("origem_levantamento_item_id" IS NOT NULL) OR ("origem_vistoria_id" IS NOT NULL) OR ("array_length"("casos_ids", 1) > 0) OR (EXISTS ( SELECT 1
           FROM "public"."operacoes" "o"
          WHERE ("o"."foco_risco_id" = "fr"."id")))) AS "tem_evidencia",
    ((("endereco_normalizado" IS NOT NULL) OR (("latitude" IS NOT NULL) AND ("longitude" IS NOT NULL)) OR ("imovel_id" IS NOT NULL)) AND (("imovel_id" IS NOT NULL) OR ("regiao_id" IS NOT NULL)) AND ("classificacao_inicial" IS NOT NULL) AND (("observacao" IS NOT NULL) AND ("length"(TRIM(BOTH FROM "observacao")) > 0)) AND (("origem_levantamento_item_id" IS NOT NULL) OR ("origem_vistoria_id" IS NOT NULL) OR ("array_length"("casos_ids", 1) > 0) OR (EXISTS ( SELECT 1
           FROM "public"."operacoes" "o"
          WHERE ("o"."foco_risco_id" = "fr"."id"))))) AS "tem_dados_minimos",
    "array_remove"(ARRAY[
        CASE
            WHEN (NOT (("endereco_normalizado" IS NOT NULL) OR (("latitude" IS NOT NULL) AND ("longitude" IS NOT NULL)) OR ("imovel_id" IS NOT NULL))) THEN 'sem_localizacao'::"text"
            ELSE NULL::"text"
        END,
        CASE
            WHEN (NOT (("imovel_id" IS NOT NULL) OR ("regiao_id" IS NOT NULL))) THEN 'sem_bairro'::"text"
            ELSE NULL::"text"
        END,
        CASE
            WHEN (NOT (("observacao" IS NOT NULL) AND ("length"(TRIM(BOTH FROM "observacao")) > 0))) THEN 'sem_descricao'::"text"
            ELSE NULL::"text"
        END,
        CASE
            WHEN (NOT (("origem_levantamento_item_id" IS NOT NULL) OR ("origem_vistoria_id" IS NOT NULL) OR ("array_length"("casos_ids", 1) > 0) OR (EXISTS ( SELECT 1
               FROM "public"."operacoes" "o"
              WHERE ("o"."foco_risco_id" = "fr"."id"))))) THEN 'sem_evidencia'::"text"
            ELSE NULL::"text"
        END], NULL::"text") AS "pendencias",
    "dados_minimos_em"
   FROM "public"."focos_risco" "fr"
  WHERE ("deleted_at" IS NULL);


ALTER VIEW "public"."v_focos_dados_minimos_status" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_focos_dados_minimos_status" IS 'Detalhamento de dados mínimos por foco: booleano por critério + array de pendências. Usada pelo GestorFocoDetalhe (painel "Dados Mínimos"). security_invoker = true — RLS de focos_risco aplicada automaticamente.';



CREATE OR REPLACE VIEW "public"."v_focos_risco_agrupados" AS
 SELECT "f"."cliente_id",
        CASE
            WHEN (("i"."quarteirao" IS NOT NULL) AND ("i"."quarteirao" <> ''::"text")) THEN 'quadra'::"text"
            WHEN (("i"."bairro" IS NOT NULL) AND ("i"."bairro" <> ''::"text")) THEN 'bairro'::"text"
            WHEN ("r"."id" IS NOT NULL) THEN 'regiao'::"text"
            ELSE 'item'::"text"
        END AS "agrupador_tipo",
        CASE
            WHEN (("i"."quarteirao" IS NOT NULL) AND ("i"."quarteirao" <> ''::"text")) THEN "i"."quarteirao"
            WHEN (("i"."bairro" IS NOT NULL) AND ("i"."bairro" <> ''::"text")) THEN "i"."bairro"
            WHEN ("r"."id" IS NOT NULL) THEN COALESCE("r"."regiao", ("r"."id")::"text")
            ELSE COALESCE("f"."codigo_foco", ("f"."id")::"text")
        END AS "agrupador_valor",
    ("count"(*))::integer AS "quantidade_focos",
    ("count"(*) FILTER (WHERE ("f"."status" = ANY (ARRAY['em_triagem'::"text", 'aguarda_inspecao'::"text"]))))::integer AS "quantidade_elegivel",
    ("count"(*) FILTER (WHERE ("f"."status" = 'em_triagem'::"text")))::integer AS "ct_em_triagem",
    ("count"(*) FILTER (WHERE ("f"."status" = 'aguarda_inspecao'::"text")))::integer AS "ct_aguarda_inspecao",
    ("count"(*) FILTER (WHERE ("f"."responsavel_id" IS NULL)))::integer AS "ct_sem_responsavel",
    "min"(
        CASE "f"."prioridade"
            WHEN 'P1'::"text" THEN 1
            WHEN 'P2'::"text" THEN 2
            WHEN 'P3'::"text" THEN 3
            WHEN 'P4'::"text" THEN 4
            WHEN 'P5'::"text" THEN 5
            ELSE 99
        END) AS "prioridade_max_ord",
    "array_agg"("f"."id" ORDER BY "f"."score_prioridade" DESC NULLS LAST) AS "foco_ids",
    "avg"("f"."latitude") AS "lat_media",
    "avg"("f"."longitude") AS "lng_media"
   FROM (("public"."focos_risco" "f"
     LEFT JOIN "public"."imoveis" "i" ON (("i"."id" = "f"."imovel_id")))
     LEFT JOIN "public"."regioes" "r" ON (("r"."id" = "f"."regiao_id")))
  WHERE (("f"."deleted_at" IS NULL) AND ("f"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"])))
  GROUP BY "f"."cliente_id",
        CASE
            WHEN (("i"."quarteirao" IS NOT NULL) AND ("i"."quarteirao" <> ''::"text")) THEN 'quadra'::"text"
            WHEN (("i"."bairro" IS NOT NULL) AND ("i"."bairro" <> ''::"text")) THEN 'bairro'::"text"
            WHEN ("r"."id" IS NOT NULL) THEN 'regiao'::"text"
            ELSE 'item'::"text"
        END,
        CASE
            WHEN (("i"."quarteirao" IS NOT NULL) AND ("i"."quarteirao" <> ''::"text")) THEN "i"."quarteirao"
            WHEN (("i"."bairro" IS NOT NULL) AND ("i"."bairro" <> ''::"text")) THEN "i"."bairro"
            WHEN ("r"."id" IS NOT NULL) THEN COALESCE("r"."regiao", ("r"."id")::"text")
            ELSE COALESCE("f"."codigo_foco", ("f"."id")::"text")
        END;


ALTER VIEW "public"."v_focos_risco_agrupados" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_focos_risco_agrupados" IS 'Focos de risco ativos agrupados por território (quadra>bairro>regiao>item). Inclui contadores de status, ct_sem_responsavel e centróide do grupo. Fix 20270221: agrupador_valor usa COALESCE(codigo_foco, id::text) para focos individuais.';



CREATE OR REPLACE VIEW "public"."v_focos_risco_analytics" WITH ("security_invoker"='true') AS
 SELECT "fr"."id",
    "fr"."cliente_id",
    "fr"."imovel_id",
    "fr"."regiao_id",
    "r"."regiao" AS "regiao_nome",
    "fr"."status",
    "fr"."prioridade",
    "fr"."origem_tipo",
    "fr"."ciclo",
    "fr"."latitude",
    "fr"."longitude",
    "fr"."endereco_normalizado",
    "fr"."suspeita_em",
    "fr"."confirmado_em",
    "fr"."resolvido_em",
    "fr"."foco_anterior_id",
    "fr"."casos_ids",
        CASE
            WHEN ("fr"."resolvido_em" IS NOT NULL) THEN "round"((EXTRACT(epoch FROM ("fr"."resolvido_em" - "fr"."suspeita_em")) / 3600.0), 2)
            ELSE NULL::numeric
        END AS "tempo_total_horas",
        CASE
            WHEN (("fr"."resolvido_em" IS NOT NULL) AND ("sla"."prazo_final" IS NOT NULL)) THEN ("fr"."resolvido_em" <= "sla"."prazo_final")
            ELSE NULL::boolean
        END AS "sla_cumprido",
        CASE
            WHEN (("fr"."resolvido_em" IS NOT NULL) AND ("sla"."inicio" IS NOT NULL)) THEN "round"((EXTRACT(epoch FROM ("fr"."resolvido_em" - "sla"."inicio")) / 3600.0), 2)
            ELSE NULL::numeric
        END AS "sla_horas_utilizadas",
    "sla"."prazo_final" AS "sla_prazo_em",
    "sla"."violado" AS "sla_violado",
    "sla"."prioridade" AS "sla_prioridade",
    ("fr"."foco_anterior_id" IS NOT NULL) AS "eh_reincidencia",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM "public"."focos_risco" "fr2"
          WHERE (("fr2"."imovel_id" = "fr"."imovel_id") AND ("fr2"."cliente_id" = "fr"."cliente_id") AND ("fr2"."id" <> "fr"."id") AND ("fr2"."deleted_at" IS NULL))), (0)::bigint) AS "total_focos_no_imovel",
    "array_length"("fr"."casos_ids", 1) AS "total_casos_proximos",
    "fr"."created_at",
    "fr"."updated_at"
   FROM (("public"."focos_risco" "fr"
     LEFT JOIN "public"."regioes" "r" ON (("r"."id" = "fr"."regiao_id")))
     LEFT JOIN "public"."sla_operacional" "sla" ON ((("sla"."foco_risco_id" = "fr"."id") AND ("sla"."status" <> ALL (ARRAY['concluido'::"text", 'vencido'::"text"])))))
  WHERE ("fr"."deleted_at" IS NULL);


ALTER VIEW "public"."v_focos_risco_analytics" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_focos_risco_analytics" IS 'View analitica de focos_risco com campos calculados: tempo_total_horas, sla_cumprido, sla_horas_utilizadas, eh_reincidencia, total_focos_no_imovel, total_casos_proximos. Exclui focos com soft delete. Filtrar por suspeita_em para recortes temporais. security_invoker = true.';



CREATE OR REPLACE VIEW "public"."v_focos_risco_ativos" WITH ("security_invoker"='true') AS
 SELECT "fr"."id",
    "fr"."cliente_id",
    "fr"."imovel_id",
    "fr"."regiao_id",
    "fr"."origem_tipo",
    "fr"."origem_levantamento_item_id",
    "fr"."origem_vistoria_id",
    "fr"."status",
    "fr"."prioridade",
    "fr"."ciclo",
    "fr"."latitude",
    "fr"."longitude",
    "fr"."endereco_normalizado",
    "fr"."suspeita_em",
    "fr"."confirmado_em",
    "fr"."resolvido_em",
    "fr"."responsavel_id",
    "fr"."desfecho",
    "fr"."foco_anterior_id",
    "fr"."casos_ids",
    "fr"."created_at",
    "fr"."updated_at",
    "fr"."prioridade_original_antes_caso",
    "fr"."deleted_at",
    "fr"."deleted_by",
    "fr"."created_by",
    "fr"."observacao",
    "fr"."classificacao_inicial",
    "fr"."dados_minimos_em",
    "fr"."inspecao_em",
    "fr"."payload",
    "fr"."score_prioridade",
    "fr"."codigo_foco",
    "i"."logradouro",
    "i"."numero",
    "i"."bairro",
    "i"."quarteirao",
    "i"."tipo_imovel",
    "r"."regiao" AS "regiao_nome",
    "u"."nome" AS "responsavel_nome",
    "sla"."prazo_final" AS "sla_prazo_em",
    "sla"."violado" AS "sla_violado",
        CASE
            WHEN ("sla"."prazo_final" IS NULL) THEN 'sem_sla'::"text"
            WHEN ("sla"."prazo_final" < "now"()) THEN 'vencido'::"text"
            WHEN ("sla"."prazo_final" < ("now"() + (("sla"."prazo_final" - "sla"."inicio") * (0.10)::double precision))) THEN 'critico'::"text"
            WHEN ("sla"."prazo_final" < ("now"() + (("sla"."prazo_final" - "sla"."inicio") * (0.30)::double precision))) THEN 'atencao'::"text"
            ELSE 'ok'::"text"
        END AS "sla_status",
    COALESCE("li"."image_url", ("fr"."payload" ->> 'foto_url'::"text")) AS "origem_image_url",
    "li"."item" AS "origem_item",
    ((("fr"."endereco_normalizado" IS NOT NULL) OR (("fr"."latitude" IS NOT NULL) AND ("fr"."longitude" IS NOT NULL)) OR ("fr"."imovel_id" IS NOT NULL)) AND (("fr"."imovel_id" IS NOT NULL) OR ("fr"."regiao_id" IS NOT NULL)) AND ("fr"."classificacao_inicial" IS NOT NULL) AND (("fr"."observacao" IS NOT NULL) AND ("length"(TRIM(BOTH FROM "fr"."observacao")) > 0)) AND (("fr"."origem_levantamento_item_id" IS NOT NULL) OR ("fr"."origem_vistoria_id" IS NOT NULL) OR ("array_length"("fr"."casos_ids", 1) > 0) OR (EXISTS ( SELECT 1
           FROM "public"."operacoes" "o"
          WHERE ("o"."foco_risco_id" = "fr"."id"))))) AS "tem_dados_minimos",
    "array_remove"(ARRAY[
        CASE
            WHEN (NOT (("fr"."endereco_normalizado" IS NOT NULL) OR (("fr"."latitude" IS NOT NULL) AND ("fr"."longitude" IS NOT NULL)) OR ("fr"."imovel_id" IS NOT NULL))) THEN 'sem_localizacao'::"text"
            ELSE NULL::"text"
        END,
        CASE
            WHEN (NOT (("fr"."imovel_id" IS NOT NULL) OR ("fr"."regiao_id" IS NOT NULL))) THEN 'sem_bairro'::"text"
            ELSE NULL::"text"
        END,
        CASE
            WHEN (NOT (("fr"."observacao" IS NOT NULL) AND ("length"(TRIM(BOTH FROM "fr"."observacao")) > 0))) THEN 'sem_descricao'::"text"
            ELSE NULL::"text"
        END,
        CASE
            WHEN (NOT (("fr"."origem_levantamento_item_id" IS NOT NULL) OR ("fr"."origem_vistoria_id" IS NOT NULL) OR ("array_length"("fr"."casos_ids", 1) > 0) OR (EXISTS ( SELECT 1
               FROM "public"."operacoes" "o"
              WHERE ("o"."foco_risco_id" = "fr"."id"))))) THEN 'sem_evidencia'::"text"
            ELSE NULL::"text"
        END], NULL::"text") AS "pendencias"
   FROM ((((("public"."focos_risco" "fr"
     LEFT JOIN "public"."imoveis" "i" ON (("i"."id" = "fr"."imovel_id")))
     LEFT JOIN "public"."regioes" "r" ON (("r"."id" = "fr"."regiao_id")))
     LEFT JOIN "public"."usuarios" "u" ON (("u"."id" = "fr"."responsavel_id")))
     LEFT JOIN "public"."sla_operacional" "sla" ON ((("sla"."foco_risco_id" = "fr"."id") AND ("sla"."status" <> ALL (ARRAY['concluido'::"text", 'vencido'::"text"])))))
     LEFT JOIN "public"."levantamento_itens" "li" ON (("li"."id" = "fr"."origem_levantamento_item_id")))
  WHERE (("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"])) AND ("fr"."deleted_at" IS NULL));


