CREATE OR REPLACE VIEW "public"."v_imoveis_para_hoje" WITH ("security_invoker"='true') AS
 SELECT "ts"."cliente_id",
    "ts"."imovel_id",
    "ts"."score",
    "ts"."classificacao",
    "ts"."fatores",
    "ts"."calculado_em",
    "im"."logradouro",
    "im"."numero",
    "im"."bairro",
    "im"."quarteirao",
    "im"."latitude",
    "im"."longitude",
    "im"."historico_recusa",
    "im"."prioridade_drone",
    "min"("sla"."prazo_final") FILTER (WHERE (("sla"."status" = ANY (ARRAY['pendente'::"text", 'em_atendimento'::"text"])) AND ("sla"."deleted_at" IS NULL))) AS "sla_mais_urgente",
    "max"("fr"."prioridade") FILTER (WHERE (("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"])) AND ("fr"."deleted_at" IS NULL))) AS "prioridade_foco_ativo",
    "count"("fr"."id") FILTER (WHERE (("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"])) AND ("fr"."deleted_at" IS NULL))) AS "focos_ativos_count"
   FROM ((("public"."territorio_score" "ts"
     JOIN "public"."imoveis" "im" ON ((("im"."id" = "ts"."imovel_id") AND ("im"."deleted_at" IS NULL))))
     LEFT JOIN "public"."focos_risco" "fr" ON ((("fr"."imovel_id" = "ts"."imovel_id") AND ("fr"."deleted_at" IS NULL))))
     LEFT JOIN "public"."sla_operacional" "sla" ON ((("sla"."foco_risco_id" = "fr"."id") AND ("sla"."deleted_at" IS NULL))))
  WHERE ("ts"."classificacao" = ANY (ARRAY['critico'::"text", 'muito_alto'::"text", 'alto'::"text"]))
  GROUP BY "ts"."cliente_id", "ts"."imovel_id", "ts"."score", "ts"."classificacao", "ts"."fatores", "ts"."calculado_em", "im"."logradouro", "im"."numero", "im"."bairro", "im"."quarteirao", "im"."latitude", "im"."longitude", "im"."historico_recusa", "im"."prioridade_drone"
  ORDER BY "ts"."score" DESC;


ALTER VIEW "public"."v_imoveis_para_hoje" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_imoveis_para_hoje" IS 'Imóveis com score alto/muito_alto/crítico para priorização diária. security_invoker = true.';



CREATE OR REPLACE VIEW "public"."v_imoveis_reincidentes" WITH ("security_invoker"='true') AS
 WITH "cadeia_focos" AS (
         SELECT "fr"."cliente_id",
            "fr"."imovel_id",
            "count"("fr"."id") AS "total_focos_historico",
            "count"("fr"."id") FILTER (WHERE ("fr"."foco_anterior_id" IS NOT NULL)) AS "focos_reincidentes",
            "count"("fr"."id") FILTER (WHERE ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"]))) AS "focos_ativos",
            "max"("fr"."suspeita_em") AS "ultimo_foco_em",
            "min"("fr"."suspeita_em") AS "primeiro_foco_em",
                CASE
                    WHEN ("count"("fr"."id") > 1) THEN ("round"(((EXTRACT(epoch FROM ("max"("fr"."suspeita_em") - "min"("fr"."suspeita_em"))) / (("count"("fr"."id") - 1))::numeric) / (86400)::numeric), 0))::integer
                    ELSE NULL::integer
                END AS "intervalo_medio_dias",
            "count"(DISTINCT "fr"."ciclo") AS "ciclos_com_foco",
            "array_agg"(DISTINCT "fr"."origem_tipo") FILTER (WHERE ("fr"."origem_tipo" IS NOT NULL)) AS "origens",
            "round"(((100.0 * ("count"("fr"."id") FILTER (WHERE ("fr"."status" = 'resolvido'::"text")))::numeric) / (NULLIF("count"("fr"."id"), 0))::numeric), 1) AS "taxa_resolucao_pct"
           FROM "public"."focos_risco" "fr"
          WHERE (("fr"."imovel_id" IS NOT NULL) AND ("fr"."deleted_at" IS NULL))
          GROUP BY "fr"."cliente_id", "fr"."imovel_id"
         HAVING ("count"("fr"."id") >= 2)
        ), "contexto_imovel" AS (
         SELECT "v"."cliente_id",
            "v"."imovel_id",
            ( SELECT "vd2"."tipo"
                   FROM ("public"."vistoria_depositos" "vd2"
                     JOIN "public"."vistorias" "v2" ON (("v2"."id" = "vd2"."vistoria_id")))
                  WHERE (("v2"."imovel_id" = "v"."imovel_id") AND ("v2"."cliente_id" = "v"."cliente_id") AND ("vd2"."qtd_com_focos" > 0) AND ("vd2"."deleted_at" IS NULL))
                  GROUP BY "vd2"."tipo"
                  ORDER BY ("sum"("vd2"."qtd_com_focos")) DESC
                 LIMIT 1) AS "deposito_predominante",
            "count"("v"."id") FILTER (WHERE ("v"."acesso_realizado" = false)) AS "tentativas_sem_acesso",
            "bool_or"("vd"."usou_larvicida") AS "usou_larvicida_alguma_vez",
            "max"("v"."data_visita") FILTER (WHERE ("v"."acesso_realizado" = true)) AS "ultima_vistoria_com_acesso"
           FROM ("public"."vistorias" "v"
             LEFT JOIN "public"."vistoria_depositos" "vd" ON ((("vd"."vistoria_id" = "v"."id") AND ("vd"."deleted_at" IS NULL))))
          WHERE ("v"."deleted_at" IS NULL)
          GROUP BY "v"."cliente_id", "v"."imovel_id"
        )
 SELECT "cf"."cliente_id",
    "cf"."imovel_id",
    "im"."logradouro",
    "im"."numero",
    "im"."bairro",
    "im"."quarteirao",
    "im"."regiao_id",
    "im"."latitude",
    "im"."longitude",
    "im"."historico_recusa",
    "im"."prioridade_drone",
    "cf"."total_focos_historico",
    "cf"."focos_reincidentes",
    "cf"."focos_ativos",
    "cf"."ultimo_foco_em",
    "cf"."primeiro_foco_em",
    "cf"."intervalo_medio_dias",
    "cf"."ciclos_com_foco",
    "cf"."origens",
    "cf"."taxa_resolucao_pct",
    "ci"."deposito_predominante",
    "ci"."tentativas_sem_acesso",
    "ci"."usou_larvicida_alguma_vez",
    "ci"."ultima_vistoria_com_acesso",
        CASE
            WHEN (("cf"."total_focos_historico" >= 5) AND ("cf"."focos_reincidentes" >= 3)) THEN 'cronico'::"text"
            WHEN (("cf"."total_focos_historico" >= 3) AND ("cf"."focos_reincidentes" >= 1)) THEN 'recorrente'::"text"
            ELSE 'pontual'::"text"
        END AS "padrao",
    (EXTRACT(day FROM ("now"() - "cf"."ultimo_foco_em")))::integer AS "dias_desde_ultimo_foco"
   FROM (("cadeia_focos" "cf"
     JOIN "public"."imoveis" "im" ON ((("im"."id" = "cf"."imovel_id") AND ("im"."deleted_at" IS NULL))))
     LEFT JOIN "contexto_imovel" "ci" ON ((("ci"."imovel_id" = "cf"."imovel_id") AND ("ci"."cliente_id" = "cf"."cliente_id"))))
  ORDER BY "cf"."total_focos_historico" DESC, "cf"."ultimo_foco_em" DESC;


ALTER VIEW "public"."v_imoveis_reincidentes" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_imoveis_reincidentes" IS 'Imóveis com padrão de reincidência (>= 2 focos históricos). Combina dados de focos_risco (Sistema B) com contexto de vistorias. Classificação: cronico (5+ focos, 3+ reincidentes) | recorrente | pontual. security_invoker = true.';



CREATE OR REPLACE VIEW "public"."v_imovel_historico_acesso" AS
SELECT
    NULL::"uuid" AS "imovel_id",
    NULL::"uuid" AS "cliente_id",
    NULL::"text" AS "logradouro",
    NULL::"text" AS "numero",
    NULL::"text" AS "bairro",
    NULL::"text" AS "quarteirao",
    NULL::boolean AS "proprietario_ausente",
    NULL::"text" AS "tipo_ausencia",
    NULL::boolean AS "tem_animal_agressivo",
    NULL::boolean AS "historico_recusa",
    NULL::boolean AS "prioridade_drone",
    NULL::boolean AS "tem_calha",
    NULL::boolean AS "calha_acessivel",
    NULL::"date" AS "notificacao_formal_em",
    NULL::bigint AS "total_visitas",
    NULL::bigint AS "total_sem_acesso",
    NULL::numeric AS "pct_sem_acesso",
    NULL::timestamp with time zone AS "ultima_visita_com_acesso",
    NULL::timestamp with time zone AS "ultima_tentativa",
    NULL::boolean AS "requer_notificacao_formal";


ALTER VIEW "public"."v_imovel_historico_acesso" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_imovel_resumo" WITH ("security_invoker"='true') AS
 SELECT "im"."id",
    "im"."cliente_id",
    "im"."regiao_id",
    "im"."bairro",
    "im"."quarteirao",
    "im"."logradouro",
    "im"."numero",
    "im"."complemento",
    "im"."tipo_imovel",
    "im"."latitude",
    "im"."longitude",
    "im"."ativo",
    "im"."historico_recusa",
    "im"."prioridade_drone",
    "im"."tem_calha",
    "im"."calha_acessivel",
    "im"."created_at",
    "im"."updated_at",
    "count"(DISTINCT "v"."id") AS "total_vistorias",
    "max"("v"."data_visita") AS "ultima_visita",
    "count"(DISTINCT
        CASE
            WHEN (("v"."acesso_realizado" = false) AND ("v"."created_at" >= ("now"() - '90 days'::interval))) THEN "v"."id"
            ELSE NULL::"uuid"
        END) AS "tentativas_sem_acesso",
    "count"(DISTINCT "fr"."id") AS "total_focos_historico",
    "count"(DISTINCT
        CASE
            WHEN ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"])) THEN "fr"."id"
            ELSE NULL::"uuid"
        END) AS "focos_ativos",
    "max"("fr"."created_at") AS "ultimo_foco_em",
    "count"(DISTINCT
        CASE
            WHEN ("sla"."status" = ANY (ARRAY['pendente'::"text", 'em_atendimento'::"text"])) THEN "sla"."id"
            ELSE NULL::"uuid"
        END) AS "slas_abertos",
    "count"(DISTINCT
        CASE
            WHEN (("fr"."foco_anterior_id" IS NOT NULL) AND ("fr"."created_at" >= ("now"() - '180 days'::interval))) THEN "fr"."id"
            ELSE NULL::"uuid"
        END) AS "focos_recorrentes",
    "ts"."score" AS "score_territorial",
    "ts"."classificacao" AS "score_classificacao",
    "ts"."fatores" AS "score_fatores",
    "ts"."calculado_em" AS "score_calculado_em"
   FROM (((("public"."imoveis" "im"
     LEFT JOIN "public"."vistorias" "v" ON ((("v"."imovel_id" = "im"."id") AND ("v"."deleted_at" IS NULL))))
     LEFT JOIN "public"."focos_risco" "fr" ON ((("fr"."imovel_id" = "im"."id") AND ("fr"."deleted_at" IS NULL))))
     LEFT JOIN "public"."sla_operacional" "sla" ON (("sla"."foco_risco_id" = "fr"."id")))
     LEFT JOIN "public"."territorio_score" "ts" ON ((("ts"."imovel_id" = "im"."id") AND ("ts"."cliente_id" = "im"."cliente_id"))))
  WHERE ("im"."deleted_at" IS NULL)
  GROUP BY "im"."id", "im"."cliente_id", "im"."regiao_id", "im"."bairro", "im"."quarteirao", "im"."logradouro", "im"."numero", "im"."complemento", "im"."tipo_imovel", "im"."latitude", "im"."longitude", "im"."ativo", "im"."historico_recusa", "im"."prioridade_drone", "im"."tem_calha", "im"."calha_acessivel", "im"."created_at", "im"."updated_at", "ts"."score", "ts"."classificacao", "ts"."fatores", "ts"."calculado_em";


ALTER VIEW "public"."v_imovel_resumo" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_imovel_resumo" IS 'Resumo territorial do imóvel: vistorias, focos históricos, SLA ativo, recorrência e score territorial. R1 (20260916): tentativas_sem_acesso filtra últimos 90 dias (consistente com trigger). R2 (20260916): focos_recorrentes filtra últimos 180 dias (evita badge eterno). Base do módulo Imóvel 360°. security_invoker=true herda RLS do usuário.';



CREATE OR REPLACE VIEW "public"."v_liraa_quarteirao" WITH ("security_invoker"='true') AS
 SELECT "v"."cliente_id",
    "v"."ciclo",
    "im"."bairro",
    "im"."quarteirao",
    "count"(DISTINCT "v"."imovel_id") AS "imoveis_inspecionados",
    "count"(DISTINCT
        CASE
            WHEN ("vd_pos"."vistoria_id" IS NOT NULL) THEN "v"."imovel_id"
            ELSE NULL::"uuid"
        END) AS "imoveis_positivos",
    "round"(
        CASE
            WHEN ("count"(DISTINCT "v"."imovel_id") > 0) THEN ((("count"(DISTINCT
            CASE
                WHEN ("vd_pos"."vistoria_id" IS NOT NULL) THEN "v"."imovel_id"
                ELSE NULL::"uuid"
            END))::numeric / ("count"(DISTINCT "v"."imovel_id"))::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END, 1) AS "iip",
    COALESCE("sum"("vd"."qtd_com_focos"), (0)::bigint) AS "total_focos",
    "round"(
        CASE
            WHEN ("count"(DISTINCT "v"."imovel_id") > 0) THEN (((COALESCE("sum"("vd"."qtd_com_focos"), (0)::bigint))::numeric / ("count"(DISTINCT "v"."imovel_id"))::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END, 1) AS "ibp",
    COALESCE("sum"(
        CASE
            WHEN ("vd"."tipo" = 'A1'::"text") THEN "vd"."qtd_com_focos"
            ELSE 0
        END), (0)::bigint) AS "focos_a1",
    COALESCE("sum"(
        CASE
            WHEN ("vd"."tipo" = 'A2'::"text") THEN "vd"."qtd_com_focos"
            ELSE 0
        END), (0)::bigint) AS "focos_a2",
    COALESCE("sum"(
        CASE
            WHEN ("vd"."tipo" = 'B'::"text") THEN "vd"."qtd_com_focos"
            ELSE 0
        END), (0)::bigint) AS "focos_b",
    COALESCE("sum"(
        CASE
            WHEN ("vd"."tipo" = 'C'::"text") THEN "vd"."qtd_com_focos"
            ELSE 0
        END), (0)::bigint) AS "focos_c",
    COALESCE("sum"(
        CASE
            WHEN ("vd"."tipo" = 'D1'::"text") THEN "vd"."qtd_com_focos"
            ELSE 0
        END), (0)::bigint) AS "focos_d1",
    COALESCE("sum"(
        CASE
            WHEN ("vd"."tipo" = 'D2'::"text") THEN "vd"."qtd_com_focos"
            ELSE 0
        END), (0)::bigint) AS "focos_d2",
    COALESCE("sum"(
        CASE
            WHEN ("vd"."tipo" = 'E'::"text") THEN "vd"."qtd_com_focos"
            ELSE 0
        END), (0)::bigint) AS "focos_e",
    COALESCE("sum"(
        CASE
            WHEN "vd"."usou_larvicida" THEN "vd"."qtd_larvicida_g"
            ELSE (0)::double precision
        END), (0)::double precision) AS "larvicida_total_g"
   FROM ((("public"."vistorias" "v"
     JOIN "public"."imoveis" "im" ON (("im"."id" = "v"."imovel_id")))
     LEFT JOIN "public"."vistoria_depositos" "vd" ON (("vd"."vistoria_id" = "v"."id")))
     LEFT JOIN LATERAL ( SELECT DISTINCT "vd2"."vistoria_id"
           FROM "public"."vistoria_depositos" "vd2"
          WHERE (("vd2"."vistoria_id" = "v"."id") AND ("vd2"."qtd_com_focos" > 0))
         LIMIT 1) "vd_pos" ON (true))
  WHERE (("v"."acesso_realizado" = true) AND ("v"."deleted_at" IS NULL) AND ("im"."deleted_at" IS NULL))
  GROUP BY "v"."cliente_id", "v"."ciclo", "im"."bairro", "im"."quarteirao";


ALTER VIEW "public"."v_liraa_quarteirao" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_liraa_quarteirao" IS 'LIRAa por quarteirão: IIP, IBP e focos por tipo de depósito PNCD. Agrega vistorias com acesso_realizado=true. security_invoker=true herda RLS do usuário.';



CREATE OR REPLACE VIEW "public"."v_operacao_focos" AS
 SELECT "cliente_id",
    "date_trunc"('day'::"text", ("created_at" AT TIME ZONE 'America/Sao_Paulo'::"text")) AS "dia",
    "count"(*) FILTER (WHERE ("tipo" = 'foco_visualizado'::"text")) AS "focos_visualizados",
    "count"(*) FILTER (WHERE ("tipo" = 'foco_iniciado'::"text")) AS "focos_iniciados",
    "count"(*) FILTER (WHERE ("tipo" = 'foco_resolvido'::"text")) AS "focos_resolvidos",
    "count"(*) FILTER (WHERE ("tipo" = 'foco_alta_prioridade_listado'::"text")) AS "listagens_alta_prioridade",
    "count"(*) FILTER (WHERE ("tipo" = 'foco_critico_exibido'::"text")) AS "criticos_exibidos",
    "count"(*) FILTER (WHERE ("tipo" = 'dashboard_aberto'::"text")) AS "dashboards_abertos",
    "count"(DISTINCT "usuario_id") AS "usuarios_unicos",
        CASE
            WHEN ("count"(*) FILTER (WHERE ("tipo" = 'foco_visualizado'::"text")) > 0) THEN "round"(((("count"(*) FILTER (WHERE ("tipo" = 'foco_iniciado'::"text")))::numeric / ("count"(*) FILTER (WHERE ("tipo" = 'foco_visualizado'::"text")))::numeric) * (100)::numeric), 1)
            ELSE NULL::numeric
        END AS "taxa_conversao_pct"
   FROM "public"."piloto_eventos"
  WHERE ("tipo" = ANY (ARRAY['foco_visualizado'::"text", 'foco_iniciado'::"text", 'foco_resolvido'::"text", 'foco_alta_prioridade_listado'::"text", 'foco_critico_exibido'::"text", 'dashboard_aberto'::"text"]))
  GROUP BY "cliente_id", ("date_trunc"('day'::"text", ("created_at" AT TIME ZONE 'America/Sao_Paulo'::"text")));


ALTER VIEW "public"."v_operacao_focos" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_piloto_despachos_supervisor" WITH ("security_invoker"='true') AS
 WITH "primeiro_despacho" AS (
         SELECT DISTINCT ON ("foco_risco_historico"."foco_risco_id") "foco_risco_historico"."foco_risco_id",
            "foco_risco_historico"."cliente_id",
            "foco_risco_historico"."alterado_por" AS "supervisor_id",
            "foco_risco_historico"."alterado_em" AS "despachado_em"
           FROM "public"."foco_risco_historico"
          WHERE ("foco_risco_historico"."status_novo" = 'aguarda_inspecao'::"text")
          ORDER BY "foco_risco_historico"."foco_risco_id", "foco_risco_historico"."alterado_em"
        )
 SELECT "pd"."cliente_id",
    "pd"."supervisor_id",
    "u"."nome" AS "supervisor_nome",
    "count"(*) FILTER (WHERE ("pd"."despachado_em" >= CURRENT_DATE)) AS "despachados_hoje",
    "count"(*) FILTER (WHERE ("pd"."despachado_em" >= (CURRENT_DATE - '7 days'::interval))) AS "despachados_7d",
    "count"(*) AS "despachados_total",
    "round"("avg"((EXTRACT(epoch FROM ("pd"."despachado_em" - "fr"."suspeita_em")) / 3600.0)) FILTER (WHERE ("pd"."despachado_em" >= (CURRENT_DATE - '7 days'::interval))), 1) AS "tempo_medio_triagem_7d_horas"
   FROM (("primeiro_despacho" "pd"
     JOIN "public"."focos_risco" "fr" ON ((("fr"."id" = "pd"."foco_risco_id") AND ("fr"."deleted_at" IS NULL))))
     LEFT JOIN "public"."usuarios" "u" ON (("u"."id" = "pd"."supervisor_id")))
  GROUP BY "pd"."cliente_id", "pd"."supervisor_id", "u"."nome";


ALTER VIEW "public"."v_piloto_despachos_supervisor" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_piloto_despachos_supervisor" IS 'Produtividade de despacho por supervisor: volume hoje, 7d, total e tempo médio em triagem. security_invoker=true. Fonte: foco_risco_historico (append-only, imutável).';



CREATE OR REPLACE VIEW "public"."v_piloto_funil_hoje" WITH ("security_invoker"='true') AS
 WITH "primeiro_despacho" AS (
         SELECT DISTINCT ON ("foco_risco_historico"."foco_risco_id") "foco_risco_historico"."foco_risco_id",
            "foco_risco_historico"."alterado_por" AS "supervisor_id",
            "foco_risco_historico"."alterado_em" AS "despachado_em"
           FROM "public"."foco_risco_historico"
          WHERE ("foco_risco_historico"."status_novo" = 'aguarda_inspecao'::"text")
          ORDER BY "foco_risco_historico"."foco_risco_id", "foco_risco_historico"."alterado_em"
        )
 SELECT "fr"."cliente_id",
    "count"(*) FILTER (WHERE ("fr"."suspeita_em" >= CURRENT_DATE)) AS "entradas_hoje",
    "count"(*) FILTER (WHERE ("fr"."suspeita_em" >= (CURRENT_DATE - '7 days'::interval))) AS "entradas_7d",
    "count"(*) FILTER (WHERE ("fr"."status" = ANY (ARRAY['suspeita'::"text", 'em_triagem'::"text"]))) AS "em_triagem_agora",
    "count"(*) FILTER (WHERE ("fr"."status" = 'aguarda_inspecao'::"text")) AS "aguarda_inspecao_agora",
    "count"(*) FILTER (WHERE ("fr"."status" = 'em_inspecao'::"text")) AS "em_inspecao_agora",
    "count"(*) FILTER (WHERE ("fr"."status" = ANY (ARRAY['confirmado'::"text", 'em_tratamento'::"text"]))) AS "em_tratamento_agora",
    "count"(*) FILTER (WHERE ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"]))) AS "ativos_total",
    "count"(*) FILTER (WHERE (("fr"."status" = 'resolvido'::"text") AND ("fr"."resolvido_em" >= CURRENT_DATE))) AS "resolvidos_hoje",
    "count"(*) FILTER (WHERE (("fr"."status" = 'resolvido'::"text") AND ("fr"."resolvido_em" >= (CURRENT_DATE - '7 days'::interval)))) AS "resolvidos_7d",
    "count"("pd"."foco_risco_id") FILTER (WHERE ("pd"."despachado_em" >= CURRENT_DATE)) AS "despachados_hoje",
    "count"("pd"."foco_risco_id") FILTER (WHERE ("pd"."despachado_em" >= (CURRENT_DATE - '7 days'::interval))) AS "despachados_7d",
    "count"(*) FILTER (WHERE (("fr"."status" = ANY (ARRAY['suspeita'::"text", 'em_triagem'::"text"])) AND ("fr"."responsavel_id" IS NULL))) AS "sem_responsavel_em_triagem",
    "count"(*) FILTER (WHERE (("fr"."status" = ANY (ARRAY['suspeita'::"text", 'em_triagem'::"text"])) AND (("now"() - "fr"."suspeita_em") > '24:00:00'::interval))) AS "envelhecidos_24h",
    "count"(*) FILTER (WHERE (("fr"."status" = 'aguarda_inspecao'::"text") AND (("now"() - "fr"."suspeita_em") > '48:00:00'::interval))) AS "aguardando_envelhecidos_48h",
    "min"("fr"."suspeita_em") FILTER (WHERE ("fr"."status" = ANY (ARRAY['suspeita'::"text", 'em_triagem'::"text"]))) AS "foco_mais_antigo_em",
    "round"("avg"((EXTRACT(epoch FROM ("pd"."despachado_em" - "fr"."suspeita_em")) / 3600.0)) FILTER (WHERE ("pd"."despachado_em" >= (CURRENT_DATE - '7 days'::interval))), 1) AS "tempo_medio_triagem_7d_horas",
    "round"("avg"((EXTRACT(epoch FROM ("fr"."inspecao_em" - "fr"."suspeita_em")) / 3600.0)) FILTER (WHERE (("fr"."inspecao_em" IS NOT NULL) AND ("fr"."inspecao_em" >= (CURRENT_DATE - '7 days'::interval)))), 1) AS "tempo_medio_suspeita_inspecao_7d_horas",
    "jsonb_build_object"('drone', "count"(*) FILTER (WHERE (("fr"."origem_tipo" = 'drone'::"text") AND ("fr"."suspeita_em" >= CURRENT_DATE))), 'cidadao', "count"(*) FILTER (WHERE (("fr"."origem_tipo" = 'cidadao'::"text") AND ("fr"."suspeita_em" >= CURRENT_DATE))), 'agente', "count"(*) FILTER (WHERE (("fr"."origem_tipo" = 'agente'::"text") AND ("fr"."suspeita_em" >= CURRENT_DATE))), 'manual', "count"(*) FILTER (WHERE (("fr"."origem_tipo" = 'manual'::"text") AND ("fr"."suspeita_em" >= CURRENT_DATE))), 'pluvio', "count"(*) FILTER (WHERE (("fr"."origem_tipo" = 'pluvio'::"text") AND ("fr"."suspeita_em" >= CURRENT_DATE)))) AS "entradas_por_origem_hoje"
   FROM ("public"."focos_risco" "fr"
     LEFT JOIN "primeiro_despacho" "pd" ON (("pd"."foco_risco_id" = "fr"."id")))
  WHERE ("fr"."deleted_at" IS NULL)
  GROUP BY "fr"."cliente_id";


ALTER VIEW "public"."v_piloto_funil_hoje" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_piloto_funil_hoje" IS 'Funil operacional do piloto: entradas → triagem → despacho → campo → resolução. Hoje + 7 dias. Tempo médio de triagem via foco_risco_historico (append-only). security_invoker=true — RLS garante isolamento por cliente.';



CREATE OR REPLACE VIEW "public"."v_piloto_prod_agentes" WITH ("security_invoker"='true') AS
 SELECT "fr"."cliente_id",
    "fr"."responsavel_id" AS "agente_id",
    "u"."nome" AS "agente_nome",
    "count"(*) FILTER (WHERE ("fr"."status" <> ALL (ARRAY['resolvido'::"text", 'descartado'::"text"]))) AS "atribuidos_ativos",
    "count"(*) FILTER (WHERE ("fr"."status" = 'aguarda_inspecao'::"text")) AS "aguardando",
    "count"(*) FILTER (WHERE ("fr"."status" = 'em_inspecao'::"text")) AS "em_inspecao",
    "count"(*) FILTER (WHERE ("fr"."inspecao_em" IS NOT NULL)) AS "iniciados_total",
    "count"(*) FILTER (WHERE (("fr"."inspecao_em" IS NOT NULL) AND ("fr"."inspecao_em" >= CURRENT_DATE))) AS "iniciados_hoje",
    "count"(*) FILTER (WHERE ("fr"."status" = 'resolvido'::"text")) AS "resolvidos_total",
    "count"(*) FILTER (WHERE (("fr"."status" = 'resolvido'::"text") AND ("fr"."resolvido_em" >= CURRENT_DATE))) AS "resolvidos_hoje",
    "count"(*) FILTER (WHERE (("fr"."status" = 'aguarda_inspecao'::"text") AND (("now"() - "fr"."suspeita_em") > '48:00:00'::interval))) AS "envelhecidos",
    "round"("avg"((EXTRACT(epoch FROM ("fr"."inspecao_em" - "fr"."suspeita_em")) / 3600.0)) FILTER (WHERE ("fr"."inspecao_em" IS NOT NULL)), 1) AS "tempo_medio_despacho_inspecao_horas"
   FROM ("public"."focos_risco" "fr"
     LEFT JOIN "public"."usuarios" "u" ON (("u"."id" = "fr"."responsavel_id")))
  WHERE (("fr"."deleted_at" IS NULL) AND ("fr"."responsavel_id" IS NOT NULL))
  GROUP BY "fr"."cliente_id", "fr"."responsavel_id", "u"."nome";


ALTER VIEW "public"."v_piloto_prod_agentes" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_piloto_prod_agentes" IS 'Produtividade dos agentes em campo: atribuídos, iniciados, resolvidos, envelhecidos. Fonte: focos_risco por responsavel_id. security_invoker=true.';



CREATE OR REPLACE VIEW "public"."v_regional_kpi_municipio" WITH ("security_invoker"='false') AS
 SELECT "c"."id" AS "cliente_id",
    "c"."nome" AS "municipio_nome",
    "c"."cidade",
    "c"."uf",
    "count"("f"."id") AS "total_focos",
    "count"("f"."id") FILTER (WHERE ("f"."status" = 'suspeita'::"text")) AS "focos_suspeita",
    "count"("f"."id") FILTER (WHERE ("f"."status" = 'em_triagem'::"text")) AS "focos_em_triagem",
    "count"("f"."id") FILTER (WHERE ("f"."status" = 'aguarda_inspecao'::"text")) AS "focos_aguarda_inspecao",
    "count"("f"."id") FILTER (WHERE ("f"."status" = ANY (ARRAY['em_inspecao'::"text", 'confirmado'::"text", 'em_tratamento'::"text"]))) AS "focos_ativos",
    "count"("f"."id") FILTER (WHERE ("f"."status" = 'confirmado'::"text")) AS "focos_confirmados",
    "count"("f"."id") FILTER (WHERE ("f"."status" = 'em_tratamento'::"text")) AS "focos_em_tratamento",
    "count"("f"."id") FILTER (WHERE ("f"."status" = 'resolvido'::"text")) AS "focos_resolvidos",
    "count"("f"."id") FILTER (WHERE ("f"."status" = 'descartado'::"text")) AS "focos_descartados",
    "round"(
        CASE
            WHEN ("count"("f"."id") FILTER (WHERE ("f"."status" <> ALL (ARRAY['suspeita'::"text", 'descartado'::"text"]))) > 0) THEN ((("count"("f"."id") FILTER (WHERE ("f"."status" = 'resolvido'::"text")))::numeric / ("count"("f"."id") FILTER (WHERE ("f"."status" <> ALL (ARRAY['suspeita'::"text", 'descartado'::"text"]))))::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END, 1) AS "taxa_resolucao_pct",
    "round"("avg"((EXTRACT(epoch FROM ("f"."resolvido_em" - "f"."confirmado_em")) / 3600.0)) FILTER (WHERE (("f"."resolvido_em" IS NOT NULL) AND ("f"."confirmado_em" IS NOT NULL))), 1) AS "tempo_medio_resolucao_horas",
    "count"("f"."id") FILTER (WHERE (("f"."status" = ANY (ARRAY['confirmado'::"text", 'em_tratamento'::"text"])) AND ("f"."confirmado_em" IS NOT NULL) AND ("f"."confirmado_em" < ("now"() - '72:00:00'::interval)))) AS "sla_vencido_count",
    "now"() AS "calculado_em"
   FROM ("public"."clientes" "c"
     LEFT JOIN "public"."focos_risco" "f" ON ((("f"."cliente_id" = "c"."id") AND ("f"."deleted_at" IS NULL))))
  WHERE (("c"."ativo" = true) AND (("c"."deleted_at" IS NULL) OR ("c"."deleted_at" > "now"())) AND ("public"."is_admin"() OR ("c"."id" IN ( SELECT "ac"."cliente_id"
           FROM ("public"."agrupamento_cliente" "ac"
             JOIN "public"."usuarios" "u" ON (("u"."agrupamento_id" = "ac"."agrupamento_id")))
          WHERE ("u"."auth_id" = "auth"."uid"())))))
  GROUP BY "c"."id", "c"."nome", "c"."cidade", "c"."uf";


ALTER VIEW "public"."v_regional_kpi_municipio" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_regional_kpi_municipio" IS 'KPI agregado por município para o papel analista_regional. security_invoker=false: acesso às tabelas base via owner. Filtragem interna por agrupamento_cliente. Sem PII.';



CREATE OR REPLACE VIEW "public"."v_regional_sla_municipio" WITH ("security_invoker"='false') AS
 SELECT "c"."id" AS "cliente_id",
    "c"."nome" AS "municipio_nome",
    "c"."cidade",
    "c"."uf",
    "count"("f"."id") FILTER (WHERE ("f"."status" = ANY (ARRAY['confirmado'::"text", 'em_tratamento'::"text"]))) AS "total_ativos",
    "count"("f"."id") FILTER (WHERE (("f"."status" = ANY (ARRAY['confirmado'::"text", 'em_tratamento'::"text"])) AND ("f"."confirmado_em" >= ("now"() - '12:00:00'::interval)))) AS "sla_ok",
    "count"("f"."id") FILTER (WHERE (("f"."status" = ANY (ARRAY['confirmado'::"text", 'em_tratamento'::"text"])) AND ("f"."confirmado_em" < ("now"() - '12:00:00'::interval)) AND ("f"."confirmado_em" >= ("now"() - '24:00:00'::interval)))) AS "sla_atencao",
    "count"("f"."id") FILTER (WHERE (("f"."status" = ANY (ARRAY['confirmado'::"text", 'em_tratamento'::"text"])) AND ("f"."confirmado_em" < ("now"() - '24:00:00'::interval)) AND ("f"."confirmado_em" >= ("now"() - '72:00:00'::interval)))) AS "sla_critico",
    "count"("f"."id") FILTER (WHERE (("f"."status" = ANY (ARRAY['confirmado'::"text", 'em_tratamento'::"text"])) AND ("f"."confirmado_em" < ("now"() - '72:00:00'::interval)))) AS "sla_vencido",
    "now"() AS "calculado_em"
   FROM ("public"."clientes" "c"
     LEFT JOIN "public"."focos_risco" "f" ON ((("f"."cliente_id" = "c"."id") AND ("f"."deleted_at" IS NULL))))
  WHERE (("c"."ativo" = true) AND (("c"."deleted_at" IS NULL) OR ("c"."deleted_at" > "now"())) AND ("public"."is_admin"() OR ("c"."id" IN ( SELECT "ac"."cliente_id"
           FROM ("public"."agrupamento_cliente" "ac"
             JOIN "public"."usuarios" "u" ON (("u"."agrupamento_id" = "ac"."agrupamento_id")))
          WHERE ("u"."auth_id" = "auth"."uid"())))))
  GROUP BY "c"."id", "c"."nome", "c"."cidade", "c"."uf";


ALTER VIEW "public"."v_regional_sla_municipio" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_regional_sla_municipio" IS 'Distribuição de SLA (buckets 12h/24h/72h) por município para analista_regional. Sem PII — apenas contagens agregadas.';



CREATE OR REPLACE VIEW "public"."v_regional_uso_sistema" WITH ("security_invoker"='false') AS
 SELECT "c"."id" AS "cliente_id",
    "c"."nome" AS "municipio_nome",
    "c"."cidade",
    "c"."uf",
    "count"("pe"."id") FILTER (WHERE ("pe"."created_at" >= ("now"() - '7 days'::interval))) AS "eventos_7d",
    "count"("pe"."id") FILTER (WHERE (("pe"."tipo" = ANY (ARRAY['triagem_distribuicao_lote'::"text", 'triagem_distribuicao_individual'::"text"])) AND ("pe"."created_at" >= ("now"() - '7 days'::interval)))) AS "distribuicoes_7d",
    "count"("pe"."id") FILTER (WHERE (("pe"."tipo" = 'foco_inspecao_iniciada'::"text") AND ("pe"."created_at" >= ("now"() - '7 days'::interval)))) AS "inspecoes_iniciadas_7d",
    "count"("pe"."id") FILTER (WHERE (("pe"."tipo" = 'foco_resolvido'::"text") AND ("pe"."created_at" >= ("now"() - '7 days'::interval)))) AS "focos_resolvidos_7d",
    "max"("pe"."created_at") AS "ultimo_evento_em",
    "now"() AS "calculado_em"
   FROM ("public"."clientes" "c"
     LEFT JOIN "public"."piloto_eventos" "pe" ON (("pe"."cliente_id" = "c"."id")))
  WHERE (("c"."ativo" = true) AND (("c"."deleted_at" IS NULL) OR ("c"."deleted_at" > "now"())) AND ("public"."is_admin"() OR ("c"."id" IN ( SELECT "ac"."cliente_id"
           FROM ("public"."agrupamento_cliente" "ac"
             JOIN "public"."usuarios" "u" ON (("u"."agrupamento_id" = "ac"."agrupamento_id")))
          WHERE ("u"."auth_id" = "auth"."uid"())))))
  GROUP BY "c"."id", "c"."nome", "c"."cidade", "c"."uf";


ALTER VIEW "public"."v_regional_uso_sistema" OWNER TO "postgres";


