CREATE OR REPLACE VIEW "public"."v_reincidencia_por_deposito" WITH ("security_invoker"='true') AS
 WITH "depositos_com_foco" AS (
         SELECT "v"."cliente_id",
            "im"."bairro",
            "im"."regiao_id",
            "vd"."tipo" AS "tipo_deposito",
            "count"(DISTINCT "v"."imovel_id") AS "imoveis_afetados",
            "sum"("vd"."qtd_com_focos") AS "total_focos_deposito",
            "sum"("vd"."qtd_eliminados") AS "total_eliminados",
            "count"(DISTINCT "v"."ciclo") AS "ciclos_com_ocorrencia",
            "round"(((100.0 * ("sum"("vd"."qtd_eliminados"))::numeric) / (NULLIF("sum"("vd"."qtd_com_focos"), 0))::numeric), 1) AS "taxa_eliminacao_pct",
            "round"(((100.0 * ("count"(*) FILTER (WHERE ("vd"."usou_larvicida" = true)))::numeric) / (NULLIF("count"(*), 0))::numeric), 1) AS "uso_larvicida_pct",
            "count"(DISTINCT "v"."imovel_id") FILTER (WHERE (EXISTS ( SELECT 1
                   FROM ("public"."vistorias" "v2"
                     JOIN "public"."vistoria_depositos" "vd2" ON (("vd2"."vistoria_id" = "v2"."id")))
                  WHERE (("v2"."imovel_id" = "v"."imovel_id") AND ("v2"."cliente_id" = "v"."cliente_id") AND ("v2"."ciclo" <> "v"."ciclo") AND ("vd2"."tipo" = "vd"."tipo") AND ("vd2"."qtd_com_focos" > 0) AND ("vd2"."deleted_at" IS NULL))))) AS "imoveis_multiciclo"
           FROM (("public"."vistorias" "v"
             JOIN "public"."vistoria_depositos" "vd" ON (("vd"."vistoria_id" = "v"."id")))
             JOIN "public"."imoveis" "im" ON (("im"."id" = "v"."imovel_id")))
          WHERE (("vd"."qtd_com_focos" > 0) AND ("v"."deleted_at" IS NULL) AND ("vd"."deleted_at" IS NULL) AND ("im"."deleted_at" IS NULL))
          GROUP BY "v"."cliente_id", "im"."bairro", "im"."regiao_id", "vd"."tipo"
        )
 SELECT "cliente_id",
    "bairro",
    "regiao_id",
    "tipo_deposito",
    "imoveis_afetados",
    "total_focos_deposito",
    "total_eliminados",
    "ciclos_com_ocorrencia",
    "taxa_eliminacao_pct",
    "uso_larvicida_pct",
    "imoveis_multiciclo",
    "round"(((100.0 * ("imoveis_multiciclo")::numeric) / (NULLIF("imoveis_afetados", 0))::numeric), 1) AS "indice_reincidencia_pct"
   FROM "depositos_com_foco"
  ORDER BY "imoveis_multiciclo" DESC, "total_focos_deposito" DESC;


ALTER VIEW "public"."v_reincidencia_por_deposito" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_reincidencia_por_deposito" IS 'Tipos de depósito que mais reincidem por bairro. indice_reincidencia_pct: % de imóveis afetados em múltiplos ciclos. security_invoker = true.';



CREATE OR REPLACE VIEW "public"."v_reincidencia_sazonalidade" WITH ("security_invoker"='true') AS
 SELECT "fr"."cliente_id",
    "im"."bairro",
    "im"."regiao_id",
    "fr"."ciclo",
    "count"("fr"."id") AS "focos_total",
    "count"("fr"."id") FILTER (WHERE ("fr"."foco_anterior_id" IS NOT NULL)) AS "focos_reincidentes",
    "count"("fr"."id") FILTER (WHERE ("fr"."status" = 'resolvido'::"text")) AS "focos_resolvidos",
    "count"(DISTINCT EXTRACT(year FROM "fr"."suspeita_em")) AS "anos_com_ocorrencia",
    "round"((("count"("fr"."id"))::numeric / (NULLIF("count"(DISTINCT EXTRACT(year FROM "fr"."suspeita_em")), 0))::numeric), 1) AS "media_focos_por_ano",
    "round"(((("count"("fr"."id") FILTER (WHERE ("fr"."suspeita_em" >= ("now"() - '2 years'::interval))))::numeric / (2)::numeric) - (("count"("fr"."id"))::numeric / (NULLIF("count"(DISTINCT EXTRACT(year FROM "fr"."suspeita_em")), 0))::numeric)), 1) AS "delta_tendencia"
   FROM ("public"."focos_risco" "fr"
     JOIN "public"."imoveis" "im" ON (("im"."id" = "fr"."imovel_id")))
  WHERE (("fr"."imovel_id" IS NOT NULL) AND ("fr"."ciclo" IS NOT NULL) AND ("fr"."deleted_at" IS NULL) AND ("im"."deleted_at" IS NULL))
  GROUP BY "fr"."cliente_id", "im"."bairro", "im"."regiao_id", "fr"."ciclo"
 HAVING ("count"("fr"."id") >= 2)
  ORDER BY ("count"("fr"."id") FILTER (WHERE ("fr"."foco_anterior_id" IS NOT NULL))) DESC;


ALTER VIEW "public"."v_reincidencia_sazonalidade" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_reincidencia_sazonalidade" IS 'Padrão sazonal de reincidência por bairro e ciclo bimestral. delta_tendencia > 0 indica piora nos últimos 2 anos vs. média histórica. security_invoker = true.';



CREATE OR REPLACE VIEW "public"."v_retencao_logs_resumo" WITH ("security_invoker"='on') AS
 SELECT 'sla_erros_criacao'::"text" AS "tabela",
    '90 dias'::"text" AS "politica",
    "count"(*) AS "total_registros",
    "count"(*) FILTER (WHERE ("sla_erros_criacao"."retention_until" < "now"())) AS "expirados",
    "min"("sla_erros_criacao"."retention_until") AS "proximo_expira"
   FROM "public"."sla_erros_criacao"
UNION ALL
 SELECT 'offline_sync_log'::"text" AS "tabela",
    '90 dias'::"text" AS "politica",
    "count"(*) AS "total_registros",
    "count"(*) FILTER (WHERE ("offline_sync_log"."retention_until" < "now"())) AS "expirados",
    "min"("offline_sync_log"."retention_until") AS "proximo_expira"
   FROM "public"."offline_sync_log"
UNION ALL
 SELECT 'unidades_saude_sync_log'::"text" AS "tabela",
    '90 dias'::"text" AS "politica",
    "count"(*) AS "total_registros",
    "count"(*) FILTER (WHERE ("unidades_saude_sync_log"."retention_until" < "now"())) AS "expirados",
    "min"("unidades_saude_sync_log"."retention_until") AS "proximo_expira"
   FROM "public"."unidades_saude_sync_log"
UNION ALL
 SELECT 'unidades_saude_sync_controle'::"text" AS "tabela",
    '1 ano'::"text" AS "politica",
    "count"(*) AS "total_registros",
    "count"(*) FILTER (WHERE ("unidades_saude_sync_controle"."retention_until" < "now"())) AS "expirados",
    "min"("unidades_saude_sync_controle"."retention_until") AS "proximo_expira"
   FROM "public"."unidades_saude_sync_controle"
UNION ALL
 SELECT 'levantamento_analise_ia'::"text" AS "tabela",
    '2 anos'::"text" AS "politica",
    "count"(*) AS "total_registros",
    "count"(*) FILTER (WHERE ("levantamento_analise_ia"."retention_until" < "now"())) AS "expirados",
    "min"("levantamento_analise_ia"."retention_until") AS "proximo_expira"
   FROM "public"."levantamento_analise_ia"
UNION ALL
 SELECT 'item_notificacoes_esus'::"text" AS "tabela",
    '5 anos'::"text" AS "politica",
    "count"(*) AS "total_registros",
    "count"(*) FILTER (WHERE ("item_notificacoes_esus"."retention_until" < "now"())) AS "expirados",
    "min"("item_notificacoes_esus"."retention_until") AS "proximo_expira"
   FROM "public"."item_notificacoes_esus"
UNION ALL
 SELECT 'foco_risco_historico'::"text" AS "tabela",
    'PERMANENTE'::"text" AS "politica",
    "count"(*) AS "total_registros",
    0 AS "expirados",
    NULL::timestamp with time zone AS "proximo_expira"
   FROM "public"."foco_risco_historico"
UNION ALL
 SELECT 'levantamento_item_status_historico'::"text" AS "tabela",
    'PERMANENTE'::"text" AS "politica",
    "count"(*) AS "total_registros",
    0 AS "expirados",
    NULL::timestamp with time zone AS "proximo_expira"
   FROM "public"."levantamento_item_status_historico"
UNION ALL
 SELECT 'sla_config_audit'::"text" AS "tabela",
    'PERMANENTE'::"text" AS "politica",
    "count"(*) AS "total_registros",
    0 AS "expirados",
    NULL::timestamp with time zone AS "proximo_expira"
   FROM "public"."sla_config_audit";


