CREATE OR REPLACE VIEW "public"."v_score_bairro" WITH ("security_invoker"='true') AS
 SELECT "ts"."cliente_id",
    "im"."bairro",
    "im"."regiao_id",
    "count"(*) AS "imoveis_com_score",
    "round"("avg"("ts"."score"), 1) AS "score_medio",
    "max"("ts"."score") AS "score_maximo",
    "percentile_cont"((0.75)::double precision) WITHIN GROUP (ORDER BY (("ts"."score")::double precision)) AS "score_p75",
    "count"(*) FILTER (WHERE ("ts"."classificacao" = ANY (ARRAY['muito_alto'::"text", 'critico'::"text"]))) AS "imoveis_criticos",
    "count"(*) FILTER (WHERE ("ts"."classificacao" = 'alto'::"text")) AS "imoveis_alto",
    "max"("ts"."calculado_em") AS "ultimo_calculo"
   FROM ("public"."territorio_score" "ts"
     JOIN "public"."imoveis" "im" ON ((("im"."id" = "ts"."imovel_id") AND ("im"."deleted_at" IS NULL))))
  GROUP BY "ts"."cliente_id", "im"."bairro", "im"."regiao_id";


ALTER VIEW "public"."v_score_bairro" OWNER TO "postgres";


