CREATE OR REPLACE VIEW "public"."v_slas_iminentes" WITH ("security_invoker"='on') AS
 SELECT "id",
    "cliente_id",
    "item_id",
    "levantamento_item_id",
    "prioridade",
    "sla_horas",
    "inicio",
    "prazo_final",
    "status",
    "escalonado",
    "escalonado_automatico",
    (GREATEST((0)::numeric, (EXTRACT(epoch FROM ("prazo_final" - "now"())) / (60)::numeric)))::integer AS "minutos_restantes",
    "round"(((EXTRACT(epoch FROM ("now"() - "inicio")) / NULLIF(EXTRACT(epoch FROM ("prazo_final" - "inicio")), (0)::numeric)) * (100)::numeric), 1) AS "pct_consumido"
   FROM "public"."sla_operacional" "s"
  WHERE (("status" = ANY (ARRAY['pendente'::"text", 'em_atendimento'::"text"])) AND ("prazo_final" IS NOT NULL) AND ("sla_horas" > 0) AND ("now"() >= ("prazo_final" - (((("sla_horas")::numeric * 0.20) || ' hours'::"text"))::interval)) AND ("now"() < "prazo_final"));


ALTER VIEW "public"."v_slas_iminentes" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_slas_iminentes" IS 'SLAs nos últimos 20% do prazo ainda não vencidos. Inclui minutos_restantes e pct_consumido para exibição no dashboard.';



