CREATE OR REPLACE VIEW "public"."v_tempo_por_estado_foco" WITH ("security_invoker"='true') AS
 WITH "historico_transicoes" AS (
         SELECT "h"."foco_risco_id",
            "h"."cliente_id",
            "h"."status_novo" AS "status",
            "h"."alterado_em" AS "entrou_em",
            "lead"("h"."alterado_em") OVER (PARTITION BY "h"."foco_risco_id" ORDER BY "h"."alterado_em") AS "proxima_transicao_em"
           FROM "public"."foco_risco_historico" "h"
          WHERE (("h"."status_novo" IS NOT NULL) AND (("h"."tipo_evento" = ANY (ARRAY['transicao_status'::"text", 'inspecao_iniciada'::"text"])) OR ("h"."tipo_evento" IS NULL)))
        )
 SELECT "foco_risco_id" AS "foco_id",
    "cliente_id",
    "status",
    "entrou_em",
    COALESCE("proxima_transicao_em", "now"()) AS "saiu_em",
    (GREATEST((0)::numeric, (EXTRACT(epoch FROM (COALESCE("proxima_transicao_em", "now"()) - "entrou_em")) / (60)::numeric)))::integer AS "duracao_minutos",
    ("proxima_transicao_em" IS NULL) AS "eh_estado_atual"
   FROM "historico_transicoes";


ALTER VIEW "public"."v_tempo_por_estado_foco" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_tempo_por_estado_foco" IS 'Duração de cada estado por foco, derivada de foco_risco_historico via LEAD(). eh_estado_atual=true quando saiu_em é now() (foco ainda neste estado). Filtro: status_novo IS NOT NULL AND (tipo_evento transicao/inspecao OR NULL legado). SLA Inteligente Fase A — não substitui sla_operacional. Migration: 20261018011000_sla_inteligente_fase_a_base.sql.';



CREATE OR REPLACE VIEW "public"."v_uso_resumo_ia" AS
 SELECT "cliente_id",
    "date_trunc"('day'::"text", ("created_at" AT TIME ZONE 'America/Sao_Paulo'::"text")) AS "dia",
    "count"(*) FILTER (WHERE ("tipo" = 'resumo_visualizado'::"text")) AS "visualizacoes",
    "count"(*) FILTER (WHERE ("tipo" = 'resumo_gerado'::"text")) AS "geracoes_auto",
    "count"(*) FILTER (WHERE ("tipo" = 'resumo_refresh_manual'::"text")) AS "refreshes_manuais",
    "count"(DISTINCT "usuario_id") FILTER (WHERE ("tipo" = ANY (ARRAY['resumo_visualizado'::"text", 'resumo_gerado'::"text", 'resumo_refresh_manual'::"text"]))) AS "usuarios_unicos"
   FROM "public"."piloto_eventos"
  WHERE ("tipo" = ANY (ARRAY['resumo_visualizado'::"text", 'resumo_gerado'::"text", 'resumo_refresh_manual'::"text"]))
  GROUP BY "cliente_id", ("date_trunc"('day'::"text", ("created_at" AT TIME ZONE 'America/Sao_Paulo'::"text")));


ALTER VIEW "public"."v_uso_resumo_ia" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_uso_rota" AS
 SELECT "cliente_id",
    "date_trunc"('day'::"text", ("created_at" AT TIME ZONE 'America/Sao_Paulo'::"text")) AS "dia",
    "count"(*) FILTER (WHERE ("tipo" = 'rota_otimizada'::"text")) AS "otimizacoes",
    "count"(*) FILTER (WHERE ("tipo" = 'rota_revertida'::"text")) AS "reversoes",
    "avg"((("payload" ->> 'imoveis_count'::"text"))::integer) FILTER (WHERE ("tipo" = 'rota_otimizada'::"text")) AS "media_imoveis_por_rota",
    "count"(DISTINCT "usuario_id") FILTER (WHERE ("tipo" = ANY (ARRAY['rota_otimizada'::"text", 'rota_revertida'::"text"]))) AS "agentes_unicos"
   FROM "public"."piloto_eventos"
  WHERE ("tipo" = ANY (ARRAY['rota_otimizada'::"text", 'rota_revertida'::"text"]))
  GROUP BY "cliente_id", ("date_trunc"('day'::"text", ("created_at" AT TIME ZONE 'America/Sao_Paulo'::"text")));


ALTER VIEW "public"."v_uso_rota" OWNER TO "postgres";


