CREATE OR REPLACE VIEW "public"."v_imovel_historico_acesso" WITH ("security_invoker"='on') AS
 SELECT "i"."id" AS "imovel_id",
    "i"."cliente_id",
    "i"."logradouro",
    "i"."numero",
    "i"."bairro",
    "i"."quarteirao",
    "i"."proprietario_ausente",
    "i"."tipo_ausencia",
    "i"."tem_animal_agressivo",
    "i"."historico_recusa",
    "i"."prioridade_drone",
    "i"."tem_calha",
    "i"."calha_acessivel",
    "i"."notificacao_formal_em",
    "count"("v"."id") AS "total_visitas",
    "count"("v"."id") FILTER (WHERE ("v"."acesso_realizado" = false)) AS "total_sem_acesso",
    "round"(((("count"("v"."id") FILTER (WHERE ("v"."acesso_realizado" = false)))::numeric / (NULLIF("count"("v"."id"), 0))::numeric) * (100)::numeric), 1) AS "pct_sem_acesso",
    "max"("v"."data_visita") FILTER (WHERE ("v"."acesso_realizado" = true)) AS "ultima_visita_com_acesso",
    "max"("v"."data_visita") AS "ultima_tentativa",
    (((("count"("v"."id") FILTER (WHERE ("v"."acesso_realizado" = false)))::numeric / (NULLIF("count"("v"."id"), 0))::numeric) > 0.8) OR ("i"."proprietario_ausente" = true)) AS "requer_notificacao_formal"
   FROM ("public"."imoveis" "i"
     LEFT JOIN "public"."vistorias" "v" ON (("v"."imovel_id" = "i"."id")))
  GROUP BY "i"."id";



