-- ── P8.2 — Dashboard Analítico Estratégico ────────────────────────────────────

CREATE OR REPLACE VIEW "public"."v_dashboard_analitico_resumo" WITH ("security_invoker"='true') AS
 SELECT v.cliente_id,
    count(*) AS total_vistorias,
    count(*) FILTER (WHERE v.prioridade_final = 'P1') AS p1_count,
    count(*) FILTER (WHERE v.prioridade_final = 'P2') AS p2_count,
    count(*) FILTER (WHERE v.prioridade_final = 'P3') AS p3_count,
    count(*) FILTER (WHERE v.prioridade_final = 'P4') AS p4_count,
    count(*) FILTER (WHERE v.resultado_operacional = 'visitado') AS visitados_count,
    count(*) FILTER (WHERE v.resultado_operacional = ANY (ARRAY['sem_acesso','sem_acesso_retorno'])) AS sem_acesso_count,
    round((100.0 * count(*) FILTER (WHERE v.resultado_operacional = 'visitado') / NULLIF(count(*) FILTER (WHERE v.resultado_operacional IS NOT NULL), 0)), 1) AS taxa_acesso_pct,
    count(*) FILTER (WHERE v.alerta_saude = 'urgente') AS alertas_urgentes,
    count(*) FILTER (WHERE v.vulnerabilidade_domiciliar = ANY (ARRAY['alta','critica'])) AS vulnerabilidade_alta_count,
    count(*) FILTER (WHERE v.risco_vetorial = ANY (ARRAY['alto','critico'])) AS risco_vetorial_alto_count,
    count(*) FILTER (WHERE v.risco_socioambiental = 'alto') AS risco_socio_alto_count
   FROM public.vistorias v
  WHERE v.deleted_at IS NULL
  GROUP BY v.cliente_id;

COMMENT ON VIEW "public"."v_dashboard_analitico_resumo" IS 'KPIs macro da consolidação avançada de vistoria por cliente. security_invoker=true — RLS de vistorias aplicado. P8.2.';

CREATE OR REPLACE VIEW "public"."v_dashboard_analitico_risco_territorial" WITH ("security_invoker"='true') AS
 SELECT v.cliente_id,
    COALESCE(im.bairro, '(sem bairro)') AS bairro,
    im.regiao_id,
    count(*) AS total_vistorias,
    count(*) FILTER (WHERE v.prioridade_final = ANY (ARRAY['P1','P2'])) AS criticos_count,
    count(*) FILTER (WHERE v.risco_vetorial = ANY (ARRAY['alto','critico'])) AS risco_vetorial_alto,
    count(*) FILTER (WHERE v.vulnerabilidade_domiciliar = ANY (ARRAY['alta','critica'])) AS vulnerabilidade_alta,
    count(*) FILTER (WHERE v.alerta_saude = ANY (ARRAY['atencao','urgente'])) AS alertas_saude,
    count(*) FILTER (WHERE v.alerta_saude = 'urgente') AS alertas_urgentes,
    count(*) FILTER (WHERE v.risco_socioambiental = 'alto') AS risco_socio_alto,
    count(*) FILTER (WHERE v.resultado_operacional = ANY (ARRAY['sem_acesso','sem_acesso_retorno'])) AS sem_acesso_total,
    round((100.0 * count(*) FILTER (WHERE v.prioridade_final = ANY (ARRAY['P1','P2'])) / NULLIF(count(*), 0)), 1) AS pct_criticos
   FROM (public.vistorias v JOIN public.imoveis im ON ((im.id = v.imovel_id AND im.deleted_at IS NULL)))
  WHERE v.deleted_at IS NULL
  GROUP BY v.cliente_id, im.bairro, im.regiao_id;

COMMENT ON VIEW "public"."v_dashboard_analitico_risco_territorial" IS 'Risco agregado por bairro: % críticos, contagens vetorial/vulnerabilidade/saúde. P8.2.';

CREATE OR REPLACE VIEW "public"."v_dashboard_analitico_vulnerabilidade" WITH ("security_invoker"='true') AS
 SELECT v.cliente_id,
    COALESCE(im.bairro, '(sem bairro)') AS bairro,
    v.vulnerabilidade_domiciliar,
    count(*) AS total
   FROM (public.vistorias v JOIN public.imoveis im ON ((im.id = v.imovel_id AND im.deleted_at IS NULL)))
  WHERE v.deleted_at IS NULL AND v.vulnerabilidade_domiciliar IS NOT NULL
  GROUP BY v.cliente_id, im.bairro, v.vulnerabilidade_domiciliar;

COMMENT ON VIEW "public"."v_dashboard_analitico_vulnerabilidade" IS 'Distribuição de vulnerabilidade_domiciliar por bairro. P8.2.';

CREATE OR REPLACE VIEW "public"."v_dashboard_analitico_alerta_saude" WITH ("security_invoker"='true') AS
 SELECT v.cliente_id,
    COALESCE(im.bairro, '(sem bairro)') AS bairro,
    v.alerta_saude,
    count(*) AS total
   FROM (public.vistorias v JOIN public.imoveis im ON ((im.id = v.imovel_id AND im.deleted_at IS NULL)))
  WHERE v.deleted_at IS NULL AND v.alerta_saude IS NOT NULL
  GROUP BY v.cliente_id, im.bairro, v.alerta_saude;

COMMENT ON VIEW "public"."v_dashboard_analitico_alerta_saude" IS 'Distribuição de alerta_saude por bairro. P8.2.';

CREATE OR REPLACE VIEW "public"."v_dashboard_analitico_resultado_operacional" WITH ("security_invoker"='true') AS
 SELECT v.cliente_id,
    COALESCE(im.bairro, '(sem bairro)') AS bairro,
    v.resultado_operacional,
    count(*) AS total
   FROM (public.vistorias v JOIN public.imoveis im ON ((im.id = v.imovel_id AND im.deleted_at IS NULL)))
  WHERE v.deleted_at IS NULL AND v.resultado_operacional IS NOT NULL
  GROUP BY v.cliente_id, im.bairro, v.resultado_operacional;

COMMENT ON VIEW "public"."v_dashboard_analitico_resultado_operacional" IS 'Distribuição de resultado_operacional por bairro. P8.2.';

CREATE OR REPLACE VIEW "public"."v_dashboard_analitico_imoveis_criticos" WITH ("security_invoker"='true') AS
 SELECT v.cliente_id,
    v.imovel_id,
    im.logradouro,
    im.numero,
    im.complemento,
    COALESCE(im.bairro, '(sem bairro)') AS bairro,
    im.regiao_id,
    v.id AS vistoria_id,
    v.data_visita,
    v.prioridade_final,
    v.prioridade_motivo,
    v.resultado_operacional,
    v.vulnerabilidade_domiciliar,
    v.alerta_saude,
    v.risco_socioambiental,
    v.risco_vetorial,
    ((CASE WHEN v.risco_vetorial = ANY (ARRAY['alto','critico']) THEN 1 ELSE 0 END +
      CASE WHEN v.vulnerabilidade_domiciliar = ANY (ARRAY['alta','critica']) THEN 1 ELSE 0 END +
      CASE WHEN v.alerta_saude = ANY (ARRAY['atencao','urgente']) THEN 1 ELSE 0 END +
      CASE WHEN v.risco_socioambiental = 'alto' THEN 1 ELSE 0 END)) AS dimensoes_criticas_count
   FROM (public.vistorias v JOIN public.imoveis im ON ((im.id = v.imovel_id AND im.deleted_at IS NULL)))
  WHERE v.deleted_at IS NULL AND v.prioridade_final = ANY (ARRAY['P1','P2']);

COMMENT ON VIEW "public"."v_dashboard_analitico_imoveis_criticos" IS 'Imóveis P1/P2 com todas as dimensões analíticas e score de criticidade (0-4). P8.2.';

-- ── P8.3 — Relatórios Automáticos e Executivos ────────────────────────────────

CREATE TABLE IF NOT EXISTS "public"."relatorios_gerados" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "cliente_id" "uuid" NOT NULL,
    "gerado_por" "uuid",
    "periodo_inicio" "date" NOT NULL,
    "periodo_fim" "date" NOT NULL,
    "payload" "jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "relatorios_gerados_pkey" PRIMARY KEY ("id"),
    CONSTRAINT "relatorios_gerados_cliente_id_fkey" FOREIGN KEY ("cliente_id") REFERENCES "public"."clientes"("id") ON DELETE CASCADE,
    CONSTRAINT "relatorios_gerados_gerado_por_fkey" FOREIGN KEY ("gerado_por") REFERENCES "auth"."users"("id") ON DELETE SET NULL
);

ALTER TABLE "public"."relatorios_gerados" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "relatorios_select_por_cliente" ON "public"."relatorios_gerados"
    FOR SELECT USING ("public"."usuario_pode_acessar_cliente"("cliente_id"));

CREATE POLICY "relatorios_insert_por_cliente" ON "public"."relatorios_gerados"
    FOR INSERT WITH CHECK ("public"."usuario_pode_acessar_cliente"("cliente_id"));

COMMENT ON TABLE "public"."relatorios_gerados" IS 'Histórico de relatórios analíticos gerados. payload = JSON completo do relatório. RLS por usuario_pode_acessar_cliente. P8.3.';



































